      SUBROUTINE AAD(X,N,IWRITE,XTEMP,MAXNXT,XAAD,ICASE,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE AVERAGE ABSOLUTE
!              DEVIATION (WITH DENOMINATOR N) OF THE DATA IN THE INPUT
!              VECTOR X.  NOTE THAT THERE ARE TWO VARIATIONS OF THIS
!              STATISTIC:
!
!              1) THE SAMPLE AVERAGE ABSOLUTE DEVIATION = (THE SUM OF
!                 THE ABSOLUTE DEVIATIONS ABOUT THE SAMPLE MEDIAN) / N).
!
!              2) THE SAMPLE AVERAGE ABSOLUTE DEVIATION = (THE SUM OF
!                 THE ABSOLUTE DEVIATIONS ABOUT THE SAMPLE MEAN) / N).
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ICASE  = EITHER "MEAN" OR "MEDI" TO SPECIFY
!                                WHICH OF THE TWO CASES TO COMPUTE.
!     OUTPUT ARGUMENTS--XAAD   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE AVERAGE ABSOLUTE
!                                DEVIATION.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE AVERAGE
!             ABSOLUTE DEVIATION (WITH DENOMINATOR N).
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEAN, MEDIAN AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--SNEDECOR AND COCHRAN, STATISTICAL METHODS,
!                 EDITION 6, 1967, PAGE 44.
!               --DIXON AND MASSEY, INTRODUCTION TO STATISTICAL
!                 ANALYSIS, EDITION 2, 1957, PAGES 19, 76.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JULY      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   1989. FIX COMPUTATIONAL BUG (ALAN)
!     UPDATED         --JULY      2014. ADD ICASE ARGUMRNT TO ALLOW
!                                       EITHER DEVIATIONS FROM THE
!                                       MEAN OR FROM THE MEDIAN
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DDEL
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMED
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='AAD '
      ISUBN2='    '
!
      IERROR='NO'
!
      DMED=0.0D0
      DDEL=0.0D0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF AAD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ICASE,N
   52   FORMAT('IBUGA3,ICASE,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************************
!               **  COMPUTE AVERAGE ABSOLUTE DEVIATION  **
!               ******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN AVERAGE ABSOLUTE DEVIATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        XAAD=0.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)
  136 FORMAT('***** WARNING IN AVERAGE ABSOLUTE DEVIATION--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,137)HOLD
  137 FORMAT('***** THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      XAAD=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE AVERAGE ABSOLUTE DEVIATION.  **
!               ***********************************************
!
      IWRIT2='OFF'
      IF(ICASE.EQ.'MEDI')THEN
        CALL MEDIAN(X,N,IWRIT2,XTEMP,MAXNXT,XMED,IBUGA3,IERROR)
        DMED=XMED
      ELSE
        CALL MEAN(X,N,IWRIT2,XMED,IBUGA3,IERROR)
        DMED=XMED
      ENDIF
!
      DN=N
      DSUM=0.0D0
      DO 300 I=1,N
        DX=X(I)
        DDEL=DX-DMED
        IF(DDEL.LT.0.0D0)DDEL=-DDEL
        DSUM=DSUM+DDEL
  300 CONTINUE
!
!     BUG FIX: AUGUST, 1987
!CCCC XAAD=DDEL/DN
!
      XAAD=DSUM/DN
!
!  END BUG FIX
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        IF(ICASE.EQ.'MEDI')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,813)N,XAAD
  813     FORMAT('THE AVERAGE ABSOLUTE DEVIATION (FROM THE MEDIAN) OF ',   &
                 I8,' THE OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,811)N,XAAD
  811     FORMAT('THE AVERAGE ABSOLUTE DEVIATION (FROM THE MEAN) OF ',   &
                 I8,' THE OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF AAD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,DMED,XAAD
 9012   FORMAT('IERROR,DMED,XAAD = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE AAD
      DOUBLE PRECISION FUNCTION ABRAM0(XVALUE)
!
!   DESCRIPTION:
!      This function calculates the Abramowitz function of order 0,
!      defined as
!
!       ABRAM0(x) = integral{ 0 to infinity } exp( -t*t - x/t ) dt
!
!       The code uses Chebyshev expansions with the coefficients
!       given to an accuracy of 20 decimal places.
!
!
!   ERROR RETURNS:
!      If XVALUE < 0.0, the function prints a message and returns the
!      value 0.0.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERMF - INTEGER - No. of terms needed for the array AB0F.
!               Recommended value such that
!                     ABS( AB0F(NTERMF) ) < EPS/100
!
!      NTERMG - INTEGER - No. of terms needed for array AB0G.
!               Recommended value such that
!                     ABS( AB0G(NTERMG) ) < EPS/100
!
!      NTERMH - INTEGER - No. of terms needed for array AB0H.
!               Recommended value such that
!                     ABS( AB0H(NTERMH) ) < EPS/100
!
!      NTERMA - INTEGER - No. of terms needed for array AB0AS.
!               Recommended value such that
!                     ABS( AB0AS(NTERMA) ) < EPS/100
!
!     XLOW1 - DOUBLE PRECISION - The value below which
!              ABRAM0 = root(pi)/2 + X ( ln X - GVAL0 )
!             Recommended value is SQRT(2*EPSNEG)
!
!     LNXMIN - DOUBLE PRECISION - The value of ln XMIN. Used to prevent
!              exponential underflow for large X.
!
!     For values of EPS, EPSNEG, XMIN refer to the file MACHCON.TXT.
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!     LOG, EXP, SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!
!      DR. ALLAN J. MACLEOD,
!      DEPT. OF MATHEMATICS AND STATISTICS,
!      UNIVERSITY OF PAISLEY ,
!      HIGH ST.,
!      PAISLEY,
!      SCOTLAND.
!      PA1 2BE
!
!      ( e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:   23 January
!
!
      INTEGER NTERMA,NTERMF,NTERMG,NTERMH
      DOUBLE PRECISION AB0F(0:8),AB0G(0:8),AB0H(0:8),AB0AS(0:27),   &
           ASLN,ASVAL,CHEVAL,FVAL,GVAL,GVAL0,HALF,HVAL,   &
           LNXMIN,ONEHUN,ONERPI,RTPIB2,RT3BPI,SIX,T,   &
           THREE,TWO,V,X,XLOW1,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*33
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA FNNAME/'ABRAM0'/
!CCCC DATA ERRMSG/'FUNCTION CALLED WITH ARGUMENT < 0'/
      DATA AB0F/-0.68121927093549469816D0,   &
                -0.78867919816149252495D0,   &
                 0.5121581776818819543D-1,   &
                -0.71092352894541296D-3,   &
                 0.368681808504287D-5,   &
                -0.917832337237D-8,   &
                 0.1270202563D-10,   &
                -0.1076888D-13,   &
                 0.599D-17/
      DATA AB0G/-0.60506039430868273190D0,   &
                -0.41950398163201779803D0,   &
                 0.1703265125190370333D-1,   &
                -0.16938917842491397D-3,   &
                 0.67638089519710D-6,   &
                -0.135723636255D-8,   &
                 0.156297065D-11,   &
                -0.112887D-14,   &
                 0.55D-18/
      DATA AB0H/1.38202655230574989705D0,   &
               -0.30097929073974904355D0,   &
                0.794288809364887241D-2,   &
               -0.6431910276847563D-4,   &
                0.22549830684374D-6,   &
               -0.41220966195D-9,   &
                0.44185282D-12,   &
               -0.30123D-15,   &
                0.14D-18/
      DATA AB0AS(0)/  1.97755499723693067407D0/
      DATA AB0AS(1)/ -0.1046024792004819485D-1/
      DATA AB0AS(2)/  0.69680790253625366D-3/
      DATA AB0AS(3)/ -0.5898298299996599D-4/
      DATA AB0AS(4)/  0.577164455305320D-5/
      DATA AB0AS(5)/ -0.61523013365756D-6/
      DATA AB0AS(6)/  0.6785396884767D-7/
      DATA AB0AS(7)/ -0.723062537907D-8/
      DATA AB0AS(8)/  0.63306627365D-9/
      DATA AB0AS(9)/ -0.989453793D-11/
      DATA AB0AS(10)/-0.1681980530D-10/
      DATA AB0AS(11)/ 0.673799551D-11/
      DATA AB0AS(12)/-0.200997939D-11/
      DATA AB0AS(13)/ 0.54055903D-12/
      DATA AB0AS(14)/-0.13816679D-12/
      DATA AB0AS(15)/ 0.3422205D-13/
      DATA AB0AS(16)/-0.826686D-14/
      DATA AB0AS(17)/ 0.194566D-14/
      DATA AB0AS(18)/-0.44268D-15/
      DATA AB0AS(19)/ 0.9562D-16/
      DATA AB0AS(20)/-0.1883D-16/
      DATA AB0AS(21)/ 0.301D-17/
      DATA AB0AS(22)/-0.19D-18/
      DATA AB0AS(23)/-0.14D-18/
      DATA AB0AS(24)/ 0.11D-18/
      DATA AB0AS(25)/-0.4D-19/
      DATA AB0AS(26)/ 0.2D-19/
      DATA AB0AS(27)/-0.1D-19/
      DATA ZERO,HALF,TWO/ 0.0D0 , 0.5D0, 2.0D0/
      DATA THREE,SIX,ONEHUN/ 3.0D0, 6.0D0 , 100.0D0/
      DATA RT3BPI/0.97720502380583984317D0/
      DATA RTPIB2/0.88622692545275801365D0/
      DATA GVAL0/0.13417650264770070909D0/
      DATA ONERPI/0.56418958354775628695D0/
!
      XLOW=0.0
      XLOW1=0.0
!
!   Start computation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         ABRAM0 = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM ABRAM0--ARGUMENT MUST BE ',   &
             'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(4) / ONEHUN
      IF ( X .LE. TWO ) THEN
         DO 10 NTERMF = 8 , 0 , -1
            IF ( ABS(AB0F(NTERMF)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERMG = 8 , 0 , -1
            IF ( ABS(AB0G(NTERMG)) .GT. T ) GO TO  29
 20      CONTINUE
 29      DO 30 NTERMH = 8 , 0 , -1
            IF ( ABS(AB0H(NTERMH)) .GT. T ) GO TO  39
 30      CONTINUE
 39      XLOW1 = SQRT ( TWO * D1MACH(3) )
      ELSE
         DO 40 NTERMA = 27 , 0 , -1
            IF ( ABS(AB0AS(NTERMA)) .GT. T ) GO TO  49
 40      CONTINUE
 49      LNXMIN = LOG(D1MACH(1))
      ENDIF
!
!   Code for 0 <= XVALUE <= 2
!
      IF ( X .LE. TWO ) THEN
         IF ( X .EQ. ZERO ) THEN
            ABRAM0 = RTPIB2
            RETURN
         ENDIF
         IF ( X .LT. XLOW1 ) THEN
            ABRAM0 = RTPIB2 + X * ( LOG( X ) - GVAL0 )
            RETURN
         ELSE
            T =  ( X * X / TWO - HALF ) - HALF
            FVAL = CHEVAL( NTERMF,AB0F,T )
            GVAL = CHEVAL( NTERMG,AB0G,T )
            HVAL = CHEVAL( NTERMH,AB0H,T )
            ABRAM0 = FVAL/ONERPI + X * ( LOG( X ) * HVAL- GVAL )
            RETURN
         ENDIF
      ELSE
!
!   Code for XVALUE > 2
!
         V = THREE *  ( (X / TWO) ** ( TWO / THREE ) )
         T =  ( SIX/V - HALF ) - HALF
         ASVAL = CHEVAL( NTERMA,AB0AS,T )
         ASLN = LOG( ASVAL / RT3BPI ) - V
         IF ( ASLN .LT. LNXMIN ) THEN
            ABRAM0 = ZERO
         ELSE
            ABRAM0 = EXP( ASLN )
         ENDIF
         RETURN
      ENDIF
      END FUNCTION ABRAM0
      DOUBLE PRECISION FUNCTION ABRAM1(XVALUE)
!
!   DESCRIPTION:
!      This function calculates the Abramowitz function of order 1,
!      defined as
!
!       ABRAM1(x) = integral{ 0 to infinity } t * exp( -t*t - x/t ) dt
!
!       The code uses Chebyshev expansions with the coefficients
!       given to an accuracy of 20 decimal places.
!
!
!   ERROR RETURNS:
!      If XVALUE < 0.0, the function prints a message and returns the
!      value 0.0.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERMF - INTEGER - No. of terms needed for the array AB1F.
!               Recommended value such that
!                     ABS( AB1F(NTERMF) ) < EPS/100
!
!      NTERMG - INTEGER - No. of terms needed for array AB1G.
!               Recommended value such that
!                     ABS( AB1G(NTERMG) ) < EPS/100
!
!      NTERMH - INTEGER - No. of terms needed for array AB1H.
!               Recommended value such that
!                     ABS( AB1H(NTERMH) ) < EPS/100
!
!      NTERMA - INTEGER - No. of terms needed for array AB1AS.
!               Recommended value such that
!                     ABS( AB1AS(NTERMA) ) < EPS/100
!
!      XLOW - DOUBLE PRECISION - The value below which
!                ABRAM1(x) = 0.5 to machine precision.
!             The recommended value is EPSNEG/2
!
!      XLOW1 - DOUBLE PRECISION - The value below which
!                ABRAM1(x) = (1 - x ( sqrt(pi) + xln(x) ) / 2
!              Recommended value is SQRT(2*EPSNEG)
!
!      LNXMIN - DOUBLE PRECISION - The value of ln XMIN. Used to prevent
!              exponential underflow for large X.
!
!      For values of EPS, EPSNEG, XMIN refer to the file MACHCON.TXT
!
!      The machine-dependent constants are computed internally by using
!      the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!     LOG, EXP, SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!
!      DR. ALLAN J. MACLEOD,
!      DEPT. OF MATHEMATICS AND STATISTICS,
!      UNIVERSITY OF PAISLEY,
!      HIGH ST.,
!      PAISLEY,
!      SCOTLAND.
!      PA1 2BE
!
!      ( e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:   23 January, 1996
!
!
      INTEGER NTERMA,NTERMF,NTERMG,NTERMH
      DOUBLE PRECISION AB1F(0:9),AB1G(0:8),AB1H(0:8),AB1AS(0:27),   &
           ASLN,ASVAL,CHEVAL,FVAL,GVAL,HALF,HVAL,   &
           LNXMIN,ONE,ONEHUN,ONERPI,RT3BPI,SIX,T,THREE,TWO,   &
           V,X,XLOW,XLOW1,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*33
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA FNNAME/'ABRAM1'/
!CCCC DATA ERRMSG/'FUNCTION CALLED WITH ARGUMENT < 0'/
      DATA AB1F/1.47285192577978807369D0,   &
                0.10903497570168956257D0,   &
               -0.12430675360056569753D0,   &
                0.306197946853493315D-2,   &
               -0.2218410323076511D-4,   &
                0.6989978834451D-7,   &
               -0.11597076444D-9,   &
                0.11389776D-12,   &
               -0.7173D-16,   &
                0.3D-19/
      DATA AB1G/0.39791277949054503528D0,   &
               -0.29045285226454720849D0,   &
                0.1048784695465363504D-1,   &
               -0.10249869522691336D-3,   &
                0.41150279399110D-6,   &
               -0.83652638940D-9,   &
                0.97862595D-12,   &
               -0.71868D-15,   &
                0.35D-18/
      DATA AB1H/0.84150292152274947030D0,   &
               -0.7790050698774143395D-1,   &
                0.133992455878390993D-2,   &
               -0.808503907152788D-5,   &
                0.2261858281728D-7,   &
               -0.3441395838D-10,   &
                0.3159858D-13,   &
               -0.1884D-16,   &
                0.1D-19/
      DATA AB1AS(0)/  2.13013643429065549448D0/
      DATA AB1AS(1)/  0.6371526795218539933D-1/
      DATA AB1AS(2)/ -0.129334917477510647D-2/
      DATA AB1AS(3)/  0.5678328753228265D-4/
      DATA AB1AS(4)/ -0.279434939177646D-5/
      DATA AB1AS(5)/  0.5600214736787D-7/
      DATA AB1AS(6)/  0.2392009242798D-7/
      DATA AB1AS(7)/ -0.750984865009D-8/
      DATA AB1AS(8)/  0.173015330776D-8/
      DATA AB1AS(9)/ -0.36648877955D-9/
      DATA AB1AS(10)/ 0.7520758307D-10/
      DATA AB1AS(11)/-0.1517990208D-10/
      DATA AB1AS(12)/ 0.301713710D-11/
      DATA AB1AS(13)/-0.58596718D-12/
      DATA AB1AS(14)/ 0.10914455D-12/
      DATA AB1AS(15)/-0.1870536D-13/
      DATA AB1AS(16)/ 0.262542D-14/
      DATA AB1AS(17)/-0.14627D-15/
      DATA AB1AS(18)/-0.9500D-16/
      DATA AB1AS(19)/ 0.5873D-16/
      DATA AB1AS(20)/-0.2420D-16/
      DATA AB1AS(21)/ 0.868D-17/
      DATA AB1AS(22)/-0.290D-17/
      DATA AB1AS(23)/ 0.93D-18/
      DATA AB1AS(24)/-0.29D-18/
      DATA AB1AS(25)/ 0.9D-19/
      DATA AB1AS(26)/-0.3D-19/
      DATA AB1AS(27)/ 0.1D-19/
      DATA ZERO,HALF,ONE/ 0.0D0, 0.5D0, 1.0D0/
      DATA TWO,THREE,SIX/ 2.0D0, 3.0D0, 6.0D0/
      DATA ONEHUN/100.0D0/
      DATA RT3BPI/ 0.97720502380583984317D0/
      DATA ONERPI/ 0.56418958354775628695D0/
!
      XLOW=0.0D0
      XLOW1=0.0D0
!
!   Start calculation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         ABRAM1 = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM ABRAM1--ARGUMENT MUST BE ',   &
             'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(4) / ONEHUN
      IF ( X .LE. TWO ) THEN
         DO 10 NTERMF = 9 , 0 , -1
            IF ( ABS(AB1F(NTERMF)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERMG = 8 , 0 , -1
            IF ( ABS(AB1G(NTERMG)) .GT. T ) GO TO  29
 20      CONTINUE
 29      DO 30 NTERMH = 8 , 0 , -1
            IF ( ABS(AB1H(NTERMH)) .GT. T ) GO TO  39
 30      CONTINUE
 39      T = D1MACH(3)
         XLOW1 = SQRT ( TWO * T )
         XLOW = T / TWO
      ELSE
         DO 40 NTERMA = 27 , 0 , -1
            IF ( ABS(AB1AS(NTERMA)) .GT. T ) GO TO  49
 40      CONTINUE
 49      LNXMIN = LOG(D1MACH(1))
      ENDIF
!
!   Code for 0 <= XVALUE <= 2
!
      IF ( X .LE. TWO ) THEN
         IF ( X .EQ. ZERO ) THEN
            ABRAM1 = HALF
            RETURN
         ENDIF
         IF ( X .LT. XLOW1 ) THEN
            IF ( X .LT. XLOW ) THEN
               ABRAM1 = HALF
            ELSE
               ABRAM1 = ( ONE - X / ONERPI - X * X * LOG( X ) ) * HALF
            ENDIF
            RETURN
         ELSE
            T =  ( X * X / TWO - HALF ) - HALF
            FVAL = CHEVAL( NTERMF,AB1F,T )
            GVAL = CHEVAL( NTERMG,AB1G,T )
            HVAL = CHEVAL( NTERMH,AB1H,T )
            ABRAM1 = FVAL - X * ( GVAL / ONERPI + X * LOG( X ) * HVAL )
            RETURN
         ENDIF
      ELSE
!
!   Code for XVALUE > 2
!
         V = THREE *  ( (X / TWO) ** ( TWO / THREE ) )
         T =  ( SIX / V - HALF ) - HALF
         ASVAL = CHEVAL( NTERMA,AB1AS,T )
         ASLN = LOG( ASVAL * SQRT ( V / THREE ) / RT3BPI ) - V
         IF ( ASLN .LT. LNXMIN ) THEN
            ABRAM1 = ZERO
         ELSE
            ABRAM1 = EXP( ASLN )
         ENDIF
         RETURN
      ENDIF
      END FUNCTION ABRAM1
      DOUBLE PRECISION FUNCTION ABRAM2(XVALUE)
!
!   DESCRIPTION:
!      This function calculates the Abramowitz function of order 2,
!      defined as
!
!       ABRAM2(x) = integral{ 0 to infinity } (t**2) * exp( -t*t - x/t ) dt
!
!      The code uses Chebyshev expansions with the coefficients
!      given to an accuracy of 20 decimal places.
!
!
!   ERROR RETURNS:
!      If XVALUE < 0.0, the function prints a message and returns the
!      value 0.0.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERMF - INTEGER - No. of terms needed for the array AB2F.
!               Recommended value such that
!                     ABS( AB2F(NTERMF) ) < EPS/100
!
!      NTERMG - INTEGER - No. of terms needed for array AB2G.
!               Recommended value such that
!                     ABS( AB2G(NTERMG) ) < EPS/100
!
!      NTERMH - INTEGER - No. of terms needed for array AB2H.
!               Recommended value such that
!                     ABS( AB2H(NTERMH) ) < EPS/100
!
!      NTERMA - INTEGER - No. of terms needed for array AB2AS.
!               Recommended value such that
!                     ABS( AB2AS(NTERMA) ) < EPS/100
!
!      XLOW - DOUBLE PRECISION - The value below which
!               ABRAM2 = root(pi)/4 to machine precision.
!             The recommended value is EPSNEG
!
!      XLOW1 - DOUBLE PRECISION - The value below which
!                ABRAM2 = root(pi)/4 - x/2 + x**3ln(x)/6
!              Recommended value is SQRT(2*EPSNEG)
!
!      LNXMIN - DOUBLE PRECISION - The value of ln XMIN. Used to prevent
!               exponential underflow for large X.
!
!     For values of EPS, EPSNEG, XMIN refer to the file MACHCON.TXT
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!     LOG, EXP
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!
!      DR. ALLAN J. MACLEOD,
!      DEPT. OF MATHEMATICS AND STATISTICS,
!      UNIVERSITY OF PAISLEY,
!      HIGH ST.,
!      PAISLEY,
!      SCOTLAND.
!      PA1 2BE
!
!      ( e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:   23 January, 1996
!
!
      INTEGER NTERMA,NTERMF,NTERMG,NTERMH
      DOUBLE PRECISION AB2F(0:9),AB2G(0:8),AB2H(0:7),AB2AS(0:26),   &
           ASLN,ASVAL,CHEVAL,FVAL,GVAL,HALF,HVAL,LNXMIN,   &
           ONEHUN,ONERPI,RTPIB4,RT3BPI,SIX,T,THREE,TWO,   &
           V,X,XLOW,XLOW1,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*33
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA FNNAME/'ABRAM2'/
!CCCC DATA ERRMSG/'FUNCTION CALLED WITH ARGUMENT < 0'/
      DATA AB2F/1.03612162804243713846D0,   &
                0.19371246626794570012D0,   &
               -0.7258758839233007378D-1,   &
                0.174790590864327399D-2,   &
               -0.1281223233756549D-4,   &
                0.4115018153651D-7,   &
               -0.6971047256D-10,   &
                0.6990183D-13,   &
               -0.4492D-16,   &
                0.2D-19/
      DATA AB2G/1.46290157198630741150D0,   &
                0.20189466883154014317D0,   &
               -0.2908292087997129022D-1,   &
                0.47061049035270050D-3,   &
               -0.257922080359333D-5,   &
                0.656133712946D-8,   &
               -0.914110203D-11,   &
                0.774276D-14,   &
               -0.429D-17/
      DATA AB2H/0.30117225010910488881D0,   &
               -0.1588667818317623783D-1,   &
                0.19295936935584526D-3,   &
               -0.90199587849300D-6,   &
                0.206105041837D-8,   &
               -0.265111806D-11,   &
                0.210864D-14,   &
               -0.111D-17/
      DATA AB2AS(0)/  2.46492325304334856893D0/
      DATA AB2AS(1)/  0.23142797422248905432D0/
      DATA AB2AS(2)/ -0.94068173010085773D-3/
      DATA AB2AS(3)/  0.8290270038089733D-4/
      DATA AB2AS(4)/ -0.883894704245866D-5/
      DATA AB2AS(5)/  0.106638543567985D-5/
      DATA AB2AS(6)/ -0.13991128538529D-6/
      DATA AB2AS(7)/  0.1939793208445D-7/
      DATA AB2AS(8)/ -0.277049938375D-8/
      DATA AB2AS(9)/  0.39590687186D-9/
      DATA AB2AS(10)/-0.5408354342D-10/
      DATA AB2AS(11)/ 0.635546076D-11/
      DATA AB2AS(12)/-0.38461613D-12/
      DATA AB2AS(13)/-0.11696067D-12/
      DATA AB2AS(14)/ 0.6896671D-13/
      DATA AB2AS(15)/-0.2503113D-13/
      DATA AB2AS(16)/ 0.785586D-14/
      DATA AB2AS(17)/-0.230334D-14/
      DATA AB2AS(18)/ 0.64914D-15/
      DATA AB2AS(19)/-0.17797D-15/
      DATA AB2AS(20)/ 0.4766D-16/
      DATA AB2AS(21)/-0.1246D-16/
      DATA AB2AS(22)/ 0.316D-17/
      DATA AB2AS(23)/-0.77D-18/
      DATA AB2AS(24)/ 0.18D-18/
      DATA AB2AS(25)/-0.4D-19/
      DATA AB2AS(26)/ 0.1D-19/
      DATA ZERO,HALF,TWO/ 0.0D0 , 0.5D0, 2.0D0/
      DATA THREE,SIX,ONEHUN/ 3.0D0, 6.0D0 , 100.0D0/
      DATA RT3BPI/ 0.97720502380583984317D0/
      DATA RTPIB4/ 0.44311346272637900682D0/
      DATA ONERPI/ 0.56418958354775628695D0/
!
      XLOW=0.0
      XLOW1=0.0
!
!   Start calculation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         ABRAM2 = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM ABRAM2--ARGUMENT MUST BE ',   &
             'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(4) / ONEHUN
      IF ( X .LE. TWO ) THEN
         DO 10 NTERMF = 9 , 0 , -1
            IF ( ABS(AB2F(NTERMF)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERMG = 8 , 0 , -1
            IF ( ABS(AB2G(NTERMG)) .GT. T ) GO TO  29
 20      CONTINUE
 29      DO 30 NTERMH = 7 , 0 , -1
            IF ( ABS(AB2H(NTERMH)) .GT. T ) GO TO  39
 30      CONTINUE
 39      XLOW = D1MACH(3)
         XLOW1 = SQRT ( TWO * XLOW )
      ELSE
         DO 40 NTERMA = 26 , 0 , -1
            IF ( ABS(AB2AS(NTERMA)) .GT. T ) GO TO  49
 40      CONTINUE
 49      LNXMIN = LOG(D1MACH(1))
      ENDIF
!
!   Code for 0 <= XVALUE <= 2
!
      IF ( X .LE. TWO ) THEN
         IF ( X .EQ. ZERO ) THEN
            ABRAM2 = RTPIB4
            RETURN
         ENDIF
         IF ( X .LT. XLOW1 ) THEN
            IF ( X .LT. XLOW ) THEN
               ABRAM2 = RTPIB4
            ELSE
               ABRAM2 = RTPIB4 - HALF * X + X * X * X * LOG( X ) / SIX
            ENDIF
            RETURN
         ELSE
            T =  ( X * X / TWO - HALF ) - HALF
            FVAL = CHEVAL( NTERMF,AB2F,T )
            GVAL = CHEVAL( NTERMG,AB2G,T )
            HVAL = CHEVAL( NTERMH,AB2H,T )
            ABRAM2 = FVAL/ONERPI + X * ( X * X * LOG(X) * HVAL- GVAL )
            RETURN
         ENDIF
      ELSE
!
!   Code for XVALUE > 2
!
         V = THREE *  ( (X / TWO) ** ( TWO / THREE ) )
         T =  ( SIX / V - HALF ) - HALF
         ASVAL = CHEVAL( NTERMA,AB2AS,T )
         ASLN = LOG( ASVAL / RT3BPI ) + LOG( V / THREE ) - V
         IF ( ASLN .LT. LNXMIN ) THEN
            ABRAM2 = ZERO
         ELSE
            ABRAM2 = EXP( ASLN )
         ENDIF
         RETURN
      ENDIF
      END FUNCTION ABRAM2
      SUBROUTINE ADAPT(NDIM, MINCLS, MAXCLS, FUNCTN,   &
           ABSREQ, RELREQ, LENWRK, WORK, ABSEST, FINEST, INFORM)
!
!   Adaptive Multidimensional Integration Subroutine
!
!   Author: Alan Genz
!           Department of Mathematics
!           Washington State University
!           Pullman, WA 99164-3113 USA
!
!  This subroutine computes an approximation to the integral
!
!      1 1     1
!     I I ... I       FUNCTN(NDIM,X)  dx(NDIM)...dx(2)dx(1)
!      0 0     0
!
!**************  Parameters for ADAPT  ********************************
!
!***** Input Parameters
!
!  NDIM    Integer number of integration variables.
!  MINCLS  Integer minimum number of FUNCTN calls to be allowed; MINCLS
!          must not exceed MAXCLS. If MINCLS < 0, then ADAPT assumes
!          that a previous call of ADAPT has been made with the same
!          integrand and continues that calculation.
!  MAXCLS  Integer maximum number of FUNCTN calls to be used; MAXCLS
!          must be >= RULCLS, the number of function calls required for
!          one application of the basic integration rule.
!           IF ( NDIM .EQ. 1 ) THEN
!              RULCLS = 11
!           ELSE IF ( NDIM .LT. 15 ) THEN
!              RULCLS = 2**NDIM + 2*NDIM*(NDIM+3) + 1
!           ELSE
!              RULCLS = 1 + NDIM*(24-NDIM*(6-NDIM*4))/3
!           ENDIF
!  FUNCTN  Externally declared real user defined integrand. Its
!          parameters must be (NDIM, Z), where Z is a real array of
!          length NDIM.
!  ABSREQ  Real required absolute accuracy.
!  RELREQ  Real required relative accuracy.
!  LENWRK  Integer length of real array WORK (working storage); ADAPT
!          needs LENWRK >= 16*NDIM + 27. For maximum efficiency LENWRK
!          should be about 2*NDIM*MAXCLS/RULCLS if MAXCLS FUNCTN
!          calls are needed. If LENWRK is significantly less than this,
!          ADAPT may be less efficient.
!
!***** Output Parameters
!
!  MINCLS  Actual number of FUNCTN calls used by ADAPT.
!  WORK    Real array (length LENWRK) of working storage. This contains
!          information that is needed for additional calls of ADAPT
!          using the same integrand (input MINCLS < 0).
!  ABSEST  Real estimated absolute accuracy.
!  FINEST  Real estimated value of integral.
!  INFORM  INFORM = 0 for normal exit, when ABSEST <= ABSREQ or
!                     ABSEST <= |FINEST|*RELREQ with MINCLS <= MAXCLS.
!          INFORM = 1 if MAXCLS was too small for ADAPT to obtain the
!                     result FINEST to within the requested accuracy.
!          INFORM = 2 if MINCLS > MAXCLS, LENWRK < 16*NDIM + 27 or
!                     RULCLS > MAXCLS.
!
!***********************************************************************
!
!     Begin driver routine. This routine partitions the working storage
!      array and then calls the main subroutine ADBASE.
!
      EXTERNAL FUNCTN
      INTEGER NDIM, MINCLS, MAXCLS, LENWRK, INFORM
      DOUBLE PRECISION   &
           FUNCTN, ABSREQ, RELREQ, WORK(LENWRK), ABSEST, FINEST
      INTEGER SBRGNS, MXRGNS, RULCLS, LENRUL,   &
       INERRS, INVALS, INPTRS, INLWRS, INUPRS, INMSHS, INPNTS, INWGTS,   &
       INLOWR, INUPPR, INWDTH, INMESH, INWORK
!
      IF ( NDIM .EQ. 1 ) THEN
         LENRUL = 5
         RULCLS = 9
      ELSE IF ( NDIM .LT. 12 ) THEN
         LENRUL = 6
         RULCLS = 2**NDIM + 2*NDIM*(NDIM+2) + 1
      ELSE
         LENRUL = 6
         RULCLS = 1 + 2*NDIM*(1+2*NDIM)
      ENDIF
      IF ( LENWRK .GE. LENRUL*(NDIM+4) + 10*NDIM + 3 .AND.   &
           RULCLS .LE. MAXCLS .AND. MINCLS .LE. MAXCLS ) THEN
        MXRGNS = ( LENWRK - LENRUL*(NDIM+4) - 7*NDIM )/( 3*NDIM + 3 )
        INERRS = 1
        INVALS = INERRS + MXRGNS
        INPTRS = INVALS + MXRGNS
        INLWRS = INPTRS + MXRGNS
        INUPRS = INLWRS + MXRGNS*NDIM
        INMSHS = INUPRS + MXRGNS*NDIM
        INWGTS = INMSHS + MXRGNS*NDIM
        INPNTS = INWGTS + LENRUL*4
        INLOWR = INPNTS + LENRUL*NDIM
        INUPPR = INLOWR + NDIM
        INWDTH = INUPPR + NDIM
        INMESH = INWDTH + NDIM
        INWORK = INMESH + NDIM
        IF ( MINCLS .LT. 0 ) SBRGNS = INT(WORK(LENWRK))
        CALL ADBASE(NDIM, MINCLS, MAXCLS, FUNCTN, ABSREQ, RELREQ,   &
             ABSEST, FINEST, SBRGNS, MXRGNS, RULCLS, LENRUL,   &
             WORK(INERRS), WORK(INVALS), WORK(INPTRS), WORK(INLWRS),   &
             WORK(INUPRS), WORK(INMSHS), WORK(INWGTS), WORK(INPNTS),   &
             WORK(INLOWR), WORK(INUPPR), WORK(INWDTH), WORK(INMESH),   &
             WORK(INWORK), INFORM)
        WORK(LENWRK) = SBRGNS
       ELSE
        INFORM = 2
        MINCLS = RULCLS
      ENDIF
!
      RETURN
      END SUBROUTINE ADAPT
      SUBROUTINE ADBASE(NDIM, MINCLS, MAXCLS, FUNCTN, ABSREQ, RELREQ,   &
           ABSEST, FINEST, SBRGNS, MXRGNS, RULCLS, LENRUL,   &
           ERRORS, VALUES, PONTRS, LOWERS,   &
           UPPERS, MESHES, WEGHTS, POINTS,   &
           LOWER, UPPER, WIDTH, MESH, WORK, INFORM)
!
!        Main adaptive integration subroutine
!
      EXTERNAL FUNCTN
      INTEGER I, J, NDIM, MINCLS, MAXCLS, SBRGNS, MXRGNS,   &
           RULCLS, LENRUL, INFORM, NWRGNS
      DOUBLE PRECISION FUNCTN, ABSREQ, RELREQ, ABSEST, FINEST,   &
           ERRORS(*), VALUES(*), PONTRS(*),   &
           LOWERS(NDIM,*), UPPERS(NDIM,*),   &
           MESHES(NDIM,*),WEGHTS(*), POINTS(*),   &
           LOWER(*), UPPER(*), WIDTH(*), MESH(*), WORK(*)
      INTEGER DIVAXN, TOP, RGNCLS, FUNCLS, DIFCLS
                                                                                                                                  
!
!     Initialization of subroutine
!
      INFORM = 2
      FUNCLS = 0
      CALL BSINIT(NDIM, WEGHTS, LENRUL, POINTS)
      IF ( MINCLS .GE. 0) THEN
!
!       When MINCLS >= 0 determine initial subdivision of the
!       integration region and apply basic rule to each subregion.
!
         SBRGNS = 0
         DO 100 I = 1,NDIM
            LOWER(I) = 0
            MESH(I) = 1
            WIDTH(I) = 1/(2*MESH(I))
            UPPER(I) = 1
 100     CONTINUE
         DIVAXN = 0
         RGNCLS = RULCLS
         NWRGNS = 1
 10      CALL DIFFER(NDIM, LOWER, UPPER, WIDTH, WORK, WORK(NDIM+1),   &
              FUNCTN, DIVAXN, DIFCLS)
         FUNCLS = FUNCLS + DIFCLS
         IF ( FUNCLS +   &
              RGNCLS*INT((MESH(DIVAXN)+1.0D0)/MESH(DIVAXN))   &
              .LE. MINCLS ) THEN
            RGNCLS = RGNCLS*INT((MESH(DIVAXN)+1.0D0)/MESH(DIVAXN))
            NWRGNS = NWRGNS*INT((MESH(DIVAXN)+1.0D0)/MESH(DIVAXN))
            MESH(DIVAXN) = MESH(DIVAXN) + 1.0D0
            WIDTH(DIVAXN) = 1.0D0/( 2.0D0*MESH(DIVAXN) )
            GO TO 10
         ENDIF
         IF ( NWRGNS .LE. MXRGNS ) THEN
            DO 200 I = 1,NDIM
               UPPER(I) = LOWER(I) + 2*WIDTH(I)
               MESH(I) = 1.0D0
 200        CONTINUE
         ENDIF
!
!     Apply basic rule to subregions and store results in heap.
!
 20      SBRGNS = SBRGNS + 1
         CALL BASRUL(NDIM, LOWER, UPPER, WIDTH, FUNCTN,   &
              WEGHTS, LENRUL, POINTS, WORK, WORK(NDIM+1),   &
              ERRORS(SBRGNS),VALUES(SBRGNS))
         CALL TRESTR(SBRGNS, SBRGNS, PONTRS, ERRORS)
         DO 300 I = 1,NDIM
            LOWERS(I,SBRGNS) = LOWER(I)
            UPPERS(I,SBRGNS) = UPPER(I)
            MESHES(I,SBRGNS) = MESH(I)
  300    CONTINUE
         DO 400 I = 1,NDIM
            LOWER(I) = UPPER(I)
            UPPER(I) = LOWER(I) + 2*WIDTH(I)
            IF ( LOWER(I)+WIDTH(I) .LT. 1 )  GO TO 20
            LOWER(I) = 0
            UPPER(I) = LOWER(I) + 2*WIDTH(I)
  400    CONTINUE
         FUNCLS = FUNCLS + SBRGNS*RULCLS
      ENDIF
!
!     Check for termination
!
 30   FINEST = 0
      ABSEST = 0
      DO 500 I = 1, SBRGNS
         FINEST = FINEST + VALUES(I)
         ABSEST = ABSEST + ERRORS(I)
 500  CONTINUE
      IF ( ABSEST .GT. MAX( ABSREQ, RELREQ*ABS(FINEST) )   &
           .OR. FUNCLS .LT. MINCLS ) THEN
!
!     Prepare to apply basic rule in (parts of) subregion with
!     largest error.
!
         TOP = INT(PONTRS(1))
         RGNCLS = RULCLS
         DO 600 I = 1,NDIM
            LOWER(I) = LOWERS(I,TOP)
            UPPER(I) = UPPERS(I,TOP)
            MESH(I) = MESHES(I,TOP)
            WIDTH(I) = (UPPER(I)-LOWER(I))/(2*MESH(I))
            RGNCLS = INT(DBLE(RGNCLS)*MESH(I))
  600    CONTINUE
         CALL DIFFER(NDIM, LOWER, UPPER, WIDTH, WORK, WORK(NDIM+1),   &
              FUNCTN, DIVAXN, DIFCLS)
         FUNCLS = FUNCLS + DIFCLS
         RGNCLS = INT(DBLE(RGNCLS)*(MESH(DIVAXN)+1.0D0)/MESH(DIVAXN))
         IF ( FUNCLS + RGNCLS .LE. MAXCLS ) THEN
            IF ( SBRGNS + 1 .LE. MXRGNS ) THEN
!
!     Prepare to subdivide into two pieces.
!
               NWRGNS = 1
               WIDTH(DIVAXN) = WIDTH(DIVAXN)/2
            ELSE
               NWRGNS = 0
               WIDTH(DIVAXN) = WIDTH(DIVAXN)   &
                              *MESH(DIVAXN)/( MESH(DIVAXN) + 1 )
               MESHES(DIVAXN,TOP) = MESH(DIVAXN) + 1
            ENDIF
            IF ( NWRGNS .GT. 0 ) THEN
!
!     Only allow local subdivision when space is available.
!
               DO 700 J = SBRGNS+1,SBRGNS+NWRGNS
                  DO 800 I = 1,NDIM
                     LOWERS(I,J) = LOWER(I)
                     UPPERS(I,J) = UPPER(I)
                     MESHES(I,J) = MESH(I)
  800             CONTINUE
  700          CONTINUE
               UPPERS(DIVAXN,TOP) = LOWER(DIVAXN) + 2*WIDTH(DIVAXN)
               LOWERS(DIVAXN,SBRGNS+1) = UPPERS(DIVAXN,TOP)
            ENDIF
            FUNCLS = FUNCLS + RGNCLS
            CALL BASRUL(NDIM, LOWERS(1,TOP), UPPERS(1,TOP), WIDTH,   &
                 FUNCTN, WEGHTS, LENRUL, POINTS, WORK, WORK(NDIM+1),   &
                 ERRORS(TOP), VALUES(TOP))
            CALL TRESTR(TOP, SBRGNS, PONTRS, ERRORS)
            DO 900 I = SBRGNS+1, SBRGNS+NWRGNS
!
!     Apply basic rule and store results in heap.
!
               CALL BASRUL(NDIM, LOWERS(1,I), UPPERS(1,I), WIDTH,   &
                    FUNCTN, WEGHTS, LENRUL, POINTS, WORK, WORK(NDIM+1),   &
                    ERRORS(I), VALUES(I))
               CALL TRESTR(I, I, PONTRS, ERRORS)
  900       CONTINUE
            SBRGNS = SBRGNS + NWRGNS
            GO TO 30
         ELSE
            INFORM = 1
         ENDIF
      ELSE
         INFORM = 0
      ENDIF
      MINCLS = FUNCLS
!
      RETURN
      END SUBROUTINE ADBASE
      SUBROUTINE ADECDF(X,AK,IADEDF,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!              (OR ASYMMETRIC DOUBLE EXPONENTIAL)
!              WITH SHAPE PARAMETER = K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 ADECDF(X,K) = 1 - (1/(1+K*K))*
!                               EXP(-SQRT(2)*K*ABS(X))    X >= 0
!                 ADECDF(X,K) = (K*K/(1+K*K))*
!                               EXP((-SQRT(2)/K)*ABS(X))  X >= 0
!                 ADECDF(X,K) = (SQRT(2)*K/(1+K^2))*
!                               EXP((-SQRT(2)/K)*ABS(X))  X < 0
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE CUMULATIVE DISTRIBUTION
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!                     --AK    = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF   = THE SINGLE PRECISION CUMULATIVE
!                               DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!             WITH SHAPE PARAMETER = K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
!
      CHARACTER*4 IADEDF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE CDF     FUNCTION  **
!               ************************************
!
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,5)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
          CALL DPWRST('XXX','WRIT')
          CDF=0.0
          GO TO 9000
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (K) IN ADECDF ',   &
             'ROUTINE IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      DX=DBLE(X)
      DK=DBLE(AK)
!
      IF(X.LT.0.0)THEN
        DTERM1=DK*DK/(1.0D0 + DK*DK)
        DCDF=DTERM1*DEXP((-DSQRT(2.0D0)/DK)*DABS(DX))
      ELSE
        DTERM1=1.0D0/(1.0D0 + DK*DK)
        DCDF=1.0D0 - DTERM1*DEXP(-DSQRT(2.0D0)*DK*DABS(DX))
      ENDIF
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ADECDF
      SUBROUTINE ADEML1(Y,N,MAXNXT,   &
                        TEMP1,DALPHA,DBETA,DH,   &
                        XMEAN,XMED,XSD,XVAR,XMIN,XMAX,   &
                        ALOCML,SCALML,AKML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE ASYMMETRIC DOUBLE EXPONENTIAL DISTRIBUTION FOR
!              THE RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).
!              THIS ROUTINE RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE
!              INTERVALS WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLAD WILL GENERATE THE OUTPUT
!              FOR THE ASYMMETRIC DOUBLE EXPONENTIAL MLE COMMAND).
!
!              THE ALGORITHM IS:
!
!              1) SORT THE DATA
!
!              2) COMPUTE
!
!                 h(x(j)) = 2*LOG[alpha(theta)) + SQRT(beta(theta))] +
!                           SQRT(alpha(theta)*SQRT(beta(theta))
!
!                 WHERE
!
!                 alpha(theta) = (1/N)*SUM[j=1 to N][(x(j) - theta)+]
!                 beta(theta)  = (1/N)*SUM[j=1 to N][(x(j) - theta)-]
!
!                 WHERE
!
!                 (x(j) - theta)+ = x(j) - theta       x(j) >= theta
!                                 = 0                  x(j) < theta
!                 (x(j) - theta)- = theta - x(j)       x(j) <= theta
!                                 = 0                  x(j) > theta
!
!              3) SET R EQUAL TO THE VALUE OF J WHERE H(x(j)) HAS
!                 IT'S MINIMUM VALUE.
!
!              4) IF R=1 OR R=N, THE MAXIMUM LIKELIHOOD ESTIMATES
!                 DO NOT EXIST.  HOWEVER, THESE CASES SUGGEST
!                 POSITIVE AND NEGATIVE EXPONENTIAL DISTRIBUTIONS,
!                 RESPECTIVELY.
!
!              5) OTHERWISE, THE MAXIMUM LIKELIHOOD ESTIMATES ARE:
!
!                 THETAHAT = X(R)
!
!                 KHAT     = (BETA(THETAHAT))**(1/4)/
!                            (ALPHA(THETAHAT))**(1/4)
!
!                 SIGMAHAT = SQRT(2)*(BETA(THETAHAT))**(1/4)*
!                            (ALPHA(THETAHAT))**(1/4)*
!                            (SQRT(ALPHA(THETAHAT)) +
!                            SQRT(BETA(THETAHAT)))
!
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 133-178.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLAD)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DALPHA(*)
      DOUBLE PRECISION DBETA(*)
      DOUBLE PRECISION DH(*)
!
      DOUBLE PRECISION DHMIN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ADEM'
      ISUBN2='L1  '
!
      IERROR='NO'
      IWRITE='OFF'
      AN=REAL(N)
      ALOCML=CPUMIN
      SCALML=CPUMIN
      AKML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF ADEML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  CARRY OUT CALCULATIONS                         **
!               **  FOR ASYMMETRIC DOUBLE EXPONENTIAL MLE ESTIMATE **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='ASYMMETRIC DOUBLE EXPONENTIAL'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXNXT,XMED,IBUGA3,IERROR)
      CALL SORT(Y,N,Y)
!
      DHMIN=DBLE(CPUMAX)
      DO 2110 I=1,N
        THETA=Y(I)
        DSUM1=0.0D0
        DSUM2=0.0D0
        DO 2120 J=1,N
          IF(Y(J).GE.THETA)DSUM1=DSUM1 + DBLE(Y(J) - THETA)
          IF(Y(J).LE.THETA)DSUM2=DSUM2 + DBLE(THETA - Y(J))
 2120   CONTINUE
        DALPHA(I)=DSUM1/DBLE(N)
        DBETA(I)=DSUM2/DBLE(N)
        DH(I)=2.0D0*DLOG(DSQRT(DALPHA(I)) + DSQRT(DBETA(I)))   &
              + DSQRT(DALPHA(I))*DSQRT(DBETA(I))
        IF(DH(I).LT.DHMIN)THEN
          DHMIN=DH(I)
          IR=I
        ENDIF
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,2125)I,IR,Y(I),DALPHA(I),DBETA(I),DH(I),DHMIN
 2125     FORMAT('I,IR,Y(I),DALPHA(I),DBETA(I),DH(I),DHMIN = ',   &
                 2I8,5G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
 2110 CONTINUE
!
      IF(IR.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
 2131   FORMAT('***** ERROR IN ASYMMETRIC DOUBLE EXPONENTIAL ',   &
             'MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2133)
 2133   FORMAT('      ESTIMATE OF LOCATION PARAMTER EQUALS DATA ',   &
             'MINIMUM.  THE MAXIMUM')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2135)
 2135   FORMAT('      LIKELIHOOD ESTIMATES DO NOT EXIST.  HOWEVER, ')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2137)
 2137   FORMAT('      THIS IMPLIES THAT AN EXPONENTIAL MODEL IS ',   &
               'APPROPRIATE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(IR.EQ.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2143)
 2143   FORMAT('      ESTIMATE OF LOCATION PARAMTER EQUALS DATA ',   &
             'MAXIMUM.  THE MAXIMUM')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2145)
 2145   FORMAT('      LIKELIHOOD ESTIMATES DO NOT EXIST.  HOWEVER, ')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2147)
 2147   FORMAT('      THIS IMPLIES THAT A NEGATIVE EXPONENTIAL ',   &
               'MODEL IS APPROPRIATE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSE
        ALOCML=Y(IR)
      ENDIF
!
      DTERM1=DBETA(IR)**(1.0D0/4.0D0)
      DTERM2=DALPHA(IR)**(1.0D0/4.0D0)
      DTERM3=DSQRT(DBETA(IR))
      DTERM4=DSQRT(DALPHA(IR))
      IF(DTERM2.LE.0.0D0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2153)
 2153   FORMAT('      INFINITE VALUE FOR THE SHAPE PARAMETER.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2155)
 2155   FORMAT('      THE CAUSE OF THIS IS TIES FOR THE ',   &
               'MAXIMUM DATA VALUE AND')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2157)
 2157   FORMAT('      THE ESTIMATE OF THE LOCATION PARAMETER ',   &
               'OCCURS AT THE DATA MAXIMUM.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      AKML=DTERM1/DTERM2
      SCALML=DSQRT(2.0D0)*DTERM2*DTERM1*(DTERM3 + DTERM4)
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF ADEML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)ALOCML,SCALML,AKML
 9019   FORMAT('ALOCML,SCALML,AKML =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9021)IERROR
 9021   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE ADEML1
      SUBROUTINE ADEPDF(X,AK,IADEDF,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!              (OR ASYMMETRIC DOUBLE EXPONENTIAL)
!              WITH SHAPE PARAMETER = K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 ADEPDF(X,K) = (SQRT(2)*K/(1+K^2))*
!                               EXP(-SQRT(2)*K*ABS(X))  X >= 0
!                 ADEPDF(X,K) = (SQRT(2)*K/(1+K^2))*
!                               EXP((-SQRT(2)/K)*ABS(X))  X < 0
!     INPUT  ARGUMENTS--X     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE PROBABILITY DENSITY
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!                     --AK    = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF   = THE SINGLE PRECISION PROBABILITY
!                               DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!             WITH SHAPE PARAMETER = K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
!
      CHARACTER*4 IADEDF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,5)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
          CALL DPWRST('XXX','WRIT')
          PDF=0.0
          GO TO 9000
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (K) IN ADEPDF ',   &
             'ROUTINE IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      DX=DBLE(X)
      DK=DBLE(AK)
!
      DTERM1=DSQRT(2.0D0)*DK/(1.0D0+DK*DK)
      IF(X.LT.0.0)THEN
        DPDF=DTERM1*DEXP((-DSQRT(2.0D0)/DK)*DABS(DX))
      ELSE
        DPDF=DTERM1*DEXP(-DSQRT(2.0D0)*DK*DABS(DX))
      ENDIF
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ADEPDF
      SUBROUTINE ADEPPF(P,AK,IADEDF,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!              (OR ASYMMETRIC DOUBLE EXPONENTIAL)
!              WITH SHAPE PARAMETER = K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PERCENT POINT FUNCTION
!                 G(P,K) = (K/SQRT(2))*LOG[((1+K**2)/K**2)*P]
!                               0 < P < K**2/(1+K**2)
!                 G(P,K) = (-1/(K*SQRT(2)))*LOG[((1+K**2)*(1-P)]
!                               K**2/(1+K**2) < P < 1
!     INPUT  ARGUMENTS--P     = THE SINGLE PRECISION VALUE AT
!                               WHICH THE PERCENT POINT
!                               FUNCTION IS TO BE EVALUATED.
!                               P SHOULD BE IN THE INTERVAL (0,1).
!                     --AK    = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF   = THE SINGLE PRECISION PERCENT POINT
!                               FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!             WITH SHAPE PARAMETER = K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DK
      DOUBLE PRECISION DPPF
!
      CHARACTER*4 IADEDF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE ADEPPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)P
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         PPF=0.0
         GO TO 9000
      ENDIF
!
!
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,5)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
          CALL DPWRST('XXX','WRIT')
          PPF=0.0
          GO TO 9000
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (K) IN ADEPPF ',   &
             'ROUTINE IS NEGATIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
      DP=DBLE(P)
      DK=DBLE(AK)
      PCUT=AK**2/(1.0+AK**2)
!
      IF(P.LT.PCUT)THEN
        DPPF=(DK/DSQRT(2.0D0))*DLOG(((1.0D0+DK*DK)/(DK*DK))*DP)
      ELSE
        DPPF=(-1.0D0/(DSQRT(2.0D0)*DK))*DLOG((1.0D0+DK*DK)*(1.0D0-DP))
      ENDIF
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ADEPPF
      SUBROUTINE ADERAN(N,AK,IADEDF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ASYMMETRIC DOUBLE EXPONENTIAL (LAPLACE)
!              DISTRIBUTION WITH SHAPE PARAMETER = AK.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 ADEPDF(X,K) = (SQRT(2)*K/(1+K^2))*
!                               EXP(-SQRT(2)*K*ABS(X))  X >= 0
!                 ADEPDF(X,K) = (SQRT(2)*K/(1+K^2))*
!                               EXP((-SQRT(2)/K)*ABS(X))  X < 0
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --AK     = THE SHAPE (PARAMETER) FOR THE
!                                ASYMMETRIC DOUBLE EXPONENTIAL
!                                DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE ASYMMETRIC DOUBLE EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETER = AK.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --AK CAN BE ANY REAL NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 134-149.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
      CHARACTER*4 IADEDF
!
      DOUBLE PRECISION U1
      DOUBLE PRECISION U2
      DOUBLE PRECISION DK
      DOUBLE PRECISION DPPF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
          CALL DPWRST('XXX','WRIT')
          PDF=0.0
          GO TO 9999
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
   15 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (K) IS ',   &
             'NON-POSITIVE.')
!
    5 FORMAT('***** ERROR--FOR THE ASYMMETRIC DOUBLE EXPONENTIAL ',   &
             'DISTRIBUTION,')
    6 FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!     USE PERCENT POINT TRANSFORMATION METHOD.
!
      NTEMP=2
      DK=DBLE(AK)
      DO 100 I=1,N
        CALL UNIRAN(NTEMP,ISEED,Y)
        U1=DBLE(Y(1))
        U2=DBLE(Y(2))
        DPPF=(1.0D0/DSQRT(2.0D0))*DLOG(U1**DK/(U2**(1.0D0/DK)))
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ADERAN
      SUBROUTINE ADJUS2(IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
!
!     PURPOSE--PACK < = INTO <=
!              PACK = < INTO =<
!              PACK > = INTO >=
!              PACK = > INTO =>
!              PACK < > INTO <>
!      NOTE--THIS PACKING IS DONE BECAUSE SUBROUTINE DPTYPE
!            AUTOMATICALLY PUTS SPACES AROUND
!            AN EQUAL SIGN AND PUTS THE EQUAL SIGN
!            IN A SEPARATE WORD.
!     NOTE--NUMARG IS CHANGED BY THIS SUBROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988. ALLOW    NOT EQUAL   <> >< NOT=
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
      DIMENSION IARGT(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ADJU'
      ISUBN2='S2  '
!
      IMAX=NUMARG-1
      IF(1.GT.IMAX)GO TO 9000
      DO 100 I=1,IMAX
      IP1=I+1
      IF(IP1.GT.NUMARG)GO TO 9000
      IF(IHARG(I).EQ.'<   '.AND.IHARG(IP1).EQ.'=   ')GO TO 110
      IF(IHARG(I).EQ.'=   '.AND.IHARG(IP1).EQ.'<   ')GO TO 120
      IF(IHARG(I).EQ.'>   '.AND.IHARG(IP1).EQ.'=   ')GO TO 130
      IF(IHARG(I).EQ.'=   '.AND.IHARG(IP1).EQ.'>   ')GO TO 140
      IF(IHARG(I).EQ.'<   '.AND.IHARG(IP1).EQ.'>   ')GO TO 150
      IF(IHARG(I).EQ.'>   '.AND.IHARG(IP1).EQ.'<   ')GO TO 160
      IF(IHARG(I).EQ.'NOT '.AND.IHARG(IP1).EQ.'=   ')GO TO 170
      GO TO 100
!
  110 CONTINUE
      IHARG(I)='<=  '
      IHARG2(I)='    '
      GO TO 250
  120 CONTINUE
      IHARG(I)='=<  '
      IHARG2(I)='    '
      GO TO 250
  130 CONTINUE
      IHARG(I)='>=  '
      IHARG2(I)='    '
      GO TO 250
  140 CONTINUE
      IHARG(I)='=>  '
      IHARG2(I)='    '
      GO TO 250
  150 CONTINUE
      IHARG(I)='<>  '
      IHARG2(I)='    '
      GO TO 250
  160 CONTINUE
      IHARG(I)='><  '
      IHARG2(I)='    '
      GO TO 250
  170 CONTINUE
      IHARG(I)='NOT='
      IHARG2(I)='    '
      GO TO 250
!
  250 CONTINUE
      JMAX=NUMARG-1
      IF(IP1.GT.JMAX)GO TO 265
      DO 260 J=IP1,JMAX
      JP1=J+1
      IHARG(J)=IHARG(JP1)
      IHARG2(J)=IHARG2(JP1)
      IARGT(J)=IARGT(JP1)
      IARG(J)=IARG(JP1)
      ARG(J)=ARG(JP1)
  260 CONTINUE
  265 CONTINUE
      NUMARG=NUMARG-1
  100 CONTINUE
!
 9000 CONTINUE
!
      RETURN
      END SUBROUTINE ADJUS2
      SUBROUTINE ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
!
!     PURPOSE--ADJUST THE IHARG,IHARG2, IARG, ARG, AND IARGT VECTORS
!              AS WELL AS THE VALUE OF NUMARG
!              WHEN HAVE MULTIPLE-WORD COMMANDS;
!              THE ADJUSTMENT RESULTS IN THE
!              FIRST ARGUMENT AFTER THE LAST WORD OF THE COMMAND
!              BEING MAPPED INTO IHARG(1), ETC.
!     NOTE--ILASTC IS THE CURRENT ARGUMENT NUMBER IN IHARG
!           OF THE CURRENT LAST WORD IN THE COMMAND PART
!           OF THE COMMAND STATEMENT.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
!
      CHARACTER*4 IBUGAD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
      DIMENSION IARGT(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IBUGAD='OFF'
!
      IF(IBUGAD.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF ADJUST--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ILASTC,NUMARG
   52 FORMAT('ILASTC,NUMARG = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I),IHARG2(I),IARG(I),ARG(I),IARGT(I)
   56 FORMAT('I,IHARG(I),IHARG2(I),IARG(I),ARG(I),IARGT(I) = ',   &
      I8,2X,A4,A4,I8,E15.7,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
      ILASTP=ILASTC+1
      IF(ILASTP.GT.NUMARG)GO TO 150
      J=0
      DO 100 I=ILASTP,NUMARG
      J=J+1
      IHARG(J)=IHARG(I)
      IHARG2(J)=IHARG2(I)
      IARG(J)=IARG(I)
      ARG(J)=ARG(I)
      IARGT(J)=IARGT(I)
  100 CONTINUE
      NUMARG=J
      GO TO 9000
!
  150 CONTINUE
      NUMARG=0
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGAD.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF ADJUST--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ILASTC,NUMARG
 9012 FORMAT('ILASTC,NUMARG = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,NUMARG
      WRITE(ICOUT,9016)I,IHARG(I),IHARG2(I),IARG(I),ARG(I),IARGT(I)
 9016 FORMAT('I,IHARG(I),IHARG2(I),IARG(I),ARG(I),IARGT(I) = ',   &
      I8,2X,A4,A4,I8,E15.7,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE ADJUST
      SUBROUTINE ADJUS3(NVAR, X, Y, Z, LOCZ, NX, NY, NZ, DIM, CONFIG, D)
!
!     NOTE: FOR DATAPLOT, RENAME TO AVOID NAME CONFLICT.
!
!CCCC SUBROUTINE ADJUST(NVAR, X, Y, Z, LOCZ, NX, NY, NZ, DIM, CONFIG, D)
!
!        ALGORITHM AS 51.2  APPL. STATIST. (1972) VOL.21, P.218
!
!        MAKES PROPORTIONAL ADJUSTMENT CORRESPONDING TO CONFIG.
!        ALL PARAMETERS ARE ASSUMED VALID WITHOUT TEST.
!
!        IF THE VALUE OF NVAR IS TO BE GREATER THAN 7, THE
!        DIMENSIONS IN THE DECLARATIONS OF SIZE AND COORD MUST
!        BE INCREASED TO NVAR+1 AND NVAR RESPECTIVELY.
!
      INTEGER SIZE(8), DIM(NVAR), CONFIG(NVAR), COORD(7)
      REAL X(NX), Y(NY), Z(NZ), D, E, ZERO, ZABS
!
      DATA ZERO /0.0/
!
      ZABS(E) = ABS(E)
!
!        SET SIZE ARRAY
!
      SIZE(1) = 1
      DO 10 K = 1, NVAR
         L = CONFIG(K)
         IF (L .EQ. 0) GO TO  20
         SIZE(K + 1) = SIZE(K) * DIM(L)
   10 CONTINUE
!
!        FIND NUMBER OF VARIABLES IN CONFIGURATION
!
      K = NVAR + 1
   20 CONTINUE
      N = K - 1
!
!        TEST SIZE OF DEVIATION
!
      L = SIZE(K)
      J = 1
      K = LOCZ
      DO 30 I = 1, L
         E = ZABS(Z(K) - Y(J))
         IF (E .GT. D) D = E
         J = J + 1
         K = K + 1
   30 CONTINUE
!
!        INITIALIZE COORDINATES
!
      DO 40 K = 1, NVAR
         COORD(K) = 0
   40 CONTINUE
      I = 1
!
!        PERFORM ADJUSTMENT
!
   50 CONTINUE
      J = 0
      DO 60 K = 1, N
         L = CONFIG(K)
         J = J + COORD(L) * SIZE(K)
   60 CONTINUE
      K = J + LOCZ
      J = J + 1
!
!        NOTE THAT Y(J) SHOULD BE NON-NEGATIVE
!
      IF (Y(J) .LE. ZERO) X(I) = ZERO
      IF (Y(J) .GT. ZERO) X(I) = X(I) * Z(K) / Y(J)
!
!        UPDATE COORDINATES
!
      I = I + 1
      DO 70 K = 1, NVAR
         COORD(K) = COORD(K) + 1
         IF (COORD(K) .LT. DIM(K)) GO TO  50
         COORD(K) = 0
   70 CONTINUE
!
      RETURN
      END SUBROUTINE ADJUS3
      FUNCTION AI (X)
!***BEGIN PROLOGUE  AI
!***PURPOSE  Evaluate the Airy function.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10D
!***TYPE      SINGLE PRECISION (AI-S, DAI-D)
!***KEYWORDS  AIRY FUNCTION, FNLIB, SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! AI(X) computes the Airy function Ai(X)
! Series for AIF        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   1.09E-19
!                                         log weighted error  18.96
!                               significant figures required  17.76
!                                    decimal places required  19.44
!
! Series for AIG        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   1.51E-17
!                                         log weighted error  16.82
!                               significant figures required  15.19
!                                    decimal places required  17.27
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  AIE, CSEVL, INITS, R1MACH, R9AIMP, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770701  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   920618  Removed space from variable names.  (RWC, WRB)
!***END PROLOGUE  AI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DIMENSION AIFCS(9), AIGCS(8)
      LOGICAL FIRST
      SAVE AIFCS, AIGCS, NAIF, NAIG, X3SML, XMAX, FIRST
      DATA AIFCS( 1) /   -.03797135849666999750E0 /
      DATA AIFCS( 2) /    .05919188853726363857E0 /
      DATA AIFCS( 3) /    .00098629280577279975E0 /
      DATA AIFCS( 4) /    .00000684884381907656E0 /
      DATA AIFCS( 5) /    .00000002594202596219E0 /
      DATA AIFCS( 6) /    .00000000006176612774E0 /
      DATA AIFCS( 7) /    .00000000000010092454E0 /
      DATA AIFCS( 8) /    .00000000000000012014E0 /
      DATA AIFCS( 9) /    .00000000000000000010E0 /
      DATA AIGCS( 1) /    .01815236558116127E0 /
      DATA AIGCS( 2) /    .02157256316601076E0 /
      DATA AIGCS( 3) /    .00025678356987483E0 /
      DATA AIGCS( 4) /    .00000142652141197E0 /
      DATA AIGCS( 5) /    .00000000457211492E0 /
      DATA AIGCS( 6) /    .00000000000952517E0 /
      DATA AIGCS( 7) /    .00000000000001392E0 /
      DATA AIGCS( 8) /    .00000000000000001E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  AI
      IF (FIRST) THEN
         NAIF = INITS (AIFCS, 9, 0.1*R1MACH(3))
         NAIG = INITS (AIGCS, 8, 0.1*R1MACH(3))
!
         X3SML = R1MACH(3)**0.3334
         XMAXT = (-1.5*LOG(R1MACH(1)))**0.6667
         XMAX = XMAXT - XMAXT*LOG(XMAXT)/   &
                         (4.0*SQRT(XMAXT)+1.0) - 0.01
      ENDIF
      FIRST = .FALSE.
!
      IF (X.GE.(-1.0)) GO TO 20
      CALL R9AIMP (X, XM, THETA)
      AI = XM * COS(THETA)
      RETURN
!
 20   IF (X.GT.1.0) GO TO 30
      Z = 0.0
      IF (ABS(X).GT.X3SML) Z = X**3
      AI = 0.375 + (CSEVL (Z, AIFCS, NAIF) - X*(0.25 +   &
        CSEVL (Z, AIGCS, NAIG)) )
      RETURN
!
 30   IF (X.GT.XMAX) GO TO 40
      AI = AIE(X) * EXP(-2.0*X*SQRT(X)/3.0)
      RETURN
!
 40   AI = 0.0
      WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
    1 FORMAT('***** WARNING FROM AI, UNDERFLOW BECAUSE THE ',   &
             'VALUE OF X IS SO BIG.  ****')
      RETURN
!
      END FUNCTION AI 
      FUNCTION AIE (X)
!***BEGIN PROLOGUE  AIE
!***PURPOSE  Calculate the Airy function for a negative argument and an
!            exponentially scaled Airy function for a non-negative
!            argument.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10D
!***TYPE      SINGLE PRECISION (AIE-S, DAIE-D)
!***KEYWORDS  EXPONENTIALLY SCALED AIRY FUNCTION, FNLIB,
!             SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! AIE(X) computes the exponentially scaled Airy function for
! non-negative X.  It evaluates AI(X) for X .LE. 0.0 and
! EXP(ZETA)*AI(X) for X .GE. 0.0 where ZETA = (2.0/3.0)*(X**1.5).
!
! Series for AIF        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   1.09E-19
!                                         log weighted error  18.96
!                               significant figures required  17.76
!                                    decimal places required  19.44
!
! Series for AIG        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   1.51E-17
!                                         log weighted error  16.82
!                               significant figures required  15.19
!                                    decimal places required  17.27
!
! Series for AIP        on the interval  0.          to  1.00000D+00
!                                        with weighted error   5.10E-17
!                                         log weighted error  16.29
!                               significant figures required  14.41
!                                    decimal places required  17.06
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CSEVL, INITS, R1MACH, R9AIMP
!***REVISION HISTORY  (YYMMDD)
!   770701  DATE WRITTEN
!   890206  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   920618  Removed space from variable names.  (RWC, WRB)
!***END PROLOGUE  AIE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DIMENSION AIFCS(9), AIGCS(8), AIPCS(34)
      LOGICAL FIRST
      SAVE AIFCS, AIGCS, AIPCS, NAIF, NAIG,   &
       NAIP, X3SML, X32SML, XBIG, FIRST
      DATA AIFCS( 1) /   -.03797135849666999750E0 /
      DATA AIFCS( 2) /    .05919188853726363857E0 /
      DATA AIFCS( 3) /    .00098629280577279975E0 /
      DATA AIFCS( 4) /    .00000684884381907656E0 /
      DATA AIFCS( 5) /    .00000002594202596219E0 /
      DATA AIFCS( 6) /    .00000000006176612774E0 /
      DATA AIFCS( 7) /    .00000000000010092454E0 /
      DATA AIFCS( 8) /    .00000000000000012014E0 /
      DATA AIFCS( 9) /    .00000000000000000010E0 /
      DATA AIGCS( 1) /    .01815236558116127E0 /
      DATA AIGCS( 2) /    .02157256316601076E0 /
      DATA AIGCS( 3) /    .00025678356987483E0 /
      DATA AIGCS( 4) /    .00000142652141197E0 /
      DATA AIGCS( 5) /    .00000000457211492E0 /
      DATA AIGCS( 6) /    .00000000000952517E0 /
      DATA AIGCS( 7) /    .00000000000001392E0 /
      DATA AIGCS( 8) /    .00000000000000001E0 /
      DATA AIPCS( 1) /   -.0187519297793868E0 /
      DATA AIPCS( 2) /   -.0091443848250055E0 /
      DATA AIPCS( 3) /    .0009010457337825E0 /
      DATA AIPCS( 4) /   -.0001394184127221E0 /
      DATA AIPCS( 5) /    .0000273815815785E0 /
      DATA AIPCS( 6) /   -.0000062750421119E0 /
      DATA AIPCS( 7) /    .0000016064844184E0 /
      DATA AIPCS( 8) /   -.0000004476392158E0 /
      DATA AIPCS( 9) /    .0000001334635874E0 /
      DATA AIPCS(10) /   -.0000000420735334E0 /
      DATA AIPCS(11) /    .0000000139021990E0 /
      DATA AIPCS(12) /   -.0000000047831848E0 /
      DATA AIPCS(13) /    .0000000017047897E0 /
      DATA AIPCS(14) /   -.0000000006268389E0 /
      DATA AIPCS(15) /    .0000000002369824E0 /
      DATA AIPCS(16) /   -.0000000000918641E0 /
      DATA AIPCS(17) /    .0000000000364278E0 /
      DATA AIPCS(18) /   -.0000000000147475E0 /
      DATA AIPCS(19) /    .0000000000060851E0 /
      DATA AIPCS(20) /   -.0000000000025552E0 /
      DATA AIPCS(21) /    .0000000000010906E0 /
      DATA AIPCS(22) /   -.0000000000004725E0 /
      DATA AIPCS(23) /    .0000000000002076E0 /
      DATA AIPCS(24) /   -.0000000000000924E0 /
      DATA AIPCS(25) /    .0000000000000417E0 /
      DATA AIPCS(26) /   -.0000000000000190E0 /
      DATA AIPCS(27) /    .0000000000000087E0 /
      DATA AIPCS(28) /   -.0000000000000040E0 /
      DATA AIPCS(29) /    .0000000000000019E0 /
      DATA AIPCS(30) /   -.0000000000000009E0 /
      DATA AIPCS(31) /    .0000000000000004E0 /
      DATA AIPCS(32) /   -.0000000000000002E0 /
      DATA AIPCS(33) /    .0000000000000001E0 /
      DATA AIPCS(34) /   -.0000000000000000E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  AIE
      IF (FIRST) THEN
         ETA = 0.1*R1MACH(3)
         NAIF  = INITS (AIFCS, 9, ETA)
         NAIG  = INITS (AIGCS, 8, ETA)
         NAIP  = INITS (AIPCS, 34, ETA)
!
         X3SML = ETA**0.3333
         X32SML = 1.3104*X3SML**2
         XBIG = R1MACH(2)**0.6666
      ENDIF
      FIRST = .FALSE.
!
      IF (X.GE.(-1.0)) GO TO 20
      CALL R9AIMP (X, XM, THETA)
      AIE = XM * COS(THETA)
      RETURN
!
 20   IF (X.GT.1.0) GO TO 30
      Z = 0.0
      IF (ABS(X).GT.X3SML) Z = X**3
      AIE = 0.375 + (CSEVL (Z, AIFCS, NAIF) - X*(0.25 +   &
        CSEVL (Z, AIGCS, NAIG)) )
      IF (X.GT.X32SML) AIE = AIE * EXP(2.0*X*SQRT(X)/3.0)
      RETURN
!
 30   SQRTX = SQRT(X)
      Z = -1.0
      IF (X.LT.XBIG) Z = 2.0/(X*SQRTX) - 1.0
      AIE = (.28125 + CSEVL (Z, AIPCS, NAIP))/SQRT(SQRTX)
      RETURN
!
      END FUNCTION AIE 
      DOUBLE PRECISION FUNCTION AIRINT(XVALUE)
!
!   DESCRIPTION:
!
!      This function calculates the integral of the Airy function Ai,
!      defined as
!
!         AIRINT(x) = {integral 0 to x} Ai(t) dt
!
!      The program uses Chebyshev expansions, the coefficients of which
!      are given to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If the argument is too large and negative, it is impossible
!      to accurately compute the necessary SIN and COS functions.
!      An error message is printed, and the program returns the
!      value -2/3 (the value at -infinity).
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - INTEGER - The no. of terms to be used from the array
!                          AAINT1. The recommended value is such that
!                             ABS(AAINT1(NTERM1)) < EPS/100,
!                          subject to 1 <= NTERM1 <= 25.
!
!      NTERM2 - INTEGER - The no. of terms to be used from the array
!                          AAINT2. The recommended value is such that
!                             ABS(AAINT2(NTERM2)) < EPS/100,
!                          subject to 1 <= NTERM2 <= 21.
!
!      NTERM3 - INTEGER - The no. of terms to be used from the array
!                          AAINT3. The recommended value is such that
!                             ABS(AAINT3(NTERM3)) < EPS/100,
!                          subject to 1 <= NTERM3 <= 40.
!
!      NTERM4 - INTEGER - The no. of terms to be used from the array
!                          AAINT4. The recommended value is such that
!                             ABS(AAINT4(NTERM4)) < EPS/100,
!                          subject to 1 <= NTERM4 <= 17.
!
!      NTERM5 - INTEGER - The no. of terms to be used from the array
!                          AAINT5. The recommended value is such that
!                             ABS(AAINT5(NTERM5)) < EPS/100,
!                          subject to 1 <= NTERM5 <= 17.
!
!      XLOW1 - DOUBLE PRECISION - The value such that, if |x| < XLOW1,
!                          AIRINT(x) = x * Ai(0)
!                     to machine precision. The recommended value is
!                          2 * EPSNEG.
!
!      XHIGH1 - DOUBLE PRECISION - The value such that, if x > XHIGH1,
!                          AIRINT(x) = 1/3,
!                      to machine precision. The recommended value is
!                          (-1.5*LOG(EPSNEG)) ** (2/3).
!
!      XNEG1 - DOUBLE PRECISION - The value such that, if x < XNEG1,
!                     the trigonometric functions in the asymptotic
!                     expansion cannot be calculated accurately.
!                     The recommended value is
!                          -(1/((EPS)**2/3))
!
!      For values of EPS and EPSNEG, refer to the file MACHCON.TXT.
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!                            COS, EXP, SIN, SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR: Dr. Allan J. MacLeod,
!           Dept. of Mathematics and Statistics,
!           Univ. of Paisley,
!           High St.,
!           Paisley,
!           SCOTLAND.
!           PA1 2BE
!
!           (e-mail:macl_ms0@paisley.ac.uk)
!
!
!   LATEST REVISION:  23 January, 1996
!
      INTEGER NTERM1,NTERM2,NTERM3,NTERM4,NTERM5
      DOUBLE PRECISION AAINT1(0:25),AAINT2(0:21),AAINT3(0:40),   &
           AAINT4(0:17),AAINT5(0:17),   &
           AIRZER,ARG,CHEVAL,EIGHT,FORTY1,FOUR,FR996,GVAL,   &
           HVAL,NINE,NINHUN,ONE,ONEHUN,PIBY4,PITIM6,RT2B3P,T,TEMP,   &
           THREE,TWO,X,XHIGH1,XLOW1,XNEG1,XVALUE,Z,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*46
!CCCC DATA FNNAME/'AIRINT'/
!CCCC DATA ERRMSG/'FUNCTION TOO NEGATIVE FOR ACCURATE COMPUTATION'/
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
