      DATA AAINT3(35)/ 0.923D-17/
      DATA AAINT3(36)/ 0.1224D-16/
      DATA AAINT3(37)/ 0.157D-17/
      DATA AAINT3(38)/-0.19D-18/
      DATA AAINT3(39)/-0.8D-19/
      DATA AAINT3(40)/-0.1D-19/
      DATA AAINT4/1.99653305828522730048D0,   &
                 -0.187541177605417759D-2,   &
                 -0.15377536280305750D-3,   &
                 -0.1283112967682349D-4,   &
                 -0.108128481964162D-5,   &
                 -0.9182131174057D-7,   &
                 -0.784160590960D-8,   &
                 -0.67292453878D-9,   &
                 -0.5796325198D-10,   &
                 -0.501040991D-11,   &
                 -0.43420222D-12,   &
                 -0.3774305D-13,   &
                 -0.328473D-14,   &
                 -0.28700D-15,   &
                 -0.2502D-16,   &
                 -0.220D-17,   &
                 -0.19D-18,   &
                 -0.2D-19/
      DATA AAINT5/1.13024602034465716133D0,   &
                 -0.464718064639872334D-2,   &
                 -0.35137413382693203D-3,   &
                 -0.2768117872545185D-4,   &
                 -0.222057452558107D-5,   &
                 -0.18089142365974D-6,   &
                 -0.1487613383373D-7,   &
                 -0.123515388168D-8,   &
                 -0.10310104257D-9,   &
                 -0.867493013D-11,   &
                 -0.73080054D-12,   &
                 -0.6223561D-13,   &
                 -0.525128D-14,   &
                 -0.45677D-15,   &
                 -0.3748D-16,   &
                 -0.356D-17,   &
                 -0.23D-18,   &
                 -0.4D-19/
      DATA ZERO,ONE,TWO/ 0.0D0 , 1.0D0 , 2.0D0 /
      DATA THREE,FOUR,EIGHT/ 3.0D0 , 4.0D0 , 8.0D0 /
      DATA NINE,FORTY1,ONEHUN/ 9.0D0 , 41.0D0 , 100.0D0/
      DATA NINHUN,FR996/ 900.0D0 , 4996.0D0 /
      DATA PIBY4/0.78539816339744830962D0/
      DATA PITIM6/18.84955592153875943078D0/
      DATA RT2B3P/0.46065886596178063902D0/
      DATA AIRZER/0.35502805388781723926D0/
!
      XHIGH1=0.0
!
!   Start computation
!
      X = XVALUE
!
!   Compute the machine-dependent constants.
!
      Z = D1MACH(3)
      XLOW1 = TWO * Z
      ARG = D1MACH(4)
      XNEG1 = - ONE / ( ARG ** (TWO/THREE) )
!
!   Error test
!
      IF ( X .LT. XNEG1 ) THEN
!CCCCC   CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         AIRINT = -TWO / THREE
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM AIRINT--FUNCTION TOO NEGATIVE FOR ',   &
             'ACCURATE COMPUTATION, ARGUMENT = ',G15.7)
!
!  continue with machine-dependent constants
!
      T = ARG / ONEHUN
      IF ( X .GE. ZERO ) THEN
         DO 10 NTERM1 = 25 , 0 , -1
            IF ( ABS(AAINT1(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERM2 = 21 , 0 , -1
            IF ( ABS(AAINT2(NTERM2)) .GT. T ) GO TO  29
 20      CONTINUE
 29      XHIGH1 = ( -THREE*LOG(Z)/TWO ) ** (TWO/THREE)
      ELSE
         DO 30 NTERM3 = 40 , 0 , -1
            IF ( ABS(AAINT3(NTERM3)) .GT. T ) GO TO  39
 30      CONTINUE
 39      DO 40 NTERM4 = 17 , 0 , -1
            IF ( ABS(AAINT4(NTERM4)) .GT. T ) GO TO  49
 40      CONTINUE
 49      DO 50 NTERM5 = 17 , 0 , -1
            IF ( ABS(AAINT5(NTERM5)) .GT. T ) GO TO  59
 50      CONTINUE
 59      CONTINUE
      ENDIF
!
!   Code for x >= 0
!
      IF ( X .GE. ZERO ) THEN
         IF ( X .LE. FOUR ) THEN
            IF ( X .LT. XLOW1 ) THEN
               AIRINT = AIRZER * X
            ELSE
               T = X / TWO - ONE
               AIRINT = CHEVAL(NTERM1,AAINT1,T) * X
            ENDIF
         ELSE
            IF ( X .GT. XHIGH1 ) THEN
               TEMP = ZERO
            ELSE
               Z = ( X + X ) * SQRT(X) / THREE
               TEMP = THREE * Z
               T = ( FORTY1 - TEMP ) / ( NINE + TEMP )
               TEMP = EXP(-Z) * CHEVAL(NTERM2,AAINT2,T) / SQRT(PITIM6*Z)
            ENDIF
            AIRINT = ONE / THREE - TEMP
         ENDIF
      ELSE
!
!   Code for x < 0
!
         IF ( X .GE. -EIGHT ) THEN
            IF ( X .GT. -XLOW1 ) THEN
               AIRINT = AIRZER * X
            ELSE
               T = -X / FOUR - ONE
               AIRINT = X * CHEVAL(NTERM3,AAINT3,T)
            ENDIF
         ELSE
            Z = - ( X + X ) * SQRT(-X) / THREE
            ARG = Z + PIBY4
            TEMP = NINE * Z * Z
            T = ( FR996 - TEMP ) / ( NINHUN + TEMP)
            GVAL = CHEVAL(NTERM4,AAINT4,T)
            HVAL = CHEVAL(NTERM5,AAINT5,T)
            TEMP = GVAL * COS(ARG) + HVAL * SIN(ARG) / Z
            AIRINT = RT2B3P * TEMP / SQRT(Z) - TWO / THREE
         ENDIF
      ENDIF
      RETURN
      END FUNCTION AIRINT
      DOUBLE PRECISION FUNCTION AIRYGI(XVALUE)
!
!   DESCRIPTION:
!
!      This subroutine computes the modified Airy function Gi(x),
!      defined as
!
!        AIRYGI(x) = [ Integral{0 to infinity} sin(x*t+t^3/3) dt ] / pi
!
!      The approximation uses Chebyshev expansions with the coefficients
!      given to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If x < -XHIGH1*XHIGH1 (see below for definition of XHIGH1), then
!      the trig. functions needed for the asymptotic expansion of Bi(x)
!      cannot be computed to any accuracy. An error message is printed
!      and the code returns the value 0.0.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - INTEGER - The no. of terms to be used from the array
!                         ARGIP1. The recommended value is such that
!                                ABS(ARGIP1(NTERM1)) < EPS/100
!                         subject to 1 <= NTERM1 <= 30.
!
!      NTERM2 - INTEGER - The no. of terms to be used from the array
!                         ARGIP2. The recommended value is such that
!                                ABS(ARGIP2(NTERM2)) < EPS/100
!                         subject to 1 <= NTERM2 <= 29.
!
!      NTERM3 - INTEGER - The no. of terms to be used from the array
!                         ARGIN1. The recommended value is such that
!                                ABS(ARGIN1(NTERM3)) < EPS/100
!                         subject to 1 <= NTERM3 <= 42.
!
!      NTERM4 - INTEGER - The no. of terms to be used from the array
!                         ARBIN1. The recommended value is such that
!                                ABS(ARBIN1(NTERM4)) < EPS/100
!                         subject to 1 <= NTERM4 <= 10.
!
!      NTERM5 - INTEGER - The no. of terms to be used from the array
!                         ARBIN2. The recommended value is such that
!                                ABS(ARBIN2(NTERM5)) < EPS/100
!                         subject to 1 <= NTERM5 <= 11.
!
!      NTERM6 - INTEGER - The no. of terms to be used from the array
!                         ARGH2. The recommended value is such that
!                                ABS(ARHIN1(NTERM6)) < EPS/100
!                         subject to 1 <= NTERM6 <= 15.
!
!      XLOW1 - DOUBLE PRECISION - The value such that, if -XLOW1 < x < XLOW1,
!                     then AIRYGI = Gi(0) to machine precision.
!                     The recommended value is   EPS.
!
!      XHIGH1 - DOUBLE PRECISION - The value such that, if x > XHIGH1, then
!                      AIRYGI = 1/(Pi*x) to machine precision.
!                      Also used for error test - see above.
!                      The recommended value is
!                          cube root( 2/EPS ).
!
!      XHIGH2 - DOUBLE PRECISION - The value above which AIRYGI = 0.0.
!                      The recommended value is
!                          1/(Pi*XMIN).
!
!      XHIGH3 - DOUBLE PRECISION - The value such that, if x < XHIGH3,
!                      then the Chebyshev expansions for the
!                      asymptotic form of Bi(x) are not needed.
!                      The recommended value is
!                          -8 * cube root( 2/EPSNEG ).
!
!      For values of EPS, EPSNEG, and XMIN refer to the file
!      MACHCON.TXT.
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!                             COS , SIN , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!          Dr. Allan J. Macleod,
!          Dept. of Mathematics and Statistics,
!          University of Paisley,
!          High St.,
!          Paisley,
!          SCOTLAND.
!
!          (e-mail: macl_ms0@paisley.ac.uk)
!
!
!   LATEST UPDATE:
!                 23 January, 1996
!
      INTEGER NTERM1,NTERM2,NTERM3,NTERM4,NTERM5,NTERM6
      DOUBLE PRECISION ARGIP1(0:30),ARGIP2(0:29),ARGIN1(0:42),   &
           ARBIN1(0:10),ARBIN2(0:11),ARHIN1(0:15),   &
           ARG,BI,CHEB1,CHEB2,CHEVAL,COSZ,FIVE,FIVE14,FOUR,   &
           GIZERO,MINATE,NINE,ONE,ONEBPI,ONEHUN,ONE76,ONE024,PIBY4,   &
           RTPIIN,SEVEN,SEVEN2,SINZ,T,TEMP,THREE,TWELHU,TWENT8,   &
           X,XCUBE,XHIGH1,XHIGH2,XHIGH3,XLOW1,XMINUS,   &
           XVALUE,Z,ZERO,ZETA
!CCCC CHARACTER FNNAME*6,ERRMSG*46
!CCCC DATA FNNAME/'AIRYGI'/
!CCCC DATA ERRMSG/'ARGUMENT TOO NEGATIVE FOR ACCURATE COMPUTATION'/
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA ARGIP1(0)/  0.26585770795022745082D0/
      DATA ARGIP1(1)/ -0.10500333097501922907D0/
      DATA ARGIP1(2)/  0.841347475328454492D-2/
