      DATA ARGIN1(39)/ 0.118D-17/
      DATA ARGIN1(40)/ 0.67D-18/
      DATA ARGIN1(41)/ 0.6D-19/
      DATA ARGIN1(42)/-0.1D-19/
      DATA ARBIN1/1.99983763583586155980D0,   &
                 -0.8104660923669418D-4,   &
                  0.13475665984689D-6,   &
                 -0.70855847143D-9,   &
                  0.748184187D-11,   &
                 -0.12902774D-12,   &
                  0.322504D-14,   &
                 -0.10809D-15,   &
                  0.460D-17,   &
                 -0.24D-18,   &
                  0.1D-19/
      DATA ARBIN2/0.13872356453879120276D0,   &
                 -0.8239286225558228D-4,   &
                  0.26720919509866D-6,   &
                 -0.207423685368D-8,   &
                  0.2873392593D-10,   &
                 -0.60873521D-12,   &
                  0.1792489D-13,   &
                 -0.68760D-15,   &
                  0.3280D-16,   &
                 -0.188D-17,   &
                  0.13D-18,   &
                 -0.1D-19/
      DATA ARHIN1/1.99647720399779650525D0,   &
                 -0.187563779407173213D-2,   &
                 -0.12186470897787339D-3,   &
                 -0.814021609659287D-5,   &
                 -0.55050925953537D-6,   &
                 -0.3763008043303D-7,   &
                 -0.258858362365D-8,   &
                 -0.17931829265D-9,   &
                 -0.1245916873D-10,   &
                 -0.87171247D-12,   &
                 -0.6084943D-13,   &
                 -0.431178D-14,   &
                 -0.29787D-15,   &
                 -0.2210D-16,   &
                 -0.136D-17,   &
                 -0.14D-18/
      DATA ZERO,ONE,THREE,FOUR/ 0.0D0 , 1.0D0 , 3.0D0 , 4.0D0 /
      DATA FIVE,SEVEN,MINATE/ 5.0D0 , 7.0D0 , -8.0D0 /
      DATA NINE,TWENT8,SEVEN2/ 9.0D0 , 28.0D0 , 72.0D0 /
      DATA ONEHUN,ONE76,FIVE14/ 100.0D0 , 176.0D0 , 514.0D0 /
      DATA ONE024,TWELHU/ 1024.0D0 , 1200.0D0 /
      DATA GIZERO/0.20497554248200024505D0/
      DATA ONEBPI/0.31830988618379067154D0/
      DATA PIBY4/0.78539816339744830962D0/
      DATA RTPIIN/0.56418958354775628695D0/
!
      XHIGH2=0.0
!
!   Start computation
!
      X = XVALUE
!
!   Compute the machine-dependent constants.
!
      Z = D1MACH(3)
      XLOW1 = Z
      ARG = D1MACH(4)
      XHIGH1 = ONE / ARG
      XHIGH1 = ( XHIGH1 + XHIGH1 ) ** (ONE/THREE)
!
!   Error test
!
      IF ( X .LT. -XHIGH1*XHIGH1 ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         AIRYGI = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM AIRYGI--ARGUMENT TOO NEGATIVE ',   &
             'FOR ACCURATE COMPUTATION, ARGUMENT = ',G15.7)
!
!  continue with machine-dependent constants
!
      T = ARG / ONEHUN
      IF ( X .GE. ZERO ) THEN
         DO 10 NTERM1 = 30 , 0 , -1
            IF ( ABS(ARGIP1(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERM2 = 29 , 0 , -1
            IF ( ABS(ARGIP2(NTERM2)) .GT. T ) GO TO  29
 20      CONTINUE
 29      TEMP = FOUR * PIBY4
         XHIGH2 = ONE / ( TEMP * D1MACH(1) )
      ELSE
         DO 30 NTERM3 = 42 , 0 , -1
            IF ( ABS(ARGIN1(NTERM3)) .GT. T ) GO TO  39
 30      CONTINUE
 39      DO 40 NTERM4 = 10 , 0 , -1
            IF ( ABS(ARBIN1(NTERM4)) .GT. T ) GO TO  49
 40      CONTINUE
 49      DO 50 NTERM5 = 11 , 0 , -1
            IF ( ABS(ARBIN2(NTERM5)) .GT. T ) GO TO  59
 50      CONTINUE
 59      DO 60 NTERM6 = 15 , 0 , -1
            IF ( ABS(ARHIN1(NTERM6)) .GT. T ) GO TO  69
 60      CONTINUE
 69      TEMP = ONE / Z
         XHIGH3 = MINATE * ( TEMP + TEMP ) ** (ONE/THREE)
      ENDIF
!
!   Code for x >= 0.0
!
      IF ( X .GE. ZERO ) THEN
         IF ( X .LE. SEVEN ) THEN
            IF ( X .LT. XLOW1 ) THEN
               AIRYGI = GIZERO
            ELSE
               T = ( NINE * X - TWENT8 ) / ( X + TWENT8 )
               AIRYGI = CHEVAL ( NTERM1 , ARGIP1 , T )
            ENDIF
         ELSE
            IF ( X .GT. XHIGH1 ) THEN
               IF ( X .GT. XHIGH2 ) THEN
                  AIRYGI = ZERO
               ELSE
                  AIRYGI = ONEBPI/X
               ENDIF
            ELSE
               XCUBE = X * X * X
               T = ( TWELHU - XCUBE ) / ( FIVE14 + XCUBE )
               AIRYGI = ONEBPI * CHEVAL(NTERM2,ARGIP2,T) / X
            ENDIF
         ENDIF
      ELSE
!
!   Code for x < 0.0
!
         IF ( X .GE. MINATE ) THEN
            IF ( X .GT. -XLOW1 ) THEN
               AIRYGI = GIZERO
            ELSE
               T = -( X + FOUR ) / FOUR
               AIRYGI = CHEVAL(NTERM3,ARGIN1,T)
            ENDIF
         ELSE
            XMINUS = -X
            T = XMINUS * SQRT(XMINUS)
            ZETA = ( T + T ) / THREE
            TEMP = RTPIIN / SQRT(SQRT(XMINUS))
            COSZ = COS ( ZETA + PIBY4 )
            SINZ = SIN ( ZETA + PIBY4 ) / ZETA
            XCUBE = X * X * X
            IF ( X .GT. XHIGH3 ) THEN
               T = - ( ONE024 / ( XCUBE ) + ONE )
               CHEB1 = CHEVAL(NTERM4,ARBIN1,T)
               CHEB2 = CHEVAL(NTERM5,ARBIN2,T)
               BI = ( COSZ * CHEB1 + SINZ * CHEB2 ) * TEMP
            ELSE
               BI = ( COSZ + SINZ * FIVE / SEVEN2 ) * TEMP
            ENDIF
            T = ( XCUBE + TWELHU ) / ( ONE76 - XCUBE )
            AIRYGI = BI + CHEVAL(NTERM6,ARHIN1,T) * ONEBPI / X
         ENDIF
      ENDIF
      RETURN
      END FUNCTION AIRYGI
      DOUBLE PRECISION FUNCTION AIRYHI(XVALUE)
!
!   DESCRIPTION:
!
!      This subroutine computes the modified Airy function Hi(x),
!      defined as
!
!         AIRYHI(x) = [ Integral{0 to infinity} exp(x*t-t^3/3) dt ] / pi
!
!      The approximation uses Chebyshev expansions with the coefficients
!      given to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If x > XHIGH1 (see below for definition of XHIGH1), then
!      the asymptotic expansion of Hi(x) will cause an overflow.
!      An error message is printed and the code returns the largest
!      floating-pt number as the result.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - INTEGER - The no. of terms to be used from the array
!                         ARHIP. The recommended value is such that
!                                ABS(ARHIP(NTERM1)) < EPS/100
!                         subject to 1 <= NTERM1 <= 31.
!
!      NTERM2 - INTEGER - The no. of terms to be used from the array
!                         ARBIP. The recommended value is such that
!                                ABS(ARBIP(NTERM2)) < EPS/100
!                         subject to 1 <= NTERM2 <= 23.
!
!      NTERM3 - INTEGER - The no. of terms to be used from the array
!                         ARGIP. The recommended value is such that
!                                ABS(ARGIP1(NTERM3)) < EPS/100
!                         subject to 1 <= NTERM3 <= 29.
!
!      NTERM4 - INTEGER - The no. of terms to be used from the array
!                         ARHIN1. The recommended value is such that
!                                ABS(ARHIN1(NTERM4)) < EPS/100
!                         subject to 1 <= NTERM4 <= 21.
!
!      NTERM5 - INTEGER - The no. of terms to be used from the array
!                         ARHIN2. The recommended value is such that
!                                ABS(ARHIN2(NTERM5)) < EPS/100
!                         subject to 1 <= NTERM5 <= 15.
!
!      XLOW1 - DOUBLE PRECISION - The value such that, if -XLOW1 < x < XLOW1,
!                     then AIRYGI = Hi(0) to machine precision.
!                     The recommended value is   EPS.
!
!      XHIGH1 - DOUBLE PRECISION - The value such that, if x > XHIGH1, then
!                      overflow might occur. The recommended value is
!                      computed as follows:
!                           compute Z = 1.5*LOG(XMAX)
!                        XHIGH1 = ( Z + LOG(Z)/4 + LOG(PI)/2 )**(2/3)
!
!      XNEG1 - DOUBLE PRECISION - The value below which AIRYHI = 0.0.
!                     The recommended value is
!                          -1/(Pi*XMIN).
!
!      XNEG2 - DOUBLE PRECISION - The value such that, if x < XNEG2, then
!                      AIRYHI = -1/(Pi*x) to machine precision.
!                      The recommended value is
!                          -cube root( 2/EPS ).
!
!      XMAX - DOUBLE PRECISION - The largest possible floating-pt. number.
!                    This is the value given to the function
!                    if x > XHIGH1.
!
!      For values of EPS, EPSNEG, XMIN  and XMAX refer to the file
!      MACHCON.TXT.
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!                            EXP , LOG , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!          Dr. Allan J. Macleod,
!          Dept. of Mathematics and Statistics,
!          University of Paisley,
!          High St.,
!          Paisley,
!          SCOTLAND.
!
!          (e-mail: macl_ms0@paisley.ac.uk)
!
!
!   LATEST UPDATE:
!                  23 January, 1996
!
      INTEGER NTERM1,NTERM2,NTERM3,NTERM4,NTERM5
      DOUBLE PRECISION ARHIP(0:31),ARBIP(0:23),ARGIP1(0:29),   &
