      DATA THRE43,FIVE14,TWELHU/ 343.0D0 , 514.0D0 , 1200.0D0 /
      DATA ONEHUN/100.0D0/
      DATA HIZERO/0.40995108496400049010D0/
      DATA LNRTPI/0.57236494292470008707D0/
      DATA ONEBPI/0.31830988618379067154D0/
!
!   Start computation
!
      X = XVALUE
!
!   Compute the machine-dependent constants.
!
      XMAX = D1MACH(2)
      TEMP = THREE * LOG(XMAX) / TWO
      ZETA = ( TEMP + LOG(TEMP)/FOUR - LOG(ONEBPI)/TWO )
      XHIGH1 = ZETA ** (TWO/THREE)
!
!   Error test
!
      IF ( X .GT. XHIGH1 ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         AIRYHI = XMAX
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM AIRYHI--ARGUMENT TO FUNCTION ',   &
              'TOO LARGE, ARGUMENT = ',G15.7)
!
!  continue with machine-dependent constants
!
      Z = D1MACH(3)
      XLOW1 = Z
      T = Z / ONEHUN
      IF ( X .GE. ZERO ) THEN
         DO 10 NTERM1 = 31 , 0 , -1
            IF ( ABS(ARHIP(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERM2 = 23 , 0 , -1
            IF ( ABS(ARBIP(NTERM2)) .GT. T ) GO TO  29
 20      CONTINUE
 29      DO 30 NTERM3 = 29 , 0 , -1
            IF ( ABS(ARGIP1(NTERM3)) .GT. T ) GO TO  39
 30      CONTINUE
 39      CONTINUE
      ELSE
         DO 40 NTERM4 = 21 , 0 , -1
            IF ( ABS(ARHIN1(NTERM4)) .GT. T ) GO TO  49
 40      CONTINUE
 49      DO 50 NTERM5 = 15 , 0 , -1
            IF ( ABS(ARHIN2(NTERM5)) .GT. T ) GO TO  59
 50      CONTINUE
 59      TEMP = ONE / ONEBPI
         XNEG1 = - ONE / ( TEMP * D1MACH(1) )
         XNEG2 = - ( ( TWO / Z ) ** (ONE/THREE) )
      ENDIF
!
!   Code for x >= 0.0
!
      IF ( X .GE. ZERO ) THEN
         IF ( X .LE. SEVEN ) THEN
            IF ( X .LT. XLOW1 ) THEN
               AIRYHI = HIZERO
            ELSE
               T = ( X + X ) / SEVEN - ONE
               TEMP = ( X + X + X ) / TWO
               AIRYHI = EXP(TEMP) * CHEVAL(NTERM1,ARHIP,T)
            ENDIF
         ELSE
            XCUBE = X * X * X
            TEMP = SQRT(XCUBE)
            ZETA = ( TEMP + TEMP ) / THREE
            T = TWO * ( SQRT(THRE43/XCUBE) ) - ONE
            TEMP = CHEVAL(NTERM2,ARBIP,T)
            TEMP = ZETA + LOG(TEMP) - LOG(X) / FOUR - LNRTPI
            BI = EXP(TEMP)
            T = ( TWELHU - XCUBE ) / ( XCUBE + FIVE14 )
            GI = CHEVAL(NTERM3,ARGIP1,T) * ONEBPI / X
            AIRYHI = BI - GI
         ENDIF
      ELSE
!
!   Code for x < 0.0
!
         IF ( X .GE. MINATE ) THEN
            IF ( X .GT. -XLOW1 ) THEN
               AIRYHI = HIZERO
            ELSE
               T = ( FOUR * X + TWELVE ) / ( X - TWELVE )
               AIRYHI = CHEVAL(NTERM4,ARHIN1,T)
            ENDIF
         ELSE
            IF ( X .LT. XNEG1 ) THEN
               AIRYHI = ZERO
            ELSE
               IF ( X .LT. XNEG2 ) THEN
                  TEMP = ONE
               ELSE
                  XCUBE = X * X * X
                  T = ( XCUBE + TWELHU ) / ( ONE76 - XCUBE )
                  TEMP = CHEVAL(NTERM5,ARHIN2,T)
               ENDIF
               AIRYHI = - TEMP * ONEBPI / X
            ENDIF
         ENDIF
      ENDIF
      RETURN
      END FUNCTION AIRYHI
      FUNCTION ALI (X)
!***BEGIN PROLOGUE  ALI
!***PURPOSE  Compute the logarithmic integral.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C5
!***TYPE      SINGLE PRECISION (ALI-S, DLI-D)
!***KEYWORDS  FNLIB, LOGARITHMIC INTEGRAL, SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! ALI(X) computes the logarithmic integral; i.e., the
! integral from 0.0 to X of (1.0/ln(t))dt.
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  EI, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770601  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!***END PROLOGUE  ALI
!***FIRST EXECUTABLE STATEMENT  ALI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      ALI = CPUMIN
!
      IF (X .LE. 0.0) THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
    1   FORMAT('***** ERORR FROM ALI, THE LOG INTEGRAL IS UNDEFINED ',   &
               'FOR NON-POSITIVE X.  *****')
        RETURN
      ENDIF
      IF (X .EQ. 1.0) THEN
        WRITE(ICOUT,2)
    2   FORMAT('***** ERORR FROM ALI, THE LOG INTEGRAL IS UNDEFINED ',   &
               'FOR X = 1.  *****')
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
!
      ALI = EI (LOG(X) )
!
      RETURN
      END FUNCTION ALI 
      double precision function alnfac(j)
!
!        algorithm as 177.2  appl. statist. (1982) vol.31, no.2
!
!        natural logarithm of factorial for non-negative agrument
!
      implicit logical (a-z)
      integer j
      double precision r(7), one, half, a0, three, four, fourtn, fortty,   &
        fivfty, w, z
      data r(1), r(2), r(3), r(4), r(5), r(6), r(7) /0.0d0, 0.0d0,   &
        0.69314718056d0, 1.79175946923d0, 3.17805383035d0,   &
        4.78749174278d0, 6.57925121101d0/
      data one, half, a0, three, four, fourtn, fortty, fivfty /   &
        1.0d0, 0.5d0, 0.918938533205d0, 3.0d0, 4.0d0, 14.0d0, 420.0d0,   &
        5040.0d0/
      if (j .ge. 0) go to 10
      alnfac = one
      return
   10 if (j .ge. 7) go to 20
      alnfac = r(j + 1)
      return
   20 w = j + 1
      z = one / (w * w)
      alnfac = (w - half) * log(w) - w + a0 + (((four - three * z)   &
        * z - fourtn) * z + fortty) / (fivfty * w)
      return
      end
      FUNCTION ALNREL(X)
!***BEGIN PROLOGUE  ALNREL
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C4B
!***KEYWORDS  ELEMENTARY FUNCTION,LOGARITHM,RELATIVE
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Evaluates ln(1+X) accurate in the sense of relative error.
!***DESCRIPTION
!
! ALNREL(X) evaluates ln(1+X) accurately in the sense of relative
! error when X is very small.  This routine must be used to
! maintain relative error accuracy whenever X is small and
! accurately known.
!
! Series for ALNR       on the interval -3.75000D-01 to  3.75000D-01
!                                        with weighted error   1.93E-17
!                                         log weighted error  16.72
!                               significant figures required  16.44
!                                    decimal places required  17.40
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CSEVL,INITS,R1MACH,XERROR
!***END PROLOGUE  ALNREL
      DIMENSION ALNRCS(23)
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA ALNRCS( 1) /   1.0378693562743770E0 /
      DATA ALNRCS( 2) /   -.13364301504908918E0 /
      DATA ALNRCS( 3) /    .019408249135520563E0 /
      DATA ALNRCS( 4) /   -.003010755112753577E0 /
      DATA ALNRCS( 5) /    .000486946147971548E0 /
      DATA ALNRCS( 6) /   -.000081054881893175E0 /
      DATA ALNRCS( 7) /    .000013778847799559E0 /
      DATA ALNRCS( 8) /   -.000002380221089435E0 /
      DATA ALNRCS( 9) /    .000000416404162138E0 /
      DATA ALNRCS(10) /   -.000000073595828378E0 /
      DATA ALNRCS(11) /    .000000013117611876E0 /
      DATA ALNRCS(12) /   -.000000002354670931E0 /
      DATA ALNRCS(13) /    .000000000425227732E0 /
      DATA ALNRCS(14) /   -.000000000077190894E0 /
      DATA ALNRCS(15) /    .000000000014075746E0 /
      DATA ALNRCS(16) /   -.000000000002576907E0 /
      DATA ALNRCS(17) /    .000000000000473424E0 /
      DATA ALNRCS(18) /   -.000000000000087249E0 /
      DATA ALNRCS(19) /    .000000000000016124E0 /
      DATA ALNRCS(20) /   -.000000000000002987E0 /
      DATA ALNRCS(21) /    .000000000000000554E0 /
      DATA ALNRCS(22) /   -.000000000000000103E0 /
      DATA ALNRCS(23) /    .000000000000000019E0 /
      DATA NLNREL, XMIN /0, 0./
!***FIRST EXECUTABLE STATEMENT  ALNREL
!
      ALNREL=CPUMIN
!
      IF (NLNREL.NE.0) GO TO 10
      NLNREL = INITS (ALNRCS, 23, 0.1*R1MACH(3))
      XMIN = -1.0 + SQRT(R1MACH(4))
!
 10   IF (X.LE.(-1.0)) THEN
!CCCC   CALL XERROR ( 'ALNREL  X IS LE -1', 18, 2, 2)
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
 101  FORMAT('***** INTERNAL ERROR FROM ALNREL: ARGUMENT LESS THAN ',   &
      'OR EQUAL TO -1')
      IF (X.LT.XMIN) THEN
!CCCC    CALL XERROR ( 'ALNREL  ANSWER LT HALF PRECISION BEC
!CCCC1AUSE X TOO NEAR -1', 54,    1, 1)
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
!CCCC   RETURN
      ENDIF
 102  FORMAT('***** INTERNAL WARNING FROM ALNREL: ANSWER IS LESS THAN'   &
      ,' HALF PRECISION BECAUSE ARGUMENT TOO NEAR -1')
!
      IF (ABS(X).LE.0.375) ALNREL = X*(1. -   &
        X*CSEVL (X/.375, ALNRCS, NLNREL))
      IF (ABS(X).GT.0.375) ALNREL = LOG (1.0+X)
!
      RETURN
      END FUNCTION ALNREL
      DOUBLE PRECISION FUNCTION ALNORM(X, UPPER)
!
!       EVALUATES THE TAIL AREA OF THE STANDARDIZED NORMAL CURVE FROM
!       X TO INFINITY IF UPPER IS .TRUE. OR FROM MINUS INFINITY TO X
!       IF UPPER IS .FALSE.
!
!  NOTE NOVEMBER 2001: MODIFY UTZERO.  ALTHOUGH NOT NECESSARY
!  WHEN USING ALNORM FOR SIMPLY COMPUTING PERCENT POINTS,
!  EXTENDING RANGE IS HELPFUL FOR USE WITH FUNCTIONS THAT
!  USE ALNORM IN INTERMEDIATE COMPUTATIONS.
!
      DOUBLE PRECISION LTONE,UTZERO,ZERO,HALF,ONE,CON,   &
       A1,A2,A3,A4,A5,A6,A7,B1,B2,   &
       B3,B4,B5,B6,B7,B8,B9,B10,B11,B12,X,Y,Z,ZEXP
      LOGICAL UPPER,UP
!
!       LTONE AND UTZERO MUST BE SET TO SUIT THE PARTICULAR COMPUTER
!
!CCCC DATA LTONE, UTZERO /7.0D0, 18.66D0/
      DATA LTONE, UTZERO /7.0D0, 38.00D0/
!CCCC DATA LTONE, UTZERO /7.0D0, 100.00D0/
      DATA ZERO,HALF,ONE,CON /0.0D0,0.5D0,1.0D0,1.28D0/
      DATA          A1,             A2,            A3,   &
                    A4,             A5,            A6,   &
                    A7   &
       /0.398942280444D0, 0.399903438504D0, 5.75885480458D0,   &
         29.8213557808D0,  2.62433121679D0, 48.6959930692D0,   &
         5.92885724438D0/
      DATA          B1,             B2,             B3,   &
                    B4,             B5,             B6,   &
                    B7,             B8,             B9,   &
                   B10,            B11,            B12   &
       /0.398942280385D0,      3.8052D-8,    1.00000615302D0,   &
         3.98064794D-4,     1.98615381364D0, 0.151679116635D0,   &
         5.29330324926D0,   4.8385912808D0,  15.1508972451D0,   &
        0.742380924027D0,   30.789933034D0,  3.99019417011D0/
!
      ZEXP(Z) = DEXP(Z)
!
      UP = UPPER
      Z = X
      IF (Z .GE. ZERO) GO TO  10
      UP = .NOT. UP
      Z = -Z
  10  IF (Z .LE. LTONE .OR. UP .AND. Z .LE. UTZERO) GO TO  20
      ALNORM = ZERO
      GO TO  40
  20  Y = HALF * Z * Z
      IF (Z .GT. CON) GO TO  30
!
      ALNORM = HALF - Z * (A1- A2 * Y / (Y + A3- A4 / (Y + A5 + A6 /   &
       (Y + A7))))
      GO TO  40
!
  30  ALNORM = B1* ZEXP(-Y)/(Z - B2 + B3/ (Z +B4 +B5/(Z -B6 +B7/   &
       (Z +B8 -B9/ (Z +B10 +B11/ (Z + B12))))))
!
  40  IF (.NOT. UP) ALNORM = ONE - ALNORM
      RETURN
      END FUNCTION ALNORM
      double precision function alogam (x, ifault)
!-----------------------------------------------------------------------
!  Name:       ALOGAM
!
!  Purpose:    Value of the log-gamma function.
!
!  Usage:      ALOGAM (X, IFAULT)
!
!  Arguments:
!     X      - Value at which the log-gamma function is to be evaluated.
!              (Input)
!     IFAULT  - Error indicator.  (Output)
!               IFAULT  DEFINITION
!                 0     No error
!                 1     X .LT. 0
!     ALGAMA - The value of the log-gamma function at XX.  (Output)
!-----------------------------------------------------------------------
!
!        Algorithm ACM 291, Comm. ACM. (1966) Vol. 9, P. 684
!
!        Evaluates natural logarithm of gamma(x)
!        for X greater than zero.
!
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    ifault
      double precision x
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      double precision f, y, z
!                                  SPECIFICATIONS FOR SAVE VARIABLES
      double precision a1, a2, a3, a4, a5, half, one, seven, zero
      save       a1, a2, a3, a4, a5, half, one, seven, zero
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  dlog
!cccc double precision dlog
      double precision zlog
!
!        The following constants are dlog(2PI)/2,
!        half, zero, one, seven
!
      data a1, a2, a3, a4, a5/0.918938533204673d0, 0.000595238095238d0,   &
           0.000793650793651d0, 0.002777777777778d0,   &
           0.083333333333333d0/
      data half, zero, one, seven/0.5d0, 0.0d0, 1.0d0, 7.0d0/
!
      zlog(f) = dlog(f)
!
      alogam = zero
      ifault = 1
      if (x .lt. zero) return
      ifault = 0
      y      = x
      f      = zero
      if (y .ge. seven) go to 30
      f = y
   10 y = y + one
      if (y .ge. seven) go to 20
      f = f*y
      go to 10
   20 f = -zlog(f)
   30 z = one/(y*y)
      alogam = f + (y-half)*zlog(y) - y + a1 + (((-a2*z+a3)*z-a4)*z+a5)   &
               /y
      return
      end
      SUBROUTINE ALDCDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE
!              ASYMMETRIC LOG DOUBLE EXPONENTIAL (LAPLACE)
!              DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X AND
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!              F(X;ALPHA,BETA)
!                  = (ALPHA/(ALPHA+BETA))*X**BETA          0 < X < 1
!                  = 1 - (BETA/(ALPHA+BETA))*X**(-ALPHA)   X >= 1
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST
!                                SHAPE PARAMETER
!                     --BETA   = THE DOUBLE PRECISION SECOND
!                                SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOZUBOWSKI AND PODGORSKI (2003), "LOG-LAPLACE
!                 DISTRIBUTIONS", INTERNATIONAL MATHEMATICAL
!                 JOURNAL, 3, 467-495.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION CDF
      DOUBLE PRECISION DC
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      CDF=0.0D0
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO THE ',   &
               'ALDCDF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO THE ',   &
               'ALDCDF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LE.0.0D0)THEN
        CDF=0.0D0
      ELSEIF(X.LT.1.0D0)THEN
        DC=DLOG(ALPHA) - DLOG(ALPHA+BETA)
        CDF=DC + BETA*DLOG(X)
        CDF=DEXP(CDF)
      ELSE
        DC=DLOG(BETA) - DLOG(ALPHA+BETA)
        CDF=(-ALPHA)*DLOG(X)
        CDF=1.0D0 - DEXP(DC+CDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ALDCDF
      SUBROUTINE ALDPDF(X,ALPHA,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE
!              ASYMMETRIC LOG DOUBLE EXPONENTIAL (LAPLACE)
!              DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X AND
!              HAS THE PROBABILITY DENSITY FUNCTION
!              f(X;ALPHA,BETA)
!                  = C*X**(BETA-1)      0 < X < 1
!                  = C*X**(-ALPHA-1)    X >= 1
!                                       ALPHA, BETA > 0
!              WITH C = ALPHA*BETA/(ALPHA + BETA)
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST
!                                SHAPE PARAMETER
!                     --BETA   = THE DOUBLE PRECISION SECOND
!                                SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KOZUBOWSKI AND PODGORSKI (2003), "LOG-LAPLACE
!                 DISTRIBUTIONS", INTERNATIONAL MATHEMATICAL
!                 JOURNAL, 3, 467-495.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DC
      DOUBLE PRECISION DTERM
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      PDF=0.0D0
!
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
               'ALDPDF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO THE ',   &
               'ALDPDF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO THE ',   &
               'ALDPDF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DC=DLOG(ALPHA) + DLOG(BETA) - DLOG(ALPHA+BETA)
!
      IF(X.LT.1.0D0)THEN
        DTERM=(BETA-1.0D0)*DLOG(X)
      ELSE
        DTERM=(-ALPHA-1.0D0)*DLOG(X)
      ENDIF
      PDF=DEXP(DC + DTERM)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ALDPDF
      SUBROUTINE ALDPPF(P,ALPHA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE
!              ASYMMETRIC LOG DOUBLE EXPONENTIAL
!              (LAPLACE) DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X AND
!              HAS THE PERCENT POINT FUNCTION
!              G(P;ALPHA,BETA) = [P**((ALPHA+BETA)/ALPHA)]**(1/BETA)
!                                0 <= P <= ALPHA/(ALPHA+BETA)
!                              = [(1-P)**((ALPHA+BETA)/BETA)]**(-1/ALPHA)
!                                ALPHA/(ALPHA+BETA) < P < 1
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION FIRST
!                                SHAPE PARAMETER
!                     --BETA   = THE DOUBLE PRECISION SECOND
!                                SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOZUBOWSKI AND PODGORSKI (2003), "LOG-LAPLACE
!                 DISTRIBUTIONS", INTERNATIONAL MATHEMATICAL
!                 JOURNAL, 3, 467-495.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
!
      IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
               'ALDPPF SUBROUTINE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
   16   FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1] INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO THE ',   &
               'ALDPPF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO THE ',   &
               'ALDPPF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DCUT=ALPHA/(ALPHA+BETA)
      IF(P.EQ.0.0D0)THEN
        PPF=0.0D0
      ELSEIF(P.LE.DCUT)THEN
        DTERM1=(ALPHA+BETA)/ALPHA
        DTERM2=(1.0D0/BETA)*DLOG(P*DTERM1)
        PPF=DEXP(DTERM2)
      ELSE
        DTERM1=(ALPHA+BETA)/BETA
        DTERM2=(-1.0D0/ALPHA)*DLOG((1.0D0-P)*DTERM1)
        PPF=DEXP(DTERM2)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ALDPPF
      SUBROUTINE ALDRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ASYMMETRIC LOG DOUBLE EXPONENTIAL DISTRIBUTION
!              WITH TAIL LENGTH PARAMETERS ALPHA AND BETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST (POSITIVE) SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND (POSITIVE) SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE
!             ASYMMETRIC LOG DOUBLE EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA AND BETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOZUBOWSKI AND PODGORSKI, "LOG-LAPLACE
!                 DISTRIBUTIONS", PAPER DOWNLOADED FROM THEIR
!                 WEB SITE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DY1
      DOUBLE PRECISION DY2
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT, 6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ASYMMETRIC ',   &
             'LOG DOUBLE EXPONENTIAL')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER FOR THE')
   25 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER FOR THE')
   16 FORMAT('      ASYMMETRIC LOG DOUBLE EXPONENTIAL RANDOM ',   &
             'NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     NOTE 3/2006: ASYMMETRIC LOG DOUBLE EXPONENTIAL CAN BE
!                  REPRESENTED AS
!                     U1**(1/ALPHA)/U2**(1/BETA)
!
!     EARLY TESTING INDICATES THAT RATIO OF UNIFORMS METHOD
!     SEEMS TO GENERATE SOME EXCESSIVELY LARGE RANDOM NUMBERS,
!     SO STICK WITH PPF METHOD FOR NOW.
!
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
!
      IALG=0
      IF(IALG.EQ.0)THEN
        CALL UNIRAN(N,ISEED,X)
        DO 100 I=1,N
          CALL ALDPPF(DBLE(X(I)),DALPHA,DBETA,DTEMP)
          X(I)=REAL(DTEMP)
  100   CONTINUE
      ELSE
        NTEMP=2
        DO 200 I=1,N
          CALL UNIRAN(NTEMP,ISEED,Y)
          DY1=DBLE(Y(1))
          DY2=DBLE(Y(2))
          X(I)=REAL(DY1**(1.0D0/DBETA)/DY2**(1.0D0/DALPHA))
  200   CONTINUE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ALDRAN
      DOUBLE PRECISION FUNCTION algdiv(a,b)
!-----------------------------------------------------------------------
!
!     COMPUTATION OF LN(GAMMA(B)/GAMMA(A+B)) WHEN B .GE. 8
!
!                         --------
!
!     IN THIS ALGORITHM, DEL(X) IS THE FUNCTION DEFINED BY
!     LN(GAMMA(X)) = (X - 0.5)*LN(X) - X + 0.5*LN(2*PI) + DEL(X).
!
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION c,c0,c1,c2,c3,c4,c5,d,h,s11,s3,s5,s7,s9,t,u,v,w,   &
                       x,x2
!     ..
!     .. External Functions ..
      DOUBLE PRECISION alnrel
      EXTERNAL alnrel
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC dlog
!     ..
!     .. Data statements ..
      DATA c0/.833333333333333D-01/,c1/-.277777777760991D-02/,   &
           c2/.793650666825390D-03/,c3/-.595202931351870D-03/,   &
           c4/.837308034031215D-03/,c5/-.165322962780713D-02/
!     ..
!     .. Executable Statements ..
!------------------------
      IF (a.LE.b) GO TO 10
      h = b/a
      c = 1.0D0/ (1.0D0+h)
      x = h/ (1.0D0+h)
      d = a + (b-0.5D0)
      GO TO 20
                                                                                                                                  
   10 h = a/b
      c = h/ (1.0D0+h)
      x = 1.0D0/ (1.0D0+h)
      d = b + (a-0.5D0)
!
!                SET SN = (1 - X**N)/(1 - X)
!
   20 x2 = x*x
      s3 = 1.0D0 + (x+x2)
      s5 = 1.0D0 + (x+x2*s3)
      s7 = 1.0D0 + (x+x2*s5)
      s9 = 1.0D0 + (x+x2*s7)
      s11 = 1.0D0 + (x+x2*s9)
!
!                SET W = DEL(B) - DEL(A + B)
!
      t = (1.0D0/b)**2
      w = ((((c5*s11*t+c4*s9)*t+c3*s7)*t+c2*s5)*t+c1*s3)*t + c0
      w = w* (c/b)
!
!                    COMBINE THE RESULTS
!
      u = d*alnrel(a/b)
      v = a* (dlog(b)-1.0D0)
      IF (u.LE.v) GO TO 30
      algdiv = (w-v) - u
      RETURN
                                                                                                                                  
   30 algdiv = (w-u) - v
      RETURN
                                                                                                                                  
      END FUNCTION algdiv
      SUBROUTINE ALPCDF(DX,DALPHA,DCDF)
!CCCC SUBROUTINE ALPCDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE ALPHA DISTRIBUTION
!              WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X, AND HAS THE CUMULATIVE DISTRIBUTION
!              FUNCTION
!
!                F(X;ALPHA) = NORCDF(ALPHA-BETA/X)/NORCDF(ALPHA)
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED BETA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            BETA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --NOVEMBER  2007. BETA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DCDF=0.0D0
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DX.EQ.0.0D0)THEN
        GO TO 9999
      ELSEIF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ALPCDF IS NEGATIVE.')
   14 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ALPCDF IS ',   &
             'NON-POSITIVE.')
   47 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      CALL NODCDF(DALPHA,DTERM1)
      DTERM2=DALPHA-(1.0D0/DX)
      CALL NODCDF(DTERM2,DTERM3)
      IF(DTERM1.GT.0.0D0)THEN
        DCDF=DTERM3/DTERM1
      ELSE
        DCDF=0.0D0
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ALPCDF
      SUBROUTINE ALPCHA(DX,DALPHA,DHAZ)
!CCCC SUBROUTINE ALPCHA(X,ALPHA,BETA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE ALPHA DISTRIBUTION
!              WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER
!              BETA.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X, AND HAS THE CUMULATIVE HAZARD
!              FUNCTION
!
!              H(X;ALPHA) = -LOG(1 - NORCDF(ALPHA-BETA/X)/NORCDF(ALPHA))
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED BETA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            BETA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DHAZ=0.0D0
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DX.EQ.0.0D0)THEN
        GO TO 9999
      ELSEIF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ALPCHAZ IS NEGATIVE.')
   14 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ALPCHAZ IS ',   &
             'NON-POSITIVE.')
   47 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      CALL NODCDF(DALPHA,DTERM1)
      DTERM2=DALPHA - (1.0D0/DX)
      CALL NODCDF(DTERM2,DTERM3)
      DCDF=1.0D0 - DTERM3/DTERM1
!
      IF(DCDF.GT.0.0D0)THEN
        DHAZ=-DLOG(DCDF)
      ELSE
        DHAZ=0.0D0
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,304)DX
        CALL DPWRST('XXX','BUG ')
      ENDIF
  301 FORMAT('**** ERROR FROM ALPCHAZ--')
  302 FORMAT('     THE CDF VALUE IS ESSENTIALLY 1, SO THE CUMULATIVE')
  303 FORMAT('     HAZARD IS UNDEFINED (SET TO 0).')
  304 FORMAT('     THE VALUE OF THE FIRST INPUT ARGUMENT IS ',G15.7)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ALPCHA
      SUBROUTINE ALPHAZ(DX,DALPHA,DHAZ)
!CCCC SUBROUTINE ALPHAZ(X,ALPHA,BETA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE ALPHA DISTRIBUTION
!              WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X, AND HAS THE HAZARD FUNCTION
!
!              H(X;ALPHA) = BETA*NORPDF(T)/
!                           (X**2*(NORCDF(ALPHA)-NORCDF(T))
!
!              WHERE T = ALPHA - BETA/X
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED BETA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            BETA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DHAZ
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DDENOM
      DOUBLE PRECISION DT
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DHAZ=0.0D0
      IF(DX.LE.0.0D0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ALPHAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DX
   47   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
   14   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ALPHAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DT=DALPHA - (1.0D0/DX)
!
      CALL NODCDF(DT,DTERM2)
      CALL NODCDF(DALPHA,DTERM3)
      DTERM1=DTERM3-DTERM2
      CALL NODPDF(DT,DNUM)
      DDENOM=(DX**2)*DTERM1
      IF(DDENOM.NE.0.0D0)THEN
        DHAZ=DNUM/DDENOM
      ELSE
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)DX
        CALL DPWRST('XXX','BUG ')
      ENDIF
  101 FORMAT('***** ERROR IN ALPHAZ--HAZARD FUNCTION IS UNDEFINED.')
  102 FORMAT('      VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ALPHAZ
      SUBROUTINE ALPFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              ALPHA MAXIMUM LIKELIHOOD EQUATIONS.
!
!              BETA*SUM[i=1 to N][1/X(i)] - N*ALPHA - N*Z = 0
!
!              (N/BETA) + BETA*SUM[i=1 to N][1/X(i)**2] -
!              ALPHA*SUM[i=1 to N][1/X(i)] = 0
!
!              WHERE
!
!              Z        = d/dalpha LOG(NORCDF(ALPHA))
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--ALPHA MAXIMUM LIKELIHOOD Y
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994), "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                WILEY, P. 173.
!              --SALVIA (1985), "RELIABILITY APPLICATIONS OF THE
!                ALPHA DISTRIBUTION", IEEE TRANSACTIONS ON
!                RELIABILITY, VOL. R-34, NO. 3, PP. 251-252.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/12
!     ORIGINAL VERSION--DECEMBER  2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION H
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DOUBLE PRECISION ERR
      DOUBLE PRECISION CON
      DOUBLE PRECISION CON2
      DOUBLE PRECISION BIG
      DOUBLE PRECISION SAFE
      DOUBLE PRECISION ERRT
      DOUBLE PRECISION FAC
      DOUBLE PRECISION HH
      DOUBLE PRECISION DZ
      INTEGER I
      INTEGER J
      PARAMETER (CON=1.4D0)
      PARAMETER (CON2=CON*CON)
      PARAMETER (BIG=1.D30)
      PARAMETER (NTAB=10)
      PARAMETER (SAFE=2.D0)
!
      DOUBLE PRECISION A(NTAB,NTAB)
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DN=DBLE(NOBS)
      DALPHA=DBLE(X(1))
      DBETA=DBLE(X(2))
      DZ=0.0D0
!
!     COMPUTE Z USING RIDDER'S METHOD:
!
      H=0.3D0
      HH=H
      CALL NODCDF(DALPHA+HH,DTERM4)
      DTERM4=DLOG(DTERM4)
      CALL NODCDF(DALPHA-HH,DTERM5)
      DTERM5=DLOG(DTERM5)
      DTERM2=(DTERM4 - DTERM5)/(2.0D0*HH)
      A(1,1)=DTERM2
      ERR=BIG
      DO 10 I=2,NTAB
        HH=HH/CON
        CALL NODCDF(DALPHA+HH,DTERM4)
        DTERM4=DLOG(DTERM4)
        CALL NODCDF(DALPHA-HH,DTERM5)
        DTERM5=DLOG(DTERM5)
        DTERM2=(DTERM4 - DTERM5)/(2.0D0*HH)
        A(1,I)=DTERM2
        FAC=CON2
        DO 20 J=2,I
          A(J,I)=(A(J-1,I)*FAC - A(J-1,I-1))/(FAC-1.0D0)
          FAC=CON2*FAC
          ERRT=MAX(DABS(A(J,I)-A(J-1,I)),DABS(A(J,I)-A(J-1,I-1)))
          IF(ERRT.LE.ERR)THEN
            ERR=ERRT
            DZ=A(J,I)
          ENDIF
   20   CONTINUE
        IF(DABS(A(I,I)-A(I-1,I-1)).GE.SAFE*ERR)GO TO 99
   10 CONTINUE
   99 CONTINUE
!
      DTERM1=DN*DALPHA
      DTERM2=DN*DZ
      DTERM3=DN/DBETA
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,NOBS
!
        DX=1.0D0/DBLE(XDATA(I))
!
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + DX*DX
!
  200 CONTINUE
!
      FVEC(1)=DBETA*DSUM1 - DTERM1 - DTERM2
      FVEC(2)=DTERM3 + DBETA*DSUM2 - DALPHA*DSUM1
!
      RETURN
      END SUBROUTINE ALPFUN 
      SUBROUTINE ALPPDF(DX,DALPHA,DPDF)
!CCCC SUBROUTINE ALPPDF(X,ALPHA,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE ALPHA DISTRIBUTION
!              WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X, AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!
!              f(X;ALPHA,BETA) = BETA*NORPDF(ALPHA-BETA/X)/
!                                [X**2*NORCDF(ALPHA)]
!
!              NOTE 11/2007: ROUTINE PREVIOSLY TREATED BETA AS A
!                            SHAPE PARAMETER.  CORRECT SO THAT
!                            BETA IS A SCALE PARAMETER (AND
!                            SO CAN BE ASSUMED TO BE 1 IN THIS
!                            ROUTINE).
!
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994), "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                WILEY, P. 173.
!              --SALVIA (1985), "RELIABILITY APPLICATIONS OF THE
!                ALPHA DISTRIBUTION", IEEE TRANSACTIONS ON
!                RELIABILITY, VOL. R-34, NO. 3, PP. 251-252.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --JULY      1995. DEFINE DPDF AS DOUBLE PREC.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPDF
!
      DOUBLE PRECISION DT
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA EPS/0.1E-16/
!
!-----START POINT-----------------------------------------------------
!
      DPDF=0.0D0
      IF(DX.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ALPPDF IS ',   &
             'NON-POSITIVE.')
   14 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ALPPDF IS ',   &
             'NON-POSITIVE.')
   47 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!
      DT=DALPHA - (1.0D0/DX)
      CALL NODPDF(DT,DTERM1)
      CALL NODCDF(DALPHA,DTERM2)
      DPDF=DTERM1/(DTERM2*(DX**2))
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ALPPDF
      SUBROUTINE ALPML1(Y,N,ALPHSV,SCALSV,MAXNXT,   &
                        TEMP1,TEMP2,DISPAR,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALPHMO,SCALMO,ALPHML,SCALML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE ALPHA DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).  THIS ROUTINE RETURNS ONLY
!              THE POINT ESTIMATES.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLAL WILL GENERATE THE OUTPUT
!              FOR THE ALPHA MLE COMMAND).
!
!     NOTE--THE MAXIMIUM LIKELIHOOD ESTIMATES ARE THE SOLUTIONS
!           TO THE FOLLOWING EQUATIONS:
!
!             BETA*SUM[i=1 to N][1/X(i)] - N*ALPHA - N*Z = 0
!
!             (N/BETA) + BETA*SUM[i=1 to N][1/X(i)**2] -
!             ALPHA*SUM[i=1 to N][1/X(i)] = 0
!
!           WHERE
!
!             Z        = d/dalpha LOG(NORCDF(ALPHA))
!
!           THE MOMENT ESTIMATES ARE
!
!           ALPHAHAT = M/S
!           BETAHAT = M**2/S
!
!           WHERE M AND S ARE THE SAMPLE MEAN AND SAMPLE SD.
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994), "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                WILEY, P. 173.
!              --SALVIA (1985), "RELIABILITY APPLICATIONS OF THE
!                ALPHA DISTRIBUTION", IEEE TRANSACTIONS ON
!                RELIABILITY, VOL. R-34, NO. 3, PP. 251-252.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLAL)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION DISPAR(*)
      DIMENSION DISPA2(1)
      INTEGER   IPPCAP(2)
      DOUBLE PRECISION DTEMP1(*)
!
      EXTERNAL ALPFUN
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ALPM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      SHAPE1=0.0
      SCALE2=0.0
      ALPHMO=0.0
      ALPHML=0.0
      SCALMO=0.0
      SCALML=0.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF ALPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  CARRY OUT CALCULATIONS                        **
!               **  FOR ALPHA MLE ESTIMATE                        **
!               ****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='ALPHA'
      SCALMO=CPUMIN
      SHAPMO=CPUMIN
      SCALML=CPUMIN
      SHAPML=CPUMIN
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               **********************************
!               **  STEP 21--                   **
!               **  CARRY OUT CALCULATIONS      **
!               **  FOR ALPHA MLE               **
!               **  ESTIMATE (FULL SAMPLE CASE) **
!               **********************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLAL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1125 I=1,N
        TEMP1(I)=1.0/Y(I)
 1125 CONTINUE
      CALL MEAN(TEMP1,N,IWRITE,ZMEAN,IBUGA3,IERROR)
      CALL SD(TEMP1,N,IWRITE,ZSD,IBUGA3,IERROR)
!
      ALPHMO=ZMEAN/ZSD
      SCALMO=ZMEAN**2/ZSD
!
      IF(ALPHSV.GT.0.0 .AND. SCALSV.GT.0.0)THEN
        XPAR(1)=DBLE(ALPHSV)
        XPAR(2)=DBLE(SCALSV)
      ELSE
!
!       IF NO STARTING VALUES SPECIFIED, COMPUTE STARTING
!       VALUES BASED ON PPCC METHOD.
!
        CALL UNIMED(N,TEMP1)
        CALL SORT(Y,N,Y)
        ICASP2='ALPH'
        ICASPL='PPCC'
        IPPCAP(1)=100
        IPPCAP(2)=1
!
!       OBTAIN LOWER/UPPER LIMITS FOR SHAPE PARAMETER
!
        CALL EXTPA2(ICASP2,IDIST,A,B,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ISUBRO,IBUGA3,IERROR)
!
!       CREATE ARRAY FOR THE CANDIDATE VALUES OF SHAPE PARAMETER
!
        NUMSHA=1
        NUMDIS=50
        CALL DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    XMIN,XMAX,A,B,   &
                    DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                    ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                    IBUGA3,ISUBRO,IERROR)
!
        CORRMX=-1.0
        IWRITE='OFF'
        DO 1010 IDIS=1,NUMDIS
          SHAPE=DISPAR(IDIS)
          DO 1020 I=1,N
            CALL ALPPPF(DBLE(TEMP1(I)),DBLE(SHAPE),DPPF)
            TEMP2(I)=REAL(DPPF)
 1020     CONTINUE
          CALL CORR(Y,TEMP2,N,IWRITE,CC,IBUGA3,IERROR)
          IF(CC.GT.CORRMX)THEN
            SHAPE1=SHAPE
            CALL LINFI2(Y,TEMP2,N,PPA0,PPA1,ISUBRO,IBUGA3,IERROR)
            CORRMX=CC
            SCALE2=PPA1
          ENDIF
 1010   CONTINUE
        XPAR(1)=DBLE(SHAPE1)
        XPAR(2)=DBLE(SCALE2)
      ENDIF
!
      IOPT=2
      TOL=1.0D-5
      NVAR=2
      NPRINT=-1
      INFO=0
      CALL DNSQE(ALPFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      ALPHML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF ALPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALPHML,SCALML,ALPHMO,SCALMO
 9017   FORMAT('ALPPML,SCALML,ALPHMO,SCALMO =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE ALPML1
      SUBROUTINE ALPPPF(DP,DALPHA,DPPF)
!CCCC SUBROUTINE ALPPPF(P,ALPHA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE ALPHA DISTRIBUTION
!              WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X, AND HAS THE PERCENT POINT FUNCTION
!
!              G(P;ALPHA,BETA) = BETA/
!                                [ALPHA - NORPPF(P*NORCDF(ALPHA))]
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --JULY      1995.   DEFINE DPPF AS DOUBLE PREC.
!     UPDATED         --NOVEMBER  2007. ALPHA IS A SCALE PARAMETER,
!                                       SO ASSUME = 1
!     UPDATED         --NOVEMBER  2007. MAKE ARGUMENTS DOUBLE PRECISON
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DPPF=0.0D0
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ALPPPF IS ',   &
             'OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
   14 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ALPCDF IS ',   &
             'NON-POSITIVE.')
   47 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      CALL NODCDF(DALPHA,DTERM1)
      DTERM2=DP*DTERM1
      CALL NODPPF(DTERM2,DTERM3)
      DDENOM=DALPHA - DTERM3
      IF(DDENOM.NE.0.0D0)THEN
        DPPF=1.0D0/DDENOM
      ELSE
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,304)DP
        CALL DPWRST('XXX','BUG ')
      ENDIF
  301 FORMAT('**** ERROR FROM ALPPPF--')
  302 FORMAT('     AN INFINITE PPF VALUE IS ENCOUNTERED (SET TO 0).')
  304 FORMAT('     THE VALUE OF THE FIRST INPUT ARGUMENT IS ',G15.7)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ALPPPF
      SUBROUTINE ALPRAN(N,ALPHA,ISEED,X)
!CCCC SUBROUTINE ALPRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ALPHA DISTRIBUTION
!              WITH SHAPE PARAMETER ALPHA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                                ALPHA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE ALPHA DISTRIBUTION
!             WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ALPPPF.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!     UPDATED         --NOVEMBER  2007. BETA IS REALLY A SCALE
!                                       PARAMETER.
!     UPDATED         --NOVEMBER  2007. CALL LIST TO ALPPPF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ALPHA RANDOM ',   &
             'NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   14 FORMAT('***** ERROR--THE VALUE OF THE ALPHA SHAPE ',   &
             'PARAMETER IS NON-POSITIVE.')
   47 FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N ALPHA DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL ALPPPF(DBLE(X(I)),DBLE(ALPHA),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ALPRAN
      SUBROUTINE ANDYK (NTOT, NBCH, XPS, XPSU,   &
                 IPBCH, NTIE, ISIZE, WK3, IWK2, ADKSTA)
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      DIMENSION XPS(*), XPSU(*), NTIE(*),   &
                ISIZE(*), WK3(*),   IWK2(*),   &
                IPBCH(*)
!
!       NTOT  -- TOTAL NUMBER OF DATA VALUES (INPUT)
!       NBCH  -- NUMBER OF BATCHES (INPUT)
!       XPS   -- DATA, POOLED AND SORTED (INPUT)
!       XPSU  -- UNIQUE VALUES OF XPS (OUTPUT)
!       IPBCH -- BATCH NUMBERS FOR XPS (INPUT)
!       NTIE  -- NUMBER OF TIES AT EACH VALUE OF XPSU (OUTPUT)
!       ISIZE -- BATCH SIZES (INPUT)
!       WK3, IWK2  -- SCRATCH WORK ARRAYS
!       ADKSTA  -- K-SAMPLE A-D STATISTIC (OUTPUT)
!
!         K-SAMPLE ANDERSON-DARLING TEST --
!            INCLUDING CORRECTION FOR TIES.
!
      ADKSTA = 0.D0
      DO 10 K=1, NBCH
         CALL ANDY2 (K, ADVAL,   &
                 NTOT, NBCH, XPS, XPSU, IPBCH, NTIE,   &
                 ISIZE, WK3, IWK2)
      ADKSTA = ADKSTA +ADVAL
10    CONTINUE
!
      ADKSTA = ADKSTA *(NTOT -1.D0) /(NTOT *(NBCH -1.D0))
      RETURN
      END SUBROUTINE ANDYK 
      SUBROUTINE ANDY2  (K, ADVAL,   &
                 NTOT, NBCH, XPS, XPSU, IPBCH,   &
                 NTIE, ISIZE, WK3, IWK2)
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      DIMENSION XPS(NTOT),   XPSU(NTOT), IPBCH(NTOT),   &
                NTIE(NTOT),  ISIZE(NBCH), WK3(NTOT),   &
                IWK2(NTOT)
!
!      -- DETERMINE THE UNIQUE VALUES, NUMBER OF TIES AND
!         NUMBER OF TIES IN KTH BATCH.
      DO 10 I=1, NTOT
         XPSU (I) = XPS (I)
         NTIE (I) = 1
         IF (IPBCH (I) .EQ. K) THEN
            IWK2  (I) = 1
         ELSE
            IWK2  (I) = 0
         END IF
10    CONTINUE
!
      I    = 2
      NDIS = NTOT
!     DO WHILE (I .LE. NDIS)
11    CONTINUE
      IF (I .GT. NDIS) GO TO 12
         IF (XPSU (I) .EQ. XPSU (I-1)) THEN
            NTIE  (I-1) = NTIE  (I-1) + NTIE  (I)
            IWK2  (I-1) = IWK2  (I-1) + IWK2  (I)
            NDIS        = NDIS -1
            DO 20 J=I, NDIS
               XPSU  (J) = XPSU  (J+1)
               NTIE  (J) = NTIE  (J+1)
               IWK2  (J) = IWK2  (J+1)
20         CONTINUE
         ELSE
            I = I +1
         END IF
      GO TO 11
12    CONTINUE
!     END DO
!
!      -- DETERMINE THE FIJ.
      XOLD = 0.0D0
      IOLD = 0
      DO 30 I=1, NDIS
         WK3 (I) = XOLD  +.5D0 *(IWK2 (I)  +IOLD)
         XOLD    = WK3 (I)
         IOLD    = IWK2 (I)
30    CONTINUE
!
!     -- CALCULATE THE ANDERSON-DARLING STATISTIC
      ADVAL = 0.D0
      NSUM  = 0
      DO 50 I=1, NDIS
         FIJ   = WK3 (I)
         HJ    = NSUM    + .5D0 *NTIE  (I)
         NSUM  = NSUM    +       NTIE (I)
         ADVAL = ADVAL   + NTIE (I) *(NTOT*FIJ -ISIZE(K)*HJ) **2   &
                        /(HJ *(NTOT-HJ) -.25D0 *NTOT*NTIE(I))
50    CONTINUE
      ADVAL = ADVAL / (ISIZE (K) *NTOT)
      RETURN
      END SUBROUTINE ANDY2  
      SUBROUTINE ANGCDF(X,CDF)
!
!     NOTE--ANGLIT CDF IS:
!              ANGCDF(X) = [SIN(X + PI/4)]**2  -PI/4 <= X <= PI/4
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      IF(X.LT.-PI/4.0)THEN
        CDF=0.0
      ELSEIF(X.GT.PI/4.0)THEN
        CDF=1.0
      ELSE
        CDF=SIN(X+PI/4.0)*SIN(X+PI/4)
      ENDIF
!
      RETURN
      END SUBROUTINE ANGCDF
      SUBROUTINE ANGPDF(X,PDF)
!
!     NOTE--ANGLIT PDF IS:
!              ANGPDF(X) = SIN(2X + PI/2)  -PI/4 <= X <= PI/4
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(X.LT.-PI/4.0 .OR. X.GT.PI/4.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** FATAL DIAGNOSTIC--THE INPUT ARGUMENT IS NOT IN ',   &
             'THE INTERVAL (-PI/4,PI/4).')
  302 FORMAT('      IT HAS THE VALUE ',E15.7)
!
      PDF=SIN(2*X+PI/2.0)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ANGPDF
      SUBROUTINE ANGPPF(P,PPF)
!
!     NOTE--ALGORITHM ADDED SEPTEMBER 1995
!           G(P) = ARCSIN(SQRT(P))-PI/4
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GT.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ANGPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      PPF=ASIN(SQRT(P))-PI/4.0
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ANGPPF
      FUNCTION ANGRAD (X1,Y1,X2,Y2,X3,Y3,IBUGA3)
!
!     PURPOSE--RETURNS THE ANGLE SWEPT OUT BETEEN TWO RAYS
!              IN 2D.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--THIS USES THE CODE FROM JOHN BURKARDT "geometry.f90"
!           LIBRARY.  WE CODE IT IN FORTRAN 77, BUT MAKE NO
!           SUBSTANTIVE CHANGES OTHERWISE.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.10
!     ORIGINAL VERSION--OCTOBER   2012.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------
!
      CHARACTER*4 IBUGA3
!
      REAL X1
      REAL Y1
      REAL X2
      REAL Y2
      REAL X3
      REAL Y3
      REAL X
      REAL Y
      REAL PI
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.14159265358979/
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGININNING OF ANGRAD')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X1,Y1,X2,Y2,X3,Y3
   53   FORMAT('X1,Y1,X2,Y2,X3,Y3 = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      X=(X1 - X2)*(X3 - X2) + (Y1 - Y2)*(Y3 - Y2)
      Y=(X1 - X2)*(Y3 - Y2) - (Y1 - Y2)*(X3 - X2)
!
      IF(X.EQ.0.0 .AND. Y.EQ.0.0)THEN
        ANGRAD = 0.0
      ELSE
         ANGRAD = ATAN2(Y,X)
         IF(ANGRAD .LT. 0.0)THEN
           ANGRAD = ANGRAD + 2.0*PI
         ENDIF
      ENDIF
!
!     WE WANT THE ANGLE BETWEEN 0 AND PI
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('AT THE END OF ANGRAD')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)X,Y,ANGRAD
 9053   FORMAT('X,Y,ANGRAD = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END FUNCTION ANGRAD 
      SUBROUTINE ANGRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ANGLIT DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE ANGLIT DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001/10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'ANGRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N ANGLIT RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      CALL ANGPPF(X(I),XTEMP)
      X(I)=XTEMP
  100 CONTINUE
!
      RETURN
      END SUBROUTINE ANGRAN
      DOUBLE PRECISION FUNCTION ANORM(ARG)
!S    REAL FUNCTION ANORM(ARG)
!------------------------------------------------------------------
!
! This function evaluates the normal distribution function:
!
!                              / x
!                     1       |       -t*t/2
!          P(x) = ----------- |      e       dt
!                 sqrt(2 pi)  |
!                             /-oo
!
!   The main computation evaluates near-minimax approximations
!   derived from those in "Rational Chebyshev approximations for
!   the error function" by W. J. Cody, Math. Comp., 1969, 631-637.
!   This transportable program uses rational functions that
!   theoretically approximate the normal distribution function to
!   at least 18 significant decimal digits.  The accuracy achieved
!   depends on the arithmetic system, the compiler, the intrinsic
!   functions, and proper selection of the machine-dependent
!   constants.
!
!*******************************************************************
!*******************************************************************
!
! Explanation of machine-dependent constants.  Let
!
!   XMIN  = the smallest positive floating-point number.
!
! Then the following machine-dependent constants must be declared
!   in DATA statements.  IEEE values are provided as a default.
!
!   EPS   = argument below which anorm(x) may be represented by
!           0.5  and above which  x*x  will not underflow.
!           A conservative value is the largest machine number X
!           such that   1.0 + X = 1.0   to machine precision.
!   XLOW  = the most negative argument for which ANORM does not
!           vanish.  This is the negative of the solution to
!                    W(x) * (1-1/x**2) = XMIN,
!           where W(x) = exp(-x*x/2)/[x*sqrt(2*pi)].
!   XUPPR = positive argument beyond which anorm = 1.0.  A
!           conservative value is the solution to the equation
!                    exp(-x*x/2) = EPS,
!           i.e., XUPPR = sqrt[-2 ln(eps)].
!
!   Approximate values for some important machines are:
!
!                          XMIN        EPS        XLOW    XUPPR
!
!  CDC 7600      (S.P.)  3.13E-294   7.11E-15   -36.641   8.072
!  CRAY-1        (S.P.)  4.58E-246   7.11E-157 -106.521  26.816
!  IEEE (IBM/XT,
!    SUN, etc.)  (S.P.)  1.18E-38    5.96E-8    -12.949   5.768
!  IEEE (IBM/XT,
!    SUN, etc.)  (D.P.)  2.23D-308   1.11D-16   -37.519   8.572
!  IBM 195       (D.P.)  5.40D-79    1.39D-17   -18.781   8.811
!  VAX D-Format  (D.P.)  2.94D-39    1.39D-17   -13.055   8.811
!  VAX G-Format  (D.P.)  5.56D-309   1.11D-16   -37.556   8.572
!
!*******************************************************************
!*******************************************************************
!
! Error returns
!
!  The program returns  ANORM = 0     for  ARG .LE. XLOW.
!
!
! Intrinsic functions required are:
!
!     ABS, AINT, EXP
!
!
!  Author: W. J. Cody
!          Mathematics and Computer Science Division
!          Argonne National Laboratory
!          Argonne, IL 60439
!
!  Latest modification: March 15, 1992
!
!------------------------------------------------------------------
      INTEGER I
!S    REAL
      DOUBLE PRECISION   &
           A,ARG,B,C,D,DEL,EPS,HALF,P,ONE,Q,RESULT,SIXTEN,   &
           SQRPI,THRSH,ROOT32,X,XLOW,XDEN,XNUM,Y,XSQ,XUPPR,ZERO
      DIMENSION A(5),B(4),C(9),D(8),P(6),Q(5)
!------------------------------------------------------------------
!  Mathematical constants
!
!  SQRPI = 1 / sqrt(2*pi), ROOT32 = sqrt(32), and
!  THRSH is the argument for which anorm = 0.75.
!------------------------------------------------------------------
!S    DATA ONE,HALF,ZERO,SIXTEN/1.0E0,0.5E0,0.0E0,1.60E1/,
!S   1     SQRPI/3.9894228040143267794E-1/,THRSH/0.66291E0/,
!S   2     ROOT32/5.656854248E0/
      DATA ONE,HALF,ZERO,SIXTEN/1.0D0,0.5D0,0.0D0,1.60D1/
      DATA SQRPI,THRSH/3.9894228040143267794D-1,0.67441D0/
      DATA ROOT32/5.656854248D0/
!------------------------------------------------------------------
!  Machine-dependent constants
!------------------------------------------------------------------
!S    DATA EPS/5.96E-8/,XLOW/-12.949E0/,XUPPR/5.768E0/
      DATA EPS/1.11D-16/,XLOW/-37.519D0/,XUPPR/8.572D0/
!------------------------------------------------------------------
!  Coefficients for approximation in first interval
!------------------------------------------------------------------
!S    DATA A/2.2352520354606839287E00,1.6102823106855587881E02,
!S   1       1.0676894854603709582E03,1.8154981253343561249E04,
!S   2       6.5682337918207449113E-2/
!S    DATA B/4.7202581904688241870E01,9.7609855173777669322E02,
!S   1       1.0260932208618978205E04,4.5507789335026729956E04/
      DATA A/2.2352520354606839287D00,1.6102823106855587881D02,   &
             1.0676894854603709582D03,1.8154981253343561249D04,   &
             6.5682337918207449113D-2/
      DATA B/4.7202581904688241870D01,9.7609855173777669322D02,   &
             1.0260932208618978205D04,4.5507789335026729956D04/
!------------------------------------------------------------------
!  Coefficients for approximation in second interval
!------------------------------------------------------------------
!S    DATA C/3.9894151208813466764E-1,8.8831497943883759412E00,
!S   1       9.3506656132177855979E01,5.9727027639480026226E02,
!S   2       2.4945375852903726711E03,6.8481904505362823326E03,
!S   3       1.1602651437647350124E04,9.8427148383839780218E03,
!S   4       1.0765576773720192317E-8/
!S    DATA D/2.2266688044328115691E01,2.3538790178262499861E02,
!S   1       1.5193775994075548050E03,6.4855582982667607550E03,
!S   2       1.8615571640885098091E04,3.4900952721145977266E04,
!S   3       3.8912003286093271411E04,1.9685429676859990727E04/
      DATA C/3.9894151208813466764D-1,8.8831497943883759412D00,   &
             9.3506656132177855979D01,5.9727027639480026226D02,   &
             2.4945375852903726711D03,6.8481904505362823326D03,   &
             1.1602651437647350124D04,9.8427148383839780218D03,   &
             1.0765576773720192317D-8/
      DATA D/2.2266688044328115691D01,2.3538790178262499861D02,   &
             1.5193775994075548050D03,6.4855582982667607550D03,   &
             1.8615571640885098091D04,3.4900952721145977266D04,   &
             3.8912003286093271411D04,1.9685429676859990727D04/
!------------------------------------------------------------------
!  Coefficients for approximation in third interval
!------------------------------------------------------------------
!S    DATA P/2.1589853405795699E-1,1.274011611602473639E-1,
!S   1       2.2235277870649807E-2,1.421619193227893466E-3,
!S   2       2.9112874951168792E-5,2.307344176494017303E-2/
!S    DATA Q/1.28426009614491121E00,4.68238212480865118E-1,
!S   1       6.59881378689285515E-2,3.78239633202758244E-3,
!S   2       7.29751555083966205E-5/
      DATA P/2.1589853405795699D-1,1.274011611602473639D-1,   &
             2.2235277870649807D-2,1.421619193227893466D-3,   &
             2.9112874951168792D-5,2.307344176494017303D-2/
      DATA Q/1.28426009614491121D00,4.68238212480865118D-1,   &
             6.59881378689285515D-2,3.78239633202758244D-3,   &
             7.29751555083966205D-5/
!------------------------------------------------------------------
      X = ARG
      Y = ABS(X)
      IF (Y .LE. THRSH) THEN
!------------------------------------------------------------------
!  Evaluate  anorm  for  |X| <= 0.66291
!                               0.6744 (= NORPPF(0.75)
!------------------------------------------------------------------
            XSQ = ZERO
            IF (Y .GT. EPS) XSQ = X * X
            XNUM = A(5)*XSQ
            XDEN = XSQ
            DO 20 I = 1, 3
               XNUM = (XNUM + A(I)) * XSQ
               XDEN = (XDEN + B(I)) * XSQ
   20       CONTINUE
            RESULT = X * (XNUM + A(4)) / (XDEN + B(4))
            RESULT = HALF + RESULT
!------------------------------------------------------------------
!  Evaluate  anorm  for 0.66291 <= |X| <= sqrt(32)
!------------------------------------------------------------------
         ELSE IF (Y .LE. ROOT32) THEN
            XNUM = C(9)*Y
            XDEN = Y
            DO 120 I = 1, 7
               XNUM = (XNUM + C(I)) * Y
               XDEN = (XDEN + D(I)) * Y
  120       CONTINUE
            RESULT = (XNUM + C(8)) / (XDEN + D(8))
            XSQ = AINT(Y*SIXTEN)/SIXTEN
            DEL = (Y-XSQ)*(Y+XSQ)
            RESULT = EXP(-XSQ*XSQ*HALF)*EXP(-DEL*HALF)*RESULT
            IF (X .GT. ZERO) RESULT = ONE - RESULT
!------------------------------------------------------------------
!  Evaluate  anorm  for |X| > sqrt(32)
!------------------------------------------------------------------
         ELSE
            RESULT = ZERO
            IF ((X .GE. XLOW) .AND. (X .LT. XUPPR)) THEN
               XSQ = ONE / (X * X)
               XNUM = P(6)*XSQ
               XDEN = XSQ
               DO 240 I = 1, 4
                  XNUM = (XNUM + P(I)) * XSQ
                  XDEN = (XDEN + Q(I)) * XSQ
  240          CONTINUE
               RESULT = XSQ *(XNUM + P(5)) / (XDEN + Q(5))
               RESULT = (SQRPI -  RESULT) / Y
               XSQ = AINT(X*SIXTEN)/SIXTEN
               DEL = (X-XSQ)*(X+XSQ)
               RESULT = EXP(-XSQ*XSQ*HALF)*EXP(-DEL*HALF)*RESULT
            END IF
            IF (X .GT. ZERO) RESULT = ONE - RESULT
      END IF
!------------------------------------------------------------------
!  Fix up for negative argument, erf, etc.
!------------------------------------------------------------------
      ANORM = RESULT
!---------- Last card of ANORM ----------
!
      RETURN
      END FUNCTION ANORM
      SUBROUTINE ARL2(DELTA, K, H, S0, ARL, ARLFIR, IFAULT)
!
!        ALGORITHM AS 258.1  APPL.STATIST. (1990), VOL.39, NO.3
!
!        Computes the average run length for a cumulative
!        sum control scheme
!
      REAL DELTA, K, H, S0, ARL, ARLFIR
      INTEGER IFAULT
      REAL ARLH, ARLHF, ARLL, ARLLF, BIGARL, BIGDEL
      INTEGER JFAULT
      DATA BIGARL / 1.E30 / , BIGDEL / 5.0 /
!
      IFAULT = 0
      IF (DELTA .LT. 0.0) THEN
         IFAULT = 1
      ELSE
!
!        Compute ARL's for upper tail.
!
         CALL ARL1(DELTA, K, H, S0, ARLH, ARLHF, IFAULT)
         IF (IFAULT .EQ. 0) THEN
!
!        If DELTA=0, then ARL's for lower tail are the same as for
!        the upper.
!
            IF (DELTA .EQ. 0.0) THEN
               ARLLF = ARLHF
               ARLL = ARLH
!
!        If DELTA is too large, skip the low-side ARL calculation.
!
            ELSE IF (DELTA .GT. BIGDEL) THEN
               ARLL = BIGARL
               ARLLF = BIGARL
            ELSE
!
!        Otherwise compute ARL's for lower tail.
!
               CALL ARL1(-DELTA, K, H, S0, ARLL, ARLLF, JFAULT)
!
!        Set lower ARL's large if negative JFAULT .GT. 0
!
               IF (ARLL .LE. ARLH .OR. ARLLF .LE. ARLHF .OR.   &
                   ARLL .LT. ARLLF .OR. JFAULT .GT. 0) THEN
                  ARLL = BIGARL
                  ARLLF = BIGARL
               END IF
            END IF
!
!        Compute two-sided ARL for S0=0.0
!
            ARL = ARLH / (1.0 + ARLH / ARLL)
!
!        Compute two-sided ARL for specified value of S0.
!
            ARLFIR = ARLHF / (1.0 + ARLH / ARLL) +   &
                     ARLH / (ARLH / ARLLF + ARLL / ARLLF) - ARL
!
!        Set IFAULT=3 if two-sided ARL's are lower bounds.
!
            IF (IFAULT .EQ. 0 .AND. S0 .GT. H / 2.0 + K) IFAULT = 3
         END IF
      END IF
      RETURN
      END SUBROUTINE ARL2
      SUBROUTINE ARL1(DELTA, K, H, S0, ARL, ARLFIR, IFAULT)
!
!        ALGORITHM AS 258.2  APPL.STATIST. (1990), VOL.39, NO.3
!
      REAL DELTA, K, H, S0, ARL, ARLFIR
      INTEGER IFAULT
      INTEGER N, N1, N2, I, J
      REAL XN
      DOUBLE PRECISION XCOND
      PARAMETER (N=12, N1=N + 1, N2=N + 2, XN=N, XCOND=100.D0)
      INTEGER IPVT(N1)
!CCCC REAL P1, P2
      DOUBLE PRECISION ALNORM
      DOUBLE PRECISION A(N1, N1), B(N1), R(N1), W(N2),   &
                       C, E1, E2, RCOND, S, T
      EXTERNAL ALNORM
!
!        N is the degree of the polynomial approximation.
!        XCOND defines the criterion for singularity:
!              XCOND+RCOND .LE. XCOND,
!        where RCOND is the reciprocal of the condition number.
!
      IFAULT = 0
      IF (K .LT. 0.0 .OR. H .LT. 0.0 .OR. S0 .LT. 0.0 .OR.   &
          S0 .GT. H) THEN
         IFAULT = 1
      ELSE IF (H .EQ. 0.0) THEN
         AK=REAL(K)
         ARL = 1.0 / ALNORM(DBLE(DELTA - AK), .FALSE.)
         ARLFIR = ARL
      ELSE
!
!        Set C.
!
         C = MAX(0.0, K - DELTA)
!
!        For each point S at which the polynomial approximation is to be
!        evaluated...
!
         DO 40 I = 0, N
!
!        Compute S
!
            S = H * I / XN
!
!        Calculate necessary exponentials in S.
!
            E1 = EXP(C * S)
            E2 = EXP((S + DELTA - K) * C + C * C / 2.0)
!
!        Apply left-hand-side of integral equation.
!
            T = E1
            DO 10 J = 1, N + 1
               A(I + 1, J) = T
               T = T * S
   10       CONTINUE
!
!        Apply lower integration limit.
!
            CALL MOMENT(-S - DELTA - C + K, -S - DELTA - C + K, N, R, W)
            DO 20 J = 1, N + 1
               A(I + 1, J) = A(I + 1, J) - R(J) * E2
   20       CONTINUE
!
!        Apply upper integration limit.
!
            CALL MOMENT(H - S - DELTA - C + K, -S - DELTA - C + K, N, R,   &
                        W)
            DO 30 J = 1, N + 1
               A(I + 1, J) = A(I + 1, J) + R(J) * E2
   30       CONTINUE
!
!        Apply term '1 + L(0) F(-S-DELTA+K)'.
!
            AK=REAL(K)
            A(I + 1, 1) = A(I + 1, 1) - ALNORM(-S - DELTA + AK,   &
                          .FALSE.)
            B(I + 1) = 1.0
   40    CONTINUE
!
!        Normalize the simultaneous equations
!
         DO 70 I = 1, N + 1
            S = 0.0
            DO 50 J = 1, N + 1
               S = MAX(S, ABS(A(I, J)))
   50       CONTINUE
            B(I) = B(I) / S
            DO 60 J = 1, N + 1
               A(I, J) = A(I, J) / S
   60       CONTINUE
   70    CONTINUE
         DO 100 J = 1, N + 1
            W(J) = 0.0
            DO 80 I = 1, N + 1
               W(J) = MAX(W(J), ABS(A(I, J)))
   80       CONTINUE
            DO 90 I = 1, N + 1
               A(I, J) = A(I, J) / W(J)
   90       CONTINUE
  100    CONTINUE
!
!        Factor matrix A.  If equations are singular to working
!        precision, IFAULT=2.
!
!        ***************************************
!        SUBROUTINE DGECO(A,LDA,N,IPVT,RCOND,Z)
!        on entry:
!        A:     the matrix to be factored.
!        LDA:   the leading dimension of array A.
!        N:     the order of the matrix A.
!        on return:
!        A:     the lu factorization of A.
!        IPVT:  pivot indices.
!        RCOND: an estimate of the reciprocal condition of A.
!        Z:     a working vector.
!        ***************************************
!
         CALL DGECO(A, N + 1, N + 1, IPVT, RCOND, R)
         IF (XCOND + RCOND .EQ. XCOND) THEN
            IFAULT = 2
         ELSE
!
!        Solve for the polynomial coefficients
!
!        ***************************************
!        SUBROUTINE DGESL(A,LDA,N,IPVT,B,JOB)
!        on entry:
!        A:     the output from dgeco.
!        LDA:   the leading dimension of array A.
!        N:     the order of the matrix A.
!        IPVT:  the pivot vector from dgeco.
!        B:     the right hand side vector.
!        JOB:   = 0       to solve A*X=B.
!               = nonzero to solve trans(A)*X=B.
!        on return:
!        B:     the solution vector X.
!        ***************************************
!
            CALL DGESL(A, N + 1, N + 1, IPVT, B, 0)
!
!        Get ARL and ARLFIR.
!
            ARL = B(1) / W(1)
            ARLFIR = 0.0
            DO 110 I = 0, N
               ARLFIR = S0 * ARLFIR + B(N - I + 1) / W(N - I + 1)
  110       CONTINUE
            ARLFIR = ARLFIR * EXP(C * S0)
         END IF
      END IF
      RETURN
      END SUBROUTINE ARL1
      SUBROUTINE ARSCDF(X,CDF)
!
!     NOTE--ARCSIN CDF IS:
!              ARSCDF(X) = (2/PI)*ARCSIN(SQRT(X))  0 < X < 1
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      IF(X.LE.0.0)THEN
        CDF=0.0
      ELSEIF(X.GE.1.0)THEN
        CDF=1.0
      ELSE
        CDF=(2.0/PI)*ASIN(SQRT(X))
      ENDIF
!
      RETURN
      END SUBROUTINE ARSCDF
      SUBROUTINE ARSPDF(X,PDF)
!
!     NOTE--ARCSIN PDF IS:
!              ARSPDF(X) = (1/PI)*(1/SQRT(X*(1-x)))  0 < x < 1
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(X.LE.0.0 .OR. X.GE.1.0)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  301 FORMAT('***** ERROR--THE INPUT ARGUMENT TO ARSPDF IS NOT IN ',  &
             'THE INTERVAL (0,1).')
  302 FORMAT('      IT HAS THE VALUE ',G15.7)
!
      PDF=1.0/(PI*SQRT(X*(1.0-X)))
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE ARSPDF
      SUBROUTINE ARSPPF(P,PPF)
!
!     NOTE--ALGORITHM ADDED SEPTEMBER 1995
!           ARSPPF(P) = (SIN(PI*P/2))**2
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GT.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ARSPPF IS ',   &
             'OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      PPF=SIN(PI*P/2.0)*SIN(PI*P/2.0)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ARSPPF
      SUBROUTINE ARSRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ARCSIN DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE ARCSIN DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ARCSIN RANDOM ',   &
             'NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N ARCSIN RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      CALL ARSPPF(X(I),XTEMP)
      X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ARSRAN
      DOUBLE PRECISION FUNCTION apser(a,b,x,eps)
!-----------------------------------------------------------------------
!     APSER YIELDS THE INCOMPLETE BETA RATIO I(SUB(1-X))(B,A) FOR
!     A .LE. MIN(EPS,EPS*B), B*X .LE. 1, AND X .LE. 0.5. USED WHEN
!     A IS VERY SMALL. USE ONLY IF ABOVE INEQUALITIES ARE SATISFIED.
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,eps,x
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION aj,bx,c,g,j,s,t,tol
!     ..
!     .. External Functions ..
      DOUBLE PRECISION psi
      EXTERNAL psi
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dlog
!     ..
!     .. Data statements ..
!--------------------
      DATA g/.577215664901533D0/
!     ..
!     .. Executable Statements ..
!--------------------
      bx = b*x
      t = x - bx
      IF (b*eps.GT.2.D-2) GO TO 10
      c = dlog(x) + psi(b) + g + t
      GO TO 20
                                                                                                                                  
   10 c = dlog(bx) + g + t
!
   20 tol = 5.0D0*eps*abs(c)
      j = 1.0D0
      s = 0.0D0
   30 j = j + 1.0D0
      t = t* (x-bx/j)
      aj = t/j
      s = s + aj
      IF (abs(aj).GT.tol) GO TO 30
!
      apser = -a* (c+s)
      RETURN
                                                                                                                                  
      END FUNCTION apser
      SUBROUTINE ASCORE(X,N,IWRITE,XSCORE,TEMP1,MAXNXT,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE ANSARI-BRADLEY SCORES
!              OF THE N ELEMENTS OF THE SINGLE PRECISION VECTOR X, AND
!              PUTS THE RESULTING N SCORES INTO THE SINGLE PRECISION
!              VECTOR XSCORE.
!
!              THE ANSARI-BRADLEY SCORES ARE DEFINED AS
!
!                 A(X(i)) = (N+1)/2 - |(R(i) - (N+1)/2|
!
!              WITH R(i) DENOTING THE RANK OF THE i-TH OBSERVATION.
!              ANSARI-BRADLEY SCORES ARE TYPICALLY USED TO TEST
!              FOR EQUAL VARIANCES FOR TWO SAMPLES.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE SCORED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XSCORE = THE SINGLE PRECISION VECTOR INTO WHICH
!                                THE SCORES FROM X WILL BE PLACED.
!     OUTPUT--THE SINGLE PRECISION VECTOR XSCORE CONTAINING THE MOOD
!             SCORES IN THE SINGLE PRECISION VECTOR X.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--RANK
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HIGGINS (2004), "INTRODUCTION TO MODERN NONPARAMETRIC
!                 STATISTICS", DUXBURY ADVANCED SERIES, P. 50.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023.06
!     ORIGINAL VERSION--JUNE      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XSCORE(*)
      DIMENSION TEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='ASCO'
      ISUBN2='RE  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF ASCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,IBUGA3,ISUBRO
   53   FORMAT('N,IBUGA3,ISUBRO = ',I8,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN ANSARI-BRADLEY SCORES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE NUMBER OF OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  GENERATE THE MOOD   SCORES            **
!               ********************************************
!
        CALL RANK(X,N,IWRITE,XSCORE,TEMP1,MAXNXT,IBUGA3,IERROR)
        TERM1=(REAL(N)+1.0)/2.0
        DO 211 K=1,N
          XSCORE(K)=TERM1 - ABS(XSCORE(K) - TERM1)
  211   CONTINUE
!
!
!               ******************************
!               **  STEP 4--                **
!               **  WRITE OUT A FEW LINES   **
!               **  OF SUMMARY INFORMATION  **
!               **  ABOUT THE CODING.       **
!               ******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IINDX=1
        WRITE(ICOUT,912)IINDX,XSCORE(IINDX)
  912   FORMAT('THE ANSARI-BRADLEY SCORE OF ROW ',I10,' = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IINDX=N
        WRITE(ICOUT,912)IINDX,XSCORE(IINDX)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF ASCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)I,X(I),XSCORE(I)
 9016     FORMAT('I,X(I),XSCORE(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE ASCORE
      SUBROUTINE ASYIK (X, FNU, KODE, FLGIK, RA, ARG, IN, Y)
!***BEGIN PROLOGUE  ASYIK
!***SUBSIDIARY
!***PURPOSE  Subsidiary to BESI and BESK
!***LIBRARY   SLATEC
!***TYPE      SINGLE PRECISION (ASYIK-S, DASYIK-D)
!***AUTHOR  Amos, D. E., (SNLA)
!***DESCRIPTION
!
!                    ASYIK computes Bessel functions I and K
!                  for arguments X.GT.0.0 and orders FNU.GE.35
!                  on FLGIK = 1 and FLGIK = -1 respectively.
!
!                                    INPUT
!
!      X    - argument, X.GT.0.0E0
!      FNU  - order of first Bessel function
!      KODE - a parameter to indicate the scaling option
!             KODE=1 returns Y(I)=        I/SUB(FNU+I-1)/(X), I=1,IN
!                    or      Y(I)=        K/SUB(FNU+I-1)/(X), I=1,IN
!                    on FLGIK = 1.0E0 or FLGIK = -1.0E0
!             KODE=2 returns Y(I)=EXP(-X)*I/SUB(FNU+I-1)/(X), I=1,IN
!                    or      Y(I)=EXP( X)*K/SUB(FNU+I-1)/(X), I=1,IN
!                    on FLGIK = 1.0E0 or FLGIK = -1.0E0
!     FLGIK - selection parameter for I or K function
!             FLGIK =  1.0E0 gives the I function
!             FLGIK = -1.0E0 gives the K function
!        RA - SQRT(1.+Z*Z), Z=X/FNU
!       ARG - argument of the leading exponential
!        IN - number of functions desired, IN=1 or 2
!
!                                    OUTPUT
!
!         Y - a vector whose first in components contain the sequence
!
!     Abstract
!         ASYIK implements the uniform asymptotic expansion of
!         the I and K Bessel functions for FNU.GE.35 and real
!         X.GT.0.0E0. The forms are identical except for a change
!         in sign of some of the terms. This change in sign is
!         accomplished by means of the flag FLGIK = 1 or -1.
!
!***SEE ALSO  BESI, BESK
!***ROUTINES CALLED  R1MACH
