       2.31395443148287E-05, 3.62642745856794E-05, 4.58006124490189E-05,   &
       5.24595294959114E-05, 5.68396208545815E-05, 5.94349820393104E-05,   &
       6.06478527578422E-05, 6.08023907788436E-05, 6.01577894539460E-05,   &
       5.89199657344698E-05, 5.72515823777593E-05, 5.52804375585853E-05/
      DATA BETA1(1,1), BETA1(2,1), BETA1(3,1), BETA1(4,1), BETA1(5,1),   &
           BETA1(6,1), BETA1(7,1), BETA1(8,1), BETA1(9,1), BETA1(10,1),   &
           BETA1(11,1),BETA1(12,1),BETA1(13,1),BETA1(14,1),BETA1(15,1),   &
           BETA1(16,1),BETA1(17,1),BETA1(18,1),BETA1(19,1),BETA1(20,1),   &
           BETA1(21,1),BETA1(22,1),BETA1(23,1),BETA1(24,1),BETA1(25,1),   &
           BETA1(26,1)     / 1.79988721413553E-02, 5.59964911064388E-03,   &
       2.88501402231133E-03, 1.80096606761054E-03, 1.24753110589199E-03,   &
       9.22878876572938E-04, 7.14430421727287E-04, 5.71787281789705E-04,   &
       4.69431007606482E-04, 3.93232835462917E-04, 3.34818889318298E-04,   &
       2.88952148495752E-04, 2.52211615549573E-04, 2.22280580798883E-04,   &
       1.97541838033063E-04, 1.76836855019718E-04, 1.59316899661821E-04,   &
       1.44347930197334E-04, 1.31448068119965E-04, 1.20245444949303E-04,   &
       1.10449144504599E-04, 1.01828770740567E-04, 9.41998224204238E-05,   &
       8.74130545753834E-05, 8.13466262162801E-05, 7.59002269646219E-05/
      DATA BETA1(1,2), BETA1(2,2), BETA1(3,2), BETA1(4,2), BETA1(5,2),   &
           BETA1(6,2), BETA1(7,2), BETA1(8,2), BETA1(9,2), BETA1(10,2),   &
           BETA1(11,2),BETA1(12,2),BETA1(13,2),BETA1(14,2),BETA1(15,2),   &
           BETA1(16,2),BETA1(17,2),BETA1(18,2),BETA1(19,2),BETA1(20,2),   &
           BETA1(21,2),BETA1(22,2),BETA1(23,2),BETA1(24,2),BETA1(25,2),   &
           BETA1(26,2)     /-1.49282953213429E-03,-8.78204709546389E-04,   &
      -5.02916549572035E-04,-2.94822138512746E-04,-1.75463996970783E-04,   &
      -1.04008550460816E-04,-5.96141953046458E-05,-3.12038929076098E-05,   &
      -1.26089735980230E-05,-2.42892608575730E-07, 8.05996165414274E-06,   &
       1.36507009262147E-05, 1.73964125472926E-05, 1.98672978842134E-05,   &
       2.14463263790823E-05, 2.23954659232457E-05, 2.28967783814713E-05,   &
       2.30785389811178E-05, 2.30321976080909E-05, 2.28236073720349E-05,   &
       2.25005881105292E-05, 2.20981015361991E-05, 2.16418427448104E-05,   &
       2.11507649256221E-05, 2.06388749782171E-05, 2.01165241997082E-05/
      DATA BETA2(1,1), BETA2(2,1), BETA2(3,1), BETA2(4,1), BETA2(5,1),   &
           BETA2(6,1), BETA2(7,1), BETA2(8,1), BETA2(9,1), BETA2(10,1),   &
           BETA2(11,1),BETA2(12,1),BETA2(13,1),BETA2(14,1),BETA2(15,1),   &
           BETA2(16,1),BETA2(17,1),BETA2(18,1),BETA2(19,1),BETA2(20,1),   &
           BETA2(21,1),BETA2(22,1),BETA2(23,1),BETA2(24,1),BETA2(25,1),   &
           BETA2(26,1)     / 5.52213076721293E-04, 4.47932581552385E-04,   &
       2.79520653992021E-04, 1.52468156198447E-04, 6.93271105657044E-05,   &
       1.76258683069991E-05,-1.35744996343269E-05,-3.17972413350427E-05,   &
      -4.18861861696693E-05,-4.69004889379141E-05,-4.87665447413787E-05,   &
      -4.87010031186735E-05,-4.74755620890087E-05,-4.55813058138628E-05,   &
      -4.33309644511266E-05,-4.09230193157750E-05,-3.84822638603221E-05,   &
      -3.60857167535411E-05,-3.37793306123367E-05,-3.15888560772110E-05,   &
      -2.95269561750807E-05,-2.75978914828336E-05,-2.58006174666884E-05,   &
      -2.41308356761280E-05,-2.25823509518346E-05,-2.11479656768913E-05/
      DATA BETA2(1,2), BETA2(2,2), BETA2(3,2), BETA2(4,2), BETA2(5,2),   &
           BETA2(6,2), BETA2(7,2), BETA2(8,2), BETA2(9,2), BETA2(10,2),   &
           BETA2(11,2),BETA2(12,2),BETA2(13,2),BETA2(14,2),BETA2(15,2),   &
           BETA2(16,2),BETA2(17,2),BETA2(18,2),BETA2(19,2),BETA2(20,2),   &
           BETA2(21,2),BETA2(22,2),BETA2(23,2),BETA2(24,2),BETA2(25,2),   &
           BETA2(26,2)     /-4.74617796559960E-04,-4.77864567147321E-04,   &
      -3.20390228067038E-04,-1.61105016119962E-04,-4.25778101285435E-05,   &
       3.44571294294968E-05, 7.97092684075675E-05, 1.03138236708272E-04,   &
       1.12466775262204E-04, 1.13103642108481E-04, 1.08651634848774E-04,   &
       1.01437951597662E-04, 9.29298396593364E-05, 8.40293133016090E-05,   &
       7.52727991349134E-05, 6.69632521975731E-05, 5.92564547323195E-05,   &
       5.22169308826976E-05, 4.58539485165361E-05, 4.01445513891487E-05,   &
       3.50481730031328E-05, 3.05157995034347E-05, 2.64956119950516E-05,   &
       2.29363633690998E-05, 1.97893056664022E-05, 1.70091984636413E-05/
      DATA BETA3(1,1), BETA3(2,1), BETA3(3,1), BETA3(4,1), BETA3(5,1),   &
           BETA3(6,1), BETA3(7,1), BETA3(8,1), BETA3(9,1), BETA3(10,1),   &
           BETA3(11,1),BETA3(12,1),BETA3(13,1),BETA3(14,1),BETA3(15,1),   &
           BETA3(16,1),BETA3(17,1),BETA3(18,1),BETA3(19,1),BETA3(20,1),   &
           BETA3(21,1),BETA3(22,1),BETA3(23,1),BETA3(24,1),BETA3(25,1),   &
           BETA3(26,1)     / 7.36465810572578E-04, 8.72790805146194E-04,   &
       6.22614862573135E-04, 2.85998154194304E-04, 3.84737672879366E-06,   &
      -1.87906003636972E-04,-2.97603646594555E-04,-3.45998126832656E-04,   &
      -3.53382470916038E-04,-3.35715635775049E-04,-3.04321124789040E-04,   &
      -2.66722723047613E-04,-2.27654214122820E-04,-1.89922611854562E-04,   &
      -1.55058918599094E-04,-1.23778240761874E-04,-9.62926147717644E-05,   &
      -7.25178327714425E-05,-5.22070028895634E-05,-3.50347750511901E-05,   &
      -2.06489761035552E-05,-8.70106096849767E-06, 1.13698686675100E-06,   &
       9.16426474122779E-06, 1.56477785428873E-05, 2.08223629482467E-05/
      DATA GAMA(1),   GAMA(2),   GAMA(3),   GAMA(4),   GAMA(5),   &
           GAMA(6),   GAMA(7),   GAMA(8),   GAMA(9),   GAMA(10),   &
           GAMA(11),  GAMA(12),  GAMA(13),  GAMA(14),  GAMA(15),   &
           GAMA(16),  GAMA(17),  GAMA(18),  GAMA(19),  GAMA(20),   &
           GAMA(21),  GAMA(22),  GAMA(23),  GAMA(24),  GAMA(25),   &
           GAMA(26)        / 6.29960524947437E-01, 2.51984209978975E-01,   &
       1.54790300415656E-01, 1.10713062416159E-01, 8.57309395527395E-02,   &
       6.97161316958684E-02, 5.86085671893714E-02, 5.04698873536311E-02,   &
       4.42600580689155E-02, 3.93720661543510E-02, 3.54283195924455E-02,   &
       3.21818857502098E-02, 2.94646240791158E-02, 2.71581677112934E-02,   &
       2.51768272973862E-02, 2.34570755306079E-02, 2.19508390134907E-02,   &
       2.06210828235646E-02, 1.94388240897881E-02, 1.83810633800683E-02,   &
       1.74293213231963E-02, 1.65685837786612E-02, 1.57865285987918E-02,   &
       1.50729501494096E-02, 1.44193250839955E-02, 1.38184805735342E-02/
!***FIRST EXECUTABLE STATEMENT  ASYJY
      TA = R1MACH(3)
      TOL = MAX(TA,1.0E-15)
      TB = R1MACH(5)
      JU = I1MACH(12)
      IF(FLGJY.EQ.1.0E0) GO TO 6
      JR = I1MACH(11)
      ELIM = -2.303E0*TB*(JU+JR)
      GO TO 7
    6 CONTINUE
      ELIM = -2.303E0*(TB*JU+3.0E0)
    7 CONTINUE
      FN = FNU
      IFLW = 0
      DO 170 JN=1,IN
        XX = X/FN
        WK(1) = 1.0E0 - XX*XX
        ABW2 = ABS(WK(1))
        WK(2) = SQRT(ABW2)
        WK(7) = FN**CON2
        IF (ABW2.GT.0.27750E0) GO TO 80
!
!     ASYMPTOTIC EXPANSION
!     CASES NEAR X=FN, ABS(1.-(X/FN)**2).LE.0.2775
!     COEFFICIENTS OF ASYMPTOTIC EXPANSION BY SERIES
!
!     ZETA AND TRUNCATION FOR A(ZETA) AND B(ZETA) SERIES
!
!     KMAX IS TRUNCATION INDEX FOR A(ZETA) AND B(ZETA) SERIES=MAX(2,SA)
!
        SA = 0.0E0
        IF (ABW2.EQ.0.0E0) GO TO 10
        SA = TOLS/LOG(ABW2)
   10   SB = SA
        DO 20 I=1,5
          AKM = MAX(SA,2.0E0)
          KMAX(I) = INT(AKM)
          SA = SA + SB
   20   CONTINUE
        KB = KMAX(5)
        KLAST = KB - 1
        SA = GAMA(KB)
        DO 30 K=1,KLAST
          KB = KB - 1
          SA = SA*WK(1) + GAMA(KB)
   30   CONTINUE
        Z = WK(1)*SA
        AZ = ABS(Z)
        RTZ = SQRT(AZ)
        WK(3) = CON1*AZ*RTZ
        WK(4) = WK(3)*FN
        WK(5) = RTZ*WK(7)
        WK(6) = -WK(5)*WK(5)
        IF(Z.LE.0.0E0) GO TO 35
        IF(WK(4).GT.ELIM) GO TO 75
        WK(6) = -WK(6)
   35   CONTINUE
        PHI = SQRT(SQRT(SA+SA+SA+SA))
!
!     B(ZETA) FOR S=0
!
        KB = KMAX(5)
        KLAST = KB - 1
        SB = BETA(KB,1)
        DO 40 K=1,KLAST
          KB = KB - 1
          SB = SB*WK(1) + BETA(KB,1)
   40   CONTINUE
        KSP1 = 1
        FN2 = FN*FN
        RFN2 = 1.0E0/FN2
        RDEN = 1.0E0
        ASUM = 1.0E0
        RELB = TOL*ABS(SB)
        BSUM = SB
        DO 60 KS=1,4
          KSP1 = KSP1 + 1
          RDEN = RDEN*RFN2
!
!     A(ZETA) AND B(ZETA) FOR S=1,2,3,4
!
          KSTEMP = 5 - KS
          KB = KMAX(KSTEMP)
          KLAST = KB - 1
          SA = ALFA(KB,KS)
          SB = BETA(KB,KSP1)
          DO 50 K=1,KLAST
            KB = KB - 1
            SA = SA*WK(1) + ALFA(KB,KS)
            SB = SB*WK(1) + BETA(KB,KSP1)
   50     CONTINUE
          TA = SA*RDEN
          TB = SB*RDEN
          ASUM = ASUM + TA
          BSUM = BSUM + TB
          IF (ABS(TA).LE.TOL .AND. ABS(TB).LE.RELB) GO TO 70
   60   CONTINUE
   70   CONTINUE
        BSUM = BSUM/(FN*WK(7))
        GO TO 160
!
   75   CONTINUE
        IFLW = 1
        RETURN
!
   80   CONTINUE
        UPOL(1) = 1.0E0
        TAU = 1.0E0/WK(2)
        T2 = 1.0E0/WK(1)
        IF (WK(1).GE.0.0E0) GO TO 90
!
!     CASES FOR (X/FN).GT.SQRT(1.2775)
!
        WK(3) = ABS(WK(2)-ATAN(WK(2)))
        WK(4) = WK(3)*FN
        RCZ = -CON1/WK(4)
        Z32 = 1.5E0*WK(3)
        RTZ = Z32**CON2
        WK(5) = RTZ*WK(7)
        WK(6) = -WK(5)*WK(5)
        GO TO 100
   90   CONTINUE
!
!     CASES FOR (X/FN).LT.SQRT(0.7225)
!
        WK(3) = ABS(LOG((1.0E0+WK(2))/XX)-WK(2))
        WK(4) = WK(3)*FN
        RCZ = CON1/WK(4)
        IF(WK(4).GT.ELIM) GO TO 75
        Z32 = 1.5E0*WK(3)
        RTZ = Z32**CON2
        WK(7) = FN**CON2
        WK(5) = RTZ*WK(7)
        WK(6) = WK(5)*WK(5)
  100   CONTINUE
        PHI = SQRT((RTZ+RTZ)*TAU)
        TB = 1.0E0
        ASUM = 1.0E0
        TFN = TAU/FN
        RDEN=1.0E0/FN
        RFN2=RDEN*RDEN
        RDEN=1.0E0
        UPOL(2) = (C(1)*T2+C(2))*TFN
        CRZ32 = CON548*RCZ
        BSUM = UPOL(2) + CRZ32
        RELB = TOL*ABS(BSUM)
        AP = TFN
        KS = 0
        KP1 = 2
        RZDEN = RCZ
        L = 2
        ISETA=0
        ISETB=0
        DO 140 LR=2,8,2
!
!     COMPUTE TWO U POLYNOMIALS FOR NEXT A(ZETA) AND B(ZETA)
!
          LRP1 = LR + 1
          DO 120 K=LR,LRP1
            KS = KS + 1
            KP1 = KP1 + 1
            L = L + 1
            S1 = C(L)
            DO 110 J=2,KP1
              L = L + 1
              S1 = S1*T2 + C(L)
  110       CONTINUE
            AP = AP*TFN
            UPOL(KP1) = AP*S1
            CR(KS) = BR(KS)*RZDEN
            RZDEN = RZDEN*RCZ
            DR(KS) = AR(KS)*RZDEN
  120     CONTINUE
          SUMA = UPOL(LRP1)
          SUMB = UPOL(LR+2) + UPOL(LRP1)*CRZ32
          JU = LRP1
          DO 130 JR=1,LR
            JU = JU - 1
            SUMA = SUMA + CR(JR)*UPOL(JU)
            SUMB = SUMB + DR(JR)*UPOL(JU)
  130     CONTINUE
          RDEN=RDEN*RFN2
          TB = -TB
          IF (WK(1).GT.0.0E0) TB = ABS(TB)
          IF (RDEN.LT.TOL) GO TO 131
          ASUM = ASUM + SUMA*TB
          BSUM = BSUM + SUMB*TB
          GO TO 140
  131     IF(ISETA.EQ.1) GO TO 132
          IF(ABS(SUMA).LT.TOL) ISETA=1
          ASUM=ASUM+SUMA*TB
  132     IF(ISETB.EQ.1) GO TO 133
          IF(ABS(SUMB).LT.RELB) ISETB=1
          BSUM=BSUM+SUMB*TB
  133     IF(ISETA.EQ.1 .AND. ISETB.EQ.1) GO TO 150
  140   CONTINUE
  150   TB = WK(5)
        IF (WK(1).GT.0.0E0) TB = -TB
        BSUM = BSUM/TB
!
  160   CONTINUE
        CALL FUNJY(WK(6), WK(5), WK(4), FI, DFI)
        TA=1.0E0/TOL
        TB=R1MACH(1)*TA*1.0E+3
        IF(ABS(FI).GT.TB) GO TO 165
        FI=FI*TA
        DFI=DFI*TA
        PHI=PHI*TOL
  165   CONTINUE
        Y(JN) = FLGJY*PHI*(FI*ASUM+DFI*BSUM)/WK(7)
        FN = FN - FLGJY
  170 CONTINUE
      RETURN
      END SUBROUTINE ASYJY 
      DOUBLE PRECISION FUNCTION ATNINT(XVALUE)
!
! DESCRIPTION:
!
!   The function ATNINT calculates the value of the
!   inverse-tangent integral defined by
!
!       ATNINT(x) = integral 0 to x ( (arctan t)/t ) dt
!
!   The approximation uses Chebyshev series with the coefficients
!   given to an accuracy of 20D.
!
!
! ERROR RETURNS:
!
!   There are no error returns from this program.
!
!
! MACHINE-DEPENDENT CONSTANTS:
!
!   NTERMS - INTEGER - The no. of terms of the array ATNINTT.
!                      The recommended value is such that
!                          ATNINA(NTERMS) < EPS/100
!
!   XLOW - DOUBLE PRECISION - A bound below which ATNINT(x) = x to machine
!                 precision. The recommended value is
!                     sqrt(EPSNEG/2).
!
!   XUPPER - DOUBLE PRECISION - A bound on x, above which, to machine precision
!                   ATNINT(x) = (pi/2)ln x
!                   The recommended value is 1/EPS.
!
!     For values of EPSNEG and EPS for various machine/compiler
!     combinations refer to the text file MACHCON.TXT
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
! INTRINSIC FUNCTIONS USED:
!
!    ABS , LOG
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL ,  D1MACH
!
!
! AUTHOR: Dr. Allan J. MacLeod,
!         Dept. of Mathematics and Statistics,
!         University of Paisley,
!         High St.,
!         PAISLEY
!         SCOTLAND
!
!         (e-mail  macl_ms0@paisley.ac.uk )
!
!
! LATEST MODIFICATION:  23 January, 1996
!
!
!
      INTEGER IND,NTERMS
      DOUBLE PRECISION ATNINA(0:22),CHEVAL,HALF,ONE,ONEHUN,T,TWOBPI,   &
           X,XLOW,XUPPER,XVALUE,ZERO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO,HALF,ONE/0.0D0 , 0.5D0 , 1.0D0/
      DATA ONEHUN/100.0D0/
      DATA TWOBPI/0.63661977236758134308D0/
      DATA ATNINA(0)/  1.91040361296235937512D0/
      DATA ATNINA(1)/ -0.4176351437656746940D-1/
      DATA ATNINA(2)/  0.275392550786367434D-2/
      DATA ATNINA(3)/ -0.25051809526248881D-3/
      DATA ATNINA(4)/  0.2666981285121171D-4/
      DATA ATNINA(5)/ -0.311890514107001D-5/
      DATA ATNINA(6)/  0.38833853132249D-6/
      DATA ATNINA(7)/ -0.5057274584964D-7/
      DATA ATNINA(8)/  0.681225282949D-8/
      DATA ATNINA(9)/ -0.94212561654D-9/
      DATA ATNINA(10)/ 0.13307878816D-9/
      DATA ATNINA(11)/-0.1912678075D-10/
      DATA ATNINA(12)/ 0.278912620D-11/
      DATA ATNINA(13)/-0.41174820D-12/
      DATA ATNINA(14)/ 0.6142987D-13/
      DATA ATNINA(15)/-0.924929D-14/
      DATA ATNINA(16)/ 0.140387D-14/
      DATA ATNINA(17)/-0.21460D-15/
      DATA ATNINA(18)/ 0.3301D-16/
      DATA ATNINA(19)/-0.511D-17/
      DATA ATNINA(20)/ 0.79D-18/
      DATA ATNINA(21)/-0.12D-18/
      DATA ATNINA(22)/ 0.2D-19/
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(4) / ONEHUN
      DO 10 NTERMS = 22 , 0 , -1
         IF ( ABS(ATNINA(NTERMS)) .GT. T ) GO TO  19
 10   CONTINUE
 19   T = D1MACH(3)
      XLOW = SQRT( T / ( ONE + ONE ) )
      XUPPER = ONE / T
!
!   Start calculation
!
      IND = 1
      X = XVALUE
      IF ( X .LT. ZERO ) THEN
         X = -X
         IND = -1
      ENDIF
!
!   Code for X < =  1.0
!
      IF ( X .LE. ONE ) THEN
         IF ( X .LT. XLOW ) THEN
            ATNINT = X
         ELSE
            T = X * X
            T =  ( T - HALF ) + ( T - HALF )
            ATNINT = X * CHEVAL( NTERMS , ATNINA , T )
         ENDIF
      ELSE
!
!   Code for X > 1.0
!
         IF ( X .GT. XUPPER ) THEN
            ATNINT = LOG( X ) / TWOBPI
         ELSE
            T = ONE / ( X * X )
            T =  ( T - HALF ) + ( T - HALF )
            ATNINT = LOG( X ) / TWOBPI + CHEVAL( NTERMS,ATNINA,T ) / X
         ENDIF
      ENDIF
      IF ( IND .LT. 0 ) ATNINT = - ATNINT
      RETURN
      END FUNCTION ATNINT
      SUBROUTINE ATNCDF(X,PHI,ALPHA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE ARCTANGENT DISTRIBUTION
!
!              THIS DISTRIBUTION IS DEFINED FOR X >= 0 AND HAS
!              THE CUMULATIVE DISTRIBUTION FUNCTION
!
!              F(X;PHI,ALPHA) = 1 - ARCTAN(ALPHA*(PHI - X) + PI/2]/
!                               (ARCTAN(ALPHA*PHI) + PI/2)
!                               X >= 0, ALPHA > 0
!
!              NOTE THAT PHI AND ALPHA ARE ANALOGOUS TO LOCATION AND
!              SCALE PARAMETERS.  HOWEVER, THEY ARE NOT TRUE LOCATION
!              AND SCALE PARAMETERS IN THE SENSE THAT
!
!                  F(X;PHI,ALPHA) = F((X-PHI)/ALPHA;0,1)
!
!              DOES NOT HOLD.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --PHI    = THE DOUBLE PRECISION PHASE SHIFT
!                                PARAMETER
!                     --ALPHA  = THE DOUBLE PRECISION SCALING PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ATAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--GLEN AND LEMIS (1997), "THE ARCTANGENT SURVIVAL
!                 DISTRIBUTION", JOURNAL OF QUALITY TECHNOLOGY,
!                 VOL. 29, NO. 2.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--JANUIARY  2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA PI/ 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      CDF=0.0D0
      IF(X.LT.0.0D0)THEN
        CDF=0.0D0
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,2)
    2   FORMAT('***** ERROR--THE SECOND ARGUMENT TO ATNCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
   46   FORMAT('      THE ARGUMENT HAS THE VALUE ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=ATAN(ALPHA*(PHI - X)) + PI/2.0D0
      TERM2=ATAN(ALPHA*PHI) + PI/2.0D0
      CDF=1.0D0 - (TERM1/TERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ATNCDF
      SUBROUTINE ATNHAZ(X,PHI,ALPHA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE ARCTANGENT DISTRIBUTION
!
!              THIS DISTRIBUTION IS DEFINED FOR X >= 0 AND HAS
!              THE HAZARD FUNCTION
!
!              h(X;PHI,ALPHA) = ALPHA/
!                               [ARCTAN(ALPHA*(PHI-X)) + PI/2]*
!                               [1 + ALPHA**2*(X - PHI)**2]
!                               X >= 0, ALPHA > 0
!
!              NOTE THAT PHI AND ALPHA ARE ANALOGOUS TO LOCATION AND
!              SCALE PARAMETERS.  HOWEVER, THEY ARE NOT TRUE LOCATION
!              AND SCALE PARAMETERS IN THE SENSE THAT
!
!                  h(X;PHI,ALPHA) = (1/ALPHA)*h((X-PHI)/ALPHA;0,1)
!
!              DOES NOT HOLD.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --PHI    = THE DOUBLE PRECISION PHASE SHIFT
!                                PARAMETER
!                     --ALPHA  = THE DOUBLE PRECISION SCALING PARAMETER
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION HAZARD FUNCTION VALUE HAZ.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ARCTAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--GLEN AND LEMIS (1997), "THE ARCTANGENT SURVIVAL
!                 DISTRIBUTION", JOURNAL OF QUALITY TECHNOLOGY,
!                 VOL. 29, NO. 2.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--JANUARY  2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA PI/ 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      IF(X.LT.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ATNHAZ IS NEGATIVE.')
    2 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ATNHAZ IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('      THE ARGUMENT HAS THE VALUE ',G15.7)
!
      TERM1=ATAN(ALPHA*(PHI-X)) + PI/2.0D0
      TERM2=1.0D0 + ALPHA**2*(X - PHI)**2
      HAZ=ALPHA/(TERM1*TERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ATNHAZ
      SUBROUTINE ATNPDF(X,PHI,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE ARCTANGENT DISTRIBUTION
!
!              THIS DISTRIBUTION IS DEFINED FOR X >= 0 AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!
!              f(X;PHI,ALPHA) = ALPHA/
!                               [ARCTAN(ALPHA*PHI) + PI/2]*
!                               [1 + ALPHA**2*(X - PHI)**2]
!                               X >= 0, ALPHA > 0
!
!              NOTE THAT PHI AND ALPHA ARE ANALOGOUS TO LOCATION AND
!              SCALE PARAMETERS.  HOWEVER, THEY ARE NOT TRUE LOCATION
!              AND SCALE PARAMETERS IN THE SENSE THAT
!
!                  f(X;PHI,ALPHA) = (1/ALPHA)*f((X-PHI)/ALPHA;0,1)
!
!              DOES NOT HOLD.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --PHI    = THE DOUBLE PRECISION PHASE SHIFT
!                                PARAMETER
!                     --ALPHA  = THE DOUBLE PRECISION SCALING PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY DENSITY
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ARCTAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--GLEN AND LEMIS (1997), "THE ARCTANGENT SURVIVAL
!                 DISTRIBUTION", JOURNAL OF QUALITY TECHNOLOGY,
!                 VOL. 29, NO. 2.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--JANUARY  2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA PI/ 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      IF(X.LT.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ATNPDF IS NEGATIVE.')
    2 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ATNPDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('      THE ARGUMENT HAS THE VALUE ',G15.7)
!
      TERM1=ATAN(ALPHA*PHI) + PI/2.0D0
      TERM2=1.0D0 + ALPHA**2*(X - PHI)**2
      PDF=ALPHA/(TERM1*TERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ATNPDF
      SUBROUTINE ATNPPF(P,PHI,ALPHA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE ARCTANGENT DISTRIBUTION
!
!              THIS DISTRIBUTION IS DEFINED FOR X >= 0 AND HAS
!              THE PERCENT POINT FUNCTION
!
!              G(P;PHI,ALPHA) = PHI + (1/ALPHA)*
!                               TAN((PI/2) - (1 - P)*(ARCTAN(ALPHA*PHI) +
!                               (PI/2))
!                               0 <= P < 1, ALPHA > 0
!
!              NOTE THAT PHI AND ALPHA ARE ANALOGOUS TO LOCATION AND
!              SCALE PARAMETERS.  HOWEVER, THEY ARE NOT TRUE LOCATION
!              AND SCALE PARAMETERS IN THE SENSE THAT
!
!                  G(P;PHI,ALPHA) = PHI * ALPHA*G(P;0,1)
!
!              DOES NOT HOLD.
!
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --PHI    = THE DOUBLE PRECISION PHASE SHIFT
!                                PARAMETER
!                     --ALPHA  = THE DOUBLE PRECISION SCALING PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ATAN, TAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--GLEN AND LEMIS (1997), "THE ARCTANGENT SURVIVAL
!                 DISTRIBUTION", JOURNAL OF QUALITY TECHNOLOGY,
!                 VOL. 29, NO. 2.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--JANUIARY  2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA PI/ 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ATNPPF IS OUTSIDE ',   &
             'THE (0,1] INTERVAL.')
    2 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ATNPPF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('      THE ARGUMENT HAS THE VALUE ',G15.7)
!
      TERM1=(PI/2.0D0) - (1.0D0 - P)*(ATAN(ALPHA*PHI) + (PI/2.0D0))
      TERM2=TAN(TERM1)
      PPF=PHI + (1.0D0/ALPHA)*TERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ATNPPF
      SUBROUTINE ATNRAN(N,PHI,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE ARCTANGENT DISTRIBUTION WITH SHAPE PARAMETERS
!              PHI AND ALPHA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER OF RANDOM
!                                NUMBERS TO BE GENERATED.
!                     --PHI    = THE SINGLE PRECISION PHASE SHIFT
!                                PARAMETER.
!                     --ALPHA  = THE SINGLE PRECISION SCALING PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR (OF DIMENSION
!                                AT LEAST N) INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE ARCTANGENT DISTRIBUTION
!             WITH SHAPE PARAMETERS PHI AND ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, ATNPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--GLEN AND LEMIS (1997), "THE ARCTANGENT SURVIVAL
!                 DISTRIBUTION", JOURNAL OF QUALITY TECHNOLOGY,
!                 VOL. 29, NO. 2.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011.1
!     ORIGINAL VERSION--JANUARY   2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DXOUT
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE NUMBER OF ARCTANGENT RANDOM ',   &
      'NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER ALPHA FOR THE ',   &
      'ARCTANGENT RANDOM NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N ARCTANGENT DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL ATNPPF(DBLE(X(I)),DBLE(PHI),DBLE(ALPHA),DXOUT)
        X(I)=REAL(DXOUT)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE ATNRAN
      SUBROUTINE AUTOCR(X,N,IWRITE,XAUTCR,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE AUTOCORRELATION COEFFICIENT
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE AUTOCORRELATION COEFFICIENT =  THE CORRELATION
!              BETWEEN X(I) AND X(I+1) OVER THE ENTIRE SAMPLE.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XAUTCR = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE AUTOCORRELATION
!                                COEFFICIENT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE AUTOCORRELATION COEFFICIENT.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JENKINS AND WATTS, SPECTRAL ANALYSIS AND
!                 ITS APPLICATIONS, 1968, PAGES 5, 182,
!                 FORMULA 5.3.33
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      1993.CHANGE DEF. TO BJ, 182, 5.3.33
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DDENOM
      DOUBLE PRECISION DSUM12
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='AUTO'
      ISUBN2='CR  '
      IERROR='NO'
!
      DN=0.0D0
      DMEAN=0.0D0
      DSUM12=0.0D0
      DDENOM=0.0D0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF AUTOCR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I10)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *******************************************
!               **  COMPUTE AUTOCORRELATION COEFFICIENT  **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN AUTOCORRELATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      COMPUTED, MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XAUTCR=1.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** NON-FATAL DIAGNOSTIC IN AUTOCR--',
!CCCC1'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XAUTCR=1.0
      GO TO 9000
  139 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE AUTOCORRELATION COEFFICIENT.  **
!               ************************************************
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN JULY 1993
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
        DX=X(I)
        DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
!CCCC THE FOLLOWING SECTION WAS ADDED  JULY 1993
      DSUM=0.0D0
      DO 250 I=1,N
        DX=X(I)
        DSUM=DSUM+(DX-DMEAN)**2
  250 CONTINUE
      DDENOM=DSUM
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN JULY 1993
      NM1=N-1
      DSUM12=0.0D0
      DO 300 I=1,NM1
        IP1=I+1
        DX1=X(I)
        DX2=X(IP1)
        DSUM12=DSUM12+(DX1-DMEAN)*(DX2-DMEAN)
  300 CONTINUE
      XAUTCR=1.0
      IF(DDENOM.GT.0.0D0)XAUTCR=DSUM12/DDENOM
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XAUTCR
  811   FORMAT('THE LAG-ONE AUTOCORRELATION COEFFICIENT OF THE ',   &
               I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF AUTOCR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)DN,DMEAN,DDENOM,DSUM12
 9014   FORMAT('DN,DMEAN,DDENOM,DSUM12 = ',4D15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XAUTCR,IERROR
 9015   FORMAT('XAUTCR,IERROR = ',G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE AUTOCR
      SUBROUTINE AUTOCV(X,N,IWRITE,XAUTCV,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE AUTOCOVARIANCE COEFFICIENT
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE AUTOCOVARIANCE COEFFICIENT =  THE COVARIANCE
!              BETWEEN X(I) AND X(I+1) OVER THE ENTIRE SAMPLE.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XAUTCV = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE AUTOCOVARIANCE
!                                COEFFICIENT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE AUTOCOVARIANCE COEFFICIENT.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JENKINS AND WATTS, SPECTRAL ANALYSIS AND
!                 ITS APPLICATIONS, 1968, PAGES 5, 180,
!                 FORMULA 5.3.25.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --JUNE      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      1993.CHANGE DEF. TO BJ, 180, 5.3.25
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DSUM
!CCCC DOUBLE PRECISION DSUM1
!CCCC DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM12
      DOUBLE PRECISION DMEAN
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='AUTO'
      ISUBN2='CV  '
!
      IERROR='NO'
!
      DN=0.0D0
      DMEAN=0.0D0
      DSUM12=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF AUTOCV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               *******************************************
!               **  COMPUTE AUTOCOVARIANCE  COEFFICIENT  **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN AUTOCV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE AUTOCOVARIANCE COEFFICIENT IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** NON-FATAL DIAGNOSTIC IN AUTOCV--',   &
      'THE SECOND INPUT ARGUMENT (N) HAS THE VALUE 1')
      CALL DPWRST('XXX','BUG ')
      XAUTCV=0.0
      GO TO 9000
  129 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN AUTOCV--',   &
      'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XAUTCV=0.0
      GO TO 9000
  139 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE AUTOCOVARIANCE  COEFFICIENT.  **
!               ************************************************
!
!CCCC THE FOLLOWING SECTION WAS CHANGED JULY 1993
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
!CCCC THE FOLLOWING SECTION WAS CHANGED JULY 1993
      NM1=N-1
      DSUM12=0.0D0
      DO 300 I=1,NM1
      IP1=I+1
      DX1=X(I)
      DX2=X(IP1)
      DSUM12=DSUM12+(DX1-DMEAN)*(DX2-DMEAN)
  300 CONTINUE
      XAUTCV=DSUM12/DN
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XAUTCV
  811 FORMAT('THE LAG-ONE AUTOCOVARIANCE COEFFICIENT OF THE ',   &
      I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF AUTOCV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DN,DMEAN,DSUM12
 9014 FORMAT('DN,DMEAN,DSUM12 = ',3D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XAUTCV
 9015 FORMAT('XAUTCV = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE AUTOCV
      REAL FUNCTION AJV(SNV, ITYPE, GAMMA, DELTA, XLAM, XI, IFAULT)
!START OF AS 100
!
!        ALGORITHM AS 100.1  APPL. STATIST. (1976) VOL.25, P.190
!
!        CONVERTS A STANDARD NORMAL VARIATE (SNV) TO A
!        JOHNSON VARIATE (AJV)
!
      REAL SNV, GAMMA, DELTA, XLAM, XI, V, W, ZERO, HALF, ONE,   &
        ZABS, ZEXP, ZSIGN
!
      DATA ZERO, HALF, ONE /0.0, 0.5, 1.0/
!
      ZABS(W) = ABS(W)
      ZEXP(W) = EXP(W)
      ZSIGN(W, V) = SIGN(W, V)
!
      AJV = ZERO
      IFAULT = 1
      IF (ITYPE .LT. 1 .OR. ITYPE .GT. 4) RETURN
      IFAULT = 0
      GO TO  (10, 20, 30, 40), ITYPE
!
!        SL DISTRIBUTION
!
   10 AJV = XLAM * ZEXP((XLAM * SNV - GAMMA) / DELTA) + XI
      RETURN
!
!        SU DISTRIBUTION
!
   20 W = ZEXP((SNV - GAMMA) / DELTA)
      W = HALF * (W - ONE / W)
      AJV = XLAM * W + XI
      RETURN
!
!        SB DISTRIBUTION
!
   30 W = (SNV - GAMMA) / DELTA
      V = ZEXP(-ZABS(W))
      V = (ONE - V) / (ONE + V)
      AJV = HALF * XLAM * (ZSIGN(V, W) + ONE) + XI
      RETURN
!
!        NORMAL DISTRIBUTION
!
   40 AJV = (SNV - GAMMA) / DELTA
      RETURN
      END FUNCTION AJV
      SUBROUTINE B2INK(X,NX,Y,NY,FCN,LDF,KX,KY,TX,TY,BCOEF,   &
                       WORK,ISPACE,IFLAG)
!***BEGIN PROLOGUE  B2INK
!***DATE WRITTEN   25 MAY 1982
!***REVISION DATE  25 MAY 1982
!***CATEGORY NO.  E1A
!***KEYWORDS  INTERPOLATION, TWO-DIMENSIONS, GRIDDED DATA, SPLINES,
!             PIECEWISE POLYNOMIALS
!***AUTHOR  BOISVERT, RONALD, NBS
!             SCIENTIFIC COMPUTING DIVISION
!             NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!             WASHINGTON, DC 20234
!***PURPOSE  B2INK DETERMINES A PIECEWISE POLYNOMIAL FUNCTION THAT
!            INTERPOLATES TWO-DIMENSIONAL GRIDDED DATA. USERS SPECIFY
!            THE POLYNOMIAL ORDER (DEGREE+1) OF THE INTERPOLANT AND
!            (OPTIONALLY) THE KNOT SEQUENCE.
!***DESCRIPTION
!
!   B2INK determines the parameters of a function that interpolates the
!   two-dimensional gridded data (X(i),Y(j),FCN(i,j)) for i=1,..,NX and
!   j=1,..,NY. The  interpolating  function  and  its  derivatives  may
!   subsequently be evaluated by the function B2VAL.
!
!   The interpolating  function  is  a  piecewise  polynomial  function
!   represented as a tensor product of one-dimensional  B-splines.  The
!   form of this function is
!
!                          NX   NY
!              S(x,y)  =  SUM  SUM  a   U (x) V (y)
!                         i=1  j=1   ij  i     j
!
!   where the functions U(i)  and  V(j)  are  one-dimensional  B-spline
!   basis functions. The coefficients a(i,j) are chosen so that
!
!         S(X(i),Y(j)) = FCN(i,j)   for i=1,..,NX and j=1,..,NY
!
!   Note that  for  each  fixed  value  of  y  S(x,y)  is  a  piecewise
!   polynomial function of x alone, and for each fixed value of x  S(x,
!   y) is a piecewise polynomial function of y alone. In one  dimension
!   a piecewise polynomial may  be  created  by  partitioning  a  given
!   interval into subintervals and defining a distinct polynomial piece
!   on each one. The points where adjacent subintervals meet are called
!   knots. Each of the functions U(i) and V(j)  above  is  a  piecewise
!   polynomial.
!
!   Users of B2INK choose the order (degree+1) of the polynomial pieces
!   used to define the piecewise polynomial in each  of  the  x  and  y
!   directions (KX and KY).  Users  also  may  define  their  own  knot
!   sequence in x and y separately (TX and TY).  If  IFLAG=0,  however,
!   B2INK will choose sequences of knots that  result  in  a  piecewise
!   polynomial interpolant with KX-2 continuous partial derivatives  in
!   x and KY-2 continuous partial derivatives in y. (KX knots are taken
!   near each endpoint, not-a-knot end conditions  are  used,  and  the
!   remaining knots are placed at data points  if  KX  is  even  or  at
!   midpoints between data points if KX is  odd.  The  y  direction  is
!   treated similarly.)
!
!   After a call to B2INK, all  information  necessary  to  define  the
!   interpolating function are contained in the parameters NX, NY,  KX,
!   KY, TX, TY, and BCOEF. These quantities should not be altered until
!   after the last call of the evaluation routine B2VAL.
!
!
!   I N P U T
!   ---------
!
!   X       Real 1D array (size NX)
!           Array of x abcissae. Must be strictly increasing.
!
!   NX      Integer scalar (.GE. 3)
!           Number of x abcissae.
!
!   Y       Real 1D array (size NY)
!           Array of y abcissae. Must be strictly increasing.
!
!   NY      Integer scalar (.GE. 3)
!           Number of y abcissae.
!
!   FCN     Real 2D array (size LDF by NY)
!           Array of function values to interpolate. FCN(I,J) should
!           contain the function value at the point (X(I),Y(J))
!
!   LDF     Integer scalar (.GE. NX)
!           The actual leading dimension of FCN used in the calling
!           calling program.
!
!   KX      Integer scalar (.GE. 2, .LT. NX)
!           The order of spline pieces in x.
!           (Order = polynomial degree + 1)
!
!   KY      Integer scalar (.GE. 2, .LT. NY)
!           The order of spline pieces in y.
!           (Order = polynomial degree + 1)
!
!
!   I N P U T   O R   O U T P U T
!   -----------------------------
!
!   TX      Real 1D array (size NX+KX)
!           The knots in the x direction for the spline interpolant.
!           If IFLAG=0 these are chosen by B2INK.
!           If IFLAG=1 these are specified by the user.
!                      (Must be non-decreasing.)
!
!   TY      Real 1D array (size NY+KY)
!           The knots in the y direction for the spline interpolant.
!           If IFLAG=0 these are chosen by B2INK.
!           If IFLAG=1 these are specified by the user.
!                      (Must be non-decreasing.)
!
!
!   O U T P U T
!   -----------
!
!   BCOEF   Real 2D array (size NX by NY)
!           Array of coefficients of the B-spline interpolant.
!           This may be the same array as FCN.
!
!
!   M I S C E L L A N E O U S
!   -------------------------
!
!   WORK    Real 1D array (size NX*NY + max( 2*KX*(NX+1),
!                                  2*KY*(NY+1) ))
!           Array of working storage.
!
!   IFLAG   Integer scalar.
!           On input:  0 == knot sequence chosen by B2INK
!                      1 == knot sequence chosen by user.
!           On output: 1 == successful execution
!                      2 == IFLAG out of range
!                      3 == NX out of range
!                      4 == KX out of range
!                      5 == X not strictly increasing
!                      6 == TX not non-decreasing
!                      7 == NY out of range
!                      8 == KY out of range
!                      9 == Y not strictly increasing
!                     10 == TY not non-decreasing
!
!***REFERENCES  CARL DE BOOR, A PRACTICAL GUIDE TO SPLINES,
!                 SPRINGER-VERLAG, NEW YORK, 1978.
!               CARL DE BOOR, EFFICIENT COMPUTER MANIPULATION OF TENSOR
!                 PRODUCTS, ACM TRANSACTIONS ON MATHEMATICAL SOFTWARE,
!                 VOL. 5 (1979), PP. 173-182.
!***ROUTINES CALLED  BTPCF,BKNOT
!***END PROLOGUE  B2INK
!
!  ------------
!  DECLARATIONS
!  ------------
!
!  PARAMETERS
!
      INTEGER   &
              NX, NY, LDF, KX, KY, IFLAG
      REAL   &
           X(NX), Y(NY), FCN(LDF,NY), TX(*), TY(*), BCOEF(NX,NY),   &
           WORK(*)
!
!  LOCAL VARIABLES
!
      INTEGER   &
              I, IW, NPK
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!
!  -----------------------
!  CHECK VALIDITY OF INPUT
!  -----------------------
!
!***FIRST EXECUTABLE STATEMENT
      IF ((IFLAG .LT. 0) .OR. (IFLAG .GT. 1))  THEN
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,921)IFLAG
  921    FORMAT('***** FROM B2INK -   IFLAG = ',I2,   &
                ' IS OUT OF RANGE. **')
         CALL DPWRST('XXX','BUG ')
         IFLAG = 2
         GO TO 9999
      ELSE IF (NX .LT. 3) THEN
         IFLAG = 3
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,931)NX
         CALL DPWRST('XXX','BUG ')
  931    FORMAT('***** FROM B2INK -  NX = ',I4,   &
                ' IS OUT OF RANGE. *****')
         GO TO 9999
      ELSE IF (NY .LT. 3) THEN
         IFLAG = 7
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,971)NY
         CALL DPWRST('XXX','BUG ')
  971    FORMAT('***** FROM B2INK - NY = ',I4,   &
                ' IS OUT OF RANGE. ****')
         GO TO 9999
      ELSE IF ((KX .LT. 2) .OR. (KX .GE. NX)) THEN
         IFLAG = 4
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,941)KX
         CALL DPWRST('XXX','BUG ')
  941    FORMAT('***** FROM B2INK - KX = ',I4,   &
                ' IS OUT OF RANGE. *****')
         GO TO 9999
      ELSE IF ((KY .LT. 2) .OR. (KY .GE. NY)) THEN
         IFLAG = 8
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,981)KY
         CALL DPWRST('XXX','BUG ')
  981    FORMAT('***** FROM B2INK - KY = ',I4,   &
                ' IS OUT OF RANGE. *****')
         GO TO 9999
      ELSE
        IVAL1=NX*NY
        IVAL2=2*KX*(NX+1)
        IVAL3=2*KY*(NY+1)
        IVAL=IVAL1 + MAX(IVAL2,IVAL3)
        IF(IVAL.GT.ISPACE)THEN
          IFLAG = 11
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1011)
 1011     FORMAT('***** FROM B2INK - INSUFFICIENT WORK SPACE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1013)IVAL
 1013     FORMAT('      REQUIRED WORK SPACE:  ',I10)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1015)ISPACE
 1015     FORMAT('      AVAILABLE WORK SPACE: ',I10)
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
!
      DO 10 I=2,NX
         IF (X(I) .LE. X(I-1)) THEN
            IFLAG = 5
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,951)
            CALL DPWRST('XXX','BUG ')
  951       FORMAT('***** FROM B2INK - X ARRAY MUST BE STRICTLY ',   &
                   'INCREASING.')
            GO TO 9999
         ENDIF
   10 CONTINUE
!
      DO 20 I=2,NY
         IF (Y(I) .LE. Y(I-1)) THEN
            IFLAG = 9
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,991)
            CALL DPWRST('XXX','BUG ')
  991       FORMAT('***** FROM B2INK - Y ARRAY MUST BE STRICTLY ',   &
                   'INCREASING.')
            GO TO 9999
         ENDIF
   20 CONTINUE
!
      IF (IFLAG .EQ. 0)  GO TO 50
         NPK = NX + KX
         DO 30 I=2,NPK
            IF (TX(I) .LT. TX(I-1)) THEN
               IFLAG = 6
               WRITE(ICOUT,999)
               CALL DPWRST('XXX','BUG ')
               WRITE(ICOUT,961)
               CALL DPWRST('XXX','BUG ')
  961          FORMAT('***** FROM B2INK -   TX ARRAY MUST BE ',   &
                      'NON-DECREASING.')
               GO TO 9999
            ENDIF
   30    CONTINUE
         NPK = NY + KY
         DO 40 I=2,NPK
            IF (TY(I) .LT. TY(I-1)) THEN
               IFLAG = 10
               WRITE(ICOUT,999)
               CALL DPWRST('XXX','BUG ')
               WRITE(ICOUT,1001)
               CALL DPWRST('XXX','BUG ')
 1001          FORMAT('***** FROM B2INK - TY ARRAY MUST BE ',   &
                      'NON-DECREASING. ***')
               GO TO 9999
            ENDIF
   40    CONTINUE
   50 CONTINUE
!
!  ------------
!  CHOOSE KNOTS
!  ------------
!
      IF (IFLAG .NE. 0)  GO TO 100
         CALL BKNOT(X,NX,KX,TX)
         CALL BKNOT(Y,NY,KY,TY)
  100 CONTINUE
!
!  -------------------------------
!  CONSTRUCT B-SPLINE COEFFICIENTS
!  -------------------------------
!
      IFLAG = 1
      IW = NX*NY + 1
      CALL BTPCF(X,NX,FCN,LDF,NY,TX,KX,WORK,WORK(IW))
      CALL BTPCF(Y,NY,WORK,NY,NX,TY,KY,BCOEF,WORK(IW))
      GO TO 9999
!
!  -----
!  EXITS
!  -----
!
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE B2INK
      REAL FUNCTION B2VAL(XVAL,YVAL,IDX,IDY,TX,TY,NX,NY,   &
        KX,KY,BCOEF,WORK)
!***BEGIN PROLOGUE  B2VAL
!***DATE WRITTEN   25 MAY 1982
!***REVISION DATE  25 MAY 1982
!***CATEGORY NO.  E1A
!***KEYWORDS  INTERPOLATION, TWO-DIMENSIONS, GRIDDED DATA, SPLINES,
!             PIECEWISE POLYNOMIALS
!***AUTHOR  BOISVERT, RONALD, NBS
!             SCIENTIFIC COMPUTING DIVISION
!             NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!             WASHINGTON, DC 20234
!***PURPOSE  B2VAL EVALUATES THE PIECEWISE POLYNOMIAL INTERPOLATING
!            FUNCTION CONSTRUCTED BY THE ROUTINE B2INK OR ONE OF ITS
!            PARTIAL DERIVATIVES.
!***DESCRIPTION
!
!   B2VAL evaluates the tensor product piecewise polynomial interpolant
!   constructed by the routine B2INK or one of its derivatives  at  the
!   point (XVAL,YVAL). To evaluate the interpolant itself, set IDX=IDY=
!   0, to evaluate the first partial with respect to x, set  IDX=1,IDY=
!   0, and so on.
!
!   B2VAL returns 0.0E0 if (XVAL,YVAL) is out of range. That is, if
!            XVAL.LT.TX(1) .OR. XVAL.GT.TX(NX+KX) .OR.
!            YVAL.LT.TY(1) .OR. YVAL.GT.TY(NY+NY)
!   If the knots  TX  and  TY  were  chosen  by  B2INK,  then  this  is
!   equivalent to
!            XVAL.LT.X(1) .OR. XVAL.GT.X(NX)+EPSX .OR.
!            YVAL.LT.Y(1) .OR. YVAL.GT.Y(NY)+EPSY
!   where EPSX = 0.1*(X(NX)-X(NX-1)) and EPSY = 0.1*(Y(NY)-Y(NY-1)).
!
!   The input quantities TX, TY, NX, NY, KX, KY, and  BCOEF  should  be
!   unchanged since the last call of B2INK.
!
!
!   I N P U T
!   ---------
!
!   XVAL    Real scalar
!           X coordinate of evaluation point.
!
!   YVAL    Real scalar
!           Y coordinate of evaluation point.
!
!   IDX     Integer scalar
!           X derivative of piecewise polynomial to evaluate.
!
!   IDY     Integer scalar
!           Y derivative of piecewise polynomial to evaluate.
!
!   TX      Real 1D array (size NX+KX)
!           Sequence of knots defining the piecewise polynomial in
!           the x direction.  (Same as in last call to B2INK.)
!
!   TY      Real 1D array (size NY+KY)
!           Sequence of knots defining the piecewise polynomial in
!           the y direction.  (Same as in last call to B2INK.)
!
!   NX      Integer scalar
!           The number of interpolation points in x.
!           (Same as in last call to B2INK.)
!
!   NY      Integer scalar
!           The number of interpolation points in y.
!           (Same as in last call to B2INK.)
!
!   KX      Integer scalar
!           Order of polynomial pieces in x.
!           (Same as in last call to B2INK.)
!
!   KY      Integer scalar
!           Order of polynomial pieces in y.
!           (Same as in last call to B2INK.)
!
!   BCOEF   Real 2D array (size NX by NY)
!           The B-spline coefficients computed by B2INK.
!
!   WORK    Real 1D array (size 3*max(KX,KY) + KY)
!           A working storage array.
!
!***REFERENCES  CARL DE BOOR, A PRACTICAL GUIDE TO SPLINES,
!                 SPRINGER-VERLAG, NEW YORK, 1978.
!***ROUTINES CALLED  INTRV,BVALU
!***END PROLOGUE  B2VAL
!
!  ------------
!  DECLARATIONS
!  ------------
!
!  PARAMETERS
!
      INTEGER   &
              IDX, IDY, NX, NY, KX, KY
      REAL   &
           XVAL, YVAL, TX(*), TY(*), BCOEF(NX,NY), WORK(*)
!
!  LOCAL VARIABLES
!
      INTEGER   &
              ILOY, INBVX, INBV, K, LEFTY, MFLAG, KCOL, IW
      REAL   &
           BVALU
!
      DATA ILOY /1/,  INBVX /1/
!     SAVE ILOY    ,  INBVX
!
!
!***FIRST EXECUTABLE STATEMENT
      B2VAL = 0.0E0
      CALL INTRV(TY,NY+KY,YVAL,ILOY,LEFTY,MFLAG)
      IF (MFLAG .NE. 0)  GO TO 100
         IW = KY + 1
         KCOL = LEFTY - KY
         DO 50 K=1,KY
            KCOL = KCOL + 1
            WORK(K) = BVALU(TX,BCOEF(1,KCOL),NX,KX,IDX,XVAL,INBVX,   &
                            WORK(IW))
   50    CONTINUE
         INBV = 1
         KCOL = LEFTY - KY + 1
         B2VAL = BVALU(TY(KCOL),WORK,KY,KY,IDY,YVAL,INBV,WORK(IW))
  100 CONTINUE
      RETURN
      END FUNCTION B2VAL
      SUBROUTINE BACK25(X2,M,N,RIGHT2,B,IBUGA3)
!
!     PURPOSE--BACK SOLVE A TRIANGULARIZED SYSTEM
!     WHICH (IT IS ASSUMED) HAS BEEN TRIANGULARIZED
!     AND RESIDES IN THE UPPER TRIANGLE OF X2(.,.)
!     AND THE RESPONSE VECTOR HAS BEEN CARRIED ALONG
!     AND THE MODIFIED RESPONSE VECTOR NOW RESIDES IN
!     THE (N+1)ST COLUMN OF X
!     NOTE--A CALL TO BACK25 IS TYPICALLY
!           PRECEEDED BY A CALL TO TRIA25
!           WHICH WILL CARRY OUT THE
!           TRIANGULARIZATION OF THE MATRIX.
!     NOTE--THE DIMENSIONS OF X2 MUST BE THE SAME
!           IN THE CALLING ROUTINE AS IN THIS SUBROUTINE.
!           THEY HAVE BEEN SET HEREIN TO 25 BY 25,
!           AND HENCE THE 25 IN THE NAME OF THIS SUBROUTINE (BACK25).
!     NOTE--BACK25 IS IDENTICAL TO BACK50 AND BACKSO
!           EXCEPT FOR THE DIMENSIONS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--FEBRUARY  1978.
!     UPDATED         --JULY      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X2(25,25)
      DIMENSION RIGHT2(*)
      DIMENSION B(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BACK'
      ISUBN2='25  '
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF BACK25--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)M,N,IBUGA3
   52 FORMAT('M,N,IBUGA3 = ',2I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,M
      WRITE(ICOUT,56)I,(X2(I,J),J=1,N)
   56 FORMAT('I,X2(I,.)  = ',I8,10E10.3)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
      DO 60 I=1,M
      WRITE(ICOUT,61)I,RIGHT2(I)
   61 FORMAT('I,RIGHT2(I)= ',I8,E10.3)
      CALL DPWRST('XXX','BUG ')
   60 CONTINUE
   90 CONTINUE
!
      I=M
  100 CONTINUE
      SUM=0.0
      IP1=I+1
      IF(IP1.GT.M)GO TO 250
      DO 200 J=IP1,M
      SUM=SUM+B(J)*X2(I,J)
  200 CONTINUE
  250 CONTINUE
      DEL=RIGHT2(I)-SUM
      B(I)=DEL/X2(I,I)
      I=I-1
      IF(I.GE.1)GO TO 100
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF BACK25--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)M,N,IBUGA3
 9012 FORMAT('M,N,IBUGA3 = ',2I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,M
      WRITE(ICOUT,9016)I,(X2(I,J),J=1,N)
 9016 FORMAT('I,X2(I,.)  = ',I8,10E10.3)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
      DO 9020 I=1,M
      WRITE(ICOUT,9021)I,RIGHT2(I),B(I)
 9021 FORMAT('I,RIGHT2(I),B(I) = ',I8,2E10.3)
      CALL DPWRST('XXX','BUG ')
 9020 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE BACK25
