      SUBROUTINE BESICF(ZZ,AA,NMAX,BI)
! THIS ROUTINE CALCULATES BESSEL FUNCTIONS I OF COMPLEX ARGUMENT AND
! REAL ORDER.  ARGUMENTS ARE AS FOR BESJCF, EXCEPT THAT HERE, IT IS REAL
! PART OF ZZ THAT MUST NOT EXCEED EXPARG IN ABSOLUTE VALUE
! EQUATION 9.6.3 OF REFERENCE 1 AS LISTED IN BESJCF IS USED
      COMPLEX ZZ,BI(*),BB,CC,ZDUMMY
!
! Definition of real and imaginary parts of complex number,
! standard Fortran and will work on Convex with -r8 -i8.
!CCCC REALP(ZDUMMY) = REAL(ZDUMMY)
      AIMAGP(ZDUMMY) = REAL((0,-1)*ZDUMMY)
!
      CC=(0.,1.)
      IF(AIMAGP(ZZ).LT.0.) CC=-CC
      BB=-CC*ZZ
      CALL BESJCF(BB,AA,NMAX,BI)
      ANGLE= 1.5707963267949*AA*AIMAGP(CC)
      BB=CMPLX(COS(ANGLE),SIN(ANGLE))
      BI(1)=-CC*BB*BI(1)
      MAXP=NMAX+2
      DO 1 N=2,MAXP
        BI(N)=BI(N)*BB
        BB=CC*BB
    1 CONTINUE
      RETURN
      END SUBROUTINE BESICF
      SUBROUTINE BESJCF(ZZ,AA,NMAX,BJ)
! THIS ROUTINE CALCULATES BESSEL FUNCTIONS J OF COMPLEX ARGUMENT AND
! REAL ORDER
! ROUTINE WRITTEN AND TESTED BY DAVID SAGIN (SOOKNE), COMPUTER CENTER,
! TEL-AVIV UNIVERSITY.  ROUTINE DATED 3/3/77
!
! DESCRIPTION OF VARIABLES IN THE CALLING VECTOR
!
! ZZ   COMPLEX ARGUMENT. LIMITATIONS ARE  ABS(AIMAG(ZZ)).LT.EXPARG (SEE
!      BELOW), AND ZZ*CONJG(ZZ) NOT ZERO IN THE COMPUTER
! AA   FRACTIONAL PART OF REAL ORDER FOR WHICH J*S AND/OR Y*S ARE TO BE
!      CALCULATED.  AA MUST BE GREATER THAN -.5 AND AT MOST +.5.
! NMAX NON-NEGATIVE INTEGER SUCH THAT NMAX+AA IS THE HIGHEST ORDER YOU
!      WANT.
! BJ   COMPLEX VECTOR OF LENGTH NMAX+2, IN
!      WHICH BESLCF RETURNS J*S OF ORDERS AA-1, AA, AA+1,...AA+NMAX.
!
! NUMBERS IN PARENTHESES (IN COMMENT CARDS BELOW) REFER TO THESE
! REFERENCES
! 1) MILTON ABRAMOWITZ AND IRENE A. STEGUN, HANDBOOK OF MATHEMATICAL
!    FUNCTIONS, NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY, 1964
! 2) M. GOLDSTEIN AND R. M. THALER, RECURRENCE TECHNIQUES FOR THE CALCU-
!    LATION OF BESSEL FUNCTIONS, MATHEMATICS OF COMPUTATION, VOLUME 13,
!    APRIL 1959, PAGE 102
! 3) F. W. J. OLVER AND D. J. SOOKNE, NOTE ON BACKWARD RECURRENCE ALGO-
!    RITHMS, MATHEMATICS OF COMPUTATION, VOLUME 26, OCT. 1972, PAGE 941
! 4) DAVID J. SOOKNE, BESSEL FUNCTIONS OF COMPLEX ARGUMENT AND INTEGER
!    ORDER, JOURNAL OF RESEARCH OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY,
!    SERIES B, VOLUME 77A, JULY-DEC. 1973, PAGE 111
! 5) A. ERDELYI ET AL., HIGHER TRANSCENDENTAL FUNCTIONS, VOLUME 2
!    CHAPTER 7, MCGRAW-HILL, NEW YORK, 1953
!
!  NOTE.
!     THIS ROUTINE CALLS A FUNCTION GAM1(X) WHICH RETURNS THE GAMMA
!     FUNCTION OF X FOR POSITIVE X .LE. GAML. SEE THE DEFINITION OF
!     GAML UNDER MACHINE DEPENDENT CONSTANTS BELOW.
!
!
!-----COMMON----------------------------------------------------------
!
      DOUBLE PRECISION DGAMMA
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      COMPLEX BJ(*),B,BA1,BB,BBB,BD,FAC,SUM,Z,ZI,ZP,ZZ,ZDUMMY
! Note: Old variable LOG changed to LOGICL by D.W. Lozier, 4/27/88, to
! avoid conflict with generic function.
      LOGICAL LOGICL(4)
!-----------------------------------------------------------------------
!
!  MACHINE DEPENDENT CONSTANTS.
!  ---------------------------
!
      SAVE ISAVE, SQRTPI, DYOUK, EXPARG, GAML, LOU
      DATA ISAVE /1/
!
! Definition of real and imaginary parts of complex number,
! standard Fortran and will work on Convex with -r8 -i8.
      REALP(ZDUMMY) = REAL(ZDUMMY)
      AIMAGP(ZDUMMY) = REAL((0,-1)*ZDUMMY)
!
      IF (ISAVE.GT.0) THEN
        ISAVE = 0
! SQUARE ROOT OF PI, MACHINE ACCURACY, AND LIMIT ON ARGUMENT TO EXP
        SQRTPI = SQRT (4.0*ATAN (1.0))
        DYOUK = R1MACH (4)
        EXPARG = LOG (R1MACH (2))
! GAML IS AN INTEGER (PREFERABLY THE SMALLEST) SUCH THAT
! 1./(1680*LGAMMA(GAML)*GAML**7).LE.DYOUK.   SEE FORMULA 6.1.41 OF (1)
! Note: Code changed 4/27/88 by D.W. Lozier to prevent integer overflow.
! Previously, an integer factorial was formed, then the log was taken.
! In IEEE double precision, GAML=32 and i! overflows, causing the old
! code to fail.
        I = 2
        GAMLF = LOG(2.0)
    6   I = I + 1
        GAML = I
        GAMLF = GAMLF + LOG(GAML)
        IF ((1680.0*GAMLF*(GAML**7)*DYOUK) .LT. 1.0) GO TO 6
        LOU = I1MACH(2)
      ENDIF
!
!-----------------------------------------------------------------------
      Z=ZZ
      A=AA
      N=NMAX
      E=REALP(Z)**2+AIMAGP(Z)**2
! CHECK THAT INPUT DATA IS LEGAL
      IF ((A .LE. -0.5) .OR. (A .GT. 0.5) .OR.   &
        (ABS(AIMAGP(Z)) .GT. EXPARG) .OR. (E .EQ. 0.) .OR. (N .LT. 0))   &
        GO TO 86
      MAXN=N
      MAXP=2+MAXN
! AVOID UNDERFLOW OR OVERFLOW IN COMPLEX DIVIDE
      F=1./MAX(ABS(REALP(Z)),ABS(AIMAGP(Z)))
      ZI=2.*F/(Z*F)
      BD=LOG(.5*Z)
      ZP=EXP(A*BD)
      BBB=ZP/REAL(DGAMMA(DBLE(1.+A)))
      LOGICL(1)=MAXN.LE.0
      LOGICL(3)=E.LE.DYOUK
      LOGICL(4)=A.EQ.0.
      FAC = (1.0, 0.0)
      IF(LOGICL(3)) GO TO 72
! ROUTINE BACALC RETURNS N AND B (=J-SUB(N+A)OF-X) WITH WHICH TO START
! CALCULATING J*S VIA BACK RECURSION
      CALL BACKLC(Z,A,N,B)
      K=(N+1)/2
      IF(N.LE.MAXN) GO TO 80
!
! INITIALIZE VARIABLES FOR THE BACK-RECURSION.  COEF IS THE COEFFICIENT
! OF THE NORMALIZATION SUM, AND FAC IS USED IN CALCULATING THE NORMALI-
! ZATION FACTOR.  THESE ARE CALCULATED VIA EQUATION 44 OF CHAPTER 7.15
! OF (5) IF A.NE.0.  IN THIS CASE, COS(PHI) IS ZERO OR 1 DEPENDING ON
! WHETHER ABS(COS(Z)) IS LESS THAN 1 OR GREATER THAN 1 RESPECTIVELY.
! IF A.EQ.0, THE NORMALIZATION IS VIA EQUATION 9.1.46 OR 9.1.47 OF (1),
! DEPENDING OR COS(Z).
!
    8 COEF=2.
      KD=1
      BB=COS(Z)
      LOGICL(2)=.FALSE.
      IF(ABS(BB).LE.1.) GO TO 11
      KD=2
      FAC=BB
      LOGICL(2)=.TRUE.
   11 IF(LOGICL(4)) GO TO 14
      D=REAL(KD*K)
      G=A*REAL(KD)
      C=D+G
      F=2.+A/REAL(K)
      IF(LOGICL(2)) F=F*SQRTPI/(REAL(DGAMMA(DBLE(A+.5)))*2.**(2.*A))
      IF(C.GT.GAML) GO TO 12
      COEF=F*REAL(DGAMMA(DBLE(C)))/REAL(DGAMMA(DBLE(D)))
      GO TO 14
   12 E=C*D
      COEF=(D-.5)*LOG(C/D)+G*(LOG(C)-1.-   &
      (1.-(C*C+E+D*D-(C**4+C*C*E+E*E+D*D*E+D**4)/(3.5*E*E))/(30.*E*E))   &
      /(12.*E))
      COEF=F*EXP(COEF)
   14 BB = (0.0, 0.0)
      SUM = (0.0, 0.0)
      G=1.
      IF(LOGICL(2).AND.K.NE.2*(K/2)) COEF=-COEF
      LOGICL(3)=2*K.NE.N
      IF(LOGICL(3)) GO TO 20
      SUM=COEF*B
! USING 9.1.27 OF (1) (EQUATION 1 OF (4) IS THE ANALOG FOR INTEGER
! ORDERS), CALCULATE UNNORMALIZED J*S OF ORDERS N-1+A, N-2+A,...A.
! ACCUMULATE THE NORMALIZATION SUM AS DESCRIBED ABOVE.
   20 E=REAL(N)+A
      N=N-1
      BBB=BB
      BB=B
      B=(ZI*E)*BB-BBB
      IF(LOGICL(1)) GO TO 22
      IF(N.LE.MAXN) BJ(N+2)=B
   22 LOGICL(3)=.NOT.LOGICL(3)
      IF(LOGICL(3)) GO TO 20
      D=REAL(K)
      K=K-1
      F=REAL(K)+A
      IF(LOGICL(4)) GO TO 24
      G=D*(REAL(N)+A)/(F*(E+1.))
      COEF=COEF*G
      IF(LOGICL(2)) COEF=COEF*REAL(N+1)/(2.*F+1.)
   24 IF(LOGICL(2)) COEF=-COEF
      IF(N.EQ.0) GO TO 28
      SUM=SUM+COEF*B
      GO TO 20
   28 BA1=(ZI*A)*B-BB
      IF(LOGICL(4)) COEF=1.
! THE BACK-RECURSION IS FINISHED.  CALCULATE THE NORMALIZATION FACTOR
      SUM=SUM+COEF*B
      F=1./MAX(ABS(REALP(SUM)),ABS(AIMAGP(SUM)))
      FAC=ZP*(F*(FAC/(CMPLX(REALP(SUM)*F,AIMAGP(SUM)*F))))
      BJ(1)=BA1*FAC
      BJ(2)=B*FAC
      IF(MAXN.EQ.0) GO TO 70
      DO 34 M=3,MAXP
        BJ(M)=FAC*BJ(M)
   34 CONTINUE
!
! THIS IS THE ONLY RETURN STATEMENT IN THE ROUTINE
!
   70 CONTINUE
      RETURN
!
! FOR VERY SMALL Z, CALCULATE J*S VIA ASYMPTOTIC FORMULA 9.1.7 OF (1)
!
   72 CONTINUE
      BJ(2)=BBB
      BB=(Z*BJ(2))*(.5/(1.+A))
      BJ(1)=-BB
      IF(.NOT.LOGICL(4)) BJ(1)=(ZI*BJ(2))*AA
      IF(MAXP.GE.3) BJ(3)=BB
      IF(MAXP.LT.4) GO TO 70
      DO 74 N=4,MAXP
        BJ(N)=(Z*BJ(N-1))*(.5/(A+REAL(N-2)))
   74 CONTINUE
      GO TO 70
! UNDERFLOW. SET J*S ZERO
   80 CONTINUE
      DO 81 M=N,MAXN
        BJ(M + 2) = (0.0, 0.0)
   81 CONTINUE
      BJ(N+2)=B
      GO TO 8
! CONK OUT
   86 CONTINUE
      WRITE (ICOUT, 88)
      CALL DPWRST('XXX','BUG ')
      WRITE (ICOUT, 89) N, A, Z
      CALL DPWRST('XXX','BUG ')
   88 FORMAT('***** FATAL ERROR (BESJCF) --- INVALID INPUT ')
   89 FORMAT('      NMAX = ',I6,' A = ',1PE22.14,' Z = ',2(1PE22.14))
      RETURN
      END SUBROUTINE BESJCF
      SUBROUTINE BESKCF(ZZ,AA,NMAX,BK)
! THIS ROUTINE CALCULATES BESSEL FUNCTIONS K OF COMPLEX ARGUMENT AND
! REAL ORDER.  ARGUMENTS ARE AS FOR ROUTINE BESJCF, EXCEPT HERE IT IS
! REAL(ZZ) WHICH MUST NOT EXCEED EXPARG IN ABSOLUTE VALUE
! K*S ARE CALCULATED BY FORWARD RECURSION, USING EQUATION 1.9 OF THE
! REFERENCE LISTED IN ROUTINE RECIPG.  TO START THE RECURSION, FUNCTION
! VALUES OF ORDERS A AND A+1 ARE CALCULATED IF A.LE.0, WHILE ORDERS A
! AND A-1 ARE CALCULATED IF A.GT.0.
! NOTE  IF ANY K-VALUE IS SO BIG THAT ITS CALCULATION WOULD CAUSE OVER-
! FLOW, IT (AND ALL HIGHER ORDERS) ARE SET TO ZERO.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      COMPLEX AK(21),AK1(21),BK(*),BB,CC,DD,EE,FF,GG,HH,PP,QQ,SS,Z,ZINV,   &
       ZZ,RR,ZDUMMY
!-----------------------------------------------------------------------
!
!  MACHINE DEPENDENT CONSTANTS.
!  ---------------------------
!
! MACHINE-DEPENDENT CONSTANTS ARE EXPLAINED IN
! ROUTINES BESJCF, BACKLC, AND BESYCF.
!
      SAVE ISAVE,PI,SQRTPI,GADOL,EXPARG,DYOUK,DYOUKH,NTERM,DYOUKI,LOU
      DATA ISAVE /1/
!
! Definition of real and imaginary parts of complex number,
! standard Fortran and will work on Convex with -r8 -i8.
      REALP(ZDUMMY) = REAL(ZDUMMY)
      AIMAGP(ZDUMMY) = REAL((0,-1)*ZDUMMY)
!
      IF (ISAVE.GT.0) THEN
        ISAVE = 0
        PI = 4.0*ATAN (1.0)
        SQRTPI = SQRT (PI)
        GADOL = R1MACH (2)
        EXPARG = LOG (GADOL)
        DYOUK = R1MACH (4)
        DYOUKH = SQRT (DYOUK)
        NTERM = 20
        DYOUKI = 1.0 / DYOUK
        LOU = I1MACH(2)
      ENDIF
!
!-----------------------------------------------------------------------
      Z=ZZ
      A=AA
      MAXP=NMAX+2
      Q=ABS(REALP(Z))
      E=Q*Q+AIMAGP(Z)**2
      IF ((A .LE. - 0.5) .OR. (A .GT. 0.5) .OR. (MAXP .LT. 2) .OR.   &
         (E .EQ. 0.0) .OR. (Q .GT. EXPARG)) GO TO 86
      F=SQRT(E)
      BIG=GADOL*MIN(.25,F/REAL(4*MAX(1,NMAX)))
! AVOID UNDERFLOW OR OVERFLOW IN COMPLEX DIVIDE
      F=1./F
      ZINV=2.*F/(Z*F)
      IF(A.EQ..5.OR.E.GE.196.) GO TO 30
      IF(E.GE.9.) GO TO 20
! FOR SMALL Z, CALCULATE K*S VIA EQUATIONS 2.1 OF THE REFERENCE LISTED
! IN ROUTINE RECIPG
      BB=.5*Z
      DD=-LOG(BB)
      EE=A*DD
      C=1.
      IF(PI*ABS(A).GT.DYOUKH) C=PI*A/SIN(PI*A)
      SS = (1.0, 0.0)
      IF ((REALP (EE) ** 2 + AIMAGP (EE) ** 2) .GT. DYOUK)   &
         SS = CMPLX (0.0, - 1.0) * SIN (CMPLX (0., 1.0) * EE) / EE
      EE=EXP(EE)
      CALL RECIPG(A,P,Q,G)
      GG=G*EE
      EE=.5*(EE+1./EE)
      FF=C*(P*EE+Q*SS*DD)
      E=A*A
      PP=.5*C*GG
      QQ=.5/GG
      CC = (1.0, 0.0)
      DD=BB*BB
      AK(1)=FF
! IF A.GT.0, CALCULATE KSUB(A-1) BY SUBSTITUTING EQUATIONS 2.1 AND 2.9
! INTO 1.9
      AK1(1)=PP
! IF A.LE.0, CALCULATE KSUB(A+1) VIA 2.9
      IF(A.GT.0.) AK1(1)=QQ
      TEST=DYOUK*MAX(ABS(REALP(AK(1))),ABS(AIMAGP(AK(1))))
      DO 10 N=1,NTERM
      EN=N
      G=1./(EN*EN-E)
      IF(A.GT.0.) GO TO 6
      HH=-G*(EN*(EN*FF+QQ)-A*PP)
      GO TO 8
    6 CONTINUE
      HH=-G*(EN*(EN*FF+PP)+A*QQ)
    8 CONTINUE
      FF=G*(EN*FF+PP+QQ)
      CC=CC*DD/EN
      AK(N+1) =CC*FF
      AK1(N+1)=CC*HH
      IF(MAX(ABS(REALP(AK(N+1))),ABS(AIMAGP(AK(N+1)))).LE.TEST) GO TO 12
      PP=PP/(EN-A)
      QQ=QQ/(EN+A)
   10 CONTINUE
      RETURN
   12 N=N+1
      M=N+1
      GG = (0.0, 0.0)
      HH = (0.0, 0.0)
      DO 14 L=1,N
         ITEMP = M - L
         GG=GG+AK(ITEMP)
         HH=HH+AK1(ITEMP)
   14 CONTINUE
      BK(2)=GG
      BK(1)=HH*ZINV
      GO TO 40
! FOR ABS(Z) BETWEEN 3 AND 14, CALCULATE K*S VIA THE ALGORITHM GIVEN
! IN SECTION 3 OF THE REFERENCE.  THE ALGORITHM IS GIVEN FOR REAL Z, BUT
! CAN BE USED WHEN THE REAL PART OF Z IS NON-NEGATIVE.
   20 CONTINUE
      TEST=DYOUKI*COS(A*PI)/(E*PI)
      E=1.
      PP = (1.0, 0.0)
      QQ = (0.0, 0.0)
      FF=Z
      IF(REALP(Z).LT.0.) FF=-Z
      C=.25-A*A
      DO 22 N=1,99
      AN=(REAL(N*N-N)+C)/REAL(N*N+N)
      E=E*AN
      EN=1./REAL(N+1)
      BB=2.*EN*(REAL(N)+FF)
      RR=QQ
      QQ=PP
      PP=BB*QQ-AN*RR
      IF(MAX(ABS(REALP(PP)),ABS(AIMAGP(PP))).GE.EN*TEST) GO TO 23
   22 CONTINUE
      RETURN
   23 CONTINUE
      PP=E/PP
      QQ = (0.0, 0.0)
      EE=PP
      M=N
      N=N+1
      DO 25 L=1,M
      N=N-1
      RR=QQ
      QQ=PP
      AINV=REAL(N*N+N)/(REAL(N*N-N)+C)
      BB=2.*(REAL(N)+FF)/REAL(N+1)
      PP=(BB*QQ-RR)*AINV
      EE=EE+PP
   25 CONTINUE
      BB=LOG(2.*FF)
      GG=EXP(-BB*(A+.5))/EE
      BK(2)=SQRTPI*EXP(A*BB-FF)*GG*PP
      E=A
      IF(A.GT.0.) E=-A
      BK(1)=.5*BK(2)*(FF-QQ/PP+(.5+E))*ZINV
      IF(REALP(Z).GE.0.) GO TO 40
! REAL(Z) IS NEGATIVE, SO USE EQUATION 9.6.31 OF REFERENCE (1) OF BESJCF
      BK(1)=-BK(1)
   26 ZINV=-ZINV
      HH=BK(1)
      GG=BK(2)
      QQ=HH
      IF(A.GT.0.) HH=QQ+A*(ZINV*GG)
      IF(A.LE.0.) QQ=HH-A*(ZINV*GG)
! NOW QQ, GG, HH ARE FUNCTIONS K OF ARGUMENT (-Z) AND ORDER A-1, A, A+1
      CALL BESICF(FF,A,NMAX,BK)
      E=1.
      IF(AIMAGP(Z).GE.0.) E=-1.
      DD=CMPLX(0.,E)
      E=-E*PI
      EE=CMPLX(0.,E)
      E=-E*A
      IF(A.NE..5) DD=CMPLX(COS(E),SIN(E))
      BK(1)=-DD*QQ-EE*BK(1)
      BK(2)=DD*GG-EE*BK(2)
      IF(MAXP.LE.2) GO TO 70
      DD=-DD
      BK(3)=DD*HH-EE*BK(3)
      IF(MAXP.EQ.3) GO TO 70
! USE FORMULA 9.6.31, RECURRING FORWARD ON K OF ARGUMENT (-Z)
      DO 28 N=4,MAXP
      IF(MAX(ABS(REALP(HH)),ABS(AIMAGP(HH))).GT.BIG) GO TO 82
      FF=GG
      GG=HH
      DD=-DD
        HH=(ZINV*(A+REAL(N-3)))*GG+FF
        BK(N)=DD*HH-EE*BK(N)
   28 CONTINUE
      GO TO 70
! FOR LARGE Z, CALCULATE K*S VIA PHASE-AMPLITUDE EQUATION 9.7.2 OF
! REFERENCE (1) LISTED IN BESJCF.
   30 CONTINUE
      FF=Z
      EE=ZINV
      IF(REALP(Z).LT.0.) FF=-FF
      IF(REALP(Z).LT.0.) EE=-EE
      DD=SQRT(.25*PI*EE)*EXP(-FF)
      C=A
      R=1.
      IF(A.GT.0.) R=-1.
      DO 32 M=1,2
        IF(M.EQ.2) C=C+R
        CALL PHASMP(C,EE,1,PP,QQ)
        ITEMP = 3 - M
        BK(ITEMP) = DD * PP
   32 CONTINUE
      IF(REALP(Z).LT.0.) GO TO 26
   40 CONTINUE
      M=3
      IF(A.GT.0.) GO TO 60
      M=4
      IF(MAXP.GE.3) BK(3)=BK(1)
      BK(1)=BK(1)-(A*ZINV)*BK(2)
! CALCULATE K*S VIA FORWARD RECURSION, CHECKING FOR POSSIBLE OVERFLOW
   60 IF(M.GT.MAXP) GO TO 70
      DO 65 N=M,MAXP
      IF(MAX(ABS(REALP(BK(N-1))),ABS(AIMAGP(BK(N-1)))).GT.BIG) GO TO 82
      BK(N)=(ZINV*(A+REAL(N-3)))*BK(N-1)+BK(N-2)
   65 CONTINUE
   70 CONTINUE
      RETURN
   82 CONTINUE
      DO 83 M=N,MAXP
         BK(M) = (0.0, 0.0)
   83 CONTINUE
      GO TO 70
   86 CONTINUE
      WRITE (ICOUT, 88)NMAX
      CALL DPWRST('XXX','BUG ')
      WRITE (ICOUT, 89)A,Z
      CALL DPWRST('XXX','BUG ')
   88 FORMAT('***** ERROR (BESKCF) --- INVALID INPUT, NMAX = ', I6)
   89 FORMAT('      A = ', 1PE22.14,' Z = ',2(1PE22.14))
      RETURN
      END SUBROUTINE BESKCF
      FUNCTION BESRAT(V)
!
!     ROUTINE NEEDED BY VKAPPA FOR COMPUTING MAXIMUM LIKELIHOOD
!     ESTIMATES FOR KAPPA (SHAPE PARAMETER OF VON MISES
!     DISTRIBUTION).  FROM:
!
! ACM ALGORITHM 571
!
! STATISTICS FOR VON MISES' AND FISCHER'S DISTRIBUTIONS
!
! BY G.W. HILL
!
! ACM TRANSACTIONS ON MATHEMATICAL SOFTWARE, JUNE 1981
!
! ----------------------------------------------------------------
! RETURNS BESRAT = A(K) FOR K = ABS(V), WHERE A(K) IS THE EXPECTED
! MODULUS OF THE MEAN VECTOR SUM OF UNIT VECTORS SAMPLED FROM THE
! VON MISES DISTRIBUTION OF DIRECTIONS IN 2D WITH PARAMETER = K.
! A(V) = THE RATIO OF MODIFIED BESSEL FUNCTIONS OF THE FIRST KIND
! OF ORDERS 1 AND 0, I.E., A(V) = I1(V)/I0(V).
! ----------------------------------------------------------------
!
!  ADJUST TO S DECIMAL DIGIT PRECISION BY SETTING DATA CONSTANTS -
!     C1 = (S+9.0-8.0/S)*0.0351
!     C2 = ((S-5.0)**3/180.0+S-5.0)/10.0
!     CX = S*0.5 + 11.0
!  FOR S IN RANGE (5,14).  THUS FOR S = 9.3 :
      DATA C1 /0.613/, C2 /0.475/, CX /15.65/
!
      Y = 0.0
      X = ABS(V)
      IF (X.GT.CX) GO TO 20
!
!  FOR SMALL X, RATIO = X/(2+X*X/(4+X*X/(6+X*X/(8+ ... )))
      N = INT((X+16.0-16.0/(X+C1+0.75))*C1)
      X = X*0.5
      XX = X*X
      DO 10 J=1,N
        Y = XX/(FLOAT(N-J+2)+Y)
   10 CONTINUE
      BESRAT = X/(1.0+Y)
      RETURN
!
!  FOR LARGE X, RATIO = 1-2/(4X-1-1/(4X/3-2-1/(4X/5-2- ... )))
   20 N = INT((68.0/X+1.0)*C2) + 1
      X = X*4.0
      XX = FLOAT(N*2+1)
      DO 30 J=1,N
        Y = XX/((-2.0-Y)*XX+X)
        XX = XX - 2.0
   30 CONTINUE
      BESRAT = 1.0 - 2.0/(X-1.0-Y)
      RETURN
      END FUNCTION BESRAT
      SUBROUTINE BESY (X, FNU, N, Y)
!***BEGIN PROLOGUE  BESY
!***PURPOSE  Implement forward recursion on the three term recursion
!            relation for a sequence of non-negative order Bessel
!            functions Y/SUB(FNU+I-1)/(X), I=1,...,N for real, positive
!            X and non-negative orders FNU.
!***LIBRARY   SLATEC
!***CATEGORY  C10A3
!***TYPE      SINGLE PRECISION (BESY-S, DBESY-D)
!***KEYWORDS  SPECIAL FUNCTIONS, Y BESSEL FUNCTION
!***AUTHOR  Amos, D. E., (SNLA)
!***DESCRIPTION
!
!     Abstract
!         BESY implements forward recursion on the three term
!         recursion relation for a sequence of non-negative order Bessel
!         functions Y/sub(FNU+I-1)/(X), I=1,N for real X .GT. 0.0E0 and
!         non-negative orders FNU.  If FNU .LT. NULIM, orders FNU and
!         FNU+1 are obtained from BESYNU which computes by a power
!         series for X .LE. 2, the K Bessel function of an imaginary
!         argument for 2 .LT. X .LE. 20 and the asymptotic expansion for
!         X .GT. 20.
!
!         If FNU .GE. NULIM, the uniform asymptotic expansion is coded
!         in ASYJY for orders FNU and FNU+1 to start the recursion.
!         NULIM is 70 or 100 depending on whether N=1 or N .GE. 2.  An
!         overflow test is made on the leading term of the asymptotic
!         expansion before any extensive computation is done.
!
!     Description of Arguments
!
!         Input
!           X      - X .GT. 0.0E0
!           FNU    - order of the initial Y function, FNU .GE. 0.0E0
!           N      - number of members in the sequence, N .GE. 1
!
!         Output
!           Y      - a vector whose first N components contain values
!                    for the sequence Y(I)=Y/sub(FNU+I-1)/(X), I=1,N.
!
!     Error Conditions
!         Improper input arguments - a fatal error
!         Overflow - a fatal error
!
!***REFERENCES  F. W. J. Olver, Tables of Bessel Functions of Moderate
!                 or Large Orders, NPL Mathematical Tables 6, Her
!                 Majesty's Stationery Office, London, 1962.
!               N. M. Temme, On the numerical evaluation of the modified
!                 Bessel function of the third kind, Journal of
!                 Computational Physics 19, (1975), pp. 324-337.
!               N. M. Temme, On the numerical evaluation of the ordinary
!                 Bessel function of the second kind, Journal of
!                 Computational Physics 21, (1976), pp. 343-350.
!***ROUTINES CALLED  ASYJY, BESY0, BESY1, BESYNU, I1MACH, R1MACH,
!                    XERMSG, YAIRY
!***REVISION HISTORY  (YYMMDD)
!   800501  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  BESY
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      EXTERNAL YAIRY, BESY0DP, BESY1DP
      INTEGER I, IFLW, J, N, NB, ND, NN, NUD, NULIM
      REAL       AZN,CN,DNU,ELIM,FLGJY,FN,FNU,RAN,S,S1,S2,TM,TRX,   &
                 W,WK,W2N,X,XLIM,XXN,Y
      REAL BESY0DP, BESY1DP
      DIMENSION W(2), NULIM(2), Y(*), WK(7)
      SAVE NULIM
!
      DATA NULIM(1),NULIM(2) / 70 , 100 /
!***FIRST EXECUTABLE STATEMENT  BESY
!
      S2=0.0
      TRX=0.0
      TM=0.0
      NN = -I1MACH(12)
!
      ELIM = 2.303E0*(NN*R1MACH(5)-3.0E0)
      XLIM = R1MACH(1)*1.0E+3
      IF (FNU.LT.0.0E0) GO TO 140
      IF (X.LE.0.0E0) GO TO 150
      IF (X.LT.XLIM) GO TO 170
      IF (N.LT.1) GO TO 160
!
!     ND IS A DUMMY VARIABLE FOR N
!
      ND = N
      NUD = INT(FNU)
      DNU = FNU - NUD
      NN = MIN(2,ND)
      FN = FNU + N - 1
      IF (FN.LT.2.0E0) GO TO 100
!
!     OVERFLOW TEST  (LEADING EXPONENTIAL OF ASYMPTOTIC EXPANSION)
!     FOR THE LAST ORDER, FNU+N-1.GE.NULIM
!
      XXN = X/FN
      W2N = 1.0E0-XXN*XXN
      IF(W2N.LE.0.0E0) GO TO 10
      RAN = SQRT(W2N)
      AZN = LOG((1.0E0+RAN)/XXN) - RAN
      CN = FN*AZN
      IF(CN.GT.ELIM) GO TO 170
   10 CONTINUE
      IF (NUD.LT.NULIM(NN)) GO TO 20
!
!     ASYMPTOTIC EXPANSION FOR ORDERS FNU AND FNU+1.GE.NULIM
!
      FLGJY = -1.0E0
      CALL ASYJY(YAIRY,X,FNU,FLGJY,NN,Y,WK,IFLW)
      IF(IFLW.NE.0) GO TO 170
      IF (NN.EQ.1) RETURN
      TRX = 2.0E0/X
      TM = (FNU+FNU+2.0E0)/X
      GO TO 80
!
   20 CONTINUE
      IF (DNU.NE.0.0E0) GO TO 30
      S1 = BESY0DP(X)
      IF (NUD.EQ.0 .AND. ND.EQ.1) GO TO 70
      S2 = BESY1DP(X)
      GO TO 40
   30 CONTINUE
      NB = 2
      IF (NUD.EQ.0 .AND. ND.EQ.1) NB = 1
      CALL BESYNU(X, DNU, NB, W)
      S1 = W(1)
      IF (NB.EQ.1) GO TO 70
      S2 = W(2)
   40 CONTINUE
      TRX = 2.0E0/X
      TM = (DNU+DNU+2.0E0)/X
!     FORWARD RECUR FROM DNU TO FNU+1 TO GET Y(1) AND Y(2)
      IF (ND.EQ.1) NUD = NUD - 1
      IF (NUD.GT.0) GO TO 50
      IF (ND.GT.1) GO TO 70
      S1 = S2
      GO TO 70
   50 CONTINUE
      DO 60 I=1,NUD
        S = S2
        S2 = TM*S2 - S1
        S1 = S
        TM = TM + TRX
   60 CONTINUE
      IF (ND.EQ.1) S1 = S2
   70 CONTINUE
      Y(1) = S1
      IF (ND.EQ.1) RETURN
      Y(2) = S2
   80 CONTINUE
      IF (ND.EQ.2) RETURN
!     FORWARD RECUR FROM FNU+2 TO FNU+N-1
      DO 90 I=3,ND
        Y(I) = TM*Y(I-1) - Y(I-2)
        TM = TM + TRX
   90 CONTINUE
      RETURN
!
  100 CONTINUE
!     OVERFLOW TEST
      IF (FN.LE.1.0E0) GO TO 110
      IF (-FN*(LOG(X)-0.693E0).GT.ELIM) GO TO 170
  110 CONTINUE
      IF (DNU.EQ.0.0E0) GO TO 120
      CALL BESYNU(X, FNU, ND, Y)
      RETURN
  120 CONTINUE
      J = NUD
      IF (J.EQ.1) GO TO 130
      J = J + 1
      Y(J) = BESY0DP(X)
      IF (ND.EQ.1) RETURN
      J = J + 1
  130 CONTINUE
      Y(J) = BESY1DP(X)
      IF (ND.EQ.1) RETURN
      TRX = 2.0E0/X
      TM = TRX
      GO TO 80
!
!
!
  140 CONTINUE
      WRITE(ICOUT,141)
  141 FORMAT('***** ERORR FROM BESY, THE ORDER FNU IS NEGATIVE. ***')
      CALL DPWRST('XXX','BUG ')
      RETURN
  150 CONTINUE
      WRITE(ICOUT,151)
  151 FORMAT('**** ERORR FROM BESY, X IS LESS THAN OR EQUAL TO ZERO. ')
      CALL DPWRST('XXX','BUG ')
      RETURN
  160 CONTINUE
      WRITE(ICOUT,161)
  161 FORMAT('***** ERORR FROM BESY, N IS LESS THAN ONE.. ***')
      CALL DPWRST('XXX','BUG ')
      RETURN
  170 CONTINUE
      WRITE(ICOUT,171)
  171 FORMAT('***** ERORR FROM BESY, OVERFLOW, FNU OR N TOO LARGE OR ',   &
             'X TOO SMALL. *****')
      RETURN
      END SUBROUTINE BESY 
      SUBROUTINE BESYNU (X, FNU, N, Y)
!***BEGIN PROLOGUE  BESYNU
!***SUBSIDIARY
!***PURPOSE  Subsidiary to BESY
!***LIBRARY   SLATEC
!***TYPE      SINGLE PRECISION (BESYNU-S, DBSYNU-D)
!***AUTHOR  Amos, D. E., (SNLA)
!***DESCRIPTION
!
!     Abstract
!         BESYNU computes N member sequences of Y Bessel functions
!         Y/SUB(FNU+I-1)/(X), I=1,N for non-negative orders FNU and
!         positive X. Equations of the references are implemented on
!         small orders DNU for Y/SUB(DNU)/(X) and Y/SUB(DNU+1)/(X).
!         Forward recursion with the three term recursion relation
!         generates higher orders FNU+I-1, I=1,...,N.
!
!         To start the recursion FNU is normalized to the interval
!         -0.5.LE.DNU.LT.0.5. A special form of the power series is
!         implemented on 0.LT.X.LE.X1 while the Miller algorithm for the
!         K Bessel function in terms of the confluent hypergeometric
!         function U(FNU+0.5,2*FNU+1,I*X) is implemented on X1.LT.X.LE.X
!         Here I is the complex number SQRT(-1.).
!         For X.GT.X2, the asymptotic expansion for large X is used.
!         When FNU is a half odd integer, a special formula for
!         DNU=-0.5 and DNU+1.0=0.5 is used to start the recursion.
!
!         BESYNU assumes that a significant digit SINH(X) function is
!         available.
!
!     Description of Arguments
!
!         Input
!           X      - X.GT.0.0E0
!           FNU    - Order of initial Y function, FNU.GE.0.0E0
!           N      - Number of members of the sequence, N.GE.1
!
!         Output
!           Y      - A vector whose first N components contain values
!                    for the sequence Y(I)=Y/SUB(FNU+I-1), I=1,N.
!
!     Error Conditions
!         Improper input arguments - a fatal error
!         Overflow - a fatal error
!
!***SEE ALSO  BESY
!***REFERENCES  N. M. Temme, On the numerical evaluation of the ordinary
!                 Bessel function of the second kind, Journal of
!                 Computational Physics 21, (1976), pp. 343-350.
!               N. M. Temme, On the numerical evaluation of the modified
!                 Bessel function of the third kind, Journal of
!                 Computational Physics 19, (1975), pp. 324-337.
!***ROUTINES CALLED  GAMMA, R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   800501  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!   900328  Added TYPE section.  (WRB)
!   900727  Added EXTERNAL statement.  (WRB)
!   910408  Updated the AUTHOR and REFERENCES sections.  (WRB)
!   920501  Reformatted the REFERENCES section.  (WRB)
!***END PROLOGUE  BESYNU
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      INTEGER I, INU, J, K, KK, N, NN
      REAL A, AK, ARG, A1, A2, BK, CB, CBK, CC, CCK, CK, COEF, CPT,   &
       CP1, CP2, CS, CS1, CS2, CX, DNU, DNU2, ETEST, ETX, F, FC, FHS,   &
       FK, FKS, FLRX, FMU, FN, FNU, FX, G, G1, G2, HPI, P, PI, PT, Q,   &
       RB, RBK, RCK, RELB, RPT, RP1, RP2, RS, RS1, RS2, RTHPI, RX, S,   &
       SA, SB, SMU, SS, ST, S1, S2, TB, TM, TOL, T1, T2, X, X1, X2, Y
      DIMENSION A(120), RB(120), CB(120), Y(*), CC(8)
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
      SAVE X1, X2, PI, RTHPI, HPI, CC
      DATA X1, X2 / 3.0E0, 20.0E0 /
      DATA PI,RTHPI        / 3.14159265358979E+00, 7.97884560802865E-01/
      DATA HPI             / 1.57079632679490E+00/
      DATA CC(1), CC(2), CC(3), CC(4), CC(5), CC(6), CC(7), CC(8)   &
                           / 5.77215664901533E-01,-4.20026350340952E-02,   &
      -4.21977345555443E-02, 7.21894324666300E-03,-2.15241674114900E-04,   &
      -2.01348547807000E-05, 1.13302723200000E-06, 6.11609500000000E-09/
!***FIRST EXECUTABLE STATEMENT  BESYNU
!
      S1=0.0
      S2=0.0
      CK=0.0
!
      AK = R1MACH(3)
      TOL = MAX(AK,1.0E-15)
      IF (X.LE.0.0E0) GO TO 270
      IF (FNU.LT.0.0E0) GO TO 280
      IF (N.LT.1) GO TO 290
      RX = 2.0E0/X
      INU = INT(FNU+0.5E0)
      DNU = FNU - INU
      IF (ABS(DNU).EQ.0.5E0) GO TO 260
      DNU2 = 0.0E0
      IF (ABS(DNU).LT.TOL) GO TO 10
      DNU2 = DNU*DNU
   10 CONTINUE
      IF (X.GT.X1) GO TO 120
!
!     SERIES FOR X.LE.X1
!
      A1 = 1.0E0 - DNU
      A2 = 1.0E0 + DNU
      T1 = 1.0E0/REAL(DGAMMA(DBLE(A1)))
      T2 = 1.0E0/REAL(DGAMMA(DBLE(A2)))
      IF (ABS(DNU).GT.0.1E0) GO TO 40
!     SERIES FOR F0 TO RESOLVE INDETERMINACY FOR SMALL ABS(DNU)
      S = CC(1)
      AK = 1.0E0
      DO 20 K=2,8
        AK = AK*DNU2
        TM = CC(K)*AK
        S = S + TM
        IF (ABS(TM).LT.TOL) GO TO 30
   20 CONTINUE
   30 G1 = -(S+S)
      GO TO 50
   40 CONTINUE
      G1 = (T1-T2)/DNU
   50 CONTINUE
      G2 = T1 + T2
      SMU = 1.0E0
      FC = 1.0E0/PI
      FLRX = LOG(RX)
      FMU = DNU*FLRX
      TM = 0.0E0
      IF (DNU.EQ.0.0E0) GO TO 60
      TM = SIN(DNU*HPI)/DNU
      TM = (DNU+DNU)*TM*TM
      FC = DNU/SIN(DNU*PI)
      IF (FMU.NE.0.0E0) SMU = SINH(FMU)/FMU
   60 CONTINUE
      F = FC*(G1*COSH(FMU)+G2*FLRX*SMU)
      FX = EXP(FMU)
      P = FC*T1*FX
      Q = FC*T2/FX
      G = F + TM*Q
      AK = 1.0E0
      CK = 1.0E0
      BK = 1.0E0
      S1 = G
      S2 = P
      IF (INU.GT.0 .OR. N.GT.1) GO TO 90
      IF (X.LT.TOL) GO TO 80
      CX = X*X*0.25E0
   70 CONTINUE
      F = (AK*F+P+Q)/(BK-DNU2)
      P = P/(AK-DNU)
      Q = Q/(AK+DNU)
      G = F + TM*Q
      CK = -CK*CX/AK
      T1 = CK*G
      S1 = S1 + T1
      BK = BK + AK + AK + 1.0E0
      AK = AK + 1.0E0
      S = ABS(T1)/(1.0E0+ABS(S1))
      IF (S.GT.TOL) GO TO 70
   80 CONTINUE
      Y(1) = -S1
      RETURN
   90 CONTINUE
      IF (X.LT.TOL) GO TO 110
      CX = X*X*0.25E0
  100 CONTINUE
      F = (AK*F+P+Q)/(BK-DNU2)
      P = P/(AK-DNU)
      Q = Q/(AK+DNU)
      G = F + TM*Q
      CK = -CK*CX/AK
      T1 = CK*G
      S1 = S1 + T1
      T2 = CK*(P-AK*G)
      S2 = S2 + T2
      BK = BK + AK + AK + 1.0E0
      AK = AK + 1.0E0
      S = ABS(T1)/(1.0E0+ABS(S1)) + ABS(T2)/(1.0E0+ABS(S2))
      IF (S.GT.TOL) GO TO 100
  110 CONTINUE
      S2 = -S2*RX
      S1 = -S1
      GO TO 160
  120 CONTINUE
      COEF = RTHPI/SQRT(X)
      IF (X.GT.X2) GO TO 210
!
!     MILLER ALGORITHM FOR X1.LT.X.LE.X2
!
      ETEST = COS(PI*DNU)/(PI*X*TOL)
      FKS = 1.0E0
      FHS = 0.25E0
      FK = 0.0E0
      RCK = 2.0E0
      CCK = X + X
      RP1 = 0.0E0
      CP1 = 0.0E0
      RP2 = 1.0E0
      CP2 = 0.0E0
      K = 0
  130 CONTINUE
      K = K + 1
      FK = FK + 1.0E0
      AK = (FHS-DNU2)/(FKS+FK)
      PT = FK + 1.0E0
      RBK = RCK/PT
      CBK = CCK/PT
      RPT = RP2
      CPT = CP2
      RP2 = RBK*RPT - CBK*CPT - AK*RP1
      CP2 = CBK*RPT + RBK*CPT - AK*CP1
      RP1 = RPT
      CP1 = CPT
      RB(K) = RBK
      CB(K) = CBK
      A(K) = AK
      RCK = RCK + 2.0E0
      FKS = FKS + FK + FK + 1.0E0
      FHS = FHS + FK + FK
      PT = MAX(ABS(RP1),ABS(CP1))
      FC = (RP1/PT)**2 + (CP1/PT)**2
      PT = PT*SQRT(FC)*FK
      IF (ETEST.GT.PT) GO TO 130
      KK = K
      RS = 1.0E0
      CS = 0.0E0
      RP1 = 0.0E0
      CP1 = 0.0E0
      RP2 = 1.0E0
      CP2 = 0.0E0
      DO 140 I=1,K
        RPT = RP2
        CPT = CP2
        RP2 = (RB(KK)*RPT-CB(KK)*CPT-RP1)/A(KK)
        CP2 = (CB(KK)*RPT+RB(KK)*CPT-CP1)/A(KK)
        RP1 = RPT
        CP1 = CPT
        RS = RS + RP2
        CS = CS + CP2
        KK = KK - 1
  140 CONTINUE
      PT = MAX(ABS(RS),ABS(CS))
      FC = (RS/PT)**2 + (CS/PT)**2
      PT = PT*SQRT(FC)
      RS1 = (RP2*(RS/PT)+CP2*(CS/PT))/PT
      CS1 = (CP2*(RS/PT)-RP2*(CS/PT))/PT
      FC = HPI*(DNU-0.5E0) - X
      P = COS(FC)
      Q = SIN(FC)
      S1 = (CS1*Q-RS1*P)*COEF
      IF (INU.GT.0 .OR. N.GT.1) GO TO 150
      Y(1) = S1
      RETURN
  150 CONTINUE
      PT = MAX(ABS(RP2),ABS(CP2))
      FC = (RP2/PT)**2 + (CP2/PT)**2
      PT = PT*SQRT(FC)
      RPT = DNU + 0.5E0 - (RP1*(RP2/PT)+CP1*(CP2/PT))/PT
      CPT = X - (CP1*(RP2/PT)-RP1*(CP2/PT))/PT
      CS2 = CS1*CPT - RS1*RPT
      RS2 = RPT*CS1 + RS1*CPT
      S2 = (RS2*Q+CS2*P)*COEF/X
!
!     FORWARD RECURSION ON THE THREE TERM RECURSION RELATION
!
  160 CONTINUE
      CK = (DNU+DNU+2.0E0)/X
      IF (N.EQ.1) INU = INU - 1
      IF (INU.GT.0) GO TO 170
      IF (N.GT.1) GO TO 190
      S1 = S2
      GO TO 190
  170 CONTINUE
      DO 180 I=1,INU
        ST = S2
        S2 = CK*S2 - S1
        S1 = ST
        CK = CK + RX
  180 CONTINUE
      IF (N.EQ.1) S1 = S2
  190 CONTINUE
      Y(1) = S1
      IF (N.EQ.1) RETURN
      Y(2) = S2
      IF (N.EQ.2) RETURN
      DO 200 I=3,N
        Y(I) = CK*Y(I-1) - Y(I-2)
        CK = CK + RX
  200 CONTINUE
      RETURN
!
!     ASYMPTOTIC EXPANSION FOR LARGE X, X.GT.X2
!
  210 CONTINUE
      NN = 2
      IF (INU.EQ.0 .AND. N.EQ.1) NN = 1
      DNU2 = DNU + DNU
      FMU = 0.0E0
      IF (ABS(DNU2).LT.TOL) GO TO 220
      FMU = DNU2*DNU2
  220 CONTINUE
      ARG = X - HPI*(DNU+0.5E0)
      SA = SIN(ARG)
      SB = COS(ARG)
      ETX = 8.0E0*X
      DO 250 K=1,NN
        S1 = S2
        T2 = (FMU-1.0E0)/ETX
        SS = T2
        RELB = TOL*ABS(T2)
        T1 = ETX
        S = 1.0E0
        FN = 1.0E0
        AK = 0.0E0
        DO 230 J=1,13
          T1 = T1 + ETX
          AK = AK + 8.0E0
          FN = FN + AK
          T2 = -T2*(FMU-FN)/T1
          S = S + T2
          T1 = T1 + ETX
          AK = AK + 8.0E0
          FN = FN + AK
          T2 = T2*(FMU-FN)/T1
          SS = SS + T2
          IF (ABS(T2).LE.RELB) GO TO 240
  230   CONTINUE
  240   S2 = COEF*(S*SA+SS*SB)
        FMU = FMU + 8.0E0*DNU + 4.0E0
        TB = SA
        SA = -SB
        SB = TB
  250 CONTINUE
      IF (NN.GT.1) GO TO 160
      S1 = S2
      GO TO 190
!
!     FNU=HALF ODD INTEGER CASE
!
  260 CONTINUE
      COEF = RTHPI/SQRT(X)
      S1 = COEF*SIN(X)
      S2 = -COEF*COS(X)
      GO TO 160
!
!
  270 CONTINUE
      WRITE(ICOUT,271)
  271 FORMAT('**** ERORR FROM BESYNU, X IS NOT POSITIVE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
  280 CONTINUE
      WRITE(ICOUT,281)
  281 FORMAT('***** ERORR FROM BESYNU, THE ORDER FNU IS NEGATIVE. ***')
      CALL DPWRST('XXX','BUG ')
      RETURN
 290  CONTINUE
      WRITE(ICOUT,291)
  291 FORMAT('***** ERORR FROM BESYNU, N IS LESS THAN ONE.. ***')
      CALL DPWRST('XXX','BUG ')
      RETURN
      END SUBROUTINE BESYNU 
      FUNCTION BESY0DP (X)
!CCCC RENAME TO AVOID CONFLICT WITH INTRINSIC BESY0 FUNCTION
!CCCC FUNCTION BESY0 (X)
!***BEGIN PROLOGUE  BESY0
!***PURPOSE  Compute the Bessel function of the second kind of order
!            zero.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10A1
!***TYPE      SINGLE PRECISION (BESY0-S, DBESY0-D)
!***KEYWORDS  BESSEL FUNCTION, FNLIB, ORDER ZERO, SECOND KIND,
!             SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! BESY0(X) calculates the Bessel function of the second kind
! of order zero for real argument X.
!
! Series for BY0        on the interval  0.          to  1.60000D+01
!                                        with weighted error   1.20E-17
!                                         log weighted error  16.92
!                               significant figures required  16.15
!                                    decimal places required  17.48
!
! Series for BM0        on the interval  0.          to  6.25000D-02
!                                        with weighted error   4.98E-17
!                                         log weighted error  16.30
!                               significant figures required  14.97
!                                    decimal places required  16.96
!
! Series for BTH0       on the interval  0.          to  6.25000D-02
!                                        with weighted error   3.67E-17
!                                         log weighted error  16.44
!                               significant figures required  15.53
!                                    decimal places required  17.13
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  BESJ0, CSEVL, INITS, R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770401  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!***END PROLOGUE  BESY0
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      EXTERNAL BESJ0DP, CSEVL
!
      DIMENSION BY0CS(13), BM0CS(21), BTH0CS(24)
      LOGICAL FIRST
      SAVE BY0CS, BM0CS, BTH0CS, TWODPI, PI4,   &
       NTY0, NTM0, NTTH0, XSML, XMAX, FIRST
      DATA BY0CS( 1) /   -.011277839392865573E0 /
      DATA BY0CS( 2) /   -.12834523756042035E0 /
      DATA BY0CS( 3) /   -.10437884799794249E0 /
      DATA BY0CS( 4) /    .023662749183969695E0 /
      DATA BY0CS( 5) /   -.002090391647700486E0 /
      DATA BY0CS( 6) /    .000103975453939057E0 /
      DATA BY0CS( 7) /   -.000003369747162423E0 /
      DATA BY0CS( 8) /    .000000077293842676E0 /
      DATA BY0CS( 9) /   -.000000001324976772E0 /
      DATA BY0CS(10) /    .000000000017648232E0 /
      DATA BY0CS(11) /   -.000000000000188105E0 /
      DATA BY0CS(12) /    .000000000000001641E0 /
      DATA BY0CS(13) /   -.000000000000000011E0 /
      DATA BM0CS( 1) /    .09284961637381644E0 /
      DATA BM0CS( 2) /   -.00142987707403484E0 /
      DATA BM0CS( 3) /    .00002830579271257E0 /
      DATA BM0CS( 4) /   -.00000143300611424E0 /
      DATA BM0CS( 5) /    .00000012028628046E0 /
      DATA BM0CS( 6) /   -.00000001397113013E0 /
      DATA BM0CS( 7) /    .00000000204076188E0 /
      DATA BM0CS( 8) /   -.00000000035399669E0 /
      DATA BM0CS( 9) /    .00000000007024759E0 /
      DATA BM0CS(10) /   -.00000000001554107E0 /
      DATA BM0CS(11) /    .00000000000376226E0 /
      DATA BM0CS(12) /   -.00000000000098282E0 /
      DATA BM0CS(13) /    .00000000000027408E0 /
      DATA BM0CS(14) /   -.00000000000008091E0 /
      DATA BM0CS(15) /    .00000000000002511E0 /
      DATA BM0CS(16) /   -.00000000000000814E0 /
      DATA BM0CS(17) /    .00000000000000275E0 /
      DATA BM0CS(18) /   -.00000000000000096E0 /
      DATA BM0CS(19) /    .00000000000000034E0 /
      DATA BM0CS(20) /   -.00000000000000012E0 /
      DATA BM0CS(21) /    .00000000000000004E0 /
      DATA BTH0CS( 1) /   -.24639163774300119E0 /
      DATA BTH0CS( 2) /    .001737098307508963E0 /
      DATA BTH0CS( 3) /   -.000062183633402968E0 /
      DATA BTH0CS( 4) /    .000004368050165742E0 /
      DATA BTH0CS( 5) /   -.000000456093019869E0 /
      DATA BTH0CS( 6) /    .000000062197400101E0 /
      DATA BTH0CS( 7) /   -.000000010300442889E0 /
      DATA BTH0CS( 8) /    .000000001979526776E0 /
      DATA BTH0CS( 9) /   -.000000000428198396E0 /
      DATA BTH0CS(10) /    .000000000102035840E0 /
      DATA BTH0CS(11) /   -.000000000026363898E0 /
      DATA BTH0CS(12) /    .000000000007297935E0 /
      DATA BTH0CS(13) /   -.000000000002144188E0 /
      DATA BTH0CS(14) /    .000000000000663693E0 /
      DATA BTH0CS(15) /   -.000000000000215126E0 /
      DATA BTH0CS(16) /    .000000000000072659E0 /
      DATA BTH0CS(17) /   -.000000000000025465E0 /
      DATA BTH0CS(18) /    .000000000000009229E0 /
      DATA BTH0CS(19) /   -.000000000000003448E0 /
      DATA BTH0CS(20) /    .000000000000001325E0 /
      DATA BTH0CS(21) /   -.000000000000000522E0 /
      DATA BTH0CS(22) /    .000000000000000210E0 /
      DATA BTH0CS(23) /   -.000000000000000087E0 /
      DATA BTH0CS(24) /    .000000000000000036E0 /
      DATA TWODPI / 0.63661977236758134E0 /
      DATA PI4 / 0.78539816339744831E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  BESY0
!
      BESY0DP = CPUMIN
!
      IF (FIRST) THEN
         NTY0 = INITS (BY0CS, 13, 0.1*R1MACH(3))
         NTM0 = INITS (BM0CS, 21, 0.1*R1MACH(3))
         NTTH0 = INITS (BTH0CS, 24, 0.1*R1MACH(3))
!
         XSML = SQRT (4.0*R1MACH(3))
         XMAX = 1.0/R1MACH(4)
      ENDIF
      FIRST = .FALSE.
!
      IF (X .LE. 0.) THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERORR FROM BESY0DP, X ZERO OR NEGATIVE.  *******')
        CALL DPWRST('XXX','BUG ')
        BESY0DP=0.0
        RETURN
      ENDIF
      IF (X.GT.4.0) GO TO 20
!
      Y = 0.
      IF (X.GT.XSML) Y = X*X
      BESY0DP = TWODPI*LOG(0.5*X)*BESJ0DP(X) + .375 + CSEVL (.125*Y-1.,   &
        BY0CS, NTY0)
      RETURN
!
 20   CONTINUE
      IF (X.GT.XMAX) THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        BESY0 = 0.0
        RETURN
      ENDIF
    2 FORMAT('***** ERORR FROM BESY0DP, NO PRECISION BECAUSE THE ',   &
             'VALUE OF X IS TOO BIG.  ****')
!
      Z = 32.0/X**2 - 1.0
      AMPL = (0.75 + CSEVL (Z, BM0CS, NTM0)) / SQRT(X)
      THETA = X - PI4 + CSEVL (Z, BTH0CS, NTTH0) / X
      BESY0DP = AMPL * SIN (THETA)
!
      RETURN
      END FUNCTION BESY0DP 
      FUNCTION BESY1DP (X)
!CCCC RENAME TO AVOID CONFLICT WITH INTRINSIC BESY1 FUNCTION
!CCCC FUNCTION BESY1 (X)
!***BEGIN PROLOGUE  BESY1
!***PURPOSE  Compute the Bessel function of the second kind of order
!            one.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10A1
!***TYPE      SINGLE PRECISION (BESY1-S, DBESY1-D)
!***KEYWORDS  BESSEL FUNCTION, FNLIB, ORDER ONE, SECOND KIND,
!             SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! BESY1(X) calculates the Bessel function of the second kind of
! order one for real argument X.
!
! Series for BY1        on the interval  0.          to  1.60000D+01
!                                        with weighted error   1.87E-18
!                                         log weighted error  17.73
!                               significant figures required  17.83
!                                    decimal places required  18.30
!
! Series for BM1        on the interval  0.          to  6.25000D-02
!                                        with weighted error   5.61E-17
!                                         log weighted error  16.25
!                               significant figures required  14.97
!                                    decimal places required  16.91
!
! Series for BTH1       on the interval  0.          to  6.25000D-02
!                                        with weighted error   4.10E-17
!                                         log weighted error  16.39
!                               significant figures required  15.96
!                                    decimal places required  17.08
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  BESJ1, CSEVL, INITS, R1MACH, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770401  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!***END PROLOGUE  BESY1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      EXTERNAL BESJ1DP, CSEVL
!
      DIMENSION BY1CS(14), BM1CS(21), BTH1CS(24)
      LOGICAL FIRST
      SAVE BY1CS, BM1CS, BTH1CS, TWODPI, PI4,   &
       NTY1, NTM1, NTTH1, XMIN, XSML, XMAX, FIRST
      DATA BY1CS( 1) /    .03208047100611908629E0 /
      DATA BY1CS( 2) /   1.262707897433500450E0 /
      DATA BY1CS( 3) /    .00649996189992317500E0 /
      DATA BY1CS( 4) /   -.08936164528860504117E0 /
      DATA BY1CS( 5) /    .01325088122175709545E0 /
      DATA BY1CS( 6) /   -.00089790591196483523E0 /
      DATA BY1CS( 7) /    .00003647361487958306E0 /
      DATA BY1CS( 8) /   -.00000100137438166600E0 /
      DATA BY1CS( 9) /    .00000001994539657390E0 /
      DATA BY1CS(10) /   -.00000000030230656018E0 /
      DATA BY1CS(11) /    .00000000000360987815E0 /
      DATA BY1CS(12) /   -.00000000000003487488E0 /
      DATA BY1CS(13) /    .00000000000000027838E0 /
      DATA BY1CS(14) /   -.00000000000000000186E0 /
      DATA BM1CS( 1) /    .1047362510931285E0 /
      DATA BM1CS( 2) /    .00442443893702345E0 /
      DATA BM1CS( 3) /   -.00005661639504035E0 /
      DATA BM1CS( 4) /    .00000231349417339E0 /
      DATA BM1CS( 5) /   -.00000017377182007E0 /
      DATA BM1CS( 6) /    .00000001893209930E0 /
      DATA BM1CS( 7) /   -.00000000265416023E0 /
      DATA BM1CS( 8) /    .00000000044740209E0 /
      DATA BM1CS( 9) /   -.00000000008691795E0 /
      DATA BM1CS(10) /    .00000000001891492E0 /
      DATA BM1CS(11) /   -.00000000000451884E0 /
      DATA BM1CS(12) /    .00000000000116765E0 /
      DATA BM1CS(13) /   -.00000000000032265E0 /
      DATA BM1CS(14) /    .00000000000009450E0 /
      DATA BM1CS(15) /   -.00000000000002913E0 /
      DATA BM1CS(16) /    .00000000000000939E0 /
      DATA BM1CS(17) /   -.00000000000000315E0 /
      DATA BM1CS(18) /    .00000000000000109E0 /
      DATA BM1CS(19) /   -.00000000000000039E0 /
      DATA BM1CS(20) /    .00000000000000014E0 /
      DATA BM1CS(21) /   -.00000000000000005E0 /
      DATA BTH1CS( 1) /    .74060141026313850E0 /
      DATA BTH1CS( 2) /   -.004571755659637690E0 /
      DATA BTH1CS( 3) /    .000119818510964326E0 /
      DATA BTH1CS( 4) /   -.000006964561891648E0 /
      DATA BTH1CS( 5) /    .000000655495621447E0 /
      DATA BTH1CS( 6) /   -.000000084066228945E0 /
      DATA BTH1CS( 7) /    .000000013376886564E0 /
      DATA BTH1CS( 8) /   -.000000002499565654E0 /
      DATA BTH1CS( 9) /    .000000000529495100E0 /
      DATA BTH1CS(10) /   -.000000000124135944E0 /
      DATA BTH1CS(11) /    .000000000031656485E0 /
      DATA BTH1CS(12) /   -.000000000008668640E0 /
      DATA BTH1CS(13) /    .000000000002523758E0 /
      DATA BTH1CS(14) /   -.000000000000775085E0 /
      DATA BTH1CS(15) /    .000000000000249527E0 /
      DATA BTH1CS(16) /   -.000000000000083773E0 /
      DATA BTH1CS(17) /    .000000000000029205E0 /
      DATA BTH1CS(18) /   -.000000000000010534E0 /
      DATA BTH1CS(19) /    .000000000000003919E0 /
      DATA BTH1CS(20) /   -.000000000000001500E0 /
      DATA BTH1CS(21) /    .000000000000000589E0 /
      DATA BTH1CS(22) /   -.000000000000000237E0 /
      DATA BTH1CS(23) /    .000000000000000097E0 /
      DATA BTH1CS(24) /   -.000000000000000040E0 /
      DATA TWODPI / 0.63661977236758134E0 /
      DATA PI4 / 0.78539816339744831E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  BESY1
      IF (FIRST) THEN
         NTY1 = INITS (BY1CS, 14, 0.1*R1MACH(3))
         NTM1 = INITS (BM1CS, 21, 0.1*R1MACH(3))
         NTTH1 = INITS (BTH1CS, 24, 0.1*R1MACH(3))
!
         XMIN = 1.571*EXP ( MAX(LOG(R1MACH(1)), -LOG(R1MACH(2)))+.01)
         XSML = SQRT (4.0*R1MACH(3))
         XMAX = 1.0/R1MACH(4)
      ENDIF
      FIRST = .FALSE.
!
      IF (X .LE. 0.) THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERORR FROM BESY1DP, X ZERO OR NEGATIVE.  *******')
        CALL DPWRST('XXX','BUG ')
        BESY1DP=0.0
        RETURN
      ENDIF
      IF (X.GT.4.0) GO TO 20
!
      IF (X .LE. XMIN) THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
      ENDIF
    2 FORMAT('***** WARNING FROM BESY1DP, UNDERFLOW BECAUSE THE ',   &
             'VALUE OF X IS SO SMALL.  ****')
      Y = 0.
      IF (X.GT.XSML) Y = X*X
      BESY1DP = TWODPI*LOG(0.5*X)*BESJ1DP(X) +   &
        (0.5 + CSEVL (.125*Y-1., BY1CS, NTY1))/X
      RETURN
!
 20   CONTINUE
      IF (X.GT.XMAX) THEN
        WRITE(ICOUT,3)
        CALL DPWRST('XXX','BUG ')
        BESY1DP = 0.0
        RETURN
      ENDIF
    3 FORMAT('***** ERORR FROM BESY1DP, NO PRECISION BECAUSE THE ',   &
             'VALUE OF X IS TOO BIG.  ****')
!
      Z = 32.0/X**2 - 1.0
      AMPL = (0.75 + CSEVL (Z, BM1CS, NTM1)) / SQRT(X)
      THETA = X - 3.0*PI4 + CSEVL (Z, BTH1CS, NTTH1) / X
      BESY1DP = AMPL * SIN (THETA)
!
      RETURN
      END FUNCTION BESY1DP 
      SUBROUTINE BESYCF(ZZ,AA,NMAX,BY)
! THIS ROUTINE CALCULATES BESSEL FUNCTIONS Y OF COMPLEX ARGUMENT AND
! REAL ORDER.  ARGUMENTS ARE AS FOR ROUTINE BESJCF.
! Y*S ARE CALCULATED BY FORWARD RECURSION, USING EQUATION 9.1.27 OF
! REFERENCE (1) LISTED IN BESJCF.  TO START THE RECURSION, FUNCTION
! VALUES OF ORDERS A AND A+1 ARE CALCULATED IF A.LE.0, WHILE ORDERS A
! AND A-1 ARE CALCULATED IF A.GT.0.
! NOTE  IF ANY Y-VALUE IS SO BIG THAT ITS CALCULATION WOULD CAUSE OVER-
! FLOW, IT (AND ALL HIGHER ORDERS) ARE SET TO ZERO.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      COMPLEX BY(*),BB,CC,DD,EE,FF,GG,HH,PP,QQ,SS,YA(21),YA1(21),Z,ZINV,   &
       ZZ,ZDUMMY
      DOUBLE PRECISION PIDBL
!-----------------------------------------------------------------------
!
!  MACHINE DEPENDENT CONSTANTS.
!  ---------------------------
!
      SAVE ISAVE,PI,PINV,PIDBL,GADOL,EXPARG,DYOUK,DYOUKH,NTERM,LOU
      DATA ISAVE /1/
!
! Definition of real and imaginary parts of complex number,
! standard Fortran and will work on Convex with -r8 -i8.
      REALP(ZDUMMY) = REAL(ZDUMMY)
      AIMAGP(ZDUMMY) = REAL((0,-1)*ZDUMMY)
!
      IF (ISAVE.GT.0) THEN
        ISAVE = 0
! PI AND 1/PI
        PI = 4.0*ATAN (1.0)
        PINV = 1.0 / PI
        PIDBL = 4.0D0 * ATAN (1.0D0)
! MACHINE-DEPENDENT CONSTANTS  LARGEST REAL NUMBER (APPROX), LIMIT ON
! ARGUMENT TO LIBRARY EXP ROUTINE, MACHINE ACCURACY, ITS SQUARE ROOT,
! AND LENGTH OF VECTORS YA1 AND YA, MINUS 1.  FOR ABS(Z).LE.3, 21 TERMS
! ARE SUFFICIENT FOR 14 SIGNIFICANT FIGURE (SEE REFERENCE LISTED BELOW).
        GADOL = R1MACH (2)
        EXPARG = LOG (GADOL)
        DYOUK = R1MACH (4)
        DYOUKH = SQRT (DYOUK)
        NTERM = 20
        LOU = I1MACH(2)
      ENDIF
!
!-----------------------------------------------------------------------
      Z=ZZ
      A=AA
      MAXP=NMAX+2
      Q=REALP(Z)
      R=ABS(AIMAGP(Z))
      E=Q*Q+R*R
      IF ((A .LE. -0.5) .OR. (A .GT. 0.5) .OR. (MAXP .LT. 2) .OR.   &
         (E .EQ. 0.0) .OR. (R .GT. EXPARG)) GO TO  86
      F=SQRT(E)
      BIG=GADOL*MIN(.25,F/REAL(4*MAX(1,NMAX)))
! AVOID UNDERFLOW OR OVERFLOW IN COMPLEX DIVIDE
      F=1./F
      ZINV=2.*F/(Z*F)
! Following statement rewritten to make compilation possible
! on Convex with -r8 -i8.
!     IF(MIN(R,REAL(MAXP)).GT.3.) GO TO  20
      IF(R.GT.3.0 .AND. MAXP.GT.3) GO TO  20
      IF(E.GE.196.) GO TO 30
      IF(E.GE.9.) GO TO 20
! FOR SMALL Z, Y IS CALCULATED VIA EQUATIONS 2.1 OR N. M. TEMME, ON THE
! NUMERICAL EVALUATION OF THE ORDINARY BESSEL FUNCTION OF THE SECOND
! KIND, REPORT TW152/75, STICHTING MATHEMATISCH CENTRUM, AMSTERDAM, 9/75
      BB=.5*Z
      DD=-LOG(BB)
      EE=A*DD
      C=PINV
      IF(ABS(A).GT.DYOUKH) C=A/SIN(PI*A)
      SS = (1.0, 0.0)
      IF ((REALP (EE) ** 2 + AIMAGP (EE) ** 2) .GT. DYOUK)   &
         SS =  CMPLX (0.0, - 1.0) * SIN (CMPLX (0.0, 1.0) * EE) / EE
      EE=EXP(EE)
      CALL RECIPG(A,P,Q,G)
      GG=G*EE
      EE=.5*(EE+1./EE)
      FF=(2.*C)*(P*EE+Q*SS*DD)
      E=A*A
      PP=C*GG
      QQ=PINV/GG
      C=.5*PI*A
      R=1.
      IF(ABS(C).GT.DYOUKH) R=SIN(C)/C
      R=PI*C*R*R
      CC = (1.0, 0.0)
      DD=-BB*BB
      GG=FF+R*QQ
      C=0.
      IF(A.NE..5) C=DCOS(PIDBL*DBLE(A))
      IF(C.LE..5) GG=(PP-QQ*C)/A
      YA(1)=GG
! IF A.LE.0, CALCULATE YA1=YSUB(A+1) AS IN THE REFERENCE
      YA1(1)=PP
! IF A.GT.0, CALCULATE YA1=YSUB(A-1)=SUM(N=0 TO INFINITY) OF
! CN*(N*GN-QN*COSPI*A), WHICH CAN BE DERIVED BY SUBSTITUTING 2.2 AND 2.3
! OF THE REFERENCE INTO 1.3.
      IF(A.GT.0.) YA1(1)=-C*QQ
      TEST =DYOUK*MAX(ABS(REALP(YA(1))),ABS(AIMAGP(YA(1))))
      DO 10 N=1,NTERM
      EN=N
      G=1./(EN*EN-E)
      IF(A.GT.0.) GO TO 6
! RECUR DIRECTLY ON GG AND HH WITHOUT USING FF AS IN THE ORIGINAL PROG.
      HH=-G*(EN*(EN*GG+C*QQ)-A*PP)
      GO TO 8
    6 CONTINUE
      HH= G*(EN*(EN*GG+PP)+A*C*QQ)
    8 CONTINUE
      GG=G*(EN*GG+PP+C*QQ)
      CC=CC*DD/EN
      YA(N+1)=CC*GG
      YA1(N+1)=CC*HH
      IF(MAX(ABS(REALP(YA(N+1))),ABS(AIMAGP(YA(N+1)))).LE.TEST)GO TO 12
      PP=PP/(EN-A)
      QQ=QQ/(EN+A)
   10 CONTINUE
      RETURN
   12 N=N+1
      M=N+1
      GG = (0.0, 0.0)
      HH = (0.0, 0.0)
      DO 14 L=1,N
         ITEMP = M - L
         GG=GG+YA(ITEMP)
         HH=HH+YA1(ITEMP)
   14 CONTINUE
      BY(2)=-GG
      BY(1)=-HH*ZINV
      M=3
!CCCC IF(A) 40,40,60
      IF(A.LE.0.0)THEN
        GO TO 40
      ELSE
        GO TO 60
      ENDIF
! FOR MAG(Z) BETWEEN 3 AND 14, OR FOR ABS(IM(Z)).GT.3, CALCULATE Y VIA
! EQUATIONS 9.6.3 AND 9.6.5 OF REFERENCE 1 LISTED IN BESJCF
   20 CONTINUE
      CALL BESJCF(Z,A,NMAX,BY)
      C=-1.
      IF(AIMAGP(Z).LT.0.) C=1.
      CC=CMPLX(0.,C)
      DD=CC*Z
      CALL BESKCF(DD,A,1,YA1)
      C=.5*C*PI*A
      DD=2.*PINV*CMPLX(COS(C),SIN(C))
      BY(1)=CC*(DD*YA1(1)-BY(1))
      GG=YA1(2)
      BY(2)=-CC*BY(2)-DD*GG
      IF(MAXP.LE.2) GO TO 70
      HH=YA1(3)
      DD=CC*DD
      BY(3)=-CC*BY(3)-DD*HH
      IF(MAXP.EQ.3) GO TO 70
      ZINV=-CC*ZINV
! IN THIS LOOP, HH IS THE FUNCTION K (OF ARGUMENT IZ OR -IZ) AND CAN BE
! CALCULATED BY FORWARD RECURSION, SINCE THE REAL PART OF THE ARGUMENT
! IS NON-NEGATIVE
      DO 24 N=4,MAXP
        IF(MAX(ABS(REALP(HH)),ABS(AIMAGP(HH))).GT.BIG) GO TO 82
        FF=GG
        GG=HH
        DD=CC*DD
        HH=(ZINV*(A+REAL(N-3)))*GG+FF
        BY(N)=-CC*BY(N)-DD*HH
   24 CONTINUE
      GO TO 70
! FOR LARGE Z, USE PHASE-AMPLITUDE EQUATIONS 9.2.5 AND 9.2.6 OF REFER-
! ENCE 1 AS LISTED IN BESJCF
   30 CONTINUE
      BB=Z
      EE=ZINV
! Set FF and GG here to avoid Univac FTN compiler warnings
! that arise due to logic here and in 38-loop below.
      FF = (0.0,0.0)
      GG = (0.0,0.0)
      IF(REALP(Z).GE.0.) GO TO 32
      BB=-BB
      EE=-EE
      E=1.
      IF(AIMAGP(Z).LT.0.) E=-1.
      C=0.
      IF(A.NE..5) C=DCOS(PIDBL*DBLE(A))
      S=SIN(-E*A*PI)
      FF=CMPLX(C,S)
      GG=CMPLX(0.,2.*E*C)
   32 CONTINUE
      BB=BB-.5*PI*(A+.5)
      CC=COS(BB)
      SS=SIN(BB)
      DD=SQRT(PINV*EE)
      C=A
      DO 38 M=1,2
      CALL PHASMP(C,EE,0,PP,QQ)
      IF(REALP(Z).LT.0.) GO TO 34
! REAL(Z).GE.0, SO USE EQUATION 9.2.6
      ITEMP = 3 - M
      BY(ITEMP)=DD*(PP*SS+QQ*CC)
!CCCC IF(M-1) 36,36,38
      IF(M-1.LE.0)THEN
        GO TO 36
      ELSE
        GO TO 38
      ENDIF
! REAL(Z).LT.0, SO SUBSTITUTE 9.2.5 AND 9.2.6 INTO 9.1.36
   34 PP=PP*(FF*SS+GG*CC)
      QQ=QQ*(FF*CC-GG*SS)
      ITEMP = 3 - M
      BY(ITEMP)=DD*(PP+QQ)
      IF(M.EQ.2) GO TO 38
      FF=-FF
      GG=-GG
   36 IF(A.GT.0.) GO TO 37
      C=C+1.
      BB=-CC
      CC=SS
      SS=BB
      GO TO 38
   37 C=C-1.
      BB=-SS
      SS=CC
      CC=BB
   38 CONTINUE
      M=3
      IF(A.GT.0.) GO TO 60
   40 IF(MAXP.GE.3) BY(3)=BY(1)
      BY(1)=(A*ZINV)*BY(2)-BY(1)
      M=4
! CALCULATE Y*S BY FORWARD RECURSION, CHECKING FOR POSSIBLE OVERFLOW
   60 IF(M.GT.MAXP) GO TO 70
      DO 65 N=M,MAXP
      IF(MAX(ABS(REALP(BY(N-1))),ABS(AIMAGP(BY(N-1)))).GT.BIG) GO TO 82
      BY(N)=(ZINV*(A+REAL(N-3)))*BY(N-1)-BY(N-2)
   65 CONTINUE
   70 CONTINUE
      RETURN
   82 CONTINUE
      DO 83 L=N,MAXP
         BY(L) = (0.0, 0.0)
   83 CONTINUE
      GO TO 70
   86 CONTINUE
      WRITE (ICOUT, 88)NMAX
      CALL DPWRST('XXX','BUG ')
      WRITE (ICOUT, 89)A,Z
      CALL DPWRST('XXX','BUG ')
   88 FORMAT('***** ERROR (BESYCF) --- INVALID INPUT, NMAX = ', I6)
   89 FORMAT('      A = ', 1PE22.14,' Z = ',2(1PE22.14))
      RETURN
      END SUBROUTINE BESYCF
      DOUBLE PRECISION FUNCTION betaln(a0,b0)
!-----------------------------------------------------------------------
!     EVALUATION OF THE LOGARITHM OF THE BETA FUNCTION
!-----------------------------------------------------------------------
!     E = 0.5*LN(2*PI)
!--------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a0,b0
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION a,b,c,e,h,u,v,w,z
      INTEGER i,n
!     ..
!     .. External Functions ..
      DOUBLE PRECISION algdiv,alnrel,bcorr,gamln,gsumln
      EXTERNAL algdiv,alnrel,bcorr,gamln,gsumln
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC dlog,dmax1,dmin1
!     ..
!     .. Data statements ..
      DATA e/.918938533204673D0/
!     ..
!     .. Executable Statements ..
!--------------------------
      a = dmin1(a0,b0)
      b = dmax1(a0,b0)
      IF (a.GE.8.0D0) GO TO 100
      IF (a.GE.1.0D0) GO TO 20
!-----------------------------------------------------------------------
!                   PROCEDURE WHEN A .LT. 1
!-----------------------------------------------------------------------
      IF (b.GE.8.0D0) GO TO 10
      betaln = gamln(a) + (gamln(b)-gamln(a+b))
      RETURN
                                                                                                                                  
   10 betaln = gamln(a) + algdiv(a,b)
      RETURN
!-----------------------------------------------------------------------
!                PROCEDURE WHEN 1 .LE. A .LT. 8
!-----------------------------------------------------------------------
   20 IF (a.GT.2.0D0) GO TO 40
      IF (b.GT.2.0D0) GO TO 30
      betaln = gamln(a) + gamln(b) - gsumln(a,b)
      RETURN
                                                                                                                                  
   30 w = 0.0D0
      IF (b.LT.8.0D0) GO TO 60
      betaln = gamln(a) + algdiv(a,b)
      RETURN
!
!                REDUCTION OF A WHEN B .LE. 1000
!
   40 IF (b.GT.1000.0D0) GO TO 80
      n = int(a - 1.0D0)
      w = 1.0D0
      DO 50 i = 1,n
          a = a - 1.0D0
          h = a/b
          w = w* (h/ (1.0D0+h))
   50 CONTINUE
      w = dlog(w)
      IF (b.LT.8.0D0) GO TO 60
      betaln = w + gamln(a) + algdiv(a,b)
      RETURN
!
!                 REDUCTION OF B WHEN B .LT. 8
!
   60 n = int(b - 1.0D0)
      z = 1.0D0
      DO 70 i = 1,n
          b = b - 1.0D0
          z = z* (b/ (a+b))
   70 CONTINUE
      betaln = w + dlog(z) + (gamln(a)+ (gamln(b)-gsumln(a,b)))
      RETURN
!
!                REDUCTION OF A WHEN B .GT. 1000
!
   80 n = int(a - 1.0D0)
      w = 1.0D0
      DO 90 i = 1,n
          a = a - 1.0D0
          w = w* (a/ (1.0D0+a/b))
   90 CONTINUE
      betaln = (dlog(w)-n*dlog(b)) + (gamln(a)+algdiv(a,b))
      RETURN
!-----------------------------------------------------------------------
!                   PROCEDURE WHEN A .GE. 8
!-----------------------------------------------------------------------
  100 w = bcorr(a,b)
      h = a/b
      c = h/ (1.0D0+h)
      u = - (a-0.5D0)*dlog(c)
      v = b*alnrel(h)
      IF (u.LE.v) GO TO 110
      betaln = (((-0.5D0*dlog(b)+e)+w)-v) - u
      RETURN
                                                                                                                                  
  110 betaln = (((-0.5D0*dlog(b)+e)+w)-u) - v
      RETURN
                                                                                                                                  
      END FUNCTION betaln
      SUBROUTINE BETCDF(X,ALPHA,BETA,CDF)
!
!     NOTE--ALGORITHM ADDED SEPTEMBER 1994 (ALAN)
!           USE DBETAI ROUTINE FROM SLATEC.  THIS USES THE
!           BOSTEN AND BATTISTE ALGORITHM.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/8
!     ORIGINAL VERSION--SEPTEMBER 1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DX
      DOUBLE PRECISION DBETAI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      IF(ALPHA.LE.0.0 .OR. BETA.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)ALPHA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(X.LE.0.0)THEN
!CCCC   WRITE(ICOUT,301)X
!CCCC   CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(X.GE.1.0)THEN
!CCCC   WRITE(ICOUT,401)X
!CCCC   CALL DPWRST('XXX','BUG ')
        CDF=1.0
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR IN BETCDF--EITHER THE ALPHA OR BETA IS ',   &
             'NON-POSITIVE.')
  103 FORMAT('      THE VALUE OF ALPHA IS ',G15.7)
  104 FORMAT('      THE VALUE OF BETA IS ',G15.7,'       ******')
!C301 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BETCDF IS ',
!CCCC1       'NON-POSITIVE.  IT HAS THE VALUE ',G15.7)
!C401 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BETCDF IS GREATER ',
!CCCC1       'THAN 1.  IT HAS THE VALUE ',G15.7)
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      DCDF=DBETAI(DX,DALPHA,DBETA)
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BETCDF
      SUBROUTINE BETFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              BETA MAXIMUM LIKELIHOOD EQUATIONS.
!
!              DIGAMMA(PHAT) - DIGAMMA(PHAT + QHAT) -
!                 SUM[I=1 TO N][LOG((X(I)-A)/(B-A))] = 0
!
!              DIGAMMA(QHAT) - DIGAMMA(PHAT + QHAT) -
!                 SUM[I=1 TO N][LOG((B - X(I))/(B-A))] = 0
!
!              WITH A AND B DENOTING THE LOWER AND UPPER LIMIT
!              PARAMETERS, RESPECTIVELY.
!
!              WE FOLLOW THE TECHNIQUE OF SETTING A AND B TO THE
!              DATA MINIMUM AND MAXIMUM, RESPECTIVELY AND TREATING
!              THEM AS "KNOWN" AS OPPOSSED TO THE FULL 4-PARAMETER
!              MAXIMUM LIKELIHOOD SOLUTION.
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN (1994).  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS: VOLUME 2", SECOND EDITION,
!                JOHN WILEY, P. 223.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 CENTER FOR APPLIED MATHEMATICS
!                 NATIONAL BUREAU OF STANDARDS
!                 WASHINGTON, D. C. 20234
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/11
!     ORIGINAL VERSION--NOVEMBER  2003.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DP
      DOUBLE PRECISION DQ
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
!---------------------------------------------------------------------
!
      COMMON /BETMLE/ BETALL, BETAUL
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  ALLOW FOR USER SPECIFIED LOWER/UPPER LIMITS, OTHERWISE USE DATA
!  MINIMUM AND MAXIMUM
!
      N=2
      IFLAG=0
!
      IF(BETALL.EQ.CPUMIN .OR. BETAUL.EQ.CPUMIN)THEN
        A=XDATA(1)
        B=XDATA(1)
        DO 100 I=1,NOBS
          IF(XDATA(I).LT.A)A=XDATA(I)
          IF(XDATA(I).GT.B)B=XDATA(I)
  100   CONTINUE
      ELSE
        A=BETALL
        B=BETAUL
      ENDIF
!
!  COMPUTE SOME SUMS
!
      DA=DBLE(A)
      DB=DBLE(B)
!
      DN=DBLE(NOBS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DP=DBLE(X(1))
      DQ=DBLE(X(2))
!
      DTERM1=DPSI(DP)
      DTERM2=DPSI(DQ)
      DTERM3=DPSI(DP+DQ)
!
!  IN ORDER TO AVOID LOG OF NON-POSITIVE NUMBER, EXCLUDE VALUES
!  THAT ARE EQUAL TO A OR B
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      N1=0
      N2=0
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DTERM4=(DX - DA)/(DB - DA)
        DTERM5=(DB - DX)/(DB - DA)
        IF(DTERM4.GT.0.0D0)THEN
          DSUM1=DSUM1 + DLOG(DTERM4)
          N1=N1+1
        ENDIF
        IF(DTERM5.GT.0.0D0)THEN
          DSUM2=DSUM2 + DLOG(DTERM5)
          N2=N2+1
        ENDIF
  200 CONTINUE
!
      IF(N1.GT.0)THEN
        FVEC(1)=DTERM1 - DTERM3 - DSUM1/DBLE(N1)
      ELSE
        FVEC(1)=0.0
      ENDIF
      IF(N2.GT.0)THEN
        FVEC(2)=DTERM2 - DTERM3 - DSUM2/DBLE(N2)
      ELSE
        FVEC(2)=0.0
      ENDIF
!
!CCCC if(iflag.eq.0)then
!CCCC   print *,'nobs,a,b=',nobs,a,b
!CCCC   print *,'dp,dq=',dp,dq
!CCCC   print *,'dterm1,dterm2,dterm3=',dterm1,dterm2,dterm3
!CCCC   print *,'dsum1,dsum2=',dsum1,dsum2
!CCCC   print *,'fvec(1),fvec(2)=',fvec(1),fvec(2)
!CCCC endif
!
      RETURN
      END SUBROUTINE BETFUN 
      DOUBLE PRECISION FUNCTION BETFU2 (DALPHA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVAL FOR THE 2-PARAMETER BETA
!              MODEL (FULL SAMPLE).  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!                 2*LL(ALPHA,BETA) - 2*LL(ALPHA,BETA(ALPHA)) -
!                                    CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(ALPHA,BETA) = -N*LOG(BETA(ALPHA,BETA)) +
!                          N*(ALPHA-1)*S3 +N*(BETA-1)*S4
!
!              GIVEN CURRENT VALUE OF ALPHA, WE COMPUTE VALUE OF
!              BETA(ALPHA).  WE THEN COMPUTE THE LIKELIHOOD FUNCTION.
!              NOTE THAT LL(ALPHA,BETA) IS COMPUTED ONCE IN DPMLBE
!              AND PASSED VIA COMMON.
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 13 (SEE
!                EXAMPLE 13.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DLLAB
      DOUBLE PRECISION DK
      COMMON/BETCO9/DSUM3,DSUM4,DLLAB,DK,N
!
      DOUBLE PRECISION DBETA
      COMMON/BETCO2/DBETA
!
      DOUBLE PRECISION DALPH2
      COMMON/BETCO4/DALPH2
!
      DOUBLE PRECISION DLBETA
      EXTERNAL DLBETA
      DOUBLE PRECISION BETFU4
      EXTERNAL BETFU4
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DBETA2
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DALPH2=DALPHA
      DBETA2=DBETA
      AE=1.D-7
      RE=1.D-7
      XSTRT=DBETA2
      XLOW=XSTRT/3.0D0
      XUP=XSTRT*3.0D0
      CALL DFZER3(BETFU4,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DBETA2=XLOW
!
!  COMPUTE LL(ALPHA,BETA)
!
      DN=DBLE(N)
      DTERM1=0.0D0
      IF(DALPHA.GT.0.0D0 .AND. DBETA.GT.0.0D0)THEN
        DTERM1=-DN*DLBETA(DALPHA,DBETA2)
      ENDIF
      DTERM2=DN*(DALPHA-1.0D0)*DSUM3
      DTERM3=DN*(DBETA2-1.0D0)*DSUM4
      DTERM4=DTERM1 + DTERM2 + DTERM3
!
      BETFU2=2.0*DLLAB - 2.0D0*DTERM4 - DK
!
      RETURN
      END FUNCTION BETFU2 
      DOUBLE PRECISION FUNCTION BETFU5 (DBETA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVAL FOR THE 2-PARAMETER BETA
!              MODEL (FULL SAMPLE).  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!                 2*LL(ALPHA,BETA) - 2*LL(ALPHA,ALPHA(BETA)) -
!                                    CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(ALPHA,BETA) = -N*LOG(BETA(ALPHA,BETA)) +
!                          N*(ALPHA-1)*S3 +N*(BETA-1)*S4
!
!              GIVEN CURRENT VALUE OF BETA, WE COMPUTE VALUE OF
!              ALPHA(BETA).  WE THEN COMPUTE THE LIKELIHOOD FUNCTION.
!              NOTE THAT LL(ALPHA,BETA) IS COMPUTED ONCE IN DPMLBE
!              AND PASSED VIA COMMON.
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 14 (SEE
!                EXAMPLE 14.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DLLAB
      DOUBLE PRECISION DK
      COMMON/BETCO9/DSUM3,DSUM4,DLLAB,DK,N
!
      DOUBLE PRECISION DALPHA
      COMMON/BETCO5/DALPHA
!
      DOUBLE PRECISION DBETA2
      COMMON/BETCO3/DBETA2
!
      DOUBLE PRECISION DLBETA
      EXTERNAL DLBETA
      DOUBLE PRECISION BETFU3
      EXTERNAL BETFU3
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DALPH2
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DBETA2=DBETA
      DALPH2=DALPHA
      AE=1.D-7
      RE=1.D-7
      XSTRT=DALPH2
      XLOW=XSTRT/3.0D0
      XUP=XSTRT*3.0D0
      CALL DFZER3(BETFU3,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DALPH2=XLOW
!
!  COMPUTE LL(ALPHA,BETA)
!
      DN=DBLE(N)
      DTERM1=0.0D0
      IF(DALPHA.GT.0.0D0 .AND. DBETA.GT.0.0D0)THEN
        DTERM1=-DN*DLBETA(DALPH2,DBETA)
      ENDIF
      DTERM2=DN*(DALPH2-1.0D0)*DSUM3
      DTERM3=DN*(DBETA-1.0D0)*DSUM4
      DTERM4=DTERM1 + DTERM2 + DTERM3
!
      BETFU5=2.0*DLLAB - 2.0D0*DTERM4 - DK
!
      RETURN
      END FUNCTION BETFU5 
      DOUBLE PRECISION FUNCTION BETFU3 (DALPHA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE ALPHA SHAPE PARAMETER
!              OF A 2-PARAMETER BETA MODEL (FULL SAMPLE).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 DIGAMMA(BETA) - DIGAMMA(ALPHA + BETA) - SUM4
!
!              WITH
!
!                 SUM4 = (1/N)*SUM[i=1 to N][LOG((B - X(i))]/(B-A)
!                 N        = SAMPLE SIZE
!                 A        = LOWER LIMIT
!                 B        = UPPER LIMIT
!
!              NOTE THAT DIGAMMA(BETA) AND SUM4 DO NOT DEPEND ON
!              THE VALUE OF ALPHA, SO THESE ARE COMPUTED ONCE AND
!              PASSED VIA COMMON BLOCKS.
!
!              GIVEN A VALUE FOR THE BETA SHAPE PARAMETER (DBETA), WE
!              NEED TO DETERMINE THE VALUE OF THE ALPHA SHAPE PARAMETER
!              (DALPHA).
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER2 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 14 (SEE
!                EXAMPLE 14.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DLLAB
      DOUBLE PRECISION DK
      COMMON/BETCO9/DSUM3,DSUM4,DLLAB,DK,N
!
      DOUBLE PRECISION DBETA
      COMMON/BETCO3/DBETA
!
      DOUBLE PRECISION DN
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBG4.EQ.'TFU3')THEN
        WRITE(ICOUT,11)DX(1)
   11   FORMAT('**** AT THE BEGINNING OF BETFU3--DX(1) = ',G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      DN=DBLE(N)
      BETFU3=DPSI(DALPHA) - DPSI(DALPHA + DBETA) - DSUM3
!
      RETURN
      END FUNCTION BETFU3 
      DOUBLE PRECISION FUNCTION BETFU4 (DBETA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE BETA SHAPE PARAMETER
!              OF A 2-PARAMETER BETA MODEL (FULL SAMPLE).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 DIGAMMA(ALPHA) - DIGAMMA(ALPHA + BETA) - SUM3
!
!              WITH
!
!                 SUM3 = (1/N)*SUM[i=1 to N][LOG((X(i) - A)]/(B-A)
!                 N        = SAMPLE SIZE
!                 A        = LOWER LIMIT
!                 B        = UPPER LIMIT
!
!              NOTE THAT DIGAMMA(ALPHA) AND SUM3 DO NOT DEPEND ON
!              THE VALUE OF BETA, SO THESE ARE COMPUTED ONCE AND
!              PASSED VIA COMMON BLOCKS.
!
!              GIVEN A VALUE FOR THE ALPHA SHAPE PARAMETER (DALPHA),
!              DETERMINE VALUE OF BETA.  THIS IS
!              THE ROOT OF THE ABOVE EQUATION.
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER2 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 14 (SEE
!                EXAMPLE 14.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DLLAB
      DOUBLE PRECISION DK
      COMMON/BETCO9/DSUM3,DSUM4,DLLAB,DK,N
!
      DOUBLE PRECISION DALPHA
      COMMON/BETCO4/DALPHA
!
      DOUBLE PRECISION DN
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBG4.EQ.'TFU3')THEN
        WRITE(ICOUT,11)DX(1)
   11   FORMAT('**** AT THE BEGINNING OF BETFU3--DX(1) = ',G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      DN=DBLE(N)
      BETFU4=DPSI(DBETA) - DPSI(DALPHA + DBETA) - DSUM4
!
      RETURN
      END FUNCTION BETFU4 
      REAL FUNCTION BETFU7(ALPHA)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING CONFIDENCE LIMITS
!              FOR PERCENTILES OF THE BETA DISTRIBUTION (BASED ON
!              MAXIMUM LIKELIHOOD ESTIMATION).  THIS FUNCTION
!              COMPUTES THE DERIVATIVE OF THE BETA PERCENT POINT
!              FUNCTION WITH RESPECT TO THE ALPHA SHAPE PARAMETER.
!
!              CALLED BY DIFF ROUTINE FOR FINDING THE DERIVATIVE
!              OF A FUNCTION.
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      REAL ALPHA
!
      COMMON/BETCO7/P,BETA
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL BETPPF(P,ALPHA,BETA,APPF)
      BETFU7=APPF
!
      RETURN
      END FUNCTION BETFU7
      REAL FUNCTION BETFU8(BETA)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING CONFIDENCE LIMITS
!              FOR PERCENTILES OF THE BETA DISTRIBUTION (BASED ON
!              MAXIMUM LIKELIHOOD ESTIMATION).  THIS FUNCTION
!              COMPUTES THE DERIVATIVE OF THE BETA PERCENT POINT
!              FUNCTION WITH RESPECT TO THE BETA SHAPE PARAMETER.
!
!              CALLED BY DIFF ROUTINE FOR FINDING THE DERIVATIVE
!              OF A FUNCTION.
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER   2004.
!
!---------------------------------------------------------------------
!
      REAL BETA
!
      COMMON/BETCO8/P,ALPHA
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL BETPPF(P,ALPHA,BETA,APPF)
      BETFU8=APPF
!
      RETURN
      END FUNCTION BETFU8
      SUBROUTINE BETLI1(Y,N,NP,   &
                        A,B,ALPHA,BETA,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LOG-LIKIHOOD FUNCTION FOR
!              THE BETA DISTRIBUTION.  THIS IS FOR THE RAW
!              DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              NOTE THAT THE LOWER AND UPPER LIMITS MUST BE EXPLICITLY
!              GIVEN.  THE ARGUMENT NP SHOULD BE 2 FOR A 2-PARAMETER
!              BETA AND 4 FOR A 4-PARAMETER BETA.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 14.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/06
!     ORIGINAL VERSION--JUNE      2013.
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DBETA
      EXTERNAL DBETA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETAZ
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BETL'
      ISUBN2='I1  '
!
      IWRITE='OFF'
      IERROR='NO'
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BETLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,A,B,ALPHA,BETA
   52   FORMAT('IBUGA3,ISUBRO,N,A,B,ALPHA,BETA = ',2(A4,2X),I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MINIM(Y,N,IWRITE,YMIN,IBUGA3,IERROR)
      CALL MAXIM(Y,N,IWRITE,YMAX,IBUGA3,IERROR)
      IF(A.GE.YMIN .OR. B.LE.YMAX)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('**** ERROR IN BETA LOG-LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('     INVALID LIMITS:')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)A
  105   FORMAT('     LOWER LIMIT    = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,106)YMIN
  106   FORMAT('     DATA MINIMUM   = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,107)B
  107   FORMAT('     UPPER LIMIT    = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,108)YMAX
  108   FORMAT('     DATA MAXIMUM   = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     THE LOG-LIKLIHOOD FUNCTION FOR THE BETA DISTRIBUTION IS:
!
!     (ALPHA-1)*SUM[LOG(Y(i) - A)] + (BETA-1)*SUM[LOG(B - Y(i))]  -
!     N*LOG(B'(2,BETA)) - N*(ALPHA+BETA-1)*LOG(B-A)
!
      DN=DBLE(N)
      DALPHA=DBLE(ALPHA)
      DBETAZ=DBLE(BETA)
      DA=DBLE(A)
      DB=DBLE(B)
!
      DTERM2=DBETA(DALPHA,DBETAZ)
      DTERM1=-DN*DLOG(DTERM2) - DN*(DALPHA+DBETAZ-1.0D0)*DLOG(DB-DA)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DLOG(DX - DA)
        DSUM2=DSUM2 + DLOG(DB - DX)
 1000 CONTINUE
!
      DLIK=(DALPHA-1.0D0)*DSUM1 + (DBETAZ-1.0D0)*DSUM2 + DTERM1
      ALIK=REAL(DLIK)
      IF(NP.EQ.2)THEN
        DNP=2.0D0
      ELSEIF(NP.EQ.4)THEN
        DNP=4.0D0
      ELSE
        DNP=4.0D0
      ENDIF
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BETLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)DTERM1,DSUM1,DSUM2
 9055   FORMAT('DTERM1,DSUM1,DSUM2,DLIK = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)AIC,AICC,BIC
 9057   FORMAT('AIC,AICC,BIC = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BETLI1
      SUBROUTINE BETML1(Y,N,DTEMP1,MAXNXT,AUSER,BUSER,   &
                        XMIN,XMAX,XMEAN,XSD,XVAR,   &
                        A,B,   &
                        ALPHMO,BETAMO,   &
                        ALPHML,BETAML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD AND
!              METHOD OF MOMENT ESTIMATES FOR THE BETA DISTRIBUTION.
!              THIS IS FOR THE 2-PARAMETER CASE (I.E., THE LOWER
!              AND UPPER LIMITS ARE ASSUMED KNOWN AND FIXED).
!
!
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--EVANS, HASTINGS, AND PEACOCK.  "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2000,
!                PP. 34-42.
!                JOHNSON, KOTZ, AND BALAKRISHNAN.  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS, VOLUME II", SECOND
!                EDITION, WILEY, 1994.
!              --KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 14.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLTO)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!CCCC DOUBLE PRECISION DAE
!CCCC DOUBLE PRECISION DRE
!CCCC DOUBLE PRECISION DXSTRT
!CCCC DOUBLE PRECISION DXLOW
!CCCC DOUBLE PRECISION DXUP
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPROD1
      DOUBLE PRECISION DPROD2
      DOUBLE PRECISION DN
!
      EXTERNAL BETFUN
      COMMON /BETMLE/ BETALL, BETAUL
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BETM'
      ISUBN2='L1  '
!
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BETML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',A4,2X,A4,2X,2I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)AUSER,BUSER
   53   FORMAT('AUSER,BUSER = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR BETA MLE ESTIMATE               **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='BETA'
      IFLAG=0
      CALL SORT(Y,N,Y)
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     NOTE 2013/06: IF NO USER LIMITS GIVEN, SET FUDGE FACTOR TO
!                   1% (INSTEAD OF A VERY SMALL FIXED EPSION VALUE).
!
      IF((AUSER.EQ.CPUMIN .OR. BUSER.EQ.CPUMIN) .OR.   &
         (AUSER.GE.XMIN .OR. BUSER.LE.XMAX))THEN
        IF((XMIN.GE.0.0 .AND. XMIN.LE.1.0) .AND.   &
           (XMAX.GE.0.0 .AND. XMAX.LE.1.0))THEN
          A=0.0
          B=1.0
        ELSE
          EPS=(XMAX - XMIN)*0.01
          A=XMIN - EPS
          B=XMAX + EPS
        ENDIF
        BETALL=A
        BETAUL=B
      ELSE
        BETALL=AUSER
        BETAUL=BUSER
        A=AUSER
        B=BUSER
      ENDIF
!
      XMEAN1=(XMEAN-A)/(B-A)
      VAR1=XVAR/((B-A)**2)
      ALPHMO=XMEAN1*(XMEAN1*(1.0-XMEAN1)/VAR1 - 1.0)
      BETAMO=(1.0-XMEAN1)*(XMEAN1*(1.0-XMEAN1)/VAR1 - 1.0)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,1001)A,B,BETALL,BETAUL
 1001   FORMAT('A,B,BETALL,BETAUL = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1003)XVAR,VAR1,XMEAN1,ALPHMO,BETAMO
 1003   FORMAT('XVAR,VAR1,XMEAN1,ALPHMO,BETAMO = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      XPAR(1)=DBLE(ALPHMO)
      XPAR(2)=DBLE(BETAMO)
      DPROD1=1.0D0
      DPROD2=1.0D0
      DN=DBLE(N)
!
      DO 3101 I=1,N
        DTERM1=DBLE((B-Y(I))/(B-A))**(1.0D0/DN)
        DTERM2=DBLE( (Y(I)-A)/(B-A))**(1.0D0/DN)
        IF(DTERM1.NE.0.0D0)DPROD1=DPROD1*DTERM1
        IF(DTERM2.NE.0.0D0)DPROD2=DPROD2*DTERM2
 3101 CONTINUE
!CCCC XPAR(1)=0.5D0*(1.0D0 - DPROD1)/(1.0D0 - DPROD2 - DPROD1)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,1011)DPROD1,DPROD2,XPAR(1)
 1011   FORMAT('DPROD1,DPROD2,XPAR(1) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      DO 3103 I=1,N
        DTERM1=DBLE((Y(I)-A)/(B-A))**(1.0D0/DN)
        DTERM2=DBLE( (B-Y(I))/(B-A))**(1.0D0/DN)
        IF(DTERM1.NE.0.0D0)DPROD1=DPROD1*DTERM1
        IF(DTERM2.NE.0.0D0)DPROD2=DPROD2*DTERM2
 3103 CONTINUE
!CCCC XPAR(2)=0.5D0*(1.0D0 - DPROD1)/(1.0D0 - DPROD1 - DPROD2)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,1013)DPROD1,DPROD2,XPAR(2)
 1013   FORMAT('DPROD1,DPROD2,XPAR(2) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(BETFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      ALPHML=REAL(XPAR(1))
      BETAML=REAL(XPAR(2))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BETML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)ALPHMO,BETAMO,ALPHML,BETAML
 9057   FORMAT('ALPHMO,BETAMO,ALPHML,BETAML = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BETML1
      SUBROUTINE BETML4(Y,N,DTEMP1,MAXNXT,   &
                        XMIN,XMAX,XMEAN,XSD,XVAR,   &
                        AMOM,BMOM,ALPHMO,BETAMO,   &
                        AML,BML,ALPHML,BETAML,MLFLAG,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD AND
!              METHOD OF MOMENT ESTIMATES FOR THE BETA DISTRIBUTION.
!              THIS IS FOR THE 4-PARAMETER CASE (I.E., THE LOWER
!              AND UPPER LIMITS ARE ESTIMATED FROM THE DATA).
!
!              NOTE THAT ML ESTIMATION CAN BE PROBLEMATIC FOR THE
!              4-PARAMETER BETA, PARTICULARLY FOR SMALL SAMPLES.
!              RETURN A FLAG THAT INDICATES WHETHER OR NOT ML
!              PROCEDURE CONVERGED.
!
!     EXAMPLE--4-PARAMETER BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--EVANS, HASTINGS, AND PEACOCK.  "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2000,
!                PP. 34-42.
!                JOHNSON, KOTZ, AND BALAKRISHNAN.  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS, VOLUME II", SECOND
!                EDITION, WILEY, 1994.
!              --KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 14.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLB4)
!     UPDATED         --JUNE      2013. IF "IDFTTY" IS SET TO MOMENTS,
!                                       THEN SKIP ML STEP
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!CCCC DOUBLE PRECISION DAE
!CCCC DOUBLE PRECISION DRE
!CCCC DOUBLE PRECISION DXSTRT
!CCCC DOUBLE PRECISION DXLOW
!CCCC DOUBLE PRECISION DXUP
!
      DOUBLE PRECISION BE4FUN
      EXTERNAL BE4FUN
      DOUBLE PRECISION BE4FU2
      EXTERNAL BE4FU2
!
!CCCC DOUBLE PRECISION DEPS
      DOUBLE PRECISION DN
!CCCC DOUBLE PRECISION DANS(10)
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
!CCCC DOUBLE PRECISION DC
!CCCC DOUBLE PRECISION DALPHA
!CCCC DOUBLE PRECISION DBETA
!CCCC DOUBLE PRECISION DALPBE
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION DTERM3
!CCCC DOUBLE PRECISION DTERM4
!CCCC DOUBLE PRECISION DTERM5
!CCCC DOUBLE PRECISION DTERM6
!CCCC DOUBLE PRECISION DTERM7
!CCCC DOUBLE PRECISION DTERM8
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DM1
      DOUBLE PRECISION DM2
      DOUBLE PRECISION DM3
      DOUBLE PRECISION DM4
!
      DOUBLE PRECISION DM1P
      DOUBLE PRECISION DM2P
      DOUBLE PRECISION DM3P
      DOUBLE PRECISION DM4P
      COMMON /BET4ML/ DM2P, DM3P, DM4P
!
      DOUBLE PRECISION SIGMA
      DOUBLE PRECISION S5
      DOUBLE PRECISION S6
      DOUBLE PRECISION S7
      DOUBLE PRECISION S8
      DOUBLE PRECISION DXMIN
      DOUBLE PRECISION DXMAX
      COMMON /BET4M2/ S5, S6, S7, S8, SIGMA, DXMIN, DXMAX
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
      INCLUDE 'DPCOST.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BETM'
      ISUBN2='L4  '
!
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BETML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',A4,2X,A4,2X,2I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)AUSER,BUSER
   53   FORMAT('AUSER,BUSER = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR BETA MLE ESTIMATE               **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      AMOM=CPUMIN
      BMOM=CPUMIN
      ALPHMO=CPUMIN
      BETAMO=CPUMIN
      AML=CPUMIN
      BML=CPUMIN
      ALPHML=CPUMIN
      BETAML=CPUMIN
!
      IDIST='BETA'
      IFLAG=0
      CALL SORT(Y,N,Y)
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DN=DBLE(N)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DO 1010 I=1,N
        DSUM1=DSUM1 + DBLE(Y(I))
        DSUM2=DSUM2 + DBLE(Y(I))**2
        DSUM3=DSUM3 + DBLE(Y(I))**3
        DSUM4=DSUM4 + DBLE(Y(I))**4
 1010 CONTINUE
      DM1=DSUM1/DN
      DM2=DSUM2/DN
      DM3=DSUM3/DN
      DM4=DSUM4/DN
      DM1P=DM1
      DM2P=DM2 - DM1**2
      DM3P=DM3 - 3.0D0*DM1*DM2 + 2.0D0*(DM1**3)
      DM4P=DM4 - 4.0D0*DM1*DM3 + 6.0D0*(DM1**2)*DM2 - 3.0D0*(DM1**4)
!
      XPAR(1)=1.0D0
      XPAR(2)=1.0D0
!
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(BE4FUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      ALPHMO=REAL(XPAR(1))
      BETAMO=REAL(XPAR(2))
!
      EPS=DBLE(XMAX - XMIN)*0.001D0
      DA=DBLE(ALPHMO)
      DB=DBLE(BETAMO)
      DTERM1=DA*(DA+DB+1.0D0)
      DTERM2=DB
      AMOM=DM1 - DSQRT(DM2P)*DSQRT(DTERM1/DTERM2)
      DTERM1=DB*(DA+DB+1.0D0)
      DTERM2=DA
      BMOM=DM1 + DSQRT(DM2P)*DSQRT(DTERM1/DTERM2)
      IF(AMOM.GE.XMIN)AMOM=XMIN - EPS
      IF(BMOM.LE.XMAX)BMOM=XMAX + EPS
!
!     NOW ATTEMPT ML ESTIMATION
!
      IF(IDFTTY.EQ.'MOME')THEN
        AML=CPUMIN
        BML=CPUMIN
        ALPHML=CPUMIN
        BETAML=CPUMIN
        GO TO 9000
      ENDIF
!
      XPAR(1)=DBLE(AMOM)
      XPAR(2)=DBLE(BMOM)
!
      DXMIN=DBLE(XMIN)
      DXMAX=DBLE(XMAX)
!
      IF(DA.GE.DXMIN)THEN
        XPAR(1)=DXMIN - 0.1*(DXMAX-DXMIN)
      ENDIF
      IF(DB.LE.DXMAX)THEN
        XPAR(2)=DXMAX + 0.1*(DXMAX-DXMIN)
      ENDIF
!
      IOPT=2
      TOL=1.0D-5
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(BE4FU2,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      IF(INFO.NE.1)THEN
        MLFLAG=1
        GO TO 4099
      ELSE
        MLFLAG=0
      ENDIF
      AML=REAL(XPAR(1))
      BML=REAL(XPAR(2))
!
!     SOMETIMES WE CAN GET "CONVERGENCE" TO AN UNREASONABLE VALUE.
!     CHECK THAT LOWER/UPPER LIMITS WITHIN 3 TIMES THE WIDTH
!     OF THE DATA.
!
      XWIDTH=XMAX - XMIN
      XUPP=XMAX + 3.0*XWIDTH
      XLOW=XMIN - 3.0*XWIDTH
      IF(AML.LT.XLOW .OR. BML.GT.XUPP)THEN
        MLFLAG=1
        GO TO 4099
      ENDIF
!
      ALPHML=REAL(S5*(SIGMA*S6-1.0D0)/(S6*(SIGMA*S5-1.0D0)-S5))
      BETAML=REAL(S6*(SIGMA*S5-1.0D0)/(S6*(SIGMA*S5-1.0D0)-S5))
!
 4099 CONTINUE
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'TML4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BETML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)AMON,BMOM,ALPHMO,BETAMO
 9056   FORMAT('AMON,BMOM,ALPHMO,BETAMO = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9057)MLFLAG,AML,BML,ALPHML,BETAML
 9057   FORMAT('MLFLAG,AML,BML,ALPHML,BETAML = ',I5,4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BETML4
      SUBROUTINE BETPDF(X,ALPHA,BETA,PDF)
!
!     NOTE--BETA PDF IS:
!              BETPDF(X,A,B) = X**(A-1)*(1-X)**(B-1)/BETA(A,B)
!           WHERE BETA(A,B) IS THE COMPLETE BETA FUNCTION.
!           USE LOGARITHMS TO OBTAIN:
!              LN(BETAPDF) = (A-1)*LN(X)+(B-1)*LN(1-X)-LN(BETA(A,B))
!           AND THEN TAKE EXPONENT.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/8
!     ORIGINAL VERSION--SEPTEMBER 1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DLBETA
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN BETCDF--THE SECOND ARGUMENT TO ',   &
               'BETPDF (ALPHA) IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)ALPHA
  103   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,102)
  102   FORMAT('***** ERROR IN BETCDF--THE THIRD ARGUMENT TO ',   &
               'BETPDF (BETA) IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)BETA
        CALL DPWRST('XXX','BUG ')
      ELSEIF(ALPHA.LT.1.0 .AND. BETA.LT.1.0)THEN
!
!       IF ALPHA < 1, UNDEFINED AT 0
!       IF BETA  < 1, UNDEFINED AT 1
!
        IF(X.LE.0.0)THEN
          WRITE(ICOUT,301)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ELSEIF(X.GE.1.0)THEN
          WRITE(ICOUT,402)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
      ELSEIF(ALPHA.LT.1.0)THEN
        IF(X.LE.0.0)THEN
          WRITE(ICOUT,301)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
        IF(X.GT.1.0)THEN
          WRITE(ICOUT,401)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
      ELSEIF(BETA.LT.1.0)THEN
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,302)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
        IF(X.GE.1.0)THEN
          WRITE(ICOUT,402)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
      ENDIF
  301 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BETPDF IS ',   &
             'NON-POSITIVE.  IT HAS THE VALUE ',G15.7)
  302 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BETPDF IS ',   &
             'NEGATIVE.  IT HAS THE VALUE ',G15.7)
  401 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BETPDF IS GREATER ',   &
             'THAN 1.  IT HAS THE VALUE ',G15.7)
  402 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BETPDF IS GREATER ',   &
             'THAN OR EQUAL TO 1.  IT HAS THE VALUE ',G15.7)
!
!CCCC IF(X.LE.0.0.OR.X.GE.1.0)GO TO 900
      IF(X.LE.0.0)THEN
        IF(ALPHA.EQ.1.0 .AND. BETA.EQ.1.0)THEN
          PDF=1.0
        ELSE
          PDF=0.0
        ENDIF
      ELSEIF(X.GE.1.0)THEN
        IF(ALPHA.EQ.1.0 .AND. BETA.EQ.1.0)THEN
          PDF=1.0
        ELSE
          PDF=0.0
        ENDIF
      ELSE
        DX=DBLE(X)
        DALPHA=DBLE(ALPHA)
        DBETA=DBLE(BETA)
        DTERM3=DLBETA(DALPHA,DBETA)
        DTERM1=(DALPHA-1.D0)*DLOG(DX)
        DTERM2=(DBETA-1.D0)*DLOG(1.D0-DX)
        DTERM4=DTERM1 + DTERM2 - DTERM3
        DPDF=DEXP(DTERM4)
        PDF=REAL(DPDF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BETPDF
      SUBROUTINE BETPPF(P,ALPHA,BETA,PPF)
!
!     NOTE--ALGORITHM ADDED SEPTEMBER 1994 (ALAN)
!           USE ALGORITHM FROM KENNEDY AND GENTLE (PP. 109-112) WITH
!           THE MODIFICATION THAT WE USE OUR BETA CDF ROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JULY      1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DX
      DOUBLE PRECISION DBETAI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0E-6/
      DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /200/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GT.1.0)GO TO 50
      IF(ALPHA.LE.0.0)GO TO 55
      IF(BETA.LE.0.0)GO TO 60
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   55 WRITE(ICOUT,11)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)ALPHA
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   60 WRITE(ICOUT,25)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)BETA
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      GO TO 9999
   90 CONTINUE
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
             'BETPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
             'BETPPF IS NON-POSITIVE')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
             'BETPPF IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      A = ALPHA
      B = BETA
!
      IERR=0
      IC = 0
      AB = A/B
      XL = 0.0
      XR = 1.0
      FXL = -P
      FXR = 1.0 - P
!CCCC INVALID P EXPLICITLY CHECKED FOR EARLIER.
      IF(FXL*FXR .GT. ZERO)GO TO 50
!
!  BISECTION METHOD
!
  105 CONTINUE
      X = (XL+XR)*0.5
      DX=DBLE(X)
      DALPHA=DBLE(A)
      DBETA=DBLE(B)
      DCDF=DBETAI(DX,DALPHA,DBETA)
      P1=REAL(DCDF)
      PPF=X
!CCCC IF(IERR.NE.0)THEN
!CCCC   WRITE(ICOUT,120)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC ENDIF
!C120 FORMAT('***** FATAL ERROR--ERROR IN BETCDF ROUTINE.  *****')
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** FATAL ERROR--BETPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BETPPF
      SUBROUTINE BETRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BETA DISTRIBUTION
!          WITH SINGLE PRECISION SHAPE
!          PARAMETERS = ALPHA AND BETA.
!              THE PROTOTYPE BETA DISTRIBUTION USED
!              HEREIN HAS MEAN = ALPHA/(ALPHA+BETA)
!              AND STANDARD DEVIATION =
!              SQRT((ALPHA*BETA) / ((ALPHA+BETA)**2)*(ALPHA+BETA+1))
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              BETWEEN 0.0 (INCLUSIVELY) AND 1.0 (INCLUSIVELY).
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/CONSTANT) * X**(ALPHA-1) * (1.0-X)**(BETA-1)
!              WHERE THE CONSTANT = THE BETA FUNCTION EVALUATED
!              AT THE VALUES ALPHA AND BETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST  SHAPE PARAMETER.
!                                ALPHA SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.0.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                                BETA  SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.0.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BETA DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA SHOULD BE GREATER THAN
!                   OR EQUAL TO 1.0.
!                 --BETA  SHOULD BE GREATER THAN
!                   OR EQUAL TO 1.0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, NORRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT, EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--GREENWOOD, 'A FAST GENERATOR FOR
!                 BETA-DISTRIBUTED RANDOM VARIABLES',
!                 COMPSTAT 1974, PROCEEDINGS IN
!                 COMPUTATIONAL STATISTICS, VIENNA,
!                 SEPTEMBER, 1974, PAGES 19-27.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 24-27.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGES 36-37.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 37-56.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 30-35.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 952.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82.3
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --JUNE      1978.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --DECEMBER  2001. FOR ALPHA < 1 OR BETA < 1,
!                                       USE PERCENT POINT METHOD
!     UPDATED         --NOVEMBER  2001. FOR ALPHA < 1 OR BETA < 1,
!                                       USE JOHNK'S ALGORITHM
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DIMENSION XN(2)
      DIMENSION U(2)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA ATHIRD/0.33333333/
      DATA SQRT3 /1.73205081/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      IF(ALPHA.LE.0.0)GO TO 60
      IF(BETA.LT.0.0)GO TO 65
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   60 WRITE(ICOUT,16)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)ALPHA
      CALL DPWRST('XXX','BUG ')
      RETURN
   65 WRITE(ICOUT,26)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)BETA
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE FIRST  INPUT ARGUMENT TO THE ',   &
      ' BETRAN SUBROUTINE IS NON-POSITIVE *****')
   16 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      ' BETRAN SUBROUTINE IS SMALLER THAN 0.0 *****')
   26 FORMAT('***** FATAL ERROR--THE THIRD  INPUT ARGUMENT TO THE ',   &
      ' BETRAN SUBROUTINE IS SMALLER THAN 0.0 *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N BETA RANDOM NUMBERS
!     BY USING THE FACT THAT
!     IF X1 IS A GAMMA VARIATE WITH PARAMETER ALPHA
!     AND IF X2 IS A GAMMA VARIATE WITH PARAMETER BETA,
!     THEN THE RATIO X1/(X1+X2) IS A BETA VARIATE
!     WITH PARAMETERS ALPHA AND BETA.
!
!     TO GENERATE N GAMMA DISTRIBUTION RANDOM NUMBERS,
!     USE GREENWOOD'S REJECTION ALGORITHM--
!     1) GENERATE A NORMAL RANDOM NUMBER;
!     2) TRANSFORM THE NORMAL VARIATE TO AN APPROXIMATE
!        GAMMA VARIATE USING THE WILSON-HILFERTY
!        APPROXIMATION (SEE THE JOHNSON AND KOTZ
!        REFERENCE, PAGE 176);
!     3) FORM THE REJECTION FUNCTION VALUE, BASED
!        ON THE PROBABILITY DENSITY FUNCTION VALUE
!        OF THE ACTUAL DISTRIBUTION OF THE PSEUDO-GAMMA
!        VARIATE, AND THE PROBABILITY DENSITY FUNCTION VALUE
!        OF A TRUE GAMMA VARIATE.
!     4) GENERATE A UNIFORM RANDOM NUMBER;
!     5) IF THE UNIFORM RANDOM NUMBER IS LESS THAN
!        THE REJECTION FUNCTION VALUE, THEN ACCEPT
!        THE PSEUDO-RANDOM NUMBER AS A GAMMA VARIATE;
!        IF THE UNIFORM RANDOM NUMBER IS LARGER THAN
!        THE REJECTION FUNCTION VALUE, THEN REJECT
!        THE PSEUDO-RANDOM NUMBER AS A GAMMA VARIATE.
!
!     FOR ALPHA < 1 AND BETA < 1, USE JOHNK'S ALGORITHM
!     (JAMES GENTLE, "RANDOM NUMBER GENERATION AND MONTE CARLO
!     METHODS", SECOND EDITION, SPRINGER-VERLANG, 2003.
!     FOR ALPHA OR BETA <= 0, THEN USE THE PERCENT POINT METHOD.
!
      IF(ALPHA.EQ.1.0 .AND. BETA.EQ.1.0)THEN
        CALL UNIRAN(N,ISEED,X)
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LT.1.0 .AND. BETA.LT.1.0)THEN
        NTEMP=1
        DO 400 I=1,N
  401     CONTINUE
          CALL UNIRAN(NTEMP,ISEED,X(I))
          U1=X(I)
          CALL UNIRAN(NTEMP,ISEED,X(I))
          U2=X(I)
          V1=U1**(1.0/ALPHA)
          V2=U2**(1.0/BETA)
          W=V1 + V2
          IF(W.GT.1)GO TO 401
          X(I)=V1/W
  400   CONTINUE
        GO TO 9000
      ENDIF
!
!     FOR CASE WHERE ALPHA < 1 AND BETA > 1 (OR SIMILARLY,
!     WHEN ALPHA > 1 AND BETA < 1), USE ALGORITHM GIVEN BY
!     IN: "A FAMILY OF SWITCHING ALGORITHMS FOR THE COMPUTER
!     GENERATION OF BETA RANDOM VARIABLES", A. C. ATKINSON,
!     BIOMETRIKA, 1979, 66, 1, PP. 141-145.
!
      IF(ALPHA.LE.1.0 .AND. BETA.GE.1.0)THEN
        NTEMP=2
        P=ALPHA
        Q=BETA
        S1=1.0
!CCCC   T=(ALPHA-1.0)/(BETA+1.0-ALPHA)
        T=(1.0-ALPHA)/(BETA+1.0-ALPHA)
        S2=T**(ALPHA-1.0)
        R=BETA*T/(BETA*T + ALPHA*(1.0-T)**BETA)
!
        DO 600 I=1,N
  610     CONTINUE
          CALL UNIRAN(NTEMP,ISEED,U)
          U1=U(1)
          U2=U(2)
          IF(U1.LE.R)THEN
            XTEMP=T*(U1/R)**(1.0/P)
            H1=XTEMP**(ALPHA-P)*(1.0-XTEMP)**(BETA-1.0)
            IF(S1*U2.LE.H1)THEN
              X(I)=XTEMP
              GO TO 600
            ELSE
              GO TO 610
            ENDIF
          ELSE
            XTEMP=1.0 - (1.0-T)*((1.0-U1)/(1.0-R))**(1.0/Q)
            H2=XTEMP**(ALPHA-1.0)
            IF(S2*U2.LE.H2)THEN
              X(I)=XTEMP
              GO TO 600
            ELSE
              GO TO 610
            ENDIF
          ENDIF
  600   CONTINUE
!CCCC   DO600I=1,N
!CCCC     CALL BETPPF(X(I),ALPHA,BETA,XTEMP)
!CCCC     X(I)=XTEMP
!C600   CONTINUE
        GO TO 9000
      ENDIF
      IF(ALPHA.GE.1.0 .AND. BETA.LE.1.0)THEN
!
        ALPSAV=ALPHA
        BETSAV=BETA
        ALPHA=BETSAV
        BETA=ALPSAV
!
        NTEMP=2
        P=ALPHA
        Q=BETA
        S1=1.0
        T=(1.0-ALPHA)/(BETA+1.0-ALPHA)
        S2=T**(ALPHA-1.0)
        R=BETA*T/(BETA*T + ALPHA*(1.0-T)**BETA)
!
        DO 700 I=1,N
  710     CONTINUE
          CALL UNIRAN(NTEMP,ISEED,U)
          U1=U(1)
          U2=U(2)
          IF(U1.LE.R)THEN
            XTEMP=T*(U1/R)**(1.0/P)
            H1=XTEMP**(ALPHA-P)*(1.0-XTEMP)**(BETA-1.0)
            IF(S1*U2.LE.H1)THEN
              X(I)=1.0-XTEMP
              GO TO 700
            ELSE
              GO TO 710
            ENDIF
          ELSE
            XTEMP=1.0 - (1.0-T)*((1.0-U1)/(1.0-R))**(1.0/Q)
            H2=XTEMP**(ALPHA-1.0)*(1.0-XTEMP)**(BETA-Q)
            IF(S2*U2.LE.H2)THEN
              X(I)=1.0-XTEMP
              GO TO 700
            ELSE
              GO TO 710
            ENDIF
          ENDIF
  700   CONTINUE
        ALPHA=ALPSAV
        BETA=BETSAV
        GO TO 9000
      ENDIF
!
      A1=1.0/(9.0*ALPHA)
      B1=SQRT(A1)
      XN01=-SQRT3+B1
      XG01=ALPHA*(1.0-A1+B1*XN01)**3
      A2=1.0/(9.0*BETA)
      B2=SQRT(A2)
      XN02=-SQRT3+B2
      XG02=BETA*(1.0-A2+B2*XN02)**3
!
      DO 100 I=1,N
!
  150 CALL NORRAN(1,ISEED,XN)
      XG=ALPHA*(1.0-A1+B1*XN(1))**3
      IF(XG.LT.0.0)GO TO 150
      TERM=(XG/XG01)**(ALPHA-ATHIRD)
      ARG=0.5*XN(1)*XN(1)-XG-0.5*XN01*XN01+XG01
      FUNCT=TERM*EXP(ARG)
      CALL UNIRAN(1,ISEED,U)
      IF(U(1).LE.FUNCT)GO TO 170
      GO TO 150
  170 XG1=XG
!
  250 CALL NORRAN(1,ISEED,XN)
      XG=BETA*(1.0-A2+B2*XN(1))**3
      IF(XG.LT.0.0)GO TO 250
      TERM=(XG/XG02)**(BETA-ATHIRD)
      ARG=0.5*XN(1)*XN(1)-XG-0.5*XN02*XN02+XG02
      FUNCT=TERM*EXP(ARG)
      CALL UNIRAN(1,ISEED,U)
      IF(U(1).LE.FUNCT)GO TO 270
      GO TO 250
  270 XG2=XG
!
      X(I)=XG1/(XG1+XG2)
!
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BETRAN
      SUBROUTINE BE4FUN (N,X,FVEC,IFLAG,XDATA,NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              FOUR-PARAMETER BETA METHOD OF MOMENT EQUATIONS
!              TO ESTIMATE THE ALPHA AND BETA SHAPE PARAMETERS:
!
!              {2*(BETA-ALPHA)/(ALPHA+BETA+2)}*
!              SQRT((ALPHA+BETA+1)/(ALPHA*BETA)) - M3/M2**(3/2)=0
!
!              3*(ALPHA+BETA+1)*[2*(ALPHA+BETA)**2 +
!              ALPHA*APHA2*(ALPHA+BETA-6)]/
!              {ALPHA*BETA*(ALPHA+BETA+2)*(ALPHA+BETA+3)} -
!              M4/M2**2 = 0
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 14.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/6
!     ORIGINAL VERSION--JUNE      2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
      DOUBLE PRECISION DTERM7
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DM2, DM3, DM4
      COMMON /BET4ML/ DM2, DM3, DM4
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=2
      IFLAG=0
!
      IF(ISUBG4.EQ.'4FUN')THEN
        WRITE(ICOUT,52)NOBS,XDATA(1)
   52   FORMAT('NOBS,XDATA(1) = ',I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DA=X(1)
      DB=X(2)
!
      DTERM1=2.0D0*(DB-DA)/(DA+DB+2.0D0)
      DTERM2=DSQRT((DA+DB+1.0D0)/(DA*DB))
      DTERM3=DM3/(DM2**1.5)
!
      DTERM4=3.0D0*(DA+DB+1.0D0)
      DTERM5=2.0D0*(DA+DB)**2 + DA*DB*(DA+DB-6.0D0)
      DTERM6=DA*DB*(DA+DB+2.0D0)*(DA+DB+3.0D0)
      DTERM7=DM4/(DM2**2)
!
      FVEC(1)=(DTERM1*DTERM2) - DTERM3
      FVEC(2)=(DTERM4*DTERM5/DTERM6) - DTERM7
!
      RETURN
      END SUBROUTINE BE4FUN 
      SUBROUTINE BE4FU2 (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              FOUR-PARAMETER BETA MAXIMUM LIKELIHOOD EQUATIONS
!              TO ESTIMATE THE A AND B LOWER AND UPPER LIMIT
!              PARAMETERS:
!
!              PSI(S5*(SIGMA*S6-1)/(S6*(SIGMA*S5-1)-S5)) -
!              PSI(1 + S5*SIGMA*S6/(S6*(SIGMA*S5-1)-S5)) -
!              S7 - LOG(SIGMA) = 0
!
!              PSI(S6*(SIGMA*S5-1)/(S6*(SIGMA*S5-1)-S5)) -
!              PSI(1 + S5*SIGMA*S6/(S6*(SIGMA*S5-1)-S5)) -
!              S8 - LOG(SIGMA) = 0
!
!              WHERE
!
!              PSI = DIGAMMA FUNCTION
!              S5 = (1/N)*SUM[1/(X(I) - A)]
!              S6 = (1/N)*SUM[1/(X(I) - B)]
!              S7 = (1/N)*SUM[LOG(X(I) - A)]
!              S8 = (1/N)*SUM[LOG(B - X(I))]
!              SIGMA = B - A
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--FOUR PARAMETER BETA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 14.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/6
!     ORIGINAL VERSION--JUNE      2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DLGSIG
      DOUBLE PRECISION DPSI
!
      EXTERNAL DPSI
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION SIGMA
      DOUBLE PRECISION S5
      DOUBLE PRECISION S6
      DOUBLE PRECISION S7
      DOUBLE PRECISION S8
      DOUBLE PRECISION DXMIN
      DOUBLE PRECISION DXMAX
      COMMON /BET4M2/ S5, S6, S7, S8, SIGMA, DXMIN, DXMAX
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=2
      IFLAG=0
!
      DA=X(1)
      DB=X(2)
      SIGMA=DB - DA
      DLGSIG=DLOG(SIGMA)
      DN=DBLE(NOBS)
      IF(DA.GE.DXMIN .OR. DB.LE.DXMAX) THEN
        FVEC(1)=99.0D0
        FVEC(2)=99.0D0
        GO TO 9000
      ENDIF
!
      S5=0.0D0
      S6=0.0D0
      S7=0.0D0
      S8=0.0D0
!
      DO 100 I=1,NOBS
        DX=DBLE(XDATA(I))
        S5=S5 + 1.0D0/(DX-DA)
        S6=S6 + 1.0D0/(DB-DX)
        S7=S7 + DLOG(DX-DA)
        S8=S8 + DLOG(DB-DX)
  100 CONTINUE
      S5=S5/DN
      S6=S6/DN
      S7=S7/DN
      S8=S8/DN
!
      DENOM=S6*(SIGMA*S5 - 1.0D0) - S5
      DTERM1=S5*(SIGMA*S6 - 1.0D0)
      DTERM2=DPSI(DTERM1/DENOM)
      DTERM3=DPSI(1.0D0 + (SIGMA*S5*S6/DENOM))
      FVEC(1)=DTERM2 - DTERM3 - S7 + DLGSIG
!
      DTERM1=S6*(SIGMA*S5 - 1.0D0)
      DTERM2=DPSI(DTERM1/DENOM)
      DTERM3=DPSI(1.0D0 + (SIGMA*S5*S6/DENOM))
      FVEC(2)=DTERM2 - DTERM3 - S8 + DLGSIG
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BE4FU2 
      FUNCTION BI (X)
!***BEGIN PROLOGUE  BI
!***PURPOSE  Evaluate the Bairy function (the Airy function of the
!            second kind).
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10D
!***TYPE      SINGLE PRECISION (BI-S, DBI-D)
!***KEYWORDS  BAIRY FUNCTION, FNLIB, SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! BI(X) calculates the Airy function of the second kind for real
! argument X.
!
! Series for BIF        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   1.88E-19
!                                         log weighted error  18.72
!                               significant figures required  17.74
!                                    decimal places required  19.20
!
! Series for BIG        on the interval -1.00000D+00 to  1.00000D+00
!                                        with weighted error   2.61E-17
!                                         log weighted error  16.58
!                               significant figures required  15.17
!                                    decimal places required  17.03
!
! Series for BIF2       on the interval  1.00000D+00 to  8.00000D+00
!                                        with weighted error   1.11E-17
!                                         log weighted error  16.95
!                        approx significant figures required  16.5
!                                    decimal places required  17.45
!
! Series for BIG2       on the interval  1.00000D+00 to  8.00000D+00
!                                        with weighted error   1.19E-18
!                                         log weighted error  17.92
!                        approx significant figures required  17.2
!                                    decimal places required  18.42
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  BIE, CSEVL, INITS, R1MACH, R9AIMP, XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770701  DATE WRITTEN
!   890531  Changed all specific intrinsics to generic.  (WRB)
!   890531  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!   900326  Removed duplicate information from DESCRIPTION section.
!           (WRB)
!***END PROLOGUE  BI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DIMENSION BIFCS(9), BIGCS(8), BIF2CS(10), BIG2CS(10)
      LOGICAL FIRST
      SAVE BIFCS, BIGCS, BIF2CS, BIG2CS, NBIF, NBIG, NBIF2,   &
       NBIG2, X3SML, XMAX, FIRST
      DATA BIFCS( 1) /   -.01673021647198664948E0 /
      DATA BIFCS( 2) /    .1025233583424944561E0 /
      DATA BIFCS( 3) /    .00170830925073815165E0 /
      DATA BIFCS( 4) /    .00001186254546774468E0 /
      DATA BIFCS( 5) /    .00000004493290701779E0 /
      DATA BIFCS( 6) /    .00000000010698207143E0 /
      DATA BIFCS( 7) /    .00000000000017480643E0 /
      DATA BIFCS( 8) /    .00000000000000020810E0 /
      DATA BIFCS( 9) /    .00000000000000000018E0 /
      DATA BIGCS( 1) /    .02246622324857452E0 /
      DATA BIGCS( 2) /    .03736477545301955E0 /
      DATA BIGCS( 3) /    .00044476218957212E0 /
      DATA BIGCS( 4) /    .00000247080756363E0 /
      DATA BIGCS( 5) /    .00000000791913533E0 /
      DATA BIGCS( 6) /    .00000000001649807E0 /
      DATA BIGCS( 7) /    .00000000000002411E0 /
      DATA BIGCS( 8) /    .00000000000000002E0 /
      DATA BIF2CS( 1) /   0.09984572693816041E0 /
      DATA BIF2CS( 2) /    .478624977863005538E0 /
      DATA BIF2CS( 3) /    .0251552119604330118E0 /
      DATA BIF2CS( 4) /    .0005820693885232645E0 /
      DATA BIF2CS( 5) /    .0000074997659644377E0 /
      DATA BIF2CS( 6) /    .0000000613460287034E0 /
      DATA BIF2CS( 7) /    .0000000003462753885E0 /
      DATA BIF2CS( 8) /    .0000000000014288910E0 /
      DATA BIF2CS( 9) /    .0000000000000044962E0 /
      DATA BIF2CS(10) /    .0000000000000000111E0 /
      DATA BIG2CS( 1) /    .033305662145514340E0 /
      DATA BIG2CS( 2) /    .161309215123197068E0 /
      DATA BIG2CS( 3) /    .0063190073096134286E0 /
      DATA BIG2CS( 4) /    .0001187904568162517E0 /
      DATA BIG2CS( 5) /    .0000013045345886200E0 /
      DATA BIG2CS( 6) /    .0000000093741259955E0 /
      DATA BIG2CS( 7) /    .0000000000474580188E0 /
      DATA BIG2CS( 8) /    .0000000000001783107E0 /
      DATA BIG2CS( 9) /    .0000000000000005167E0 /
      DATA BIG2CS(10) /    .0000000000000000011E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  BI
      IF (FIRST) THEN
         ETA = 0.1*R1MACH(3)
         NBIF  = INITS (BIFCS , 9, ETA)
         NBIG  = INITS (BIGCS , 8, ETA)
         NBIF2 = INITS (BIF2CS, 10, ETA)
         NBIG2 = INITS (BIG2CS, 10, ETA)
!
         X3SML = ETA**0.3333
         XMAX = (1.5*LOG(R1MACH(2)))**0.6666
      ENDIF
      FIRST = .FALSE.
!
      IF (X.GE.(-1.0)) GO TO 20
      CALL R9AIMP (X, XM, THETA)
      BI = XM * SIN(THETA)
      RETURN
!
 20   IF (X.GT.1.0) GO TO 30
      Z = 0.0
      IF (ABS(X).GT.X3SML) Z = X**3
      BI = 0.625 + CSEVL (Z, BIFCS, NBIF) + X*(0.4375 +   &
        CSEVL (Z, BIGCS, NBIG))
      RETURN
!
 30   IF (X.GT.2.0) GO TO 40
      Z = (2.0*X**3 - 9.0) / 7.0
      BI = 1.125 + CSEVL (Z, BIF2CS, NBIF2) + X*(0.625 +   &
        CSEVL (Z, BIG2CS, NBIG2))
      RETURN
!
 40   IF (X .GT. XMAX) THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        BI = 0.0
        RETURN
      ENDIF
    1 FORMAT('***** ERORR FROM BI, OVERFLOWS BECAUSE THE ',   &
             'VALUE OF X IS TOO BIG.  ****')
!
      BI = BIE(X) * EXP(2.0*X*SQRT(X)/3.0)
      RETURN
!
      END FUNCTION BI 
      FUNCTION BIE (X)
!***BEGIN PROLOGUE  BIE
!***PURPOSE  Calculate the Bairy function for a negative argument and an
!            exponentially scaled Bairy function for a non-negative
!            argument.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C10D
!***TYPE      SINGLE PRECISION (BIE-S, DBIE-D)
!***KEYWORDS  BAIRY FUNCTION, EXPONENTIALLY SCALED, FNLIB,
!             SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
! Evaluate BI(X) for X .LE. 0  and  BI(X)*EXP(ZETA)  where
! ZETA = 2/3 * X**(3/2)  for X .GE. 0.0
!
! Series for BIF        on the interval -1.00000D+00 to  1.00000D+00
