      DATA BIP2CS(10) /    .0000000003736681366E0 /
      DATA BIP2CS(11) /    .0000000005766930320E0 /
      DATA BIP2CS(12) /    .0000000000621812650E0 /
      DATA BIP2CS(13) /   -.0000000000632941202E0 /
      DATA BIP2CS(14) /   -.0000000000149150479E0 /
      DATA BIP2CS(15) /    .0000000000078896213E0 /
      DATA BIP2CS(16) /    .0000000000024960513E0 /
      DATA BIP2CS(17) /   -.0000000000012130075E0 /
      DATA BIP2CS(18) /   -.0000000000003740493E0 /
      DATA BIP2CS(19) /    .0000000000002237727E0 /
      DATA BIP2CS(20) /    .0000000000000474902E0 /
      DATA BIP2CS(21) /   -.0000000000000452616E0 /
      DATA BIP2CS(22) /   -.0000000000000030172E0 /
      DATA BIP2CS(23) /    .0000000000000091058E0 /
      DATA BIP2CS(24) /   -.0000000000000009814E0 /
      DATA BIP2CS(25) /   -.0000000000000016429E0 /
      DATA BIP2CS(26) /    .0000000000000005533E0 /
      DATA BIP2CS(27) /    .0000000000000002175E0 /
      DATA BIP2CS(28) /   -.0000000000000001737E0 /
      DATA BIP2CS(29) /   -.0000000000000000010E0 /
      DATA ATR / 8.7506905708484345E0 /
      DATA BTR / -2.093836321356054E0 /
      DATA FIRST /.TRUE./
!***FIRST EXECUTABLE STATEMENT  BIE
      IF (FIRST) THEN
         ETA = 0.1*R1MACH(3)
         NBIF = INITS (BIFCS, 9, ETA)
         NBIG = INITS (BIGCS, 8, ETA)
         NBIF2 = INITS (BIF2CS, 10, ETA)
         NBIG2 = INITS (BIG2CS, 10, ETA)
         NBIP  = INITS (BIPCS , 24, ETA)
         NBIP2 = INITS (BIP2CS, 29, ETA)
!
         X3SML = ETA**0.3333
         X32SML = 1.3104*X3SML**2
         XBIG = R1MACH(2)**0.6666
      ENDIF
      FIRST = .FALSE.
!
      IF (X.GE.(-1.0)) GO TO 20
      CALL R9AIMP (X, XM, THETA)
      BIE = XM * SIN(THETA)
      RETURN
!
 20   IF (X.GT.1.0) GO TO 30
      Z = 0.0
      IF (ABS(X).GT.X3SML) Z = X**3
      BIE = 0.625 + CSEVL (Z, BIFCS, NBIF) + X*(0.4375 +   &
        CSEVL (Z, BIGCS, NBIG))
      IF (X.GT.X32SML) BIE = BIE * EXP(-2.0*X*SQRT(X)/3.0)
      RETURN
!
 30   IF (X.GT.2.0) GO TO 40
      Z = (2.0*X**3 - 9.0) / 7.0
      BIE = EXP(-2.0*X*SQRT(X)/3.0) * (1.125 + CSEVL (Z, BIF2CS, NBIF2)   &
        + X*(0.625 + CSEVL (Z, BIG2CS, NBIG2)) )
      RETURN
!
 40   IF (X.GT.4.0) GO TO 50
      SQRTX = SQRT(X)
      Z = ATR/(X*SQRTX) + BTR
      BIE = (0.625 + CSEVL (Z, BIPCS, NBIP)) / SQRT(SQRTX)
      RETURN
!
 50   SQRTX = SQRT(X)
      Z = -1.0
      IF (X.LT.XBIG) Z = 16.0/(X*SQRTX) - 1.0
      BIE = (0.625 + CSEVL (Z, BIP2CS, NBIP2))/SQRT(SQRTX)
      RETURN
!
      END FUNCTION BIE 
      DOUBLE PRECISION FUNCTION bfrac(a,b,x,y,lambda,eps)
!-----------------------------------------------------------------------
!     CONTINUED FRACTION EXPANSION FOR IX(A,B) WHEN A,B .GT. 1.
!     IT IS ASSUMED THAT  LAMBDA = (A + B)*Y - B.
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,eps,lambda,x,y
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION alpha,an,anp1,beta,bn,bnp1,c,c0,c1,e,n,p,r,r0,s,   &
                       t,w,yp1
!     ..
!     .. External Functions ..
      DOUBLE PRECISION brcomp
      EXTERNAL brcomp
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs
!     ..
!     .. Executable Statements ..
!--------------------
      bfrac = brcomp(a,b,x,y)
      IF (bfrac.EQ.0.0D0) RETURN
!
      c = 1.0D0 + lambda
      c0 = b/a
      c1 = 1.0D0 + 1.0D0/a
      yp1 = y + 1.0D0
!
      n = 0.0D0
      p = 1.0D0
      s = a + 1.0D0
      an = 0.0D0
      bn = 1.0D0
      anp1 = 1.0D0
      bnp1 = c/c1
      r = c1/c
!
!        CONTINUED FRACTION CALCULATION
!
   10 n = n + 1.0D0
      t = n/a
      w = n* (b-n)*x
      e = a/s
      alpha = (p* (p+c0)*e*e)* (w*x)
      e = (1.0D0+t)/ (c1+t+t)
      beta = n + w/s + e* (c+n*yp1)
      p = 1.0D0 + t
      s = s + 2.0D0
!
!        UPDATE AN, BN, ANP1, AND BNP1
!
      t = alpha*an + beta*anp1
      an = anp1
      anp1 = t
      t = alpha*bn + beta*bnp1
      bn = bnp1
      bnp1 = t
!
      r0 = r
      r = anp1/bnp1
      IF (abs(r-r0).LE.eps*r) GO TO 20
!
!        RESCALE AN, BN, ANP1, AND BNP1
!
      an = an/bnp1
      bn = bn/bnp1
      anp1 = r
      bnp1 = 1.0D0
      GO TO 10
!
!                 TERMINATION
!
   20 bfrac = bfrac*r
      RETURN
                                                                                                                                  
      END FUNCTION bfrac
      SUBROUTINE BFRCDF(X,ALPHA,BETA,R,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BRITTLE FRACTURE DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS ALPHA, BETA,
!              AND R.  THE BRITTLE FRACTURE DISTRIBUTION HAS
!              THE CUMULATIVE DISTRIBUTION FUNCTION
!
!              F(X;ALPHA,BETA,R) = 1 - EXP(-ALPHA*X**(2*R)*
!                                  EXP(-BETA/X**2))
!                                  X > 0; ALPHA, R > 0; BETA >= 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --R      = THE DOUBLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BRITTLE FRACTURE
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA, BETA AND R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA AND R SHOULD BE POSITIVE AND BETA SHOULD BE
!                   NON-NEGATIVE.
!                 --X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(X.LE.0.0D0)THEN
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFRCDF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFRCDF IS ',   &
             'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(R.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO BFRCDF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DEXP(-BETA/X**2)
      DTERM2=DEXP(-ALPHA*X**(2.0D0*R)*DTERM1)
      CDF=1.0D0 - DTERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFRCDF
      SUBROUTINE BFRCHA(X,ALPHA,BETA,R,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE BRITTLE FRACTURE DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS ALPHA, BETA,
!              AND R.  THE BRITTLE FRACTURE DISTRIBUTION HAS
!              THE CUMULATIVE HAZARD FUNCTION
!
!              H(X;ALPHA,BETA,R) = -ALPHA*X**(2*R)*EXP(-BETA/X**2)
!                                  X > 0; ALPHA, R > 0; BETA >= 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --R      = THE DOUBLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION CUMULATIVE
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE HAZ FOR THE BRITTLE FRACTURE
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA, BETA AND R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA AND R SHOULD BE POSITIVE AND BETA SHOULD BE
!                   NON-NEGATIVE.
!                 --X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0D0
      IF(X.LE.0.0D0)THEN
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFRCHAZ IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFRCHAZ IS ',   &
             'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(R.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO BFRCHAZ IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
!CCCC DTERM1=DEXP(-BETA/X**2)
!CCCC HAZ=ALPHA*X**(2.0D0*R)*DTERM1
      DTERM1=DLOG(ALPHA) + (2.0D0*R)*DLOG(X) - BETA/X**2
      HAZ=DEXP(DTERM1)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFRCHA
      SUBROUTINE BFRFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE-THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!             BRITTLE FRACTURE MAXIMUM LIKELIHOOD EQUATIONS.
!             SPECIFICALLY IT SOLVES FOR BETA AND R BY
!             SOLVING THE EQUATIONS:
!
!             0 = (ANUM/ADEN) + SUM[i=1 to N][1/(r*X(i)**2 + BETA) -
!                 SUM[i=1 to N][X(i)**2]
!
!                 ANUM = N*SUM[i=1 TO N][X(i)**2**(2*R-2)*
!                        EXP(-BETA/X(i)**2)
!                 ADEN = SUM[i=1 TO N][X(i)**(2*R)*EXP(-BETA/X(i)**2)]
!
!             0 = 2*SUM[i=1 TO N][LOG(X(i))] +
!                 SUM[i=1 TO N][1/(R + BETA/X(i)**2)] - (ANUM/ADEN)
!
!                 ANUM = 2*SUM[i=1 TO N][LOG(X(i))*X(i)**(2*R)*
!                        EXP(-BETA/X(i)**2)]
!                 ADEN = SUM[i=1 TO N][X(i)**(2*R)*EXP(-BETA/X(i)**2)]
!
!             CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!             NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!             DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!             OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--BRITTLE FRACTURE MAXIMUM LIKELIHOOD Y
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DR
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DSUM6
      DOUBLE PRECISION DSUM7
      DOUBLE PRECISION DSUM8
      DOUBLE PRECISION DTERM1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DN=DBLE(NOBS)
      DBETA=DBLE(X(1))
      DR=DBLE(X(2))
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
      DSUM6=0.0D0
      DSUM7=0.0D0
      DSUM8=0.0D0
!
      DO 200 I=1,NOBS
!
        DX=DBLE(XDATA(I))
        DX2=DX*DX
        DTERM1=DEXP(-DBETA/DX2)
!
        DSUM1=DSUM1 + DX**(2.0D0*DR - 2.0D0)*DTERM1
        DSUM2=DSUM2 + DX**(2.0D0*DR)*DTERM1
        DSUM3=DSUM3 + 1.0D0/(DR*DX2 + DBETA)
        DSUM4=DSUM4 + DX2
!
        DSUM5=DSUM5 + DLOG(DX)
        DSUM6=DSUM6 + 1.0D0/(DR + DBETA/DX2)
        DSUM7=DSUM7 + DLOG(DX)*DX**(2.0D0*DR)*DTERM1
        DSUM8=DSUM8 + DX**(2.0D0*DR)*DTERM1
!
  200 CONTINUE
!
      FVEC(1)=DN*(DSUM1/DSUM2) + DSUM3 - DSUM4
      FVEC(2)=2.0D0*DSUM5 + DSUM6 - (2.0D0*DN*DSUM7/DSUM8)
!
      RETURN
      END SUBROUTINE BFRFUN 
      SUBROUTINE BFRHAZ(X,ALPHA,BETA,R,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE BRITTLE FRACTURE DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS ALPHA, BETA,
!              AND R.  THE BRITTLE FRACTURE DISTRIBUTION HAS
!              THE HAZARD FUNCTION
!
!              h(X;ALPHA,BETA,R) = f(x;ALPHA,BETA,R)/
!                                  (1 - F(X;ALPHA,BETA,R)
!                                  X > 0; ALPHA, R > 0; BETA >= 0
!              WITH f AND F DENOTING THE BRITTLE FRACTURE
!              PROBABILITY DENISTY AND CUMULATIVE DISTRIBUTION
!              FUNCTIONS, RESPECTIVELY.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --R      = THE DOUBLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION HAZARD
!             FUNCTION VALUE HAZ FOR THE BRITTLE FRACTURE
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA, BETA AND R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA AND R SHOULD BE POSITIVE AND BETA SHOULD BE
!                   NON-NEGATIVE.
!                 --X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0D0
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BFRHAZ IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFRHAZ IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFRHAZ IS ',   &
             'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(R.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO BFRHAZ IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLOG(2.0D0) + DLOG(ALPHA) + (2.0D0*R - 1.0D0)*DLOG(X)
      DTERM2=DLOG((BETA/X**2) + R)
      DTERM3=-(BETA/X**2) - ALPHA*X**(2.0D0*R)*EXP(-BETA/X**2)
      PDFLOG=DTERM1 + DTERM2 + DTERM3
!
      DTERM1=DEXP(-BETA/X**2)
      CDFLOG=-ALPHA*X**(2.0D0*R)*DTERM1
!
      HAZ=DEXP(PDFLOG - CDFLOG)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFRHAZ
      SUBROUTINE BFRLI1(Y,N,   &
                        ALPHA,BETA,R,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR THE
!              BRITTLE FRACTURE DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/8
!     ORIGINAL VERSION--AUGUST    2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DR
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BFRL'
      ISUBN2='I1  '
!
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BFRLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,ALPHA,BETA,R
   52   FORMAT('IBUGA3,ISUBRO,N,ALPHA,BETA,R = ',2(A4,2X),I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     N*LOG(2) + N*LOG(ALPHA) +
!     (2*R-1)*SUM[i=1 to N][LOG(X(i))] +
!     SUM[i=1 to N][LOG(R + B/X(i)**2)] -
!     BETA*SUM[i=1 to N][X(i)**-2] -
!     ALPHA*SUM[i=1 to N][X(i)**(2*R)*EXP(-BETA/X(i)**2)]
!
      DN=DBLE(N)
      DR=DBLE(R)
      DB=DBLE(BETA)
      DA=DBLE(ALPHA)
      DTERM1=DN*DLOG(2.0D0) + DN*DLOG(DA)
      DTERM2=2.D0*DR - 1.0D0
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DLOG(DX)
        DSUM2=DSUM2 + DLOG(DR + (DB/DX**2))
        DSUM3=DSUM3 + 1.0D0/DX**2
        DSUM4=DSUM4 + DX**(2.0D0*DR)*DEXP(-DB/DX**2)
 1000 CONTINUE
!
      DLIK=DTERM1 + DTERM2*DSUM1 + DSUM2 - DB*DSUM3 - DA*DSUM4
      ALIK=REAL(DLIK)
      DNP=3.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BFRLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)DSUM1,DSUM2,DSUM3,DSUM4
 9012   FORMAT('DSUM1,DSUM2,DSUM3,DSUM4 = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DTERM1,DTERM2,DTERM3
 9013   FORMAT('DTERM1,DTERM2,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BFRLI1
      SUBROUTINE BFRPDF(X,ALPHA,BETA,R,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BRITTLE FRACTURE DISTRIBUTION
!              WITH DOUBLE PRECISION SHAPE PARAMETERS ALPHA, BETA,
!              AND R.  THE BRITTLE FRACTURE DISTRIBUTION HAS
!              THE PROBABILITY DENSITY FUNCTION
!
!              f(X;ALPHA,BETA,R) = 2*ALPHA*X**(2*R-1)*
!                                  (BETA/X**2 + R)*
!                                  EXP[-(BETA/X**2)-ALPHA*X**(2*R)*
!                                  EXP(-BETA/X**2)]
!                                 X > 0; ALPHA, R > 0; BETA >= 0
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE DOUBLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --R      = THE DOUBLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BRITTLE FRACTURE
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA, BETA AND R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA AND R SHOULD BE POSITIVE AND BETA SHOULD BE
!                   NON-NEGATIVE.
!                 --X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BFRPDF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFRPDF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFRPDF IS ',   &
             'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(R.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO BFRPDF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLOG(2.0D0) + DLOG(ALPHA) + (2.0D0*R - 1.0D0)*DLOG(X)
      DTERM2=DLOG((BETA/X**2) + R)
      DTERM3=-(BETA/X**2) - ALPHA*X**(2.0D0*R)*EXP(-BETA/X**2)
      PDF=DEXP(DTERM1 + DTERM2 + DTERM3)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFRPDF
      SUBROUTINE BFRPPF(DP,DALPHA,DBETA,DR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BRITTLE FRACTURE DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;ALPHA,BETA,R) = 1 - EXP(-ALPHA*X**2*EXP(-BETA/X**2))
!                                X > 0; ALPHA, R > 0; BETA >= 0
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE FIRST SHAPE PARAMETER
!                     --DBETA  = THE SECOND SHAPE PARAMETER
!                     --DR     = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BRITTLE FRACTURE DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA, BETA, AND R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BFRCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0D-9/
      DATA SIG /1.0D-8/
      DATA ZERO /0.D0/
      DATA MAXIT /1000/
!CCCC DATA EPS2 /1.0D-12/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BFRPPF IS ',   &
               'OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFRPPF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DBETA.LT.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFRPPF IS ',   &
             'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO BFRPPF IS ',   &
             'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('****** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      XL = 0.0D0
      XR = 10.0D0
      ICOUNT=0
      MAXCNT=10000
      DINC=10.0D0
!
   91 CONTINUE
      IF(XL.LE.0.0D0)XL=0.0D0
      IF(XR.LE.0.0D0)XR=XL+DINC
      CALL BFRCDF(XL,DALPHA,DBETA,DR,CDFL)
      CALL BFRCDF(XR,DALPHA,DBETA,DR,CDFR)
      IF(CDFL.LT.DP .AND. CDFR.LT.DP)THEN
        XL=XR
        XR=XL+DINC
      ELSEIF(CDFL.GT.DP .AND. CDFR.GT.DP)THEN
        XL=XL-DINC
        IF(XL.LT.0.0D0)XL=0.0D0
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   96 FORMAT('***** ERROR--BFRPPF UNABLE TO FIND BRACKETING INTERVAL.')
      GO TO 91
!
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL=-DP
      FXR=1.0D0 - DP
!
  105 CONTINUE
      DX = (XL+XR)*0.5D0
      CALL BFRCDF(DX,DALPHA,DBETA,DR,DCDF)
      P1=DCDF
      DPPF=DX
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = DX
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = DX
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9000
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
  130 FORMAT('***** ERROR--BFRPPF ROUTINE DID NOT CONVERGE.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFRPPF
      SUBROUTINE BFRRAN(N,ALPHA,BETA,R,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BRITTLE FRACTURE DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA, BETA, AND R.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER RMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BRITTLE FRACTURE DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA, BETA, AND R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA AND R SHOULD BE POSITIVE, BETA SHOULD BE
!                   NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BFRPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--BLACK, DURHAM, AND PADGETT (1990), "PARAMETER
!                 ESTIMATION FOR A NEW DISTRIBUTION FOR THE STRENGTH
!                 OF BRITTLE FIBERS: A SIMULATION STUDY",
!                 COMMUNICATIONS IN STATISTICS--SIMULATION AND
!                 COMPUTATION, VOL. 19, PP. 809-825
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION RMBER--2008.3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF BRITTLE ',   &
               'FRACTURE RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFRRAN IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFRRAN ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO BFRRAN IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)R
        CALL DPWRST('XXX','BUG ')
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      CALL UNIRAN(N,ISEED,X)
!
      DO 100 I=1,N
        CALL BFRPPF(DBLE(X(I)),DBLE(ALPHA),DBLE(BETA),DBLE(R),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFRRAN
      SUBROUTINE BFWCDF(X,GAMMA,AL,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BRITTLE FIBER WEIBULL
!              DISTRIBUTION WITH TAIL LENGTH PARAMETER GAMMA AND
!              GAUGE LENGTH PARAMETER L.
!
!              THE BRITTLE FIBER WEIBULL DISTRIBUTION USED HEREIN IS
!              DEFINED FOR ALL POSITIVE X AND HAS THE
!              CUMULATIVE DISTRIBUTION FUNCTION
!
!                 F(P;GAMMA,L,SCALE) = 1 - EXP[-L*(X/SCALE)**GAMMA]
!
!              THE SCALE PARAMETER IS SET TO 1 IN THIS ROUTINE.
!     INPUT  ARGUMENTS--X      = THE VALUE AT WHICH THE CUMULATIVE
!                                DISTRIBUTION FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER GAMMA.
!                     --AL     = THE GAUGE LENGTH PARAMETER L.
!     OUTPUT ARGUMENTS--CDF    = THE CUMULATIVE DISTRIBUTION FUNCTION
!                                VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BRITTLE FIBER WEIBULL
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER GAMMA AND
!             GAUGE LENGTH PARAMETER L.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA AND AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--AUGUST    2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION AL
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION CDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BFWCDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BFWCDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(X.GT.0.0D0)THEN
        CDF=1.0D0 - DEXP(-AL*(X**GAMMA))
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWCDF
      SUBROUTINE BFWCD2(X,NX,LI,PI,NI,GAMMA,ALOC,SCALE,   &
                        CDF,   &
                        ISUBRO,IBUGA2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BRITTLE FIBER WEIBULL
!              DISTRIBUTION WITH TAIL LENGTH PARAMETER = GAMMA AND
!              GAUGE LENGTH PARAMETER L.
!
!              THE BRITTLE FIBER WEIBULL DISTRIBUTION USED HEREIN IS
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!
!              F(P;GAMMA,L,SCALE) = 1 - EXP[-L*(X/SCALE)**GAMMA]
!
!              THE BFWCDF ROUTINE COMPUTES THIS FUNCTION FOR A SINGLE
!              VALUE OF L.  THIS ROUTINE COMPUTES THIS FUNCTION FOR
!              MULTIPLE VALUES OF L.  IT DOES THIS USING A MIXTURE
!              APPROACH.  THAT IS
!
!              F(X;GAMMA,L,LOC,SCALE) = SUM[i=1 to NI]
!                  [p(i)*BFWCDF(X;GAMMA,L(i),LOC,SCALE)]
!
!              WHERE NI IS THE NUMBER OF DISTINCT VALUES FOR L.
!
!              THIS ROUTINE ASSUMES THAT THE LOCATION/SCALE/SHAPE
!              PARAMETERS ARE FIXED (I.E., ONLY L VARIES).
!
!              CURRENTLY, WE RESTRICT L TO A MAXIMUM OF 10 DISTINCT
!              LEVELS.
!
!     INPUT  ARGUMENTS--X      = A VARIABLE CONTAINING THE VALUES AT WHICH
!                                THE CUMULATIVE DISTRIBUTION FUNCTION IS
!                                TO BE EVALUATED.
!                     --NX     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR X.
!                     --LI     = A VARIABLE CONTAINING THE GAUGE LENGTH
!                                PARAMETER L.
!                     --PI     = A VARIABLE CONTAINING THE "MIXING"
!                                PROPORTIONS FOR LI.
!                     --NI     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR LI AND PI.
!                     --GAMMA  = THE SHAPE PARAMETER GAMMA.
!                     --ALOC   = THE LOCATION PARAMETER.
!                     --SCALE  = THE SCALE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = A VARIABLE CONTAINING THE CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUES.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUES.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BFWCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--OCTOBER   2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION LI(*)
      DOUBLE PRECISION PI(*)
      DOUBLE PRECISION CDF(*)
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION ALOC
      DOUBLE PRECISION SCALE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'WCD2')THEN
        WRITE(ICOUT,31)IBUGA2,ISUBRO
   31   FORMAT('AT THE BEGINNING OF BFWCD2')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN BRITTLE FIBER WEIBULL CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)
    3   FORMAT('      THE NUMBER OF REQUESTED CDF VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)NX
    5   FORMAT('      THE NUMBER OF REQUESTED CDF VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
   15   FORMAT('      THE NUMBER OF REQUESTED L VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.GT.10)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,18)
   18   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS GREATER THAN 10.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,23)
   23   FORMAT('      THE VALUE OF THE SHAPE PARAMETER (GAMMA) ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,25)GAMMA
   25   FORMAT('      THE VALUE OF GAMMA  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(SCALE.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,33)
   33   FORMAT('      THE VALUE OF THE SCALE PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,35)SCALE
   35   FORMAT('      THE VALUE OF THE SCALE PARAMETER  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DSUM1=0.0D0
      DO 50 I=1,NI
        IF(LI(I).LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,52)I
   52     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE GAUGE LENGTH ',   &
                 'ARGUMENT (L) IS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,54)LI(I)
   54     FORMAT('      THE VALUE OF L(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ELSEIF(PI(I).LE.0.0D0 .OR. PI(I).GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,57)I
   57     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE MIXING ',   &
                 'ARGUMENT (P)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,58)
   58     FORMAT('      OUTSIDE THE (0,1) INTERVAL).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,59)PI(I)
   59     FORMAT('      THE VALUE OF P(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
        DSUM1=DSUM1 + PI(I)
   50 CONTINUE
!
!     CHECK THAT MIXING PROPORTIONS SUM TO 1
!
      IF(ABS(DSUM1 - 1.0D0).GT.0.000001D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE MIXING PROPORTIONS DO NOT SUM TO ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)REAL(DSUM1)
   65   FORMAT('      THE SUM OF THE MIXING PROPORTIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOW COMPUTE THE CDF BY SUMMING OVER THE L(I) CASES
!
      DO 100 I=1,NX
        DSUM1=0.0D0
        DO 200 J=1,NI
          DTERM1=(X(I)-ALOC)/SCALE
          CALL BFWCDF(DTERM1,GAMMA,LI(J),DTERM2)
          DSUM1=DSUM1 + PI(J)*DTERM2
  200   CONTINUE
        CDF(I)=DSUM1
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWCD2
      SUBROUTINE BFWFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              BRITTLE FIBER WEIBULL MAXIMUM LIKELIHOOD
!              EQUATIONS.
!
!              SIGMA - (SUM[i=1 to N][L(i)*X(i)**G]/N)**(1/G)
!
!              N/G - N*LOG(SIGMA) + SUM[i=1 to n][LOG(X(i))] -
!                    SUM[i=1 to n][L(i)*(X(i)/G)**G*LOG(X(i)/G]
!
!              WITH G AND SIGMA DENOTING THE SHAPE PARAMETER GAMMA AND
!              SCALE PARAMETER SIGMA, RESPECTIVELY.
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!
!              THE L(i) ARE THE GAUGE LENGTHS.  THESE CAN EITHER
!              BE CONSTANT (I.E., WE ARE FITTING A SINGLE LEVEL OF
!              L) OR VARIABLE.  THE L VALUES ARE STORED IN THE UPPER
!              HALF OF THE DATA ARRAY.
!
!     EXAMPLE--BRITTLE FIBER WEIBULL MAXIMUM LIKELIHOOD Y L
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/11
!     ORIGINAL VERSION--NOVEMBER  2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DS
      DOUBLE PRECISION DL
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DG=X(1)
      DS=X(2)
      DN=DBLE(NOBS)
!
      DTERM1=(DN/DG) - DN*DLOG(DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DL=DBLE(XDATA(NOBS+I))
        DTERM2=DLOG(DX)
        DTERM3=DX/DS
        DSUM1=DSUM1+DLOG(DX)
        DSUM2=DSUM2 + DL*(DTERM3**DG)*DLOG(DTERM3)
        DSUM3=DSUM3 + DL*(DX**DG)
  200 CONTINUE
!
      FVEC(1)=DTERM1 + DSUM1 - DSUM2
      FVEC(2)=(DSUM3/DS**DG) - DN
!
      RETURN
      END SUBROUTINE BFWFUN 
      SUBROUTINE BFWLI1(Y,XL,N,ICASPL,MINMAX,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE 3-PARAMETER BRITTLE FIBER WEIBULL DISTRIBUTION.
!              THIS IS FOR THE RAW DATA CASE (I.E., NO GROUPING AND
!              NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              THE BRITTLE FIBER DISTRIBUTION IS A RE-PARAMETERIZED
!              VERSION OF THE WEIBULL DISTRIBUTION.  IT INCLUDES A
!              GAUGE LENGTH PARAMETER (ASSUMED KNOWN).
!
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!              --KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 17.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/9
!     ORIGINAL VERSION--SEPTEMBER 2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DL
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DG
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XL(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BFWL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BFWLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,MINMAX
   52   FORMAT('IBUGA3,ISUBRO,MINMAX = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),XL(I)
   57     FORMAT('I,Y(I),XL(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'BFWE')ALOC=0.0
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     SUM[i=1 to n][LOG(L(i)] +
!     N*(LOG(SHAPE) - SHAPE*LOG(SCALE)) +
!     (SHAPE-1)*SUM[i=1 to n][LOG(X(i) - LOC] -
!     SUM[i=1 to n][-L(i)*((X(i) - LOC)/SCALE)**SHAPE]
!
!     L IS THE GAUGE LENGTH PARAMETER.  THE "XL" ARRAY ALLOWS
!     DIFFERENT VALUES OF L
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DG=DBLE(SHAPE)
      DTERM1=DN*(DLOG(DG) - DG*DLOG(DS))
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DL=DBLE(XL(I))
        DSUM1=DSUM1 + DLOG(DX - DU)
        DSUM2=DSUM2 + DL*((DX-DU)/DS)**DG
        DSUM3=DSUM3 + DLOG(DL)
 1000 CONTINUE
!
      DLIK=DTERM1 + (DG-1.0D0)*DSUM1 - DSUM2
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'3BFW')DNP=3.0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BFWLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BFWLI1
      SUBROUTINE BFWML1(Y,AL,N,MAXNXT,   &
                        TEMP1,TEMP2,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        SCALSV,SHAPSV,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER BRITTLE FIBER WEIBULL DISTRIBUTION FOR
!              THE RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).
!              THIS ROUTINE CURRENTLY RETURNS ONLY THE POINT ESTIMATES.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMBFW WILL GENERATE THE OUTPUT
!              FOR THE BRITTLE FIBER WEIBULL MLE COMMAND).
!
!              THE MLE ESTIMATES ARE THE SOLUTION TO THE FOLLOWING
!              TWO SIMULTANEOUS NON-LINEAR EQUATIONS:
!
!              SIGMA - (SUM[i=1 to N][L(i)*X(i)**G]/N)**(1/G)
!
!              N/G - N*LOG(SIGMA) + SUM[i=1 to n][LOG(X(i))] -
!                    SUM[i=1 to n][L(i)*(X(i)/G)**G*LOG(X(i)/G]
!
!              WITH G AND SIGMA DENOTING THE SHAPE PARAMETER GAMMA AND
!              SCALE PARAMETER SIGMA, RESPECTIVELY.
!
!              THE L(i) ARE THE GAUGE LENGTHS.  THESE CAN EITHER
!              BE CONSTANT (I.E., WE ARE FITTING A SINGLE LEVEL OF
!              L) OR VARIABLE.  THE L VALUES ARE STORED IN THE UPPER
!              HALF OF THE DATA ARRAY.
!
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/11
!     ORIGINAL VERSION--NOVEMBER  2010.
!     UPDATED         --JUNE      2011. MODIFIED ALGORITHM FOR
!                                       DETERMINING STARTING VALUES
!     UPDATED         --MAY       2012. MODIFIED ALGORITHM FOR
!                                       DETERMINING STARTING VALUES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION AL(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      EXTERNAL BFWFUN
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWEIBC
      CHARACTER*4 IWEIFL
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BFWM'
      ISUBN2='L1  '
      IERROR='NO'
!
      DO 11 I=1,MAXNXT
        TEMP1(I)=0.0
        TEMP2(I)=0.0
   11 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BFWML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IERROR,N
   52   FORMAT('IBUGA3,ISUBRO,IERROR,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),AL(I)
   57     FORMAT('I,Y(I),AL(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'WML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  CARRY OUT CALCULATIONS                         **
!               **  FOR BRITTLE FIBER WEIBULL MLE ESTIMATE         **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='2-PARAMETER BRITTLE FIBER WEIBULL'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      SHAPML=CPUMIN
      SCALML=CPUMIN
!
      IF(SHAPSV.GT.0.0 .AND. SCALSV.GT.0.0)THEN
        XPAR(1)=DBLE(SHAPSV)
        XPAR(2)=DBLE(SCALSV)
      ELSE
!
!       IF NO STARTING VALUES SPECIFIED, COMPUTE STARTING
!       VALUES BASED ON STANDARD 2-PARAMETER WEIBULL.
!
!       THIS IS NOT REALLY SATISFACTORY AS THE "L" PARAMETER
!       MAY DISTORT THE SCALE PARAMETER.
!
!       2011/6: MODIFY ALGORITHM FOR STARTING VALUES.  USE
!
!               1) ESTIMATE SHAPE BASED ON THE STANDARD WEIBULL
!                  SINCE THE SHAPE PARAMETER FOR STANDARD WEIBULL
!                  AND BRITTLE FIBER WEIBULL SHOULD BASICALLY BE
!                  EQUIVALENT.
!
!               2) BASED ON THIS ESTIMATE OF GAMMA, GENERATE
!                  A PROBABILITY PLOT AND USE THE ESTIMATE OF
!                  SCALE (PPA1) FROM THIS.
!
!                  NOTE: 2012/5 - JUST USE THE EQUATION
!
!                        SIGMA = (SUM[i=1 to N][L(i)*X(i)**G]/N)**(1/G)
!
        IWEIBC='OFF'
        IWEIFL='WEIB'
        MINMAX=1
        CALL WEIML1(Y,N,IWEIBC,IWEIFL,MINMAX,   &
                    TEMP1,DTEMP1,   &
                    XMEAN,XSD,XVAR,XMIN,XMAX,   &
                    ZMEAN,ZSD,   &
                    SCALML,SCALSE,GHAT,SHAPSE,   &
                    SHAPBC,SHABSE,COVSE,COVBSE,   &
                    ISUBRO,IBUGA3,IERROR)
!
!CCCC   IWRITE='OFF'
!CCCC   AN=REAL(N)
!CCCC   CALL MEAN(AL,N,IWRITE,ALMEAN,IBUGA3,IERROR)
!
!CCCC   CALL SORT(Y,N,Y)
!CCCC   CALL UNIMED(N,TEMP1)
!CCCC   DO120I=1,N
!CCCC     CALL BFWPPF(DBLE(TEMP1(I)),DBLE(GHAT),DBLE(ALMEAN),DWOUT)
!CCCC     TEMP1(I)=REAL(DWOUT)
!C120   CONTINUE
!CCCC   CALL LINFIT(Y,TEMP1,N,
!CCCC1              PPA0,PPA1,XRESSD,XRESDF,PPCC,SDPPA0,SDPPA,CCALBE,
!CCCC1              ISUBRO,IBUGA3,IERROR)
!
        DSUM1=0.0D0
        DO 120 I=1,N
          DSUM1=DSUM1 + DBLE(AL(I))*DBLE(Y(I))**DBLE(GHAT)
  120   CONTINUE
        DSCALE=(DSUM1/DBLE(N))**(1.0D0/DBLE(GHAT))
!
        XPAR(1)=DBLE(GHAT)
!CCCC   XPAR(2)=DBLE(PPA1)
        XPAR(2)=DSCALE
      ENDIF
!
      DO 1010 I=1,N
        IINDX=I+N
        IF(IINDX.GT.MAXNXT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1111)
 1111     FORMAT('**** ERROR IN 2-PARAMETER BRITTLE FIBER WEIBULL ',   &
                 'MAXIMUM LIKELIHOOD')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1113)MAXNXT/2
 1113     FORMAT('     MAXIMUM NUMBER OF ROWS (',I8,') EXCEEDED.')
          CALL DPWRST('XXX','WRIT')
          SHAPML=CPUMIN
          SCALML=CPUMIN
          IERROR='YES'
          GO TO 9000
        ENDIF
        Y(I+N)=AL(I)
 1010 CONTINUE
!
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(BFWFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      SHAPML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'WML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BFWML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPSV,SCALSV,SHAPML,SCALML
 9017   FORMAT('SHAPSV,SCALSV,SHAPML,SCALML =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)XPAR(1),XPAR(2),INFO
 9019   FORMAT('XPAR(1),XPAR(2),INFO =  ',2G15.7,I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BFWML1
      SUBROUTINE BFWPDF(X,GAMMA,AL,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BRITTLE FIBER WEIBULL
!              DISTRIBUTION WITH TAIL LENGTH PARAMETER = GAMMA AND
!              GAUGE LENGTH PARAMETER L.
!
!              THE BRITTLE FIBER WEIBULL DISTRIBUTION USED HEREIN IS
!              DEFINED FOR ALL POSITIVE X AND HAS THE
!              PROBABILITY DENSITY FUNCTION
!
!              f(X;GAMMA,L,SCALE) = L*GAMMA*(X**(GAMMA-1))*
!                                   EXP(-L*((X/SCALE)**GAMMA))/
!                                   (SCALE**GAMMA)
!
!              THE S PARAMETER IS THE SCALE PARAMETER AND IS SET TO
!              1 FOR THIS SUBROUTINE.
!     INPUT  ARGUMENTS--X      = THE VALUE AT WHICH THE
!                                PROBABILITY DENSITY FUNCTION IS TO
!                                BE EVALUATED.  X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER GAMMA.
!                     --AL     = THE GAUGE LENGTH PARAMETER L.
!     OUTPUT ARGUMENTS--PDF    = THE PROBABILITY DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION VALUE
!             PDF FOR THE BRITTLE FIBER WEIBULL DISTRIBUTION WITH
!             TAIL LENGTH PARAMETER = GAMMA AND GAUGE LENGTH PARAMETER L.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA AND AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--AUGUST    2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION AL
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF(X.LT.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BFWPDF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.EQ.0.0D0)THEN
        IF(GAMMA.EQ.1.0D0)THEN
          PDF=1.0D0
          GO TO 9000
        ELSEIF(GAMMA.GT.1.0D0)THEN
          PDF=0.0D0
          GO TO 9000
        ELSE
          WRITE(ICOUT,7)
    7     FORMAT('***** ERROR--THE FIRST ARGUMENT TO BFWPDF IS ',   &
                 'ZERO.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BFWPDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BFWPDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DTERM1=AL*GAMMA*(X**(GAMMA-1.0))
      DTERM2=DEXP(-AL*(X**GAMMA))
      PDF=DTERM1*DTERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWPDF
      SUBROUTINE BFWPD2(X,NX,LI,PI,NI,GAMMA,ALOC,SCALE,   &
                        PDF,   &
                        ISUBRO,IBUGA2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BRITTLE FIBER WEIBULL
!              DISTRIBUTION WITH TAIL LENGTH PARAMETER = GAMMA AND
!              GAUGE LENGTH PARAMETER L.
!
!              THE BRITTLE FIBER WEIBULL DISTRIBUTION USED HEREIN IS
!              HAS THE PROBABILITY DENSITY FUNCTION
!
!              f(X;GAMMA,L,SCALE) = L*GAMMA*(X**(GAMMA-1))*
!                                   EXP(-L*((X/SCALE)**GAMMA))/
!                                   (SCALE**GAMMA)
!
!              THE BFWPDF ROUTINE COMPUTES THIS FUNCTION FOR A SINGLE
!              VALUE OF L.  THIS ROUTINE COMPUTES THIS FUNCTION FOR
!              MULTIPLE VALUES OF L.  IT DOES THIS USING A MIXTURE
!              APPROACH.  THAT IS
!
!              f(X;GAMMA,L,LOC,SCALE) = SUM[i=1 to NI]
!                  [p(i)*BFWPDF(X;GAMMA,L(i),LOC,SCALE)]
!
!              WHERE NI IS THE NUMBER OF DISTINCT VALUES FOR L.
!
!              THIS ROUTINE ASSUMES THAT THE LOCATION/SCALE/SHAPE
!              PARAMETERS ARE FIXED (I.E., ONLY L VARIES).
!
!              CURRENTLY, WE RESTRICT L TO A MAXIMUM OF 10 DISTINCT
!              LEVELS.
!
!     INPUT  ARGUMENTS--X      = A VARIABLE CONTAINING THE VALUES AT WHICH
!                                THE PROBABILITY DENSITY FUNCTION IS TO
!                                BE EVALUATED.
!                     --NX     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR X.
!                     --LI     = A VARIABLE CONTAINING THE GAUGE LENGTH
!                                PARAMETER L.
!                     --PI     = A VARIABLE CONTAINING THE "MIXING"
!                                PROPORTIONS FOR LI.
!                     --NI     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR LI AND PI.
!                     --GAMMA  = THE SHAPE PARAMETER GAMMA.
!                     --ALOC   = THE LOCATION PARAMETER.
!                     --SCALE  = THE SCALE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = A VARIABLE CONTAINING THE PROBABILITY
!                                DENSITY FUNCTION VALUES.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION VALUES.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA AND AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BFWPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--OCTOBER   2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION LI(*)
      DOUBLE PRECISION PI(*)
      DOUBLE PRECISION PDF(*)
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION ALOC
      DOUBLE PRECISION SCALE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'WCD2')THEN
        WRITE(ICOUT,31)IBUGA2,ISUBRO
   31   FORMAT('AT THE BEGINNING OF BFWCD2')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN BRITTLE FIBER WEIBULL PDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)
    3   FORMAT('      THE NUMBER OF REQUESTED PDF VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)NX
    5   FORMAT('      THE NUMBER OF REQUESTED PDF VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
   15   FORMAT('      THE NUMBER OF REQUESTED L VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.GT.10)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,18)
   18   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS GREATER THAN 10.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,23)
   23   FORMAT('      THE VALUE OF THE SHAPE PARAMETER (GAMMA) ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,25)GAMMA
   25   FORMAT('      THE VALUE OF GAMMA  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(SCALE.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,33)
   33   FORMAT('      THE VALUE OF THE SCALE PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,35)SCALE
   35   FORMAT('      THE VALUE OF THE SCALE PARAMETER  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 40 I=1,NX
        IF((GAMMA.GE.1.0D0 .AND. X(I).LT.ALOC) .OR.   &
           (GAMMA.LT.1.0D0 .AND. X(I).LE.ALOC))THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,45)I
   45     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE INPUT ',   &
                 'ARGUMENT IS ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,47)
   47     FORMAT('      LESS THAN OR EQUAL TO THE LOCATION PARAMETER.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,48)X(I)
   48     FORMAT('      THE VALUE OF X(I)                    = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,49)ALOC
   49     FORMAT('      THE VALUE OF THE LOCATION PARAMETER  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
   40 CONTINUE
!
      DSUM1=0.0D0
      DO 50 I=1,NI
        IF(LI(I).LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,52)I
   52     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE GAUGE LENGTH ',   &
                 'ARGUMENT (L) IS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,54)LI(I)
   54     FORMAT('      THE VALUE OF L(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ELSEIF(PI(I).LE.0.0D0 .OR. PI(I).GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,57)I
   57     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE MIXING ',   &
                 'ARGUMENT (P)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,58)
   58     FORMAT('      OUTSIDE THE (0,1) INTERVAL).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,59)PI(I)
   59     FORMAT('      THE VALUE OF P(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
        DSUM1=DSUM1 + PI(I)
   50 CONTINUE
!
!     CHECK THAT MIXING PROPORTIONS SUM TO 1
!
      IF(ABS(DSUM1 - 1.0D0).GT.0.000001D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE MIXING PROPORTIONS DO NOT SUM TO ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)REAL(DSUM1)
   65   FORMAT('      THE SUM OF THE MIXING PROPORTIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOW COMPUTE THE PDF BY SUMMING OVER THE L(I) CASES
!
      DO 100 I=1,NX
        DSUM1=0.0D0
        DO 200 J=1,NI
          DTERM1=(X(I)-ALOC)/SCALE
          CALL BFWPDF(DTERM1,GAMMA,LI(J),DTERM2)
          DSUM1=DSUM1 + PI(J)*(DTERM2/SCALE)
  200   CONTINUE
        PDF(I)=DSUM1
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWPD2
      SUBROUTINE BFWPPF(P,GAMMA,AL,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BRITTLE FIBER WEIBULL
!              DISTRIBUTION WITH TAIL LENGTH PARAMETER GAMMA AND
!              GAUGE LENGTH PARAMETER L.
!
!              THE BRITTLE FIBER WEIBULL DISTRIBUTION USED HEREIN IS
!              DEFINED FOR ALL POSITIVE X AND HAS THE PERCENT POINT
!              FUNCTION
!
!                 G(P;GAMMA,L) = [LOG(1/(1-P))/L]**(1/GAMMA)
!
!     INPUT  ARGUMENTS--P      = THE VALUE AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.  P SHOULD
!                                BE IN THE INTERVAL (0,1).
!                     --GAMMA  = THE SHAPE PARAMETER GAMMA.
!                     --AL     = THE GAUGE LENGTH PARAMETER L.
!     OUTPUT ARGUMENTS--PPF    = THE PERCENT POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BRITTLE FIBER WEIBULL
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER GAMMA AND
!             GAUGE LENGTH PARAMETER L.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE IN THE INTERVAL (0,1).
!                 --GAMMA AND AL SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--AUGUST    2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION AL
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BFWPPF IS ',   &
               'OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(1.0D0 - P.LE.0.0D0)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BFWPPF IS ',   &
               'TOO CLOSE TO 1 TO COMPUTE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BFWPPF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BFWPPF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(P.EQ.0.0D0)THEN
        PPF=0.0D0
      ELSE
        DTERM1=DLOG(1.0D0/(1.0D0 - P))
        PPF=(DTERM1/AL)**(1.0D0/GAMMA)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWPPF
      SUBROUTINE BFWPP2(P,NX,LI,PI,NI,GAMMA,ALOC,SCALE,   &
                        PPF,   &
                        ISUBRO,IBUGA2,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BRITTLE FIBER WEIBULL
!              DISTRIBUTION.
!
!              THE BFWPPF ROUTINE COMPUTES THIS FUNCTION FOR A SINGLE
!              VALUE OF L.  THIS ROUTINE COMPUTES THIS FUNCTION FOR
!              MULTIPLE VALUES OF L.  IT DOES THIS USING A MIXTURE
!              APPROACH.  ALTHOUGH BFWPPF COMPUTES THIS USING AN
!              CLOSED FORMULA, BFWPP2 NEEDS TO COMPUTE IT BY
!              NUMERICALLY INVERTING THE CUMULATIVE DISTRIBUTION
!              FUNCTION.
!
!              THIS ROUTINE ASSUMES THAT THE LOCATION/SCALE/SHAPE
!              PARAMETERS ARE FIXED (I.E., ONLY L VARIES).
!
!              CURRENTLY, WE RESTRICT L TO A MAXIMUM OF 10 DISTINCT
!              LEVELS.
!
!     INPUT  ARGUMENTS--P      = A VARIABLE CONTAINING THE VALUES AT WHICH
!                                THE PERCENT POINT FUNCTION IS
!                                TO BE EVALUATED.
!                     --NX     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR P.
!                     --LI     = A VARIABLE CONTAINING THE GAUGE LENGTH
!                                PARAMETER L.
!                     --PI     = A VARIABLE CONTAINING THE "MIXING"
!                                PROPORTIONS FOR LI.
!                     --NI     = A PARAMETER THAT SPECIFIES THE NUMBER
!                                OF VALUES FOR LI AND PI.
!                     --GAMMA  = THE SHAPE PARAMETER GAMMA.
!                     --ALOC   = THE LOCATION PARAMETER.
!                     --SCALE  = THE SCALE PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = A VARIABLE CONTAINING THE CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUES.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUES.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BFWCD2.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--OCTOBER   2010.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P(*)
      DOUBLE PRECISION LI(*)
      DOUBLE PRECISION PI(*)
      DOUBLE PRECISION PPF(*)
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION ALOC
      DOUBLE PRECISION SCALE
!
      DOUBLE PRECISION DCDF(1)
      DOUBLE PRECISION DX(1)
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DP
      DOUBLE PRECISION DP1
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DCDFL
      DOUBLE PRECISION DCDFR
      DOUBLE PRECISION DXL
      DOUBLE PRECISION DXR
      DOUBLE PRECISION DFXL
      DOUBLE PRECISION DFXR
      DOUBLE PRECISION DFCS
      DOUBLE PRECISION DXRML
      DOUBLE PRECISION DSIG
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION LMIN
      DOUBLE PRECISION LMAX
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS /1.0D-14/
      DATA DSIG /1.0D-14/
      DATA MAXIT /1000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'WCD2')THEN
        WRITE(ICOUT,31)IBUGA2,ISUBRO
   31   FORMAT('AT THE BEGINNING OF BFWCD2')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN BRITTLE FIBER WEIBULL PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)
    3   FORMAT('      THE NUMBER OF REQUESTED PPF VALUES IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)NX
    5   FORMAT('      THE NUMBER OF REQUESTED PPF VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
   15   FORMAT('      THE NUMBER OF REQUESTED L VALUES  = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NI.GT.10)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,18)
   18   FORMAT('      THE NUMBER OF DISTINCT GAUGE LENGTH (L) VALUES ',   &
               'IS GREATER THAN 10.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)NI
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,23)
   23   FORMAT('      THE VALUE OF THE SHAPE PARAMETER (GAMMA) ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,25)GAMMA
   25   FORMAT('      THE VALUE OF GAMMA  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(SCALE.LE.0.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,33)
   33   FORMAT('      THE VALUE OF THE SCALE PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,35)SCALE
   35   FORMAT('      THE VALUE OF THE SCALE PARAMETER  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DSUM1=0.0D0
      DO 50 I=1,NI
        IF(LI(I).LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,52)I
   52     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE GAUGE LENGTH ',   &
                 'ARGUMENT (L) IS NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,54)LI(I)
   54     FORMAT('      THE VALUE OF L(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ELSEIF(PI(I).LE.0.0D0 .OR. PI(I).GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,57)I
   57     FORMAT('      FOR ROW ',I8,' THE VALUE OF THE MIXING ',   &
                 'ARGUMENT (P)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,58)
   58     FORMAT('      OUTSIDE THE (0,1) INTERVAL).')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,59)PI(I)
   59     FORMAT('      THE VALUE OF P(I)  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
          IERROR='YES'
        ENDIF
        DSUM1=DSUM1 + PI(I)
   50 CONTINUE
!
!     CHECK THAT MIXING PROPORTIONS SUM TO 1
!
      IF(ABS(DSUM1 - 1.0D0).GT.0.000001D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE MIXING PROPORTIONS DO NOT SUM TO ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)REAL(DSUM1)
   65   FORMAT('      THE SUM OF THE MIXING PROPORTIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOW COMPUTE THE PPF BY NUMERICALLY INVERTING THE CDF FUNCTION
!
      NTEMP=1
      LMIN=LI(1)
      LMAX=LI(1)
      DO 90 I=1,NI
        IF(LI(I).LT.LMIN)LMIN=LI(I)
        IF(LI(I).GT.LMAX)LMAX=LI(I)
   90 CONTINUE
!
      DO 100 I=1,NX
        DP=P(I)
!
        IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)I
  105     FORMAT('      FOR ROW ',I8,' THE PROBABILITY PARAMETER (P) ',   &
                 'IS OUTSIDE THE (0,1) INTERVAL.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,106)DP
  106     FORMAT('      THE VALUE OF P  = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(1.0D0 - DP.LE.0.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,108)I
  108     FORMAT('      FOR ROW ',I8,' THE PROBABILITY PARAMETER (P) ',   &
                 'IS TOO CLOSE TO 1 TO COMPUTE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,106)DP
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        IF(DP.EQ.0.0D0)THEN
          PPF(I)=ALOC
          GO TO 100
        ENDIF
!
!       STEP 1: FIND BRACKETING INTERVAL
!
        CALL BFWPPF(DP,GAMMA,LMIN,DTERM1)
        DTERM1=ALOC + SCALE*DTERM1
        CALL BFWPPF(DP,GAMMA,LMAX,DTERM2)
        DTERM2=ALOC + SCALE*DTERM2
        DXL=MIN(DTERM1,DTERM2)
        DXR=MAX(DTERM1,DTERM2)
        IF(DXL.EQ.DXR)THEN
          PPF(I)=DXL
          GO TO 100
        ENDIF
        NTEMP=1
        DX(1)=DXL
        CALL BFWCD2(DX,NTEMP,LI,PI,NI,GAMMA,ALOC,SCALE,DCDF,   &
                    ISUBRO,IBUGA2,IERROR)
        DCDFL=DCDF(1)
        DX(1)=DXR
        CALL BFWCD2(DX,NTEMP,LI,PI,NI,GAMMA,ALOC,SCALE,DCDF,   &
                    ISUBRO,IBUGA2,IERROR)
        DCDFR=DCDF(1)
!
        IF(DCDFL.LT.DP .AND. DCDFR.LT.DP)THEN
          PPF(I)=CPUMIN
          GO TO 100
        ELSEIF(DCDFL.GT.DP .AND. DCDFR.GT.DP)THEN
          PPF(I)=CPUMIN
          GO TO 100
        ENDIF
!
!       STEP 2: BISECTION METHOD
!
        IC = 0
        DFXL = -DP
        DFXR = 1.0D0 - DP
  205   CONTINUE
        DX(1)=(DXL+DXR)*0.5D0
        CALL BFWCD2(DX,NTEMP,LI,PI,NI,GAMMA,ALOC,SCALE,DCDF,   &
                    ISUBRO,IBUGA2,IERROR)
        DP1=DCDF(1)
        DPPF=DX(1)
        DFCS = DP1 - DP
!
        IF(DFCS*DFXL.GT.0.0D0)THEN
          DXL = DX(1)
          DFXL = DFCS
        ELSE
          DXR = DX(1)
          DFXR = DFCS
        ENDIF
!
        DXRML = DXR - DXL
        IF(DXRML.LE.DSIG .AND. DABS(DFCS).LE.DEPS)THEN
          PPF(I)=DPPF
          GO TO 100
        ENDIF
!
!       STEP 3: ERROR MESSAGE FOR NO CONVERGENCE
!
        IC = IC + 1
        IF(IC.LE.MAXIT)GO TO 205
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,230)I,DP
  230   FORMAT('      FOR ROW ',I8,' (P = ',G15.7,'), THERE WAS ',   &
               'NO CONVERGENCE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,233)
  233   FORMAT('      LAST VALUE OBTAINED WILL BE USED.')
        CALL DPWRST('XXX','BUG ')
        PPF(I)=DPPF
        GO TO 100
!
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWPP2
      SUBROUTINE BFWRAN(N,GAMMA,AL,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BRITTLE FIBER WEIBULL DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.  NOT THAT THE
!              "GAUGE LENGTH" PARAMETER, L, IS ASSUMED FIXED AND KNOWN.
!              THIS IS ESSENTIALLY A RE-PARAMETERIZED WEIBULL
!              DISTRIBUTION THAT HAS THE PROBABILITY DENSITY FUNCTION
!
!              F(X;GAMMA,L,SCALE) = L*GAMMA*(X**(GAMMA-1))*
!                                   EXP(-L*((X/SCALE)**GAMMA))/
!                                   (SCALE**GAMMA)
!
!              SCALE IS SET TO 1 IN THIS ROUTINE.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --AL     = THE SINGLE PRECISION VALUE THAT SPECIEIS
!                                THE GAUGE LENGTH PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE BRITTLE FRACTURE WEIBULL
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!                 --AL    SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BFWPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010.8
!     ORIGINAL VERSION--AUGUST    2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF BRITTLE FIBER ',   &
               'WEIBULL RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE REQUESTED NUMBER OF RANDOM NUMBERS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE VALUE OF THE SHAPE PARAMETER (GAMMA) ',   &
               'FOR THE BRITTLE FIBER WEIBULL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,17)
   17   FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF GAMMA IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(AL.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE VALUE OF THE GAUGE LENGTH PARAMETER ',   &
               '(L) FOR THE BRITTLE FIBER WEIBULL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,27)
   27   FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)AL
   45   FORMAT('***** THE VALUE OF L IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N BRITTLE FIBER WEIBULL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL BFWPPF(DBLE(X(I)),DBLE(GAMMA),DBLE(AL),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BFWRAN
      SUBROUTINE BGECDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE BETA-GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X.
!
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;ALPHA,BETA) = B(ALPHA+1,X+BETA-1)/BETA(ALPHA,BETA)
!              WHERE B(A,B) IS THE BETA FUNCTION.
!              NOTE THAT HESSELAGER GIVES THIS AS
!              p(X;ALPHA,BETA) = B(X+ALPHA,BETA+1)/BETA(ALPHA,BETA)
!              (WE USE HESSELAGER'S RECCURENCE FORMUALAS FOR THE
!              CDF).
!
!              HESSELAGER'S RECURRENCE FORMULA FOR THE CUMULATIVE
!              DISTRIBUTION FUNCTION IS:
!
!                p(X;ALHA,BETA) - [(X+ALPHA-1)/(X+ALPHA+BETA)]*
!                                 p(X-1;ALPHA,BETA)
!
!              CONVERTING THIS TO THE MORE COMMON PARAMETERIZATION
!              YIELDS
!
!                p(X;ALHA,BETA) - [(X+BETA-2)/(X+ALPHA+BETA-1)]*
!                                 p(X-1;ALPHA,BETA)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE BETA-GEOMETRIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --ALPHA AND BETA SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLBETA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--OLE HESSELAGER (1994).  "A RECURSIVE PROCEDURE
!                 FOR CALCULATIONS OF SOME COMPOUND DISTRIBUTIONS",
!                 ASTIN BULLETIN, VOL. 24, NO. 1, PP. 19-32.
!               --JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, CHAPTER 6.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG< MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DLBETA
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
!
      INCLUDE 'DPCOMC.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BGECDF ',   &
              ' BGECDF IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BGECDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      INTX=INT(X+0.5)
      FINTX=REAL(INTX)
      IF(INTX.LT.1)THEN
        CDF=0.0
        GO TO 9999
      ENDIF
!
      DX=DBLE(FINTX)
      IF(DX.GT.DBLE(I1MACH(9)))THEN
        WRITE(ICOUT,55)
   55   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BGECDF IS GREATER ',   &
               'THAN THE LARGEST MACHINE INTEGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      DSUM=0.0D0
!
!     COMPUTE PDF FOR X = 1
!
      DTERM1=DLBETA(DALPHA+1.0D0,DBETA)
      DTERM2=DLBETA(DALPHA,DBETA)
      DTERM3=DTERM1-DTERM2
      DPDFSV=DEXP(DTERM3)
      DSUM=DPDFSV
!
      IF(INTX.GT.1)THEN
        DO 100 I=2,INTX
!CCCC     DPDF= DPDFSV*(DBLE(I)+DALPHA-1.0D0)/(DBLE(I)+DALPHA+DBETA)
          DPDF= DPDFSV*(DBLE(I)+DBETA-2.0D0)/   &
                (DBLE(I)+DALPHA+DBETA-1.0D0)
          DPDFSV=DPDF
          DSUM=DSUM + DPDF
  100   CONTINUE
        CDF=REAL(DSUM)
      ELSE
        CDF=REAL(DPDFSV)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BGECDF
      SUBROUTINE BG2CDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE BETA-GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X.
!
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;ALPHA,BETA) = B(ALPHA+1,X+BETA)/BETA(ALPHA,BETA)
!              WHERE B(A,B) IS THE BETA FUNCTION.
!              NOTE THAT HESSELAGER GIVES THIS AS
!              p(X;ALPHA,BETA) = B(X+ALPHA,BETA+1)/BETA(ALPHA,BETA)
!              THAT IS, THE ALPHA AND BETA ARE REVERSED.
!              (WE USE HESSELAGER'S RECCURENCE FORMUALAS FOR THE
!              CDF).
!
!              HESSELAGER'S RECURRENCE FORMULA FOR THE CUMULATIVE
!              DISTRIBUTION FUNCTION IS:
!
!                p(X;ALHA,BETA) - [(X+ALPHA-1)/(X+ALPHA+BETA)]*
!                                 p(X-1;ALPHA,BETA)
!
!              REVERSING THE ALPHA AND BETA YIELDS
!
!                p(X;ALHA,BETA) - [(X+BETA-1)/(X+ALPHA+BETA)]*
!                                 p(X-1;ALPHA,BETA)
!
!              NOTE THAT THE BGECDF ROUTINE IS THE BETA-GEOMETRIC
!              THAT STARTS WITH X = 1 WHEREAS THIS ROUTINE IS
!              SHIFTED TO START AT X = 0.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE BETA-GEOMETRIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --ALPHA AND BETA SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLBETA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--OLE HESSELAGER (1994).  "A RECURSIVE PROCEDURE
!                 FOR CALCULATIONS OF SOME COMPOUND DISTRIBUTIONS",
!                 ASTIN BULLETIN, VOL. 24, NO. 1, PP. 19-32.
!               --JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, CHAPTER 6.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG< MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DLBETA
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
!
      INCLUDE 'DPCOMC.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BG2CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BG2CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      INTX=INT(X+0.5)
      FINTX=REAL(INTX)
      IF(INTX.LT.0)THEN
        CDF=0.0
        GO TO 9999
      ENDIF
!
      DX=DBLE(FINTX)
      IF(DX.GT.DBLE(I1MACH(9)))THEN
        WRITE(ICOUT,55)
   55   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
               'BG2CDF SUBROUTINE IS GREATER THAN')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)
   56   FORMAT('      THE LARGEST MACHINE INTEGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
!
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      DSUM=0.0D0
!
!     COMPUTE PDF FOR X = 0
!
      DTERM1=DLBETA(DALPHA+1.0D0,DBETA)
      DTERM2=DLBETA(DALPHA,DBETA)
      DTERM3=DTERM1-DTERM2
      DPDFSV=DEXP(DTERM3)
      DSUM=DPDFSV
!
      IF(INTX.GT.0)THEN
        DO 100 I=1,INTX
          DPDF= DPDFSV*(DBLE(I)+DBETA-1.0D0)/   &
                (DBLE(I)+DALPHA+DBETA)
          DPDFSV=DPDF
          DSUM=DSUM + DPDF
  100   CONTINUE
        CDF=REAL(DSUM)
      ELSE
        CDF=REAL(DPDFSV)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BG2CDF
      SUBROUTINE BGEFUN(N,X,FVEC,IFLAG,XDATA,NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              BETA-GEOMETRIC MAXIMUM LIKELIHOOD EQUATIONS.
!
!              (N/PI) - SUM[i=1 to N]{SUM[r=1 to Y(i)-1]
!                       [1/(1-PI+(r-1)*THETA)]} = 0
!
!              SUM[i=1 to N]{SUM[r=1 to Y(i)-1]
!                       [(r-1)/(1-PI+(r-1)*THETA)] - SUM[r=1 to Y*i]
!                       [(r-1)/(1+(r-1)*THETA)] = 0
!
!              WITH THETA AND PI DENOTING THE SHAPE PARAMETERS.
!
!              NOTE THAT
!
!                 PI = ALPHA/(ALPHA+BETA)
!                 THETA = 1/(ALPHA + BETA)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--BETA-GEOMETRIC MAXIMUM LIKELIHOOD Y
!     REFERENCE --SUDHIR R. PAUL (2004).  "APPLICATIONS OF THE
!                 BETA DISTRIBUTION" in "HANDBOOK OF THE BETA
!                 DISTRIBUTION", EDITED BY GUPTA AND NADARAJAH,
!                 MARCEL-DEKKER, PP.431-436.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DTHETA=X(1)
      DPI=X(2)
      DN=DBLE(NOBS)
!
      DC1=DN/DPI
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,NOBS
        DSUM3=0.0D0
        DSUM4=0.0D0
        DSUM5=0.0D0
!
        DX=DBLE(XDATA(I))
        IX1=INT(DX+0.01) - 1
        IX2=IX1+1
        IF(IX1.GE.1)THEN
          DO 300 IR=1,IX1
            DR=DBLE(IR)
            DC2=1.0D0-DPI+(DR-1.0D0)*DTHETA
            DSUM3=DSUM3 + 1.0D0/DC2
            DSUM4=DSUM4 + (DR-1.0D0)/DC2
  300     CONTINUE
          DSUM1=DSUM1 + DSUM3
        ENDIF
!
        IF(IX2.GE.1)THEN
          DO 400 IR=1,IX2
            DR=DBLE(IR)
            DC2=1.0D0 + (DR-1.0D0)*DTHETA
            DSUM5=DSUM5 + (DR-1.0D0)/DC2
  400     CONTINUE
          DSUM2=DSUM2 + (DSUM4 - DSUM5)
        ENDIF
!
  200 CONTINUE
!
      FVEC(1)=DC1 - DSUM1
      FVEC(2)=DSUM2
!
      RETURN
      END SUBROUTINE BGEFUN
      SUBROUTINE BGEPDF(X,ALPHA,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE BETA-GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              POSITIVE INTEGER X.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;ALPHA,BETA) = B(ALPHA+1,X+BETA-1)/BETA(ALPHA,BETA)
!              WHERE B(A,B) IS THE BETA FUNCTION.
!              NOTE THAT HESSELAGER GIVES THIS AS
!              p(X;ALPHA,BETA) = B(X+ALPHA,BETA+1)/BETA(ALPHA,BETA)
!              (WE USE HESSELAGER'S RECCURENCE FORMUALAS FOR THE
!              CDF).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF
!             FOR THE BETA-GEOMETRIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
