      SUBROUTINE BGERAN(ALPHA,BETA,N,ISEED,X,IBGEDF)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BETA-GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = P FOLLOWING A BETA DISTRIBUTION WITH
!              SHAPE PARAMETERS ALPHA AND BETA.
!              AND NPAR (INCLUSIVELY).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER OF THE
!                                BETA DISTRIBUTION.
!                                ALPHA > 0.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER OF THE
!                                BETA DISTRIBUTION.
!                                BETA > 0.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BETA-GEOMETRIC DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA, BETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GEORAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE RANDOM NUMBER
!              GENERATOR MUST NECESSARILY BE A
!              SEQUENCE OF ***INTEGER*** VALUES,
!              THE OUTPUT VECTOR X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VECTORS FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--OLE HESSELAGER (1994).  "A RECURSIVE PROCEDURE
!                 FOR CALCULATIONS OF SOME COMPOUND DISTRIBUTIONS",
!                 ASTIN BULLETIN, VOL. 24, NO. 1, PP. 19-32.
!               --SUDHIR R. PAUL (2004).  "APPLICATIONS OF THE
!                 BETA DISTRIBUTION" in "HANDBOOK OF THE BETA
!                 DISTRIBUTION", EDITED BY GUPTA AND NADARAJAH,
!                 MARCEL-DEKKER, PP.431-436.
!               --JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, CHAPTER 6.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DIMENSION XTEMP(1)
!
      CHARACTER*4 IBGEDF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--NUMBER OF BETA-GEOMETRIC RANDOM ',   &
      'NUMBERS REQUESTED < 1')
   11 FORMAT('***** ERROR--THE ALPHA SHAPE PARAMETER ARGUMENT',   &
      ' TO THE BGERAN SUBROUTINE IS <= 0')
   12 FORMAT('***** ERROR--THE BETA SHAPE PARAMETER ARGUMENT',   &
      ' TO THE BGERAN SUBROUTINE IS <= 0')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.8)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     FIRST, GENERATE N BETA RANDOM NUMBERS.
!
      CALL BETRAN(N,ALPHA,BETA,ISEED,X)
!
      NTEMP=1
      DO 100 I=1,N
!
  110   CONTINUE
        P=X(I)
        IF(P.LE.0.0 .OR. P.GE.1.0)THEN
          CALL BETRAN(NTEMP,ALPHA,BETA,ISEED,X(I))
          GO TO 110
        ENDIF
        CALL GE2RAN(NTEMP,P,ISEED,XTEMP)
        X(I)=XTEMP(1)
        IF(IBGEDF.EQ.'SHIF')X(I)=X(I)-1.0
!
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BGERAN
      SUBROUTINE bgrat(a,b,x,y,w,eps,ierr)
!-----------------------------------------------------------------------
!     ASYMPTOTIC EXPANSION FOR IX(A,B) WHEN A IS LARGER THAN B.
!     THE RESULT OF THE EXPANSION IS ADDED TO W. IT IS ASSUMED
!     THAT A .GE. 15 AND B .LE. 1.  EPS IS THE TOLERANCE USED.
!     IERR IS A VARIABLE THAT REPORTS THE STATUS OF THE RESULTS.
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,eps,w,x,y
      INTEGER ierr
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION bm1,bp2n,cn,coef,dj,j,l,lnx,n2,nu,p,q,r,s,sum,t,   &
                       t2,u,v,z
      INTEGER i,n,nm1
!     ..
!     .. Local Arrays ..
      DOUBLE PRECISION c(30),d(30)
!     ..
!     .. External Functions ..
      DOUBLE PRECISION algdiv,alnrel,gam1
      EXTERNAL algdiv,alnrel,gam1
!     ..
!     .. External Subroutines ..
      EXTERNAL grat1
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dlog,exp
!     ..
!     .. Executable Statements ..
!
      bm1 = (b-0.5D0) - 0.5D0
      nu = a + 0.5D0*bm1
      IF (y.GT.0.375D0) GO TO 10
      lnx = alnrel(-y)
      GO TO 20
                                                                                                                                  
   10 lnx = dlog(x)
   20 z = -nu*lnx
      IF (b*z.EQ.0.0D0) GO TO 70
!
!                 COMPUTATION OF THE EXPANSION
!                 SET R = EXP(-Z)*Z**B/GAMMA(B)
!
      r = b* (1.0D0+gam1(b))*exp(b*dlog(z))
      r = r*exp(a*lnx)*exp(0.5D0*bm1*lnx)
      u = algdiv(b,a) + b*dlog(nu)
      u = r*exp(-u)
      IF (u.EQ.0.0D0) GO TO 70
      CALL grat1(b,z,r,p,q,eps)
!
      v = 0.25D0* (1.0D0/nu)**2
      t2 = 0.25D0*lnx*lnx
      l = w/u
      j = q/r
      sum = j
      t = 1.0D0
      cn = 1.0D0
      n2 = 0.0D0
      DO 50 n = 1,30
          bp2n = b + n2
          j = (bp2n* (bp2n+1.0D0)*j+ (z+bp2n+1.0D0)*t)*v
          n2 = n2 + 2.0D0
          t = t*t2
          cn = cn/ (n2* (n2+1.0D0))
          c(n) = cn
          s = 0.0D0
          IF (n.EQ.1) GO TO 40
          nm1 = n - 1
          coef = b - n
          DO 30 i = 1,nm1
              s = s + coef*c(i)*d(n-i)
              coef = coef + b
   30     CONTINUE
   40     d(n) = bm1*cn + s/n
          dj = d(n)*j
          sum = sum + dj
          IF (sum.LE.0.0D0) GO TO 70
          IF (abs(dj).LE.eps* (sum+l)) GO TO 60
   50 CONTINUE
!
!                    ADD THE RESULTS TO W
!
   60 ierr = 0
      w = w + u*sum
      RETURN
!
!               THE EXPANSION CANNOT BE COMPUTED
!
   70 ierr = 1
      RETURN
                                                                                                                                  
      END SUBROUTINE bgrat
      SUBROUTINE BILINR(Z,Y,X,N,Y2,X2,N2,IWRITE,Z2,   &
                        YTEMP,XTEMP,YDIST,XDIST,   &
                        ZDIST,ZTEMP2,ZTEMP,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE BI-LINEAR INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Z      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                Z AXIS DATA POINTS.
!                     --Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                VERTICAL AXIS INTERPOLATION
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Z2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                Z AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR
!           Y2(.) BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     NOTE--IT DOES ASSUME THAT THE ORIGINAL (Y,X) POINTS FORM A
!           RECTANGULAR GRID (ALTHOUGH THE GRID DOES NOT HAVE TO BE
!           PRE-SORTED).
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!     UPDATED         --JUNE      2019. DIMENSIONING OF SCRATCH
!                                       ARRAYS IN CALLING ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
      DIMENSION Z2(*)
!
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
      DIMENSION YDIST(*)
      DIMENSION XDIST(*)
      DIMENSION ZDIST(*)
      DIMENSION ZTEMP2(*)
      DIMENSION ZTEMP(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BILI'
      ISUBN2='NR  '
      IERROR='NO'
!
      ISTART=0
      ILAST=0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LINR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BILINR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,N2
   52   FORMAT('N,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Z(I),Y(I),X(I)
   56     FORMAT('I,Z(I),Y(I),X(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I),X2(I)
   66     FORMAT('I,Y2(I),X2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 11--                         **
!               **  SORT THE INPUT DATA ACCORDING     **
!               **  TO THE HORIZONTAL AXIS VARIABLE   **
!               ****************************************
!
      ISTEPN='11'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LINR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1010 ,I=1,N
        XTEMP(I)=X(I)
 1010 CONTINUE
!
      CALL SORTC(X,Y,N,X,Y)
      CALL SORTC(XTEMP,Z,N,XTEMP,Z)
!
!               *******************************************************
!               **  STEP 12--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT X VALUES        **
!               *******************************************************
!
      ISTEPN='12'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LINR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTX=0
      DO 1210 I=1,N
        IF(NDISTX.GT.0)THEN
          DO 1215 I2=1,NDISTX
           IF(X(I).EQ.XDIST(I2))GO TO 1210
 1215     CONTINUE
        ENDIF
        NDISTX=NDISTX+1
        XDIST(NDISTX)=X(I)
 1210 CONTINUE
!
      CALL SORT(XDIST,NDISTX,XDIST)
!
!               *******************************************************
!               **  STEP 13--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT Y VALUES        **
!               *******************************************************
!
      ISTEPN='13'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LINR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTY=0
      DO 1310 I=1,N
        IF(NDISTY.GT.0)THEN
          DO 1315 I2=1,NDISTY
            IF(Y(I).EQ.YDIST(I2))GO TO 1310
 1315     CONTINUE
        ENDIF
        NDISTY=NDISTY+1
        YDIST(NDISTY)=Y(I)
 1310 CONTINUE
!
      CALL SORT(YDIST,NDISTY,YDIST)
!
!               *******************************************************
!               **  STEP 14--                                        **
!               **  SORT Y ASSOCIATED WITH EACH DISTINCT X VALUE     **
!               **  CHECK FOR REPLICATION OF POINTS                  **
!               **  IF ALL DISTINCT (THAT IS, NO REPLICATION),     **
!               **  (THAT IS, HAVE NO REPLICATION),                **
!               **  THEN COPY OVER Z VALUES.                       **
!               **  IF NOT ALL DISTINCT                            **
!               **  (THAT IS, HAVE SOME REPLICATION),              **
!               **  THEN COMPUTE A MEAN VALUE OVER THE REPLICATES  **
!               **  AND TREAT THAT AS THE COMMON VALUE.            **
!               **  THE CORE OF THE INTERPOLATION CODE             **
!               **  IS EXPECTING SORTED, DISTINCT X AND Y VALUES.   **
!               **  ALSO CHECK THAT X AND Y FORM A RECTANGULAR GRID.**
!               *******************************************************
!
      ISTEPN='14'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LINR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMZ=0
      ISTART=1
      DO 1410 I=1,NDISTX
        XT=XDIST(I)
        ICOUNT=0
        DO 1420 J=ISTART,N
        IF(X(J).EQ.XT)THEN
          IF(ICOUNT.EQ.0)IFRST=J
          ICOUNT=ICOUNT+1
          YTEMP(ICOUNT)=Y(J)
          ZTEMP(ICOUNT)=Z(J)
          ILAST=J
        ELSEIF(X(J).GT.XT)THEN
          GO TO 1421
        ENDIF
 1420   CONTINUE
 1421   CONTINUE
!
        ISTART=ILAST+1
        CALL SORTC(YTEMP,ZTEMP,ICOUNT,YTEMP,ZTEMP)
        DO 1471 K=1,NDISTY
          TAG=YDIST(K)
          J=0
          DO 1472 II=1,ICOUNT
            IF(YTEMP(II).EQ.TAG)THEN
              J=J+1
              ZTEMP2(J)=ZTEMP(II)
            END IF
 1472     CONTINUE
          NI=J
          IF(NI.EQ.1)THEN
            NUMZ=NUMZ+1
            ZDIST(NUMZ)=ZTEMP2(1)
          ELSE IF(NI.GT.1)THEN
            CALL MEAN(ZTEMP2,NI,IWRITE,ZMEAN,IBUGG3,IERROR)
            NUMZ=NUMZ+1
            ZDIST(NUMZ)=ZMEAN
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1491)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1492)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
 1471   CONTINUE
!
 1410 CONTINUE
!
 1491 FORMAT('******* ERROR FROM BILINR.  ORIGINAL X AND Y')
 1492 FORMAT('        DATA DO NOT FORM A RECTANGULAR GRID.  ******')
!
!               ********************************************
!               **  STEP 14--                             **
!               **  COMPUTE INTERPOLATED VALUES           **
!               ********************************************
!
      CALL BILIN2(ZDIST,YDIST,XDIST,NDISTX,NDISTY,Y2,X2,N2,Z2,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LINR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BILINR--')
        CALL DPWRST('XXX','BUG ')
        DO 9042 I=1,N2
          WRITE(ICOUT,9043)I,X2(I),Y2(I),Z2(I)
 9043     FORMAT('I,X2(I),Y2(I),Z2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9042   CONTINUE
        WRITE(ICOUT,9051)NDISTX,NDISTY
 9051   FORMAT('NDISTX,NDISTY = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9052 I=1,NDISTX
          DO 9054 J=1,NDISTY
            WRITE(ICOUT,9053)I,J,XDIST(I),YDIST(J),ZDIST((I-1)*NDISTY+J)
 9053       FORMAT('I,J,XDIST(I),YDIST(J),ZDIST = ',2I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
 9054     CONTINUE
 9052   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE BILINR
      SUBROUTINE BILIN2(Z,Y,X,NX,NY,Y2,X2,N2,Z2,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE BI-LINEAR INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Z      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                Z AXIS DATA POINTS.
!                     --Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                VERTICAL AXIS INTERPOLATION
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Z2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR
!           Z2(.) BEING IDENTICAL TO THE INPUT VECTOR Z(.)
!     NOTE--THE X AND Y POINTS ARE ASSUMED TO LIE ON A RECTANGULAR GRID
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Z2(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BILI'
      ISUBN2='N2  '
      IERROR='NO'
!
      IY1=0
      IY2=0
      IX1=0
      IX2=0
!
      DO 10 I=1,N2
        Z2(I)=0.0
 10   CONTINUE
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'LIN2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF BILIN2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)NX,NY
   52 FORMAT('NX, NY = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 54 I=1,NX
      DO 55 J=1,NY
      INDX=(I-1)*NY+J
      WRITE(ICOUT,53)I,J,X(I),Y(J),Z(INDX)
      CALL DPWRST('XXX','BUG ')
 53   FORMAT('I,J,X(I),Y(J),Z = ',2I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 55   CONTINUE
 54   CONTINUE
      WRITE(ICOUT,62)N2
   62 FORMAT('N2 = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,N2
      WRITE(ICOUT,66)I,Y2(I),X2(I)
   66 FORMAT('I,Y2(I),X2(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
   90 CONTINUE
!
!               ****************************************
!               **  STEP 31--
!               **  COMPUTE INTERPOLATION VALUES
!               ****************************************
!
      DO 3100 J=1,N2
      XT=X2(J)
      IF(X(1).GT.XT.OR.XT.GT.X(NX))GO TO 3110
      YT=Y2(J)
      IF(Y(1).GT.YT.OR.YT.GT.Y(NY))GO TO 3120
      GO TO 3129
!
 3110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3111)
 3111 FORMAT('***** ERROR IN BILIN2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3112)
 3112 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3113)
 3113 FORMAT('      A SMOOTHED VALUE BEYOND THE X RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3114)
 3114 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3115)
 3115 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3116)X(1)
 3116 FORMAT('         SMALLEST DATA POINT X(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3117)X(NX)
 3117 FORMAT('         LARGEST DATA POINT  X(NX)     = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3118)XT
 3118 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 3120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3121)
 3121 FORMAT('***** ERROR IN BILIN2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3122)
 3122 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3123)
 3123 FORMAT('      A SMOOTHED VALUE BEYOND THE Y RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3124)
 3124 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3125)
 3125 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3126)Y(1)
 3126 FORMAT('         SMALLEST DATA POINT Y(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3127)Y(NY)
 3127 FORMAT('         LARGEST DATA POINT  Y(NY)     = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3128)YT
 3128 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 3129 CONTINUE
!
      DO 3200 I=1,NX-1
      IF(XT.GE.X(I).AND.XT.LE.X(I+1))THEN
        IX1=I
        IX2=I+1
        GO TO 3209
      ENDIF
 3200 CONTINUE
 3209 CONTINUE
!
      DO 3210 I=1,NY-1
      IF(YT.GE.Y(I).AND.YT.LE.Y(I+1))THEN
        IY1=I
        IY2=I+1
        GO TO 3219
      ENDIF
 3210 CONTINUE
 3219 CONTINUE
!
      A1=Z(NX*(IX1-1)+IY1)
      A2=Z(NX*(IX2-1)+IY1)
      A3=Z(NX*(IX2-1)+IY2)
      A4=Z(NX*(IX1-1)+IY2)
      T=XT-X(IX1)/(X(IX2)-X(IX1))
      U=YT-Y(IY1)/(Y(IY2)-Y(IY1))
      Z2(J)=(1.0-T)*(1.0-U)*A1 + T*(1.0-U)*A2 + T*U*A3 + (1.0-T)*U*A4
!
 3100 CONTINUE
!
!               ****************************************
!               **  STEP 41--
!               **  IF CALLED FOR,
!               **  WRITE OUT INTERPOLATION VALUES
!               ****************************************
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'LIN2')GO TO 4190
      DO 4100 J=1,N2
      WRITE(ICOUT,4110)X2(J),Y2(J),Z2(J)
      CALL DPWRST('XXX','BUG ')
 4110 FORMAT('X2(J),Y2(J),Z2(J) = ',3E15.7)
 4100 CONTINUE
 4190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'LIN2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF BILIN2--')
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE BILIN2
      SUBROUTINE BINCDF(X,P,N,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X FOR THE
!              BINOMIAL DISTRIBUTION WITH DOUBLE PRECISION 'BERNOULLI
!              PROBABILITY' PARAMETER = P, AND INTEGER 'NUMBER OF
!              BERNOULLI TRIALS' PARAMETER = N.  THE BINOMIAL
!              DISTRIBUTION USED HEREIN HAS MEAN = N*P AND
!              STANDARD DEVIATION = SQRT(N*P*(1-P)).  THIS DISTRIBUTION
!              IS DEFINED FOR ALL DISCRETE INTEGER X BETWEEN 0
!              (INCLUSIVELY) AND N (INCLUSIVELY).
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!
!                 p(X;P,N) = C(N,X) * P**X * (1-P)**(N-X).
!
!              WHERE C(N,X) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF N ITEMS
!              TAKEN X AT A TIME.  THE BINOMIAL DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF SUCCESSES IN N BERNOULLI
!              (0,1) TRIALS WHERE THE PROBABILITY OF SUCCESS
!              IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE CUMULATIVE DISTRIBUTION FUNCTION
!                                IS TO BE EVALUATED.  X SHOULD BE
!                                INTEGRAL-VALUED, AND BETWEEN 0.0
!                                AND N (INCLUSIVELY).
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE BINOMIAL DISTRIBUTION.  P SHOULD BE
!                                BETWEEN 0.0 (INCLUSIVELY) AND
!                                1.0 (INCLUSIVELY).
!                     --N      = THE INTEGER VALUE OF THE 'NUMBER OF
!                                BERNOULLI TRIALS' PARAMETER.
!                                N SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BINOMIAL DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P
!             AND 'NUMBER OF BERNOULLI TRIALS' PARAMETER = N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE INTEGRAL-VALUED, AND BETWEEN 0.0
!                  (INCLUSIVELY) AND N (INCLUSIVELY).
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY) AND 1.0
!                   (INCLUSIVELY).
!                 --N SHOULD BE A POSITIVE INTEGER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBETAI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 38.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 945, FORMULAE 26.5.24 AND
!                 26.5.28, AND PAGE 929.
!               --JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 50-86,
!                 ESPECIALLY PAGES 63-64.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 135-142.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 120-125.
!               --MOOD AND GRABLE, INTRODUCTION TO THE THEORY
!                 OF STATISTICS, EDITION 2, 1963, PAGES 64-69.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGES 264-272.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --MAY       1977.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2009. USE DBETAI FUNCTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      EXTERNAL DBETAI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      DN=DBLE(N)
!
      IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.LT.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0D0 .OR. X.GT.DN)THEN
        WRITE(ICOUT,4)N
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        IF(X.LT.0.0D0)CDF=0.0D0
        IF(X.GT.DN)CDF=1.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO BINCDF IS OUTSIDE ',   &
             'THE (0,N) = (0,',I8,') INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO BINCDF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO BINCDF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I10)
!
!     TREAT IMMEDIATELY THE SPECIAL CASE OF X = N,
!     IN WHICH CASE CDF = 1.0.
!     ALSO TREAT IMMEDIATELY THE SPECIAL CASE OF P = 0.0
!     IN WHICH CASE CDF = 1.0 FOR ALL X.
!     THIRDLY, TREAT THE SPECIAL CASE IN WHICH P = 1.0
!     IN WHICH CASE CDF = 0.0 FOR ALL X SMALLER THAN N
!     AND CDF = 1.0 FOR ALL X EQUAL TO OR LARGER
!     THAN N.
!
      INTX=INT(X+0.0001D0)
      DX=DBLE(INTX)
!
      IF(INTX.EQ.N)THEN
        CDF=1.0D0
      ELSEIF(P.EQ.0.0D0)THEN
        CDF=1.0D0
      ELSEIF(P.EQ.1.0D0 .AND. INTX.GE.N)THEN
        CDF=1.0D0
      ELSEIF(P.EQ.1.0D0 .AND. INTX.LT.N)THEN
        CDF=0.0
      ELSE
        CDF=1.0D0 - DBETAI(DBLE(P),DX+1.0D0,DN-DX)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BINCDF
      REAL FUNCTION BINFUN(P)
!
!     PURPOSE--DPMLBI CALLS FZERO TO FIND A ROOT FOR ONE OF
!              THE FOLLOWING FUNCTIONS:
!
!                 BINCDF(X;P,N) - (1 - ALPHA/2) = 0
!                 BINCDF(X;P,N) - (ALPHA/2)     = 0
!
!              WITH X, P, N, AND ALPHA DENOTING THE NUMBER OF
!              SUCCESSES, THE PROBABILITY OF SUCCESS PARAMETER,
!              THE NUMBER OF TRIALS, AND DESIRED SIGNIFICANCE
!              LEVEL RESPECTIVELY.  DPMLBI IS TRYING TO DETERMINE
!              AN EXACT CONFIDENCE INTERVAL FOR P.  THE VALUES
!              FOR X, N, AND (1 - ALPHA/2) (OR ALPHA/2) ARE PASSED
!              IN VIA A COMMON BLOCK.
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE BINFUN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BINCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KARL BURY (1999). "STATISTICAL DISTRIBUTIONS IN
!                 ENGINEERING", CAMBRIDGE UNIVERSITY PRESS, P. 74.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.8
!     ORIGINAL VERSION--AUGUST    2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
!
      COMMON/BINCOM/X,CONST,N
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL BINCDF(DBLE(X),DBLE(P),N,DCDF)
      BINFUN=REAL(DCDF) - CONST
!
      RETURN
      END FUNCTION BINFUN
      SUBROUTINE BINMAT(Y1,Y2,N,ICASL7,IWRITE,XIDTEM,STAT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GIVEN TWO BINARY RESPONSE VARIABLES (BINARY IN THE
!              SENSE OF BEING EITHER 0 OR 1 VALUES), COMPUTE
!              VARIOUS SIMILARITY, DISSIMILARITY AND INDEX VALUES.
!
!              THIS IS SPECIFICALLY FOR THE 2X2 CASE.  THAT IS,
!              EACH VARIABLE HAS TWO MUTUALLY EXCLUSIVE
!              CHOICES CODED AS 1 (FOR SUCCESS) OR 0 (FOR
!              FAILURE).  A FALSE POSITIVE IS DEFINED AS THE
!              ERROR WHERE THE SECOND VARIABLE IS 1 AND THE FIRST
!              VARIABLE IS A 0.  THIS DEFINES THE FOLLOWING
!              CONTNGENCY TABLE:
!
!                                    RESPONSE VARIABLE 2
!                                             0      1
!                                       -----------------
!                 RESPONSE VARIABLE 1:  0  |  A      B   |
!                                       1  |  C      D   |
!                                       -----------------
!
!              WHERE A, B, C, AND D DENOTE THE COUNTS FOR EACH
!              OF THESE CATEGORIES.
!
!              ROUSSEEUW AND KAUFFMAN DOCUMENT THE FOLLOWING
!              MATCHING SCORES THAT ARE OFTEN USED IN CLUSTERING
!              APPLICATIONS:
!
!              SYMMETRIC BINARY VARIABLES
!                 SIMILARITY:
!                 MATCHING COEFFICIENT:    (A+D)/(A+B+C+D)
!                 ROGERS AND TANIMOTO:     (A+D)/((A+D) + 2*(B+C))
!                 SOKAL AND SNEATH:        2*(A+D)/(2*(A+D) + (B+C))
!                 YULES Q                  (A*D - B*C)/(A*D + B*C)
!
!                 DISSIMILARITY:
!                 MATCHING COEFFICIENT:    (B+C)/(A+B+C+D)
!                 ROGERS AND TANIMOTO:     2*(B+C)/((A+D) + 2*(B+C))
!                 SOKAL AND SNEATH:        (B+C)/(2*(A+D) + (B+C))
!
!              ASYMMETRIC BINARY VARIABLES (MOST IMPORTANT VALUE
!              CODED AS 1)
!                 SIMILARITY:
!                 JACCARD COEFFICIENT:    A/(A+B+C)
!                 DICE COEFFICIENT:       2*A/(2*A+B+C)
!                 SOKAL COEFFICIENT:      A/(A+2(B+C))
!
!
!                 DISSIMILARITY:
!                 JACCARD COEFFICIENT:    (A+D)/(A+B+C+D)
!                 DICE COEFFICIENT:       (B+C)/(2*A+B+C)
!                 SOKAL COEFFICIENT:      2*(B+C)/(A+2(B+C))
!
!              ASYMMETRIC COEFFICIENTS ARE TYPICALLY USED WHEN
!              ONE OUTCOME IS RARE (E.G., MATCHING A RARE OUTCOME
!              IS THE IMPORTANT EVENT).
!
!              YOUDEN'S INDEX IS DEFINED AS
!
!                  J = (A*D - B*C)/((A+B)*(C+D))
!
!               YOUDEN'S INDEX IS TYPICALLY USED IN THE CONTEXT
!               OF ASSESSING THE PERFORMANCE OF A DIAGNOSTIC TEST
!               RATHER THAN AS A SIMILARITY OR DISSIMILARITY
!               MEASURE.  SPECIFICALLY, 0 INDICATES A TEST WITH
!               NO USEFUL INFORMATION WHILE 1 INDICATES A TEST WITH
!               NO FALSE POSITIVE AND NO FALSE NEGATIVES.
!
!              YULE'S Q (WHICH IS EQUIVALENT TO THE KRUSKAL GOODMAN
!              GAMMA COEFFICIENT FOR THIS CASE) IS DEFINED AS
!
!                  Q = (A*D - B*C)/(A*D + B*C)
!
!               YULE'S Y IS DEFINED IN TERMS OF THE YULE'S Q AS:
!
!                  Y = (1 - SQRT(1 - Q**2))/Q
!
!               OR DIRECTLY AS:
!
!                  {SQRT(A*D) - SQRT(B*C)}/{SQRT(A*D) + SQRT(B*C)}
!
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED FALSE POSITIVE PROPORTION
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE
!             MATCHING COEFFICIENT OF DATA IN THE INPUT VECTORS Y1
!             AND Y2.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--KAUFMAN AND ROUSSEEUW (1990), "FINDING GROUPS IN DATA:
!                AN INTRODUCTION TO CLUSTER ANALYSIS", WILEY.
!              --YOUDEN (1950), "INDEX FOR RATING DIAGNOSTIC TESTS",
!                CANCER, 3, PP. 32-35.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/08
!     ORIGINAL VERSION--AUGUST    2017.
!     UPDATED         --JANUARY   2019. YOUDEN INDEX
!     UPDATED         --AUGUST    2019. GAMMA COEFFICIENT FOR 2X2 CASE
!     UPDATED         --AUGUST    2019. YULE'S Y
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASL7
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*33 ISTAT
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION XIDTEM(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BINM'
      ISUBN2='AT  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NMAT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BINMAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASL7,N
   52   FORMAT('IBUGA3,ISUBRO,ICASL7,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE BINARY MATCHING ROUTINE--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLES IS LESS THAN ONE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NMAT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N.EQ.2)THEN
        A=Y1(1)
        B=Y2(1)
        C=Y1(2)
        D=Y2(2)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((A.EQ.0.0 .OR. A.EQ.1.0) .AND.   &
           (B.EQ.0.0 .OR. B.EQ.1.0) .AND.   &
           (C.EQ.0.0 .OR. C.EQ.1.0) .AND.   &
           (D.EQ.0.0 .OR. D.EQ.1.0)) GO TO 3000
!
        IF(A.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(B.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(C.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(D.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
      CALL DISTIN(Y1,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N
          Y1(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N
            IF(Y1(I).NE.1.0)Y1(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N
            IF(Y1(I).EQ.ATEMP1)Y1(I)=0.0
            IF(Y1(I).EQ.ATEMP2)Y1(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2211)
 2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2213)
 2213   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2215)NDIST
 2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL DISTIN(Y2,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N
          Y2(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N
            IF(Y2(I).NE.1.0)Y2(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N
            IF(Y2(I).EQ.ATEMP1)Y2(I)=0.0
            IF(Y2(I).EQ.ATEMP2)Y2(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      A=0.0
      B=0.0
      C=0.0
      D=0.0
      DO 2410 I=1,N
        IF(Y1(I).EQ.1.0 .AND. Y2(I).EQ.1.0)THEN
          D=D+1.0
        ELSEIF(Y1(I).EQ.0.0 .AND. Y2(I).EQ.0.0)THEN
          A=A+1.0
        ELSEIF(Y1(I).EQ.1.0 .AND. Y2(I).EQ.0.0)THEN
          C=C+1.0
        ELSEIF(Y1(I).EQ.0.0 .AND. Y2(I).EQ.1.0)THEN
          B=B+1.0
        ENDIF
 2410 CONTINUE
!
 3000 CONTINUE
!
      IF(ICASL7.EQ.'BMDI')THEN
        STAT=(B+C)/(A+B+C+D)
        ISTAT='MATCHING DISSIMILARITY'
      ELSEIF(ICASL7.EQ.'BMSI')THEN
        STAT=(A+D)/(A+B+C+D)
        ISTAT='MATCHING SIMILARITY'
      ELSEIF(ICASL7.EQ.'BMRD')THEN
        ANUM=2.0*(B+C)
        DENOM=(A+D) + 2.0*(B+C)
        STAT=ANUM/DENOM
        ISTAT='ROGERS AND TANIMOTO DISSIMILARITY'
      ELSEIF(ICASL7.EQ.'BMRS')THEN
        ANUM=A+D
        DENOM=(A+D) + 2.0*(B+C)
        STAT=ANUM/DENOM
        ISTAT='ROGERS AND TANIMOTO SIMILARITY'
      ELSEIF(ICASL7.EQ.'BMSD')THEN
        ANUM=B+C
        DENOM=2.0*(A+D) + (B+C)
        STAT=ANUM/DENOM
        ISTAT='SOKAL AND SNEATH DISSIMILARITY'
      ELSEIF(ICASL7.EQ.'BMSS')THEN
        ANUM=2.0*(A+D)
        DENOM=2.0*(A+D) + (B+C)
        STAT=ANUM/DENOM
        ISTAT='SOKAL AND SNEATH SIMILARITY'
      ELSEIF(ICASL7.EQ.'BJDI')THEN
        ANUM=B+C
        DENOM=A+B+C
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='JACCARD ASYMMETRIC DISSIMILARITY'
      ELSEIF(ICASL7.EQ.'BJSI')THEN
        ANUM=A
        DENOM=A+B+C
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='JACCARD ASYMMETRIC SIMILARITY'
      ELSEIF(ICASL7.EQ.'BDDI')THEN
        ANUM=B+C
        DENOM=2.0*A+B+C
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='DICE ASYMMETRIC DISSIMILARITY'
      ELSEIF(ICASL7.EQ.'BDSI')THEN
        ANUM=2.0*A
        DENOM=2.0*A+B+C
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='DICE ASYMMETRIC SIMILARITY'
      ELSEIF(ICASL7.EQ.'BSDI')THEN
        ANUM=2.0*(B+C)
        DENOM=A+2.0*(B+C)
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='SOKAL ASYMMETRIC DISSIMILARITY'
      ELSEIF(ICASL7.EQ.'BSSI')THEN
        ANUM=A
        DENOM=A+2.0*(B+C)
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='SOKAL ASYMMETRIC SIMILARITY'
      ELSEIF(ICASL7.EQ.'YULQ' .OR. ICASL7.EQ.'GC22')THEN
        ANUM=A*D - B*C
        DENOM=A*D + B*C
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='YULES Q'
      ELSEIF(ICASL7.EQ.'YOUD')THEN
        ANUM=A*D - B*C
        DENOM=(A+B)*(C+D)
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='YOUDEN INDEX'
      ELSEIF(ICASL7.EQ.'YULY')THEN
        ANUM=SQRT(A*D) - SQRT(B*C)
        DENOM=SQRT(A*D) + SQRT(B*C)
        IF(DENOM.GT.0.0)THEN
          STAT=ANUM/DENOM
        ELSE
          STAT=CPUMIN
        ENDIF
        ISTAT='YULES Y'
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)ISTAT,STAT
  811   FORMAT('THE ',A33,' COEFFICIENT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NMAT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF BINMAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,A,B,C,D,STAT
 9013   FORMAT('IERROR,A,B,C,D,STAT = ',A4,2X,5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE BINMAT
      FUNCTION BINOM(N,M)
!***BEGIN PROLOGUE  BINOM
!***DATE WRITTEN   770701   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C1
!***KEYWORDS  BINOMIAL COEFFICIENTS,SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the binomial coefficients.
!***DESCRIPTION
!
! BINOM(N,M) calculates the binomial coefficient (N!)/((M!)*(N-M)!).
!***REFERENCES  (NONE)
!***ROUTINES CALLED  ALNREL,R1MACH,R9LGMC,XERROR
!***END PROLOGUE  BINOM
      DOUBLE PRECISION D9LGMC
      INCLUDE 'DPCOMC.INC'
!
      INCLUDE 'DPCOP2.INC'
!
      DATA SQ2PIL / 0.91893853320467274E0 /
      DATA BILNMX, FINTMX / 0.0, 0.0 /
!***FIRST EXECUTABLE STATEMENT  BINOM
!
      BINOM=0.0
!
      IF (BILNMX.NE.0.0) GO TO 10
      BILNMX = LOG (R1MACH(2))
      FINTMX = 0.9/R1MACH(3)
!
 10   CONTINUE
      IF(N.LT.0)THEN
        WRITE(ICOUT,1)
 1      FORMAT('***** ERROR: FIRST ARGUMENT TO BINOM IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(M.LT.0)THEN
        WRITE(ICOUT,2)
 2      FORMAT('***** ERROR: SECOND ARGUMENT TO BINOM IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF (N.LT.M) THEN
        WRITE(ICOUT,3)
 3      FORMAT('***** ERROR: FIRST ARGUMENT TO BINOM IS LESS THAN ',   &
               'SECOND ARGUMENT.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      K = MIN0 (M, N-M)
      IF (K.GT.20) GO TO 30
      IF (FLOAT(K)*LOG(AMAX0(N,1)).GT.BILNMX) GO TO 30
!
      BINOM = 1.
      IF (K.EQ.0) GO TO 9000
!
      DO 20 I=1,K
        BINOM = BINOM * FLOAT(N-I+1)/FLOAT(I)
 20   CONTINUE
!
      IF (BINOM.LT.FINTMX) BINOM = AINT (BINOM+0.5)
      GO TO 9000
!
! IF K.LT.9, APPROX IS NOT VALID AND ANSWER IS CLOSE TO THE OVERFLOW LIM
 30   CONTINUE
      IF (K.LT.9) THEN
        WRITE(ICOUT,31)
 31     FORMAT('***** ERROR: BINOM OVERFLOWS BECAUSE ONE (OR BOTH) OF ',   &
               'THE ARGUMENTS IS TOO LARGE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      XN = N + 1
      XK = K + 1
      XNK = N - K + 1
!
      CORR = SNGL(D9LGMC(DBLE(XN))) - SNGL(D9LGMC(DBLE(XK))) -   &
             SNGL(D9LGMC(DBLE(XNK)))
      BINOM = XK*LOG(XNK/XK) - XN*ALNREL(-(XK-1.)/XN)   &
        - 0.5*LOG(XN*XNK/XK) + 1.0 - SQ2PIL + CORR
!
      IF (BINOM.GT.BILNMX) THEN
!
        WRITE(ICOUT,41)
 41     FORMAT('***** ERROR: BINOM OVERFLOWS BECAUSE ONE (OR BOTH) OF ',   &
               'THE ARGUMENTS IS TOO LARGE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      BINOM = EXP (BINOM)
      IF (BINOM.LT.FINTMX) BINOM = AINT (BINOM+0.5)
!
 9000 CONTINUE
      RETURN
      END FUNCTION BINOM
      SUBROUTINE BINPDF(X,P,N,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X FOR THE
!              BINOMIAL DISTRIBUTION WITH DOUBLE PRECISION 'BERNOULLI
!              PROBABILITY' PARAMETER = P, AND INTEGER 'NUMBER OF
!              BERNOULLI TRIALS' PARAMETER = N.  THE BINOMIAL
!              DISTRIBUTION USED HEREIN HAS MEAN = N*P AND
!              STANDARD DEVIATION = SQRT(N*P*(1-P)).  THIS DISTRIBUTION
!              IS DEFINED FOR ALL DISCRETE INTEGER X BETWEEN 0
!              (INCLUSIVELY) AND N (INCLUSIVELY).
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!
!                 p(X;P,N) = C(N,X) * P**X * (1-P)**(N-X).
!
!              WHERE C(N,X) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF N ITEMS
!              TAKEN X AT A TIME.  THE BINOMIAL DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF SUCCESSES IN N BERNOULLI
!              (0,1) TRIALS WHERE THE PROBABILITY OF SUCCESS
!              IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE PORBABILITY MASS FUNCTION
!                                IS TO BE EVALUATED.  X SHOULD BE
!                                INTEGRAL-VALUED, AND BETWEEN 0.0
!                                AND N (INCLUSIVELY).
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE BINOMIAL DISTRIBUTION.  P SHOULD BE
!                                BETWEEN 0.0 (EXCLUSIVELY) AND
!                                1.0 (INCLUSIVELY).
!                     --N      = THE INTEGER VALUE OF THE 'NUMBER OF
!                                BERNOULLI TRIALS' PARAMETER.
!                                N SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY MASS
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE PDF
!             FOR THE BINOMIAL DISTRIBUTION WITH 'BERNOULLI PROBABILITY'
!             PARAMETER = P AND 'NUMBER OF BERNOULLI TRIALS'
!             PARAMETER = N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE INTEGRAL-VALUED, AND BETWEEN 0.0
!                  (INCLUSIVELY) AND N (INCLUSIVELY).
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY) AND 1.0
!                   (INCLUSIVELY).
!                 --N SHOULD BE A POSITIVE INTEGER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BINRAW.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CATHERINE LOADER (2000), "FAST AND ACCURATE COMPUTATION
!                 OF BINOMIAL PROBABILITIES", BELL LABS?
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      DN=DBLE(N)
!
      IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.LT.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0D0 .OR. X.GT.DN)THEN
        WRITE(ICOUT,4)N
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO BINPDF IS OUTSIDE ',   &
             'THE (0,N) = (0,',I8,') INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO BINPDF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO BINPDF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I10)
!
      INTX=INT(X+0.0001D0)
      DX=DBLE(INTX)
      DQ=1.0D0 - P
      ILOG=0
!
      CALL BINRAW(DX,P,DQ,DN,PDF,ILOG)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BINPDF
      SUBROUTINE BINPPF(P,PPAR,N,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE AT THE DOUBLE PRECISION VALUE P FOR THE BINOMIAL
!              DISTRIBUTION WITH DOUBLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = PPAR, AND INTEGER 'NUMBER OF BERNOULLI
!              TRIALS' C              PARAMETER = N.  THE BINOMIAL
!              DISTRIBUTION USED HEREIN HAS MEAN = N*PPAR AND
!              STANDARD DEVIATION = SQRT(N*PPAR*(1-PPAR)).  THIS
!              DISTRIBUTION IS DEFINED FOR ALL DISCRETE INTEGER X
!              BETWEEN 0 (INCLUSIVELY) AND N (INCLUSIVELY).
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!
!                 p(X;P,N) = C(N,X) * PPAR**X * (1-PPAR)**(N-X).
!
!              WHERE C(N,X) IS THE COMBINATORIAL FUNCTION EQUALING THE
!              NUMBER OF COMBINATIONS OF N ITEMS TAKEN X AT A TIME.
!              THE BINOMIAL DISTRIBUTION IS THE DISTRIBUTION OF THE
!              NUMBER OF SUCCESSES IN N BERNOULLI (0,1) TRIALS WHERE
!              THE PROBABILITY OF SUCCESS IN A SINGLE TRIAL = PPAR.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE (BETWEEN
!                                0.0 (INCLUSIVELY) AND 1.0
!                                (INCLUSIVELY)) AT WHICH THE PERCENT
!                                POINT FUNCTION IS TO BE EVALUATED.
!                     --PPAR   = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE BINOMIAL DISTRIBUTION.  PPAR SHOULD
!                                BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                                1.0 (EXCLUSIVELY).
!                     --N      = THE INTEGER VALUE OF THE 'NUMBER OF
!                                BERNOULLI TRIALS' PARAMETER.  N SHOULD
!                                BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF
!             FOR THE BINOMIAL DISTRIBUTION WITH 'BERNOULLI PROBABILITY'
!             PARAMETER = PPAR AND 'NUMBER OF BERNOULLI TRIALS'
!             PARAMETER = N.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--PPAR SHOULD BE BETWEEN 0.0 (INCLUSIVELY) AND 1.0
!                  (EXCLUSIVELY).
!                 --N SHOULD BE A POSITIVE INTEGER.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY) AND 1.0
!                   (INCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF, BINCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 50-86,
!                 ESPECIALLY PAGE 64, FORMULA 36.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 36-41.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 135-142.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 120-125.
!               --MOOD AND GRABLE, INTRODUCTION TO THE THEORY
!                 OF STATISTICS, EDITION 2, 1963, PAGES 64-69.
!               --OWEN, HANDBOOK OF STATISTICAL
!                 TABLES, 1962, PAGES 264-272.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2009. MAKE DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(PPAR.LT.0.0D0 .OR. PPAR.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.LT.1)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO BINPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO BINPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO BINPPF IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      DN=DBLE(N)
      DPPAR=PPAR
      IX0=0
      IX1=0
      IX2=0
      P0=0.0D0
      P1=0.0D0
      P2=0.0D0
!
!     TREAT CERTAIN SPECIAL CASES IMMEDIATELY--
!     1) P = 0.0 OR 1.0
!     2) P = 0.5 AND PPAR = 0.5
!     3) PPF = 0 OR N
!
      IF(P.EQ.0.0D0)THEN
        PPF=0.0D0
        GO TO 9000
      ELSEIF(P.EQ.1.0D0)THEN
        PPF=DBLE(N)
        GO TO 9000
      ELSEIF(P.EQ.0.5D0 .AND. PPAR.EQ.0.5D0)THEN
        IPPF=N/2
        PPF=DBLE(IPPF)
        GO TO 9000
      ENDIF
!
      PF0=(1.0D0-DPPAR)**N
      QFN=1.0D0-(DPPAR**N)
      IF(P.LE.PF0)THEN
        PPF=0.0D0
        GO TO 9000
      ELSEIF(P.GT.QFN)THEN
        PPF=DBLE(N)
        GO TO 9000
      ENDIF
!
!     DETERMINE AN INITIAL APPROXIMATION TO THE BINOMIAL
!     PERCENT POINT BY USE OF THE NORMAL APPROXIMATION
!     TO THE BINOMIAL.
!     (SEE JOHNSON AND KOTZ, DISCRETE DISTRIBUTIONS,
!     PAGE 64, FORMULA 36).
!
      AMEAN=DN*DPPAR
      SD=SQRT(DN*DPPAR*(1.0D0-DPPAR))
      CALL NODPPF(P,ZPPF)
      X2=AMEAN-0.5D0+ZPPF*SD
      IX2=INT(X2)
!
!     CHECK AND MODIFY (IF NECESSARY) THIS INITIAL
!     ESTIMATE OF THE PERCENT POINT
!     TO ASSURE THAT IT BE IN THE CLOSED INTERVAL 0 TO N.
!
      IF(IX2.LT.0)IX2=0
      IF(IX2.GT.N)IX2=N
!
!     DETERMINE UPPER AND LOWER BOUNDS ON THE DESIRED
!     PERCENT POINT BY ITERATING OUT (BOTH BELOW AND ABOVE)
!     FROM THE ORIGINAL APPROXIMATION AT STEPS
!     OF 1 STANDARD DEVIATION.
!     THE RESULTING BOUNDS WILL BE AT MOST
!     1 STANDARD DEVIATION APART.
!
      IX0=0
      IX1=N
      ISD=INT(SD+1.0D0)
      X2=REAL(IX2)
      CALL BINCDF(X2,DPPAR,N,P2)
!
      IF(P2.LT.P)THEN
        IX0=IX2
        I=0
  215   CONTINUE
        I=I+1
        IF(I.GT.1000000)THEN
          WRITE(ICOUT,249)
  249     FORMAT('***** INTERNAL ERROR IN BINPPF SUBROUTINE *****')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,222)
  222     FORMAT('      NO UPPER BOUND FOUND AFTER 10**7 ITERATIONS')
          CALL DPWRST('XXX','BUG ')
          GO TO 950
        ENDIF
        IX2=IX0+ISD
        IF(IX2.GE.IX1)GO TO 275
        X2=IX2
        CALL BINCDF(X2,DPPAR,N,P2)
        IF(P2.GE.P)THEN
          IX1=IX2
          GO TO 275
        ENDIF
        IX0=IX2
        GO TO 215
!
      ELSE
!
        IX1=IX2
        I=0
  255   CONTINUE
        I=I+1
        IF(I.GT.1000000)THEN
          WRITE(ICOUT,249)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,262)
  262     FORMAT('      NO LOWER BOUND FOUND AFTER 10**7 ITERATIONS')
          CALL DPWRST('XXX','BUG ')
          GO TO 950
        ENDIF
        IX2=IX1-ISD
        IF(IX2.LE.IX0)GO TO 275
        X2=IX2
        CALL BINCDF(X2,PPAR,N,P2)
        IF(P2.LT.P)THEN
          IX0=IX2
        ELSE
          IX1=IX2
          GO TO 255
        ENDIF
      ENDIF
!
  275 CONTINUE
      IF(IX0.EQ.IX1)THEN
        IF(IX0.EQ.0)THEN
          IX1=IX1+1
        ELSEIF(IX0.EQ.N)THEN
          IX0=IX0-1
        ELSE
          WRITE(ICOUT,249)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,282)
  282     FORMAT('      LOWER AND UPPER BOUND IDENTICAL')
          CALL DPWRST('XXX','BUG ')
          GO TO 950
        ENDIF
      ENDIF
!
!     COMPUTE BINOMIAL PROBABILITIES FOR THE
!     DERIVED LOWER AND UPPER BOUNDS.
!
      X0=IX0
      X1=IX1
      CALL BINCDF(X0,PPAR,N,P0)
      CALL BINCDF(X1,PPAR,N,P1)
!
!     CHECK THE PROBABILITIES FOR PROPER ORDERING
!
      IF(P0.LT.P.AND.P.LE.P1)THEN
        GO TO 490
      ELSEIF(P0.EQ.P)THEN
        PPF=DBLE(IX0)
        GO TO 9000
      ELSEIF(P1.EQ.P)THEN
        PPF=DBLE(IX1)
        GO TO 9000
      ELSEIF(P0.GT.P1)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,431)
  431   FORMAT('      LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
               'UPPER BOUND PROBABILITY (P1)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ELSEIF(P0.GT.P)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,441)
  441   FORMAT('      LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
               'INPUT PROBABILITY (P)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ELSEIF(P1.LT.P)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,451)
  451   FORMAT('      UPPER BOUND PROBABILITY (P1) LESS    THAN ',   &
               'INPUT PROBABILITY (P)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ELSE
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,401)
  401   FORMAT('IMPOSSIBLE BRANCH CONDITION ENCOUNTERED')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ENDIF
  490 CONTINUE
!
!     THE STOPPING CRITERION IS THAT THE LOWER BOUND
!     AND UPPER BOUND ARE EXACTLY 1 UNIT APART.
!     CHECK TO SEE IF IX1 = IX0 + 1;
!     IF SO, THE ITERATIONS ARE COMPLETE;
!     IF NOT, THEN BISECT, COMPUTE PROBABILIIES,
!     CHECK PROBABILITIES, AND CONTINUE ITERATING
!     UNTIL IX1 = IX0 + 1.
!
  300 CONTINUE
!
      IX0P1=IX0+1
      IF(IX1.EQ.IX0P1)THEN
        PPF=IX1
        IF(P0.EQ.P)PPF=IX0
        GO TO 9000
      ENDIF
      IX2=(IX0+IX1)/2
      IF(IX2.EQ.IX0)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,611)
  611   FORMAT('BISECTION VALUE (X2) = LOWER BOUND (X0)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ELSEIF(IX2.EQ.IX1)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,621)
  621   FORMAT('BISECTION VALUE (X2) = UPPER BOUND (X1)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ENDIF
      X2=IX2
      CALL BINCDF(X2,PPAR,N,P2)
      IF(P0.LT.P2.AND.P2.LT.P1)THEN
        IF(P2.LE.P)THEN
          IX0=IX2
          P0=P2
        ELSE
          IX1=IX2
          P1=P2
        ENDIF
        GO TO 300
      ELSEIF(P2.LE.P0)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,641)
  641   FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
               'LESS THAN LOWER BOUND PROBABILITY (P0)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ELSEIF(P2.GE.P1)THEN
        WRITE(ICOUT,249)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,651)
  651   FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
               'GREATER THAN UPPER BOUND PROBABILITY (P1)')
        CALL DPWRST('XXX','BUG ')
        GO TO 950
      ENDIF
!
  950 CONTINUE
      WRITE(ICOUT,240)IX0,P0
  240 FORMAT('IX0  = ',I8,10X,'P0 = ',F14.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,241)IX1,P1
  241 FORMAT('IX1  = ',I8,10X,'P1 = ',F14.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,242)IX2,P2
  242 FORMAT('IX2  = ',I8,10X,'P2 = ',F14.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,244)P
  244 FORMAT('P    = ',F14.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,245)PPAR,N
  245 FORMAT('PPAR = ',F14.7,10X,'N  = ',I8)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BINPPF
      SUBROUTINE BINRAN(N,P,NPAR,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BINOMIAL DISTRIBUTION
!              WITH SINGLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = P,
!              AND INTEGER 'NUMBER OF BERNOULLI TRIALS'
!              PARAMETER = NPAR.
!              THE BINOMIAL DISTRIBUTION USED
!              HEREIN HAS MEAN = NPAR*P
!              AND STANDARD DEVIATION = SQRT(NPAR*P*(1-P)).
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              DISCRETE INTEGER X BETWEEN 0 (INCLUSIVELY)
!              AND NPAR (INCLUSIVELY).
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = C(NPAR,X) * P**X * (1-P)**(NPAR-X).
!              WHERE C(NPAR,X) IS THE COMBINATORIAL FUNCTION
!              EQUALING THE NUMBER OF COMBINATIONS OF NPAR ITEMS
!              TAKEN X AT A TIME.
!              THE BINOMIAL DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF
!              SUCCESSES IN NPAR BERNOULLI (0,1)
!              TRIALS WHERE THE PROBABILITY OF SUCCESS
!              IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE 'BERNOULLI PROBABILITY'
!                                PARAMETER FOR THE BINOMIAL
!                                DISTRIBUTION.
!                                P SHOULD BE BETWEEN
!                                0.0 (EXCLUSIVELY) AND
!                                1.0 (EXCLUSIVELY).
!                     --NPAR   = THE INTEGER VALUE
!                                OF THE 'NUMBER OF BERNOULLI TRIALS'
!                                PARAMETER.
!                                NPAR SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BINOMIAL DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P
!             AND 'NUMBER OF BERNOULLI TRIALS' PARAMETER = NPAR.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!                 --NPAR SHOULD BE A POSITIVE INTEGER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GEORAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE RANDOM NUMBER
!              GENERATOR MUST NECESSARILY BE A
!              SEQUENCE OF ***INTEGER*** VALUES,
!              THE OUTPUT VECTOR X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VECTORS FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969, PAGES 50-86.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 41.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 135-142.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --KENDALL AND STUART, THE ADVANCED THEORY OF
!                 STATISTICS, VOLUME 1, EDITION 2, 1963, PAGES 120-125.
!               --MOOD AND GRABLE, INTRODUCTION TO THE THEORY
!                 OF STATISTICS, EDITION 2, 1963, PAGES 64-69.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 39-40.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DIMENSION U(2)
      DIMENSION G(2)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 55
      IF(NPAR.LT.1)GO TO 60
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   55 WRITE(ICOUT,11)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      RETURN
   60 WRITE(ICOUT,25)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)NPAR
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE FIRST  INPUT ARGUMENT TO THE ',   &
      ' BINRAN SUBROUTINE IS NON-POSITIVE *****')
   11 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT TO THE ',   &
      ' BINRAN SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   25 FORMAT('***** FATAL ERROR--THE 3RD INPUT ARGUMENT TO THE ',   &
      ' BINRAN SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     CHECK ON THE MAGNITUDE OF P,
!     AND BRANCH TO THE FASTER
!     GENERATION METHOD ACCORDINGLY.
!
      IF(P.LT.0.1)GO TO 450
!
!     IF P IS MODERATE OR LARGE,
!     GENERATE N BINOMIAL RANDOM NUMBERS
!     USING THE REJECTION METHOD.
!
      DO 100 I=1,N
      ISUM=0
      DO 200 J=1,NPAR
      CALL UNIRAN(1,ISEED,U)
      IF(U(1).LE.P)ISUM=ISUM+1
  200 CONTINUE
      X(I)=ISUM
  100 CONTINUE
      RETURN
!
!     IF P IS SMALL,
!     GENERATE N BINOMIAL NUMBERS
!     USING THE FACT THAT THE
!     WAITING TIME FOR 1 SUCCESS IN
!     BERNOULLI TRIALS HAS A
!     GEOMETRIC DISTRIBUTION.
!
  450 CONTINUE
      DO 500 I=1,N
        ISUM=0
        J=1
  550   CALL GEORAN(1,P,ISEED,G)
        IG=INT(G(1)+0.5)
        ISUM=ISUM+IG+1
        IF(ISUM.GT.NPAR)GO TO 650
        J=J+1
        GO TO 550
  650   CONTINUE
        X(I)=INT(J-1)
  500 CONTINUE
      RETURN
!
      END SUBROUTINE BINRAN
      SUBROUTINE BINRAW(DX,DP,DQ,DN,DPDF,ILOG)
!
!     PURPOSE--THIS SUBROUTINE IMPLEMENTS CATHERINE LOADER'S
!              ALGORITHM FOR THE BINOMIAL PDF.  THIS ROUTINE IS
!              CALLED BY SEVERAL OTHER ROUTINES (BINPDF, GEOPDF,
!              NBPDF).  THE ERROR CHECKING AND CHECKING FOR
!              APPROPRIATE RANGES IS PERFORMED BY THESE HIGHER LEVEL
!              CALLS.
!
!              THIS ALGORITHM IS BASED ON A SADDLE POINT APPROXIMATION.
!
!              THIS ROUTINE ALLOWS THE OPTION OF RETURNING THE
!              LOGARITHM OF THE PDF.
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT WHICH THE
!                                BINOMIAL PDF IS TO BE EVALUATED.
!                     --DP     = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE BINOMIAL DISTRIBUTION.
!                     --DN     = THE DOUBLE PRECISION VALUE OF THE
!                                'NUMBER OF BERNOULLI TRIALS' PARAMETER.
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY MASS
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE DPDF.
!     PRINTING--NONE
!     RESTRICTIONS--DX SHOULD BE INTEGRAL-VALUED AND BETWEEN 0.0 (INCLUSIVELY)
!                   AND DN (INCLUSIVELY).
!                 --DP SHOULD BE BETWEEN 0.0 (EXCLUSIVELY) AND 1.0
!                   (INCLUSIVELY).
!                 --DN SHOULD BE A POSITIVE.
!
!                   NOTE THAT THE CHECK FOR RESTRICTIONS IS TO BE
!                   PERFORMED BY THE CALLING ROUTINES.
!
!     OTHER DATAPAC   SUBROUTINES NEEDED--STRERR, BD0, DLNREL.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CATHERINE LOADER (2000), "FAST AND ACCURATE COMPUTATION
!                 OF BINOMIAL PROBABILITIES", BELL LABS?
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/3
!     ORIGINAL VERSION--MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      DOUBLE PRECISION LF
      DOUBLE PRECISION LC
      INTEGER ILOG
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI2/6.283185307179586476925286/
!
!-----START POINT-----------------------------------------------------
!
!     STEP 1: P = 0 OR P = 1 CASES
!
      IF(DP.EQ.0.0D0)THEN
        IF(DX.EQ.0.0D0)THEN
          DPF=1.0D0
          IF(ILOG.EQ.1)DPDF=0.0D0
        ELSE
          DPF=0.0D0
          IF(ILOG.EQ.1)DPDF=DBLE(CPUMIN)
        ENDIF
        GO TO 9000
      ELSEIF(DQ.EQ.0.0D0)THEN
        IF(DX.EQ.DN)THEN
          DPF=1.0D0
          IF(ILOG.EQ.1)DPDF=0.0D0
        ELSE
          DPF=0.0D0
          IF(ILOG.EQ.1)DPDF=DBLE(CPUMIN)
        ENDIF
        GO TO 9000
      ENDIF
!
!     STEP 2: X = 0 AND X = N CASES
!
      IF(DX.EQ.0.0D0)THEN
        IF(DN.EQ.0.0D0)THEN
          DPF=1.0D0
          IF(ILOG.EQ.1)DPDF=0.0D0
        ELSE
          IF(DP.LT.0.1D0)THEN
            LC=-BD0(DN,DN*DQ) - DN*DP
          ELSE
            LC=DN*LOG(DQ)
          ENDIF
          IF(ILOG.EQ.1)THEN
            DPDF=LC
          ELSE
            DPDF=EXP(LC)
          ENDIF
        ENDIF
        GO TO 9000
      ELSEIF(DX.EQ.DN)THEN
        IF(DQ.LT.0.1D0)THEN
          LC=-BD0(DN,DN*DP) - DN*DQ
        ELSE
          LC=DN*LOG(DP)
        ENDIF
        IF(ILOG.EQ.1)THEN
          DPDF=LC
        ELSE
          DPDF=EXP(LC)
        ENDIF
        GO TO 9000
      ENDIF
!
      IF(DX.LT.0.0D0 .OR. DX.GT.DN)THEN
        IF(ILOG.EQ.1)THEN
          DPDF=DBLE(CPUMIN)
        ELSE
          DPDF=0.0D0
        ENDIF
      ENDIF
!
!     STEP 3: GENERAL CASE
!
      LC=STRERR(DN) - STRERR(DX) - STRERR(DN-DX) - BD0(DX,DN*DP) -   &
         BD0(DN-DX,DN*DQ)
      LF=LOG(DPI2) + LOG(DX) + DLNREL(-DX/DN)
      IF(ILOG.EQ.1)THEN
        DPDF=LC - 0.5D0*LF
       ELSE
        DPDF=EXP(LC - 0.5D0*LF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BINRAW
      SUBROUTINE BINTK(X,Y,T,N,K,BCOEF,Q,WORK)
!***BEGIN PROLOGUE  BINTK
!***DATE WRITTEN   800901   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  E1A
!***KEYWORDS  B-SPLINE,DATA FITTING,INTERPOLATION,SPLINE
!***AUTHOR  AMOS, D. E., (SNLA)
!***PURPOSE  Produces the B-spline coefficients, BCOEF, of the
!            B-spline of order K with knots T(I), I=1,...,N+K, which
!            takes on the value Y(I) at X(I), I=1,...,N.
!***DESCRIPTION
!
!     Written by Carl de Boor and modified by D. E. Amos
!
!     References
!
!          A Practical Guide to Splines by C. de Boor, Applied
!          Mathematics Series 27, Springer, 1979.
!
!     Abstract
!
!         BINTK is the SPLINT routine of the reference.
!
!         BINTK produces the B-spline coefficients, BCOEF, of the
!         B-spline of order K with knots T(I), I=1,...,N+K, which
!         takes on the value Y(I) at X(I), I=1,...,N.  The spline or
!         any of its derivatives can be evaluated by calls to BVALU.
!         The I-th equation of the linear system A*BCOEF = B for the
!         coefficients of the interpolant enforces interpolation at
!         X(I)), I=1,...,N.  Hence, B(I) = Y(I), all I, and A is
!         a band matrix with 2K-1 bands if A is invertible. The matrix
!         A is generated row by row and stored, diagonal by diagonal,
!         in the rows of Q, with the main diagonal going into row K.
!         The banded system is then solved by a call to BNFAC (which
!         constructs the triangular factorization for A and stores it
!         again in Q), followed by a call to BNSLV (which then
!         obtains the solution BCOEF by substitution). BNFAC does no
!         pivoting, since the total positivity of the matrix A makes
!         this unnecessary.  The linear system to be solved is
!         (theoretically) invertible if and only if
!                 T(I) .LT. X(I)) .LT. T(I+K),        all I.
!         Equality is permitted on the left for I=1 and on the right
!         for I=N when K knots are used at X(1) or X(N).  Otherwise,
!         violation of this condition is certain to lead to an error.
!
!         BINTK calls BSPVN, BNFAC, BNSLV, XERROR
!
!     Description of Arguments
!         Input
!           X       - vector of length N containing data point abscissa
!                     in strictly increasing order.
!           Y       - corresponding vector of length N containing data
!                     point ordinates.
!           T       - knot vector of length N+K
!                     since T(1),..,T(K) .LE. X(1) and T(N+1),..,T(N+K)
!                     .GE. X(N), this leaves only N-K knots (not nec-
!                     essarily X(I)) values) interior to (X(1),X(N))
!           N       - number of data points, N .GE. K
!           K       - order of the spline, K .GE. 1
!
!         Output
!           BCOEF   - a vector of length N containing the B-spline
!                     coefficients
!           Q       - a work vector of length (2*K-1)*N, containing
!                     the triangular factorization of the coefficient
!                     matrix of the linear system being solved.  The
!                     coefficients for the interpolant of an
!                     additional data set (X(I)),YY(I)), I=1,...,N
!                     with the same abscissa can be obtained by loading
!                     YY into BCOEF and then executing
!                         call BNSLV(Q,2K-1,N,K-1,K-1,BCOEF)
!           WORK    - work vector of length 2*K
!
!     Error Conditions
!         Improper  input is a fatal error
!         Singular system of equations is a fatal error
!***REFERENCES  D.E. AMOS, *COMPUTATION WITH SPLINES AND B-SPLINES*,
!                 SAND78-1968,SANDIA LABORATORIES,MARCH,1979.
!               C. DE BOOR, *PACKAGE FOR CALCULATING WITH B-SPLINES*,
!                 SIAM JOURNAL ON NUMERICAL ANALYSIS, VOLUME 14, NO. 3,
!                 JUNE 1977, PP. 441-472.
!               C. DE BOOR, *A PRACTICAL GUIDE TO SPLINES*, APPLIED
!                 MATHEMATICS SERIES 27, SPRINGER, 1979.
!***ROUTINES CALLED  BNFAC,BNSLV,BSPVN,XERROR
!***END PROLOGUE  BINTK
!
!
      INTEGER IFLAG, IWORK, K, N, I, ILP1MX, J, JJ, KM1, KPKM2, LEFT,   &
       LENQ, NP1
      REAL BCOEF(N), Y(N), Q(1), T(1), X(N), XI, WORK(1)
!     DIMENSION Q(2*K-1,N), T(N+K)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  BINTK
      IF(K.LT.1) GO TO 100
      IF(N.LT.K) GO TO 105
      JJ = N - 1
      IF(JJ.EQ.0) GO TO 6
      DO 5 I=1,JJ
      IF(X(I).GE.X(I+1)) GO TO 110
    5 CONTINUE
    6 CONTINUE
      NP1 = N + 1
      KM1 = K - 1
      KPKM2 = 2*KM1
      LEFT = K
!                ZERO OUT ALL ENTRIES OF Q
      LENQ = N*(K+KM1)
      DO 10 I=1,LENQ
        Q(I) = 0.0E0
   10 CONTINUE
!
!  ***   LOOP OVER I TO CONSTRUCT THE  N  INTERPOLATION EQUATIONS
      DO 50 I=1,N
        XI = X(I)
        ILP1MX = MIN0(I+K,NP1)
!        *** FIND  LEFT  IN THE CLOSED INTERVAL (I,I+K-1) SUCH THAT
!                T(LEFT) .LE. X(I) .LT. T(LEFT+1)
!        MATRIX IS SINGULAR IF THIS IS NOT POSSIBLE
        LEFT = MAX0(LEFT,I)
        IF (XI.LT.T(LEFT)) GO TO 80
   20   IF (XI.LT.T(LEFT+1)) GO TO 30
        LEFT = LEFT + 1
        IF (LEFT.LT.ILP1MX) GO TO 20
        LEFT = LEFT - 1
        IF (XI.GT.T(LEFT+1)) GO TO 80
!        *** THE I-TH EQUATION ENFORCES INTERPOLATION AT XI, HENCE
!        A(I,J) = B(J,K,T)(XI), ALL J. ONLY THE  K  ENTRIES WITH  J =
!        LEFT-K+1,...,LEFT ACTUALLY MIGHT BE NONZERO. THESE  K  NUMBERS
!        ARE RETURNED, IN  BCOEF (USED FOR TEMP.STORAGE HERE), BY THE
!        FOLLOWING
   30   CALL BSPVN(T, K, K, 1, XI, LEFT, BCOEF, WORK, IWORK)
!        WE THEREFORE WANT  BCOEF(J) = B(LEFT-K+J)(XI) TO GO INTO
!        A(I,LEFT-K+J), I.E., INTO  Q(I-(LEFT+J)+2*K,(LEFT+J)-K) SINCE
!        A(I+J,J)  IS TO GO INTO  Q(I+K,J), ALL I,J,  IF WE CONSIDER  Q
!        AS A TWO-DIM. ARRAY , WITH  2*K-1  ROWS (SEE COMMENTS IN
!        BNFAC). IN THE PRESENT PROGRAM, WE TREAT  Q  AS AN EQUIVALENT
!        ONE-DIMENSIONAL ARRAY (BECAUSE OF FORTRAN RESTRICTIONS ON
!        DIMENSION STATEMENTS) . WE THEREFORE WANT  BCOEF(J) TO GO INTO
!        ENTRY
!            I -(LEFT+J) + 2*K + ((LEFT+J) - K-1)*(2*K-1)
!                   =  I-LEFT+1 + (LEFT -K)*(2*K-1) + (2*K-2)*J
!        OF  Q .
        JJ = I - LEFT + 1 + (LEFT-K)*(K+KM1)
        DO 40 J=1,K
          JJ = JJ + KPKM2
          Q(JJ) = BCOEF(J)
   40   CONTINUE
   50 CONTINUE
!
!     ***OBTAIN FACTORIZATION OF  A  , STORED AGAIN IN  Q.
      CALL BNFAC(Q, K+KM1, N, KM1, KM1, IFLAG)
      GO TO (60, 90), IFLAG
!     *** SOLVE  A*BCOEF = Y  BY BACKSUBSTITUTION
   60 DO 70 I=1,N
        BCOEF(I) = Y(I)
   70 CONTINUE
      CALL BNSLV(Q, K+KM1, N, KM1, KM1, BCOEF)
      RETURN
!
!
   80 CONTINUE
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,81)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,82)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,83)
      CALL DPWRST('XXX','BUG ')
   81 FORMAT('***** FROM BINTK,  SOME ABSCISSA WAS NOT IN THE SUPPORT')
   82 FORMAT('      OF THE CORRESPONDING BASIS FUNCTION AND THE')
   83 FORMAT('      SYSTEM IS SINGULAR.                         *****')
      RETURN
   90 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,91)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,92)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,93)
      CALL DPWRST('XXX','BUG ')
   91 FORMAT('***** FROM BINTK,  THE SYSTEM OF SOLVER DETECTS A')
   92 FORMAT('      SINGULAR SYSTEM ALTHOUGH THE THEORETICAL')
   93 FORMAT('      CONDITIONS FOR A SOLUTION WERE SATISFIED.  *****')
      RETURN
  100 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','BUG ')
  101 FORMAT('***** FROM BINTK,  K DOES NOT SATISFY K.GE.1 *****')
      RETURN
  105 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,106)
      CALL DPWRST('XXX','BUG ')
  106 FORMAT('***** FROM BINTK,  N DOES NOT SATISFY N.GE.K *****')
      RETURN
  110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
      CALL DPWRST('XXX','BUG ')
  111 FORMAT('***** FROM BINTK, X(I) DOES NOT SATISFY ')
  112 FORMAT('      X(I).LT.X(I+1) FOR SOME I         *****')
      RETURN
      END SUBROUTINE BINTK
      DOUBLE PRECISION FUNCTION BIRINT(XVALUE)
!
!   DESCRIPTION:
!      This function calculates the integral of the Airy function Bi, defined
!
!          BIRINT(x) = integral{0 to x} Bi(t) dt
!
!      The program uses Chebyshev expansions, the coefficients of which
!      are given to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If the function is too large and positive the correct
!      value would overflow. An error message is printed and the
!      program returns the value XMAX.
!
!      If the argument is too large and negative, it is impossible
!      to accurately compute the necessary SIN and COS functions,
!      for the asymptotic expansion.
!      An error message is printed, and the program returns the
!      value 0 (the value at -infinity).
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - INTEGER - The no. of terms to be used from the array
!                          ABINT1. The recommended value is such that
!                             ABS(ABINT1(NTERM1)) < EPS/100,
!                          subject to 1 <= NTERM1 <= 36.
!
!      NTERM2 - INTEGER - The no. of terms to be used from the array
!                          ABINT2. The recommended value is such that
!                             ABS(ABINT2(NTERM2)) < EPS/100,
!                          subject to 1 <= NTERM2 <= 37.
!
!      NTERM3 - INTEGER - The no. of terms to be used from the array
!                          ABINT3. The recommended value is such that
!                             ABS(ABINT3(NTERM3)) < EPS/100,
!                          subject to 1 <= NTERM3 <= 37.
!
!      NTERM4 - INTEGER - The no. of terms to be used from the array
!                          ABINT4. The recommended value is such that
!                             ABS(ABINT4(NTERM4)) < EPS/100,
!                          subject to 1 <= NTERM4 <= 20.
!
!      NTERM5 - INTEGER - The no. of terms to be used from the array
!                          ABINT5. The recommended value is such that
!                             ABS(ABINT5(NTERM5)) < EPS/100,
!                          subject to 1 <= NTERM5 <= 20.
!
!      XLOW1 - DOUBLE PRECISION - The value such that, if |x| < XLOW1,
!                          BIRINT(x) = x * Bi(0)
!                     to machine precision. The recommended value is
!                          2 * EPSNEG.
!
!      XHIGH1 - DOUBLE PRECISION - The value such that, if x > XHIGH1,
!                      the function value would overflow.
!                      The recommended value is computed as
!                          z = ln(XMAX) + 0.5ln(ln(XMAX)),
!                          XHIGH1 = (3z/2)^(2/3)
!
!      XNEG1 - DOUBLE PRECISION - The value such that, if x < XNEG1,
!                     the trigonometric functions in the asymptotic
!                     expansion cannot be calculated accurately.
!                     The recommended value is
!                          -(1/((EPS)**2/3))
!
!      XMAX - DOUBLE PRECISION - The value of the largest positive floating-pt
!                    number. Used in giving a value to the function
!                    if x > XHIGH1.
!
!      For values of EPS, EPSNEG, and XMAX see the file MACHCON.TXT.
!
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!                            COS, EXP, LOG, SIN, SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR: Dr. Allan J. MacLeod,
!           Dept. of Mathematics and Statistics,
!           Univ. of Paisley,
!           High St.,
!           Paisley,
!           SCOTLAND.
!           PA1 2BE
!
!           (e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:  23 January, 1996
!
      INTEGER NTERM1,NTERM2,NTERM3,NTERM4,NTERM5
      DOUBLE PRECISION ABINT1(0:36),ABINT2(0:37),ABINT3(0:37),   &
           ABINT4(0:20),ABINT5(0:20),   &
           ARG,BIRZER,CHEVAL,EIGHT,FOUR,F1,F2,NINE,NINHUN,   &
           ONE,ONEHUN,ONEPT5,PIBY4,RT2B3P,SIXTEN,SEVEN,T,TEMP,   &
           THREE,THR644,X,XLOW1,XHIGH1,XMAX,XNEG1,XVALUE,   &
           Z,ZERO
!CCCC CHARACTER FNNAME*6,ERMSG1*31,ERMSG2*31
!CCCC DATA FNNAME/'BIRINT'/
!CCCC DATA ERMSG1/'ARGUMENT TOO LARGE AND POSITIVE'/
!CCCC DATA ERMSG2/'ARGUMENT TOO LARGE AND NEGATIVE'/
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
