      DATA THREE,FOUR,SEVEN/ 3.0D0 , 4.0D0 , 7.0D0 /
      DATA EIGHT,NINE,SIXTEN/ 8.0D0 , 9.0D0 , 16.0D0 /
      DATA ONEHUN,NINHUN,THR644/100.0D0 , 900.0D0 , 3644.0D0 /
      DATA PIBY4/0.78539816339744830962D0/
      DATA RT2B3P/0.46065886596178063902D0/
      DATA BIRZER/0.61492662744600073515D0/
!
!   Start computation
!
      X = XVALUE
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(3)
      F2 = ONE + ONE
      XNEG1 = -ONE/(T**(F2/THREE))
      XMAX = D1MACH(2)
      F1 = LOG(XMAX)
      TEMP = F1 + LOG(F1)/F2
      XHIGH1 = (THREE*TEMP/F2)**(F2/THREE)
!
!   Error test
!
      IF ( X .GT. XHIGH1 ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERMSG1)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         BIRINT = XMAX
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM BIRINT--ARGUMENT TOO LARGE AND ',   &
              'POSITIVE, ARGUMENT = ',G15.7)
      IF ( X .LT. XNEG1 ) THEN
!CCCc    CALL ERRPRN(FNNAME,ERMSG2)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,201)X
         CALL DPWRST('XXX','BUG ')
         BIRINT = ZERO
         RETURN
      ENDIF
  201 FORMAT('***** ERROR FROM BIRINT--ARGUMENT TOO LARGE AND ',   &
              'NEGATIVE, ARGUMENT = ',G15.7)
!CCCC DATA ERMSG2/'ARGUMENT TOO LARGE AND NEGATIVE'/
!
!  continue with machine-dependent constants
!
      XLOW1 = F2 * T
      T = T / ONEHUN
      IF ( X .GE. ZERO ) THEN
         DO 10 NTERM1 = 36 , 0 , -1
            IF ( ABS(ABINT1(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERM2 = 37 , 0 , -1
            IF ( ABS(ABINT2(NTERM2)) .GT. T ) GO TO  29
 20      CONTINUE
 29      CONTINUE
      ELSE
         DO 30 NTERM3 = 37 , 0 , -1
            IF ( ABS(ABINT3(NTERM3)) .GT. T ) GO TO  39
 30      CONTINUE
 39      DO 40 NTERM4 = 20 , 0 , -1
            IF ( ABS(ABINT4(NTERM4)) .GT. T ) GO TO  49
 40      CONTINUE
 49      DO 50 NTERM5 = 20 , 0 , -1
            IF ( ABS(ABINT5(NTERM5)) .GT. T ) GO TO  59
 50      CONTINUE
 59      CONTINUE
      ENDIF
!
!   Code for x >= 0.0
!
      IF ( X .GE. ZERO ) THEN
         IF ( X .LT. XLOW1 ) THEN
            BIRINT = BIRZER * X
         ELSE
            IF ( X .LE. EIGHT ) THEN
               T = X / FOUR - ONE
               BIRINT = X * EXP(ONEPT5*X) * CHEVAL(NTERM1,ABINT1,T)
            ELSE
               T = SIXTEN * SQRT(EIGHT/X) / X - ONE
               Z = ( X + X ) * SQRT(X) / THREE
               TEMP = RT2B3P * CHEVAL(NTERM2,ABINT2,T) / SQRT(Z)
               TEMP = Z + LOG(TEMP)
               BIRINT = EXP(TEMP)
            ENDIF
         ENDIF
      ELSE
!
!   Code for x < 0.0
!
         IF ( X .GE. -SEVEN ) THEN
            IF ( X .GT. -XLOW1 ) THEN
               BIRINT = BIRZER * X
            ELSE
               T = - ( X + X ) / SEVEN - ONE
               BIRINT = X * CHEVAL(NTERM3,ABINT3,T)
            ENDIF
         ELSE
            Z = - ( X + X ) * SQRT(-X) / THREE
            ARG = Z + PIBY4
            TEMP = NINE * Z * Z
            T = (THR644 - TEMP ) / ( NINHUN + TEMP )
            F1 = CHEVAL(NTERM4,ABINT4,T) * SIN(ARG)
            F2 = CHEVAL(NTERM5,ABINT5,T) * COS(ARG) / Z
            BIRINT = ( F2 - F1 ) * RT2B3P / SQRT(Z)
         ENDIF
      ENDIF
      RETURN
      END FUNCTION BIRINT
      SUBROUTINE BIVAR(Z,Y,X,N,Y2,X2,N2,IWRITE,Z2,   &
                       YTEMP,XTEMP,YDIST,XDIST,ZDIST,   &
                       ZTEMP2,ZTEMP,TX,TY,WORK,ISPACE,   &
                       IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE BI-VARIATE INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).  THIS ROUTINE USES THE
!              B2INK AND B@VAL ROUTINES FROM CMLIB WRITTEN BY
!              RON BOISVERT OF NIST.
!     INPUT  ARGUMENTS--Z      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                Z AXIS DATA POINTS.
!                     --Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                VERTICAL AXIS INTERPOLATION
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Z2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                Z AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR
!           Y2(.) BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     NOTE--IT DOES ASSUME THAT THE ORIGINAL (Y,X) POINTS FORM A
!           RECTANGULAR GRID (ALTHOUGH THE GRID DOES NOT HAVE TO BE
!           PRE-SORTED).
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!     UPDATED         --JUNE      2019. DIMENSION SCRATCH ARRAYS IN
!                                       CALLING ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
      DIMENSION Z2(*)
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
      DIMENSION YDIST(*)
      DIMENSION XDIST(*)
      DIMENSION ZDIST(*)
      DIMENSION ZTEMP2(*)
      DIMENSION ZTEMP(*)
      DIMENSION TX(*)
      DIMENSION TY(*)
      DIMENSION WORK(ISPACE)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIVA'
      ISUBN2='R   '
      IERROR='NO'
!
      ISTART=0
      ILAST=0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'IVAR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BIVAR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,N2,ISPACE
   52   FORMAT('N,N2,ISPACE = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Z(I),Y(I),X(I)
   56     FORMAT('I,Z(I),Y(I),X(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I),X2(I)
   66     FORMAT('I,Y2(I),X2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 11--                         **
!               **  SORT THE INPUT DATA ACCORDING     **
!               **  TO THE HORIZONTAL AXIS VARIABLE   **
!               ****************************************
!
      ISTEPN='11'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'IVAR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1010 ,I=1,N
        XTEMP(I)=X(I)
 1010 CONTINUE
!
      CALL SORTC(X,Y,N,X,Y)
      CALL SORTC(XTEMP,Z,N,XTEMP,Z)
!
!               *******************************************************
!               **  STEP 12--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT X VALUES        **
!               *******************************************************
!
      ISTEPN='12'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'IVAR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTX=0
      DO 1210 I=1,N
        IF(NDISTX.GT.0)THEN
          DO 1215 I2=1,NDISTX
           IF(X(I).EQ.XDIST(I2))GO TO 1210
 1215     CONTINUE
        ENDIF
        NDISTX=NDISTX+1
        XDIST(NDISTX)=X(I)
 1210 CONTINUE
!
      CALL SORT(XDIST,NDISTX,XDIST)
!
!               *******************************************************
!               **  STEP 13--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT Y VALUES        **
!               *******************************************************
!
      ISTEPN='13'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'IVAR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTY=0
      DO 1310 I=1,N
        IF(NDISTY.GT.0)THEN
          DO 1315 I2=1,NDISTY
            IF(Y(I).EQ.YDIST(I2))GO TO 1310
 1315     CONTINUE
        ENDIF
        NDISTY=NDISTY+1
        YDIST(NDISTY)=Y(I)
 1310 CONTINUE
!
      CALL SORT(YDIST,NDISTY,YDIST)
!
!               *******************************************************
!               **  STEP 14--                                        **
!               **  SORT Y ASSOCIATED WITH EACH DISTINCT X VALUE     **
!               **  CHECK FOR REPLICATION OF POINTS                  **
!               **  IF ALL DISTINCT (THAT IS, NO REPLICATION),     **
!               **  (THAT IS, HAVE NO REPLICATION),                **
!               **  THEN COPY OVER Z VALUES.                       **
!               **  IF NOT ALL DISTINCT                            **
!               **  (THAT IS, HAVE SOME REPLICATION),              **
!               **  THEN COMPUTE A MEAN VALUE OVER THE REPLICATES  **
!               **  AND TREAT THAT AS THE COMMON VALUE.            **
!               **  THE CORE OF THE INTERPOLATION CODE             **
!               **  IS EXPECTING SORTED, DISTINCT X AND Y VALUES.   **
!               **  ALSO CHECK THAT X AND Y FORM A RECTANGULAR GRID.**
!               *******************************************************
!
      ISTEPN='14'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'IVAR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMZ=0
      ISTART=1
      DO 1410 I=1,NDISTX
        XT=XDIST(I)
        ICOUNT=0
        DO 1420 J=ISTART,N
        IF(X(J).EQ.XT)THEN
          IF(ICOUNT.EQ.0)IFRST=J
          ICOUNT=ICOUNT+1
          YTEMP(ICOUNT)=Y(J)
          ZTEMP(ICOUNT)=Z(J)
          ILAST=J
        ELSEIF(X(J).GT.XT)THEN
          GO TO 1421
        ENDIF
 1420   CONTINUE
 1421   CONTINUE
!
        ISTART=ILAST+1
        CALL SORTC(YTEMP,ZTEMP,ICOUNT,YTEMP,ZTEMP)
        DO 1471 K=1,NDISTY
          TAG=YDIST(K)
          J=0
          DO 1472 II=1,ICOUNT
            IF(YTEMP(II).EQ.TAG)THEN
              J=J+1
              ZTEMP2(J)=ZTEMP(II)
            END IF
 1472     CONTINUE
          NI=J
          IF(NI.EQ.1)THEN
            NUMZ=NUMZ+1
            ZDIST(NUMZ)=ZTEMP2(1)
          ELSE IF(NI.GT.1)THEN
            CALL MEAN(ZTEMP2,NI,IWRITE,ZMEAN,IBUGG3,IERROR)
            NUMZ=NUMZ+1
            ZDIST(NUMZ)=ZMEAN
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1491)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1492)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
 1471   CONTINUE
!
 1410 CONTINUE
!
 1491 FORMAT('******* ERROR FROM BIVAR.  ORIGINAL X AND Y')
 1492 FORMAT('        DATA DO NOT FORM A RECTANGULAR GRID.  ******')
!
!               ********************************************
!               **  STEP 15--                             **
!               **  CHECK FOR USER PARAMETERS XDEGREE AND **
!               **  YDEGREE FOR ORDER OF POLYNOMIALS      **
!               ********************************************
!
      IXDEG=4
      IYDEG=4
!
      XDEG=3.0
      IHP='XDEG'
      IHP2='REE '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 1510
      XDEG=VALUE(ILOCP)
 1510 CONTINUE
!
      IXDEG=INT(XDEG+0.5)
      IF(IXDEG.LT.1.OR.IXDEG.GT.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1511)
 1511   FORMAT('***** ERROR IN BIVAR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1512)
 1512   FORMAT('      THE POLYNOMIAL DEGREE FOR THE B-SPLINE IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1514)
 1514   FORMAT('      X DIRECTION MUST BE BETWEEN 1 AND 3 INCLUSIVE;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1515)
 1515   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1516)XDEG
 1516   FORMAT('      THE CURRENT VALUE OF XDEGREE IS ',E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1517)
 1517   FORMAT('      A VALUE OF 3.0 WILL BE USED')
        CALL DPWRST('XXX','BUG ')
        IXDEG=3
      ENDIF
      IXDEG=IXDEG+1
!
      YDEG=3.0
      IHP='YDEG'
      IHP2='REE '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 1610
      YDEG=VALUE(ILOCP)
 1610 CONTINUE
!
      IYDEG=INT(YDEG+0.5)
      IF(IYDEG.GE.1.AND.IYDEG.LE.3)GO TO 1619
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1511)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1512)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1614)
 1614 FORMAT('      Y DIRECTION MUST BE BETWEEN 1 AND 3 INCLUSIVE;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1615)
 1615 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1616)YDEG
 1616 FORMAT('      THE CURRENT VALUE OF YDEGREE IS ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1617)
 1617 FORMAT('      A VALUE OF 3.0 WILL BE USED')
      CALL DPWRST('XXX','BUG ')
      IYDEG=3
 1619 CONTINUE
      IYDEG=IYDEG+1
!
!
!               ********************************************
!               **  STEP 15--                             **
!               **  COMPUTE INTERPOLATED VALUES           **
!               ********************************************
!
      CALL BIVAR2(ZDIST,YDIST,XDIST,NDISTX,NDISTY,Y2,X2,N2,Z2,   &
                  IXDEG,IYDEG,   &
                  TX,TY,WORK,ISPACE,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'IVAR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BIVAR--')
        CALL DPWRST('XXX','BUG ')
        DO 9042 I=1,N2
          WRITE(ICOUT,9043)I,X2(I),Y2(I),Z2(I)
 9043     FORMAT('I,X2(I),Y2(I),Z2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9042   CONTINUE
        WRITE(ICOUT,9051)NDISTX,NDISTY
 9051   FORMAT('NDISTX,NDISTY = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9052 I=1,NDISTX
          DO 9054 J=1,NDISTY
            WRITE(ICOUT,9053)I,J,XDIST(I),YDIST(J),ZDIST((I-1)*NDISTY+J)
 9053       FORMAT('I,J,XDIST(I),YDIST(J),ZDIST = ',2I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
 9054     CONTINUE
 9052   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE BIVAR
      SUBROUTINE BIVAR2(Z,Y,X,NX,NY,Y2,X2,N2,Z2,   &
                        IXDEG,IYDEG,   &
                        TX,TY,WORK,ISPACE,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE BI-LINEAR INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).  THIS ROUTINE USES THE
!              B2INK AND B2VAL ROUTINES FROM CMLIB WRITTEN BY
!              RON BOISVERT OF NIST.
!     INPUT  ARGUMENTS--Z      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                Z AXIS DATA POINTS.
!                     --Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                VERTICAL AXIS INTERPOLATION
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Z2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR
!           Z2(.) BEING IDENTICAL TO THE INPUT VECTOR Z(.)
!     NOTE--THE X AND Y POINTS ARE ASSUMED TO LIE ON A RECTANGULAR GRID
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Z2(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION TX(*)
      DIMENSION TY(*)
      DIMENSION WORK(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIVA'
      ISUBN2='R2  '
      IERROR='NO'
!
      DO 10 I=1,N2
        Z2(I)=0.0
 10   CONTINUE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'VAR2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BIVAR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NX,NY,N2
   52   FORMAT('NX,NY,N2 = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 54 I=1,NX
          DO 55 J=1,NY
            INDX=(I-1)*NY+J
            WRITE(ICOUT,53)I,J,X(I),Y(J),Z(INDX)
            CALL DPWRST('XXX','BUG ')
 53         FORMAT('I,J,X(I),Y(J),Z = ',2I8,3E15.7)
            CALL DPWRST('XXX','BUG ')
 55       CONTINUE
 54     CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I),X2(I)
   66     FORMAT('I,Y2(I),X2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 31--
!               **  COMPUTE INTERPOLATION VALUES
!               ****************************************
!
      DO 3100 J=1,N2
      XT=X2(J)
      IF(X(1).GT.XT.OR.XT.GT.X(NX))GO TO 3110
      YT=Y2(J)
      IF(Y(1).GT.YT.OR.YT.GT.Y(NY))GO TO 3120
      GO TO 3129
!
 3110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3111)
 3111 FORMAT('***** ERROR IN BIVAR2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3112)
 3112 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3113)
 3113 FORMAT('      A SMOOTHED VALUE BEYOND THE X RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3114)
 3114 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3115)
 3115 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3116)X(1)
 3116 FORMAT('         SMALLEST DATA POINT X(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3117)X(NX)
 3117 FORMAT('         LARGEST DATA POINT  X(NX)     = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3118)XT
 3118 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 3120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3121)
 3121 FORMAT('***** ERROR IN BIVAR2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3122)
 3122 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3123)
 3123 FORMAT('      A SMOOTHED VALUE BEYOND THE Y RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3124)
 3124 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3125)
 3125 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3126)Y(1)
 3126 FORMAT('         SMALLEST DATA POINT Y(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3127)Y(NY)
 3127 FORMAT('         LARGEST DATA POINT  Y(NY)     = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3128)YT
 3128 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 3129 CONTINUE
 3100 CONTINUE
!
      IFLAG=0
      CALL B2INK(X,NX,Y,NY,Z,NX,IXDEG,IYDEG,TX,TY,Z,   &
                 WORK,ISPACE,IFLAG)
      IF(IFLAG.GT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,3130)IFLAG
        CALL DPWRST('XXX','BUG ')
 3130   FORMAT('***** B2INK RETURNED ERROR CODE ',I2)
        WRITE(ICOUT,3131)
        CALL DPWRST('XXX','BUG ')
 3131   FORMAT('      NO INTERPOLATION PERFORMED.     *****')
        GO TO 9000
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'VAR2')THEN
        DO 3191 J=1,NX+IXDEG
          WRITE(ICOUT,3192)J,TX(J)
          CALL DPWRST('XXX','BUG ')
 3192     FORMAT('J,TX(J) = ',I5,1X,G15.7)
 3191   CONTINUE
        DO 3193 J=1,NY+IYDEG
          WRITE(ICOUT,3194)J,TY(J)
          CALL DPWRST('XXX','BUG ')
 3194     FORMAT('J,TY(J) = ',I5,1X,G15.7)
 3193   CONTINUE
      ENDIF
!
      IDX=0
      IDY=0
      DO 3200 I=1,N2
        XVAL=X2(I)
        YVAL=Y2(I)
        Z2(I)=B2VAL(XVAL,YVAL,IDX,IDY,TX,TY,NX,NY,IXDEG,IYDEG,   &
                   Z,WORK)
 3200 CONTINUE
!
!               ****************************************
!               **  STEP 41--                         **
!               **  IF CALLED FOR,                    **
!               **  WRITE OUT INTERPOLATION VALUES    **
!               ****************************************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.NE.'VAR2')THEN
        DO 4100 J=1,N2
          WRITE(ICOUT,4110)X2(J),Y2(J),Z2(J)
          CALL DPWRST('XXX','BUG ')
 4110     FORMAT('X2(J),Y2(J),Z2(J) = ',3G15.7)
 4100   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'VAR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BIVAR2--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE BIVAR2
      SUBROUTINE BIWMCV(X,Y,N,IWRITE,XTEMP,XTEMP2,MAXNXT,XBWCOV,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE BIWEIGHT MID-COVARIANCE ESTIMATOR
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE BIWEIGHT MID-COVARIANCE ESTIMATE IS DEFINED AS:
!                 s(bxy)**2 = SUM'[{a(i)*(x-x')**2*(1-u**2)**2}*
!                             {b(i)*(y-y')**2*(1-v**2)**2}]/
!                            {SUM'[a(i)*(1-u**2)*(1-5*u**2)]*
!                            SUM'[b(i)*(1-v**2)*(1-5*v**2)]}
!              WHERE
!                 y' = MEDIAN OF Y
!                 x' = MEDIAN OF X
!                 MAD = MEDIAN ABSOLUTE DEVIATION
!                 u(i) = (X(i) - x')/(9*MAD)
!                 v(i) = (Y(i) - y')/(9*MAD)
!                 a(i) = 1 if |u(i)| <= 1, 0 otherwise
!                 b(i) = 1 if |v(i)| <= 1, 0 otherwise
!                 SUM' means the summation is for u**2 < 1 or v**2 < 1
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS X AND Y.
!     OUTPUT ARGUMENTS--XBWCOV    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE BIWEIGHT MID-COVARIANCE
!                                ESTIMATE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE BIWEIGHT LOCATION ESTIMATE.
!     OTHER DATAPLOT  SUBROUTINES NEEDED--MEDIAN, MAD
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MOSTELLER AND TUKEY, 'DATA ANALYSIS AND REGRESSION'
!                 ADDISON AND WESLEY, 1977, PP. 204-206.
!     REFERENCES--RAND R. WILCOX, 'INTORIDUCTION TO ROBUST ESTIMATION
!                 AND HYPOTHESIS TESTING'
!                 ACADEMIC PRESS, 1997. PP. 196-197.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/7
!     ORIGINAL VERSION--JULY      2002.
!     UPDATED         --JULY      2010. CALL LIST TO MAD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DUI
      DOUBLE PRECISION DSBI
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XTEMP(*)
      DIMENSION XTEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIWM'
      ISUBN2='CV  '
      XBWCOV=0.0
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BIWMCV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************************************
!               **  COMPUTE BIWEIGHT MID-COVARIANCE ESTIMATE **
!               ***********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN BIWEIGHT MID-COVARIANCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS LESS THAN ONE ',   &
               'OBSERVATION.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XBWCOV=0.0
      GO TO 8000
  139 CONTINUE
!
!               ******************************************************
!               **  STEP 2--                                        **
!               **  COMPUTE THE BIWEIGHT MID-COVARIANCE ESTIMATE.   **
!               ******************************************************
!
      IWRIT2='OFF'
      CALL MEDIAN(X,N,IWRIT2,XTEMP,MAXNXT,XMED,IBUGA3,IERROR)
      CALL MAD(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
!
      CALL MEDIAN(Y,N,IWRIT2,XTEMP,MAXNXT,YMED,IBUGA3,IERROR)
      CALL MAD(Y,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,YMAD,IBUGA3,IERROR)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DO 300 I=1,N
        DUI=DBLE((X(I) - XMED)/(9.0*XMAD))
        DVI=DBLE((Y(I) - YMED)/(9.0*YMAD))
        IF(DUI*DUI.LE.1.0D0)THEN
          DTERM1=DBLE(X(I)-XMED)*(1.0D0 - DUI**2)**2
          DSUM2=DSUM2 + (1.0D0 - DUI**2)*(1.0D0 - 5.0D0*DUI**2)
        ELSE
          DTERM1=0.0D0
        ENDIF
        IF(DVI*DVI.LE.1.0D0)THEN
          DTERM2=DBLE(Y(I)-YMED)*(1.0D0 - DVI**2)**2
          DSUM3=DSUM3 + (1.0D0 - DVI**2)*(1.0D0 - 5.0D0*DVI**2)
        ELSE
          DTERM2=0.0D0
        ENDIF
        DSUM1=DSUM1 + DTERM1*DTERM2
  300 CONTINUE
      DSBI=DBLE(N)*DSUM1/(DSUM2*DSUM3)
      XBWCOV=REAL(DSBI)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XBWCOV
  811   FORMAT('THE BIWEIGHT MID-COVARIANCE ESTIMATE OF THE ',I8,   &
               ' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BIWMCV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N
 9012   FORMAT('IBUGA3,IERROR,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XMED,XMAD,YMED,YMAD,XBWCOV
 9015   FORMAT('XMED,XMAD,YMED,YMAD,XBWCOV = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE BIWMCV
      SUBROUTINE BIWEIG(RES,N,IWRITE,WEIGHT,IBUGA3,IERROR)
!
!     PURPOSE--DETERMINE THE N VERTICAL (ROBUST) WEIGHTS WEIGHT(.)
!              BASED ON A BIWEIGHT WEIGHTING SCHEME OF
!              THE RESIDUALS IN RES(.).
!     NOTE--IF ALL INPUT RESIDUALS ARE ZERO, THIS SUBROUTINE
!           WILL OUTPUT ALL WEIGHTS AS UNITY.
!     REFERENCE--CHAMBERS, ET AL.  GRAPHICAL METHODS FOR DATA ANALYSIS.
!                WADSWORTH, 11013, PAGES 98-101, 122-123.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/2
!     ORIGINAL VERSION--FEBRUARY   1988
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION RES(*)
      DIMENSION WEIGHT(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIWE'
      ISUBN2='IG  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BIWEIG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IERROR,IWRITE,N
   52   FORMAT('IBUGA3,IERROR,IWRITE,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 61 I=1,N
            WRITE(ICOUT,62)I,RES(I)
   62       FORMAT('I,RES(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
   61     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN BIWEIG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT FULL SAMPLE SIZE, FOR WHICH BIWEIGHT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      WEIGHTS ARE TO BE COMPUTED, MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)N
  116   FORMAT('      THE FULL SAMPLE SIZE N = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 11--                                    **
!               **  COMPUTE THE BIWEIGHT WEIGHTING               **
!               **     1) COMPUTE ABSOLUTE VALUE OF RESIDUALS    **
!               **     2) COMPUTE MEDIAN ABSOLUTE VALUE RESIDUAL **
!               **     3) COMPUTE CUTOFF = +-6*M.A.R.            **
!               **     4) ASSIGN 0 WEIGHTS OUTSIDE OF REGION     **
!               **     5) ASSIGN BIWEIGHTS INSIDE OF REGION      **
!               ***************************************************
!
      DO 1100 I=1,N
        WEIGHT(I)=ABS(RES(I))
 1100 CONTINUE
!
      CALL SORT(WEIGHT,N,WEIGHT)
      IEVODD=N-(N/2)*2
      NMID=N/2
      NMIDP1=NMID+1
      XMEDAT=0.0
      XMEDAR=0.0
      IF(IEVODD.EQ.0)XMEDAR=(WEIGHT(NMID)+WEIGHT(NMIDP1))/2.0
      IF(IEVODD.EQ.1)XMEDAR=WEIGHT(NMIDP1)
!
      IF(XMEDAR.EQ.0.0)THEN
        CONST=(-999.0)
        DO 1111 I=1,N
          WEIGHT(I)=1.0
 1111   CONTINUE
        SUM=REAL(N)
      ELSE
        CONST=6.0*XMEDAR
        SUM=0.0
        DO 1121 I=1,N
          U=RES(I)/CONST
          WEIGHT(I)=0.0
          IF(-1.0.LE.U.AND.U.LE.1.0)WEIGHT(I)=(1.0-U**2)**2
          SUM=SUM + WEIGHT(I)
 1121   CONTINUE
      ENDIF
!
      IF(SUM.LE.0.0)WEIGHT(1:N)=1.0
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BIWEIG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N,XMEDAR
 9012   FORMAT('IBUGA3,IERROR,N,XMEDAR = ',2(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 9021 I=1,N
            WRITE(ICOUT,9022)I,RES(I),WEIGHT(I)
 9022       FORMAT('I,RES(I),WEIGHT(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE BIWEIG
      SUBROUTINE BIWMDV(X,N,IWRITE,XTEMP,XTEMP2,MAXNXT,XBWMDV,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE BIWEIGHT MIDVARIANCE ESTIMATOR
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE BIWEIGHT MIDVARIANCE ESTIMATE IS DEFINED AS:
!                 s(bi)**2 = SUM'[(y-y')**2*(1-u**2)**4]/
!                            {SUM'[1-u**2)*(1-5*u**2)]**2}
!              WHERE
!                 y' = MEDIAN OF Y
!                 MAD = MEDIAN ABSOLUTE DEVIATION
!                 u(i) = (Y(i) - y')/(9*MAD)
!                 SUM' means the summation is for u**2 <= 1
!              NOTE THAT THIS IS A SLIGHT VARIATION OF THE
!                   BIWEIGHT SCALE ESTIMATE.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XBWMDV    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE BIWEIGHT MIDVARIANCE
!                                ESTIMATE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE BIWEIGHT LOCATION ESTIMATE.
!     OTHER DATAPLOT  SUBROUTINES NEEDED--MEAN, MAD
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MOSTELLER AND TUKEY, 'DATA ANALYSIS AND REGRESSION'
!                 ADDISON AND WESLEY, 1977, PP. 204-206.
!     REFERENCES--RAND R. WILCOX, 'INTORIDUCTION TO ROBUST ESTIMATION
!                 AND HYPOTHESIS TESTING'
!                 ACADEMIC PRESS, 1997.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/7
!     ORIGINAL VERSION--JULY      2002.
!     UPDATED         --JULY      2010. CALL LIST TO MAD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DUI
      DOUBLE PRECISION DSBI
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DIMENSION XTEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIWM'
      ISUBN2='DV  '
      XBWMDV=0.0
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BIWMDV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  COMPUTE BIWEIGHT MIDVARIANCE ESTIMATE **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN BIWEIGHT MID-VARIANCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS LESS THAN ONE ',   &
               'OBSERVATION.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        XBWMDV=CPUMIN
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XBWMDV=0.0
      GO TO 8000
  139 CONTINUE
!
!               ***************************************************
!               **  STEP 2--                                     **
!               **  COMPUTE THE BIWEIGHT MIDVARIANCE ESTIMATE.   **
!               ***************************************************
!
      IWRIT2='OFF'
      CALL MEDIAN(X,N,IWRIT2,XTEMP,MAXNXT,XMED,IBUGA3,IERROR)
      CALL MAD(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 300 I=1,N
        DUI=DBLE((X(I) - XMED)/(9.0*XMAD))
        IF(DUI*DUI.LT.1.0D0)THEN
          DSUM1=DSUM1 + (DBLE(X(I)-XMED)**2)*(1.0D0 - DUI**2)**4
          DSUM2=DSUM2 + (1.0D0 - DUI**2)*(1.0D0 - 5.0D0*DUI**2)
        ENDIF
  300 CONTINUE
      DSBI=DBLE(N)*DSUM1/(DSUM2*DSUM2)
      XBWMDV=REAL(DSBI)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XBWMDV
  811   FORMAT('THE BIWEIGHT MIDVARIANCE ESTIMATE OF THE ',I8,   &
               ' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BIWMDV--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N,XBWMDV
 9012   FORMAT('IBUGA3,IERROR,N,XBWMDV = ',A4,2X,A4,2X,I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE BIWMDV
      SUBROUTINE BIWLOC(X,N,IWRITE,XTEMP,XTEMP2,MAXNXT,XBW,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE BIWEIGHT LOCATION ESTIMATOR
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE BIWEIGHT LOCATION ESTIMATE IS DEFINED AS:
!                 y* = SUM[w(i)*y(i)]/SUM[w(i)]
!              WHERE
!                 w(i) = (1 - ((y(i) - y*)/(6*MAD))**2)**2
!                                    if (y(i) - y*)/(6*MAD))**2   < 1
!                      = 0           otherwise
!              WHERE MAD IS THE BIWEIGHT LOCATION ESTIMATE
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XBW    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE BIWEIGHT LOCATION
!                                ESTIMATE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE BIWEIGHT LOCATION ESTIMATE.
!     OTHER DATAPLOT  SUBROUTINES NEEDED--MEAN, MAD
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MOSTELLER AND TUKEY, 'DATA ANALYSIS AND REGRESSION'
!                 ADDISON AND WESLEY, 1977, PP. 204-206.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DWT
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DIMENSION XTEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIWL'
      ISUBN2='OC  '
      XBW=0.0
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF BIWLOC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ******************************************
!               **  COMPUTE BIWEIGHT LOCATION ESTIMATE **
!               ******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GT.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN BIWLOC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE BIWEIGHT LOCATION ESTIMATE IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      COMPUTED, MUST BE 2 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('***** NON-FATAL DIAGNOSTIC IN BIWLOC--',   &
      'THE FIRST INPUT ARGUMENT (A VECTOR) HAS ALL ELEMENTS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      XBW=HOLD
      GO TO 9000
  139 CONTINUE
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE BIWEIGHT LOCATION ESTIMATE.  **
!               ***********************************************
!
      IWRIT2='OFF'
!
      DO 195 I=1,N
        XTEMP2(I)=X(I)
  195 CONTINUE
!
      CALL MEAN(X,N,IWRIT2,XMEAN,IBUGA3,IERROR)
!CCCC CALL MAD(X,N,IWRIT2,XTEMP,MAXNXT,XMAD,IBUGA3,IERROR)
      ITER=0
!
      DO 198 I=1,N
        X(I)=XTEMP2(I)
  198 CONTINUE
!
  200 CONTINUE
!
      DO 205 I=1,N
        XTEMP2(I)=ABS(X(I)-XMEAN)
  205 CONTINUE
      CALL MEDIAN(XTEMP2,N,IWRIT2,XTEMP,MAXNXT,XMAD,IBUGA3,IERROR)
!
      XMEANO=XMEAN
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 300 I=1,N
      XTEMP(I)=((X(I) - XMEAN)/(6.0*XMAD))**2
      IF(XTEMP(I).LT.1.0)THEN
        DWT=DBLE(XTEMP(I))
        DWT=(1.0D0 - DWT)**2
        DSUM1=DSUM1 + DWT*DBLE(X(I))
        DSUM2=DSUM2 + DWT
      ENDIF
  300 CONTINUE
      IF(DSUM2.NE.0.0D0)THEN
        XMEAN=REAL(DSUM1/DSUM2)
      ELSE
       XMEAN=0.0
      ENDIF
      ITER=ITER+1
      IF(ABS(XMEAN-XMEANO).GT.0.00001 .AND. ITER.LE.10)GO TO 200
      XBW=XMEAN
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XBW
  811 FORMAT('THE BIWEIGHT LOCATION ESTIMATE OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF BIWLOC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XBW
 9015 FORMAT('XBW = ',E15.7)
      CALL DPWRST('XXX','BUG ')
9090  CONTINUE
!
      RETURN
      END SUBROUTINE BIWLOC
      SUBROUTINE BIWSCA(X,N,IWRITE,XTEMP,XTEMP2,MAXNXT,XBS,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE BIWEIGHT SCALE ESTIMATOR
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE BIWEIGHT LOCATION ESTIMATE IS DEFINED AS:
!                 s(bi)**2= SUM'[(y-y')**2*(1-u**2)**4]/
!                           {SUM'[1-u**2)*(1-5*u**2)]*
!                           [-1 + SUM'[(1-u**2)*(1-5*u**2)]}
!              WHERE
!                 y' = MEDIAN OF Y
!                 MAD = MEDIAN ABSOLUTE DEVIATION
!                 u(i) = (Y(i) - y')/(9*MAD)
!                 SUM' means the summation is for u**2 <= 1
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XBS    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE BIWEIGHT LOCATION
!                                ESTIMATE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE BIWEIGHT LOCATION ESTIMATE.
!     OTHER DATAPLOT  SUBROUTINES NEEDED--MEAN, MAD
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MOSTELLER AND TUKEY, 'DATA ANALYSIS AND REGRESSION'
!                 ADDISON AND WESLEY, 1977, PP. 204-206.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/11
!     ORIGINAL VERSION--NOVEMBER  2001.
!     UPDATED         --JULY      2010. CALL LIST TO MAD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DUI
      DOUBLE PRECISION DSBI
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DIMENSION XTEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BIWL'
      ISUBN2='OC  '
      XBS=0.0
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BIWSCA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************************
!               **  COMPUTE BIWEIGHT SCALE ESTIMATE     **
!               ******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN BIWEIGHT SCALE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS LESS THAN ONE ',   &
               'OBSERVATION.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        XBS=CPUMIN
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
      IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XBS=0.0
      GO TO 8000
  139 CONTINUE
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE BIWEIGHT SCALE ESTIMATE.     **
!               ***********************************************
!
      IWRIT2='OFF'
      CALL BIWLOC(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,XBW,IBUGA3,IERROR)
      CALL MAD(X,N,IWRIT2,XTEMP,XTEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 300 I=1,N
        DUI=DBLE((X(I) - XBW)/(9.0*XMAD))
        IF(DUI*DUI.LE.1.0D0)THEN
          DSUM1=DSUM1 + (DBLE(X(I)-XBW)**2)*(1.0D0 - DUI**2)**4
          DSUM2=DSUM2 + (1.0D0 - DUI**2)*(1.0D0 - 5.0D0*DUI**2)
        ENDIF
  300 CONTINUE
      DSBI=DBLE(N)*DSUM1/(DSUM2*(-1.0D0 + DSUM2))
      XBS=REAL(DSBI)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XBS
  811   FORMAT('THE BIWEIGHT SCALE ESTIMATE OF THE ',I8,   &
               ' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BIWSCA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N,XBS
 9012   FORMAT('IBUGA3,IERROR,N,XBS = ',A4,2X,A4,2X,I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE BIWSCA
      SUBROUTINE BKNOT(X,N,K,T)
!***BEGIN PROLOGUE  BKNOT
!***REFER TO  B2INK,B3INK
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  BKNOT
!
!  --------------------------------------------------------------------
!  BKNOT CHOOSES A KNOT SEQUENCE FOR INTERPOLATION OF ORDER K AT THE
!  DATA POINTS X(I), I=1,..,N.  THE N+K KNOTS ARE PLACED IN THE ARRAY
!  T.  K KNOTS ARE PLACED AT EACH ENDPOINT AND NOT-A-KNOT END
!  CONDITIONS ARE USED.  THE REMAINING KNOTS ARE PLACED AT DATA POINTS
!  IF N IS EVEN AND BETWEEN DATA POINTS IF N IS ODD.  THE RIGHTMOST
!  KNOT IS SHIFTED SLIGHTLY TO THE RIGHT TO INSURE PROPER INTERPOLATION
!  AT X(N) (SEE PAGE 350 OF THE REFERENCE).
!  --------------------------------------------------------------------
!
!  ------------
!  DECLARATIONS
!  ------------
!
!  PARAMETERS
!
      INTEGER   &
              N, K
      REAL   &
           X(N), T(*)
!
!  LOCAL VARIABLES
!
      INTEGER   &
              I, J, IPJ, NPJ, IP1
      REAL   &
           RNOT
!
!
!  ----------------------------
!  PUT K KNOTS AT EACH ENDPOINT
!  ----------------------------
!
!     (SHIFT RIGHT ENPOINTS SLIGHTLY -- SEE PG 350 OF REFERENCE)
      RNOT = X(N) + 0.10E0*( X(N)-X(N-1) )
      DO 110 J=1,K
         T(J) = X(1)
         NPJ = N + J
         T(NPJ) = RNOT
  110 CONTINUE
!
!  --------------------------
!  DISTRIBUTE REMAINING KNOTS
!  --------------------------
!
      IF (MOD(K,2) .EQ. 1)  GO TO 150
!
!     CASE OF EVEN K --  KNOTS AT DATA POINTS
!
      I = (K/2) - K
      JSTRT = K+1
      DO 120 J=JSTRT,N
         IPJ = I + J
         T(J) = X(IPJ)
  120 CONTINUE
      GO TO 200
!
!     CASE OF ODD K --  KNOTS BETWEEN DATA POINTS
!
  150 CONTINUE
      I = (K-1)/2 - K
      IP1 = I + 1
      JSTRT = K + 1
      DO 160 J=JSTRT,N
         IPJ = I + J
         T(J) = 0.50E0*( X(IPJ) + X(IPJ+1) )
  160 CONTINUE
  200 CONTINUE
!
      RETURN
      END SUBROUTINE BKNOT
      SUBROUTINE BNDRY(A,BOX,IMX,JMX,IB,JB,NB,ISUBRO,IBUGG3)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        BYTE TO CHARACTER*1,
!                                        DO WHILE/END DO (ALAN HECKERT).
!     UPDATED         --JULY      1990.  999.999 TO ANINE
!     UPDATED         --JULY      1990.  ( ) AROUND ALL EXPR. ANINE
!     UPDATED         --JULY      1990.  MAJOR CHANGES
!     UPDATED         --APRIL     1992.  JO TO J0 (ALAN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOCP.INC'
!
!---------------------------------------------------------------------
!
!CCCC BYTE BOX(4,MAXIMX,MAXJMX),SBOX     AUGUST 1988
!CCCC DIMENSION A(IMX,JMX),IB(*),JB(*)   AUGUST 1988
!
!CCCC BYTE BOX                           JANUARY 1989
!CCCC BYTE SBOX                          JANUARY 1989
      CHARACTER*1 BOX
!CCCC CHARACTER*1 SBOX
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
!
      DIMENSION A(MAXIMX,MAXJMX)
      DIMENSION BOX(4,MAXIMX,MAXJMX)
      DIMENSION IB(*)
      DIMENSION JB(*)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'NDRY')THEN
        WRITE(ICOUT,51)IMX,JMX,MAXIMX,MAXJMX,NB
   51   FORMAT('FROM BNDRY: IMX,JMX,MAXIMX,MAXJMX,NB = ',5I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1990
!CCCC AND ALL SUBSEQUENT OCCURRANCES OF 999.999   JULY 1990
!CCCC WERE CHANGED TO ANINE       JULY 1990
      ANINE=999.999
!
      DO 100 I=1,IMX
        DO 110 J=1,JMX
          DO 120 L=1,4
            BOX(L,I,J)='0'
 120      CONTINUE
 110    CONTINUE
 100  CONTINUE
      DO 200 I=1,IMX
        BOX(4,I,1)='2'
        BOX(2,I,JMX-1)='2'
        DO 210 L=1,4
          BOX(L,I,JMX)='2'
 210    CONTINUE
 200  CONTINUE
      DO 300 J=1,JMX
        BOX(1,1,J)='2'
        BOX(3,IMX-1,J)='2'
        DO 310 L=1,4
          BOX(L,IMX,J)='2'
 310    CONTINUE
 300  CONTINUE
      DO 400 I=1,IMX
        DO 410 J=1,JMX
          IF (A(I,J).EQ.ANINE) THEN
            DO 420 N=1,4
              II=MAX0(1,I-N/3)
              JJ=MAX0(1,J-MOD(N/2,2))
              DO 430 L=1,4
                BOX(L,II,JJ)='2'
 430          CONTINUE
              III=MIN0(IMX,MAX0(1,II+1-2*(N/3)))
              JJJ=MIN0(JMX,MAX0(1,JJ+MAX0(3-2*N,2*N-7)))
              L=1+2*(N/3)
              BOX(L,III,JJ)='2'
              L=MAX0(6-2*N,2*N-4)
              BOX(L,II,JJJ)='2'
 420        CONTINUE
          END IF
 410    CONTINUE
 400  CONTINUE
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'NDRY')THEN
        DO 1050 II=1,IMX
          DO 1055 JJ=1,JMX
            WRITE(ICOUT,1059)II,JJ,BOX(1,II,JJ),BOX(2,II,JJ),   &
                                   BOX(3,II,JJ),BOX(4,II,JJ)
 1059       FORMAT('II,JJ,BOX(1,II,JJ),BOX(2,II,JJ),BOX(2,II,JJ),',   &
                   'BOX(4,II,JJ) = ',2I6,3X,4(2X,A1))
            CALL DPWRST('XXX','BUG ')
 1055     CONTINUE
 1050   CONTINUE
      ENDIF
!
      I0=0
      J0=0
      I=0
!CCCC DO WHILE (I0.EQ.0.AND.I.LT.IMX)    JANUARY 1989
 500  CONTINUE
       IF(I0.NE.0.OR.I.GE.IMX)GO TO 599
        I=I+1
        J=0
!CCCC   DO WHILE (J0.EQ.0.AND.J.LT.JMX)  JANUARY 1989
 600    CONTINUE
!CCCC THE FOLLOWING LINE WAS FIXED   APRIL 1992   (ALAN)
!CCCC    IF(JO.NE.0.OR.J.GE.JMX)GO TO 699
         IF(J0.NE.0.OR.J.GE.JMX)GO TO 699
          J=J+1
          IF (BOX(3,I,J).EQ.'0') THEN
            I0=I
            J0=J
          END IF
          GO TO 600
 699    CONTINUE
        GO TO 500
 599  CONTINUE
      I=I0
      J=J0
      NB=1
      IB(NB)=I
      JB(NB)=J
      IFLG=0
      IJD=1
!CCCC DO WHILE (IFLG.EQ.0)               JANUARY 1989
 700  CONTINUE
      IF(IFLG.NE.0)GO TO 799
!
        IF (IJD.EQ.1) THEN
          AMM=ANINE
          AM0=ANINE
          AMP=ANINE
          A0M=ANINE
          A00=ANINE
          A0P=ANINE
          APM=ANINE
          AP0=ANINE
          APP=ANINE
          IF(I.GT.1.AND.J.GT.1)AMM=A(I-1,J-1)
          IF(I.GT.1.AND.J.GT.0)AM0=A(I-1,J)
          IF(I.GT.1.AND.J.LT.JMX)AMP=A(I-1,J+1)
          IF(I.GT.0.AND.J.GT.1)A0M=A(I,J-1)
          IF(I.GT.0.AND.J.GT.0)A00=A(I,J)
          IF(I.GT.0.AND.J.LT.JMX)A0P=A(I,J+1)
          IF(I.LT.IMX.AND.J.GT.1)APM=A(I+1,J-1)
          IF(I.LT.IMX.AND.J.GT.0)AP0=A(I+1,J)
          IF(I.LT.IMX.AND.J.LT.JMX)APP=A(I+1,J+1)
          IF ((AM0.NE.ANINE).AND.   &
              (((AMM.NE.ANINE)).OR.   &
                ((AMP.NE.ANINE)))) THEN
            I=I-1
            IJD=4
          ELSE IF ((A0P.NE.ANINE).AND.   &
              (((AMP.NE.ANINE)).OR.   &
                ((APP.NE.ANINE)))) THEN
            J=J+1
            IJD=1
          ELSE IF ((AP0.NE.ANINE).AND.   &
              (((APM.NE.ANINE)).OR.   &
                ((APM.NE.ANINE)))) THEN
            I=I+1
            IJD=2
          END IF
!
        ELSE IF (IJD.EQ.2) THEN
          AMM=ANINE
          AM0=ANINE
          AMP=ANINE
          A0M=ANINE
          A00=ANINE
          A0P=ANINE
          APM=ANINE
          AP0=ANINE
          APP=ANINE
          IF(I.GT.1.AND.J.GT.1)AMM=A(I-1,J-1)
          IF(I.GT.1.AND.J.GT.0)AM0=A(I-1,J)
          IF(I.GT.1.AND.J.LT.JMX)AMP=A(I-1,J+1)
          IF(I.GT.0.AND.J.GT.1)A0M=A(I,J-1)
          IF(I.GT.0.AND.J.GT.0)A00=A(I,J)
          IF(I.GT.0.AND.J.LT.JMX)A0P=A(I,J+1)
          IF(I.LT.IMX.AND.J.GT.1)APM=A(I+1,J-1)
          IF(I.LT.IMX.AND.J.GT.0)AP0=A(I+1,J)
          IF(I.LT.IMX.AND.J.LT.JMX)APP=A(I+1,J+1)
          IF ((A0P.NE.ANINE).AND.   &
              (((AMP.NE.ANINE)).OR.   &
                ((APP.NE.ANINE)))) THEN
            J=J+1
            IJD=1
          ELSE IF ((AP0.NE.ANINE).AND.   &
              (((APM.NE.ANINE)).OR.   &
                ((APM.NE.ANINE)))) THEN
            I=I+1
            IJD=2
          ELSE IF ((A0M.NE.ANINE).AND.   &
              (((AMM.NE.ANINE)).OR.   &
                ((APM.NE.ANINE)))) THEN
            J=J-1
            IJD=3
          END IF
!
        ELSE IF (IJD.EQ.3) THEN
          AMM=ANINE
          AM0=ANINE
          AMP=ANINE
          A0M=ANINE
          A00=ANINE
          A0P=ANINE
          APM=ANINE
          AP0=ANINE
          APP=ANINE
          IF(I.GT.1.AND.J.GT.1)AMM=A(I-1,J-1)
          IF(I.GT.1.AND.J.GT.0)AM0=A(I-1,J)
          IF(I.GT.1.AND.J.LT.JMX)AMP=A(I-1,J+1)
          IF(I.GT.0.AND.J.GT.1)A0M=A(I,J-1)
          IF(I.GT.0.AND.J.GT.0)A00=A(I,J)
          IF(I.GT.0.AND.J.LT.JMX)A0P=A(I,J+1)
          IF(I.LT.IMX.AND.J.GT.1)APM=A(I+1,J-1)
          IF(I.LT.IMX.AND.J.GT.0)AP0=A(I+1,J)
          IF(I.LT.IMX.AND.J.LT.JMX)APP=A(I+1,J+1)
          IF ((AP0.NE.ANINE).AND.   &
              (((APM.NE.ANINE)).OR.   &
                ((APM.NE.ANINE)))) THEN
            I=I+1
            IJD=2
          ELSE IF ((A0M.NE.ANINE).AND.   &
              (((AMM.NE.ANINE)).OR.   &
                ((APM.NE.ANINE)))) THEN
            J=J-1
            IJD=3
          ELSE IF ((AM0.NE.ANINE).AND.   &
              (((AMM.NE.ANINE)).OR.   &
                ((AMP.NE.ANINE)))) THEN
            I=I-1
            IJD=4
          END IF
!
        ELSE IF (IJD.EQ.4) THEN
          AMM=ANINE
          AM0=ANINE
          AMP=ANINE
          A0M=ANINE
          A00=ANINE
          A0P=ANINE
          APM=ANINE
          AP0=ANINE
          APP=ANINE
          IF(I.GT.1.AND.J.GT.1)AMM=A(I-1,J-1)
          IF(I.GT.1.AND.J.GT.0)AM0=A(I-1,J)
          IF(I.GT.1.AND.J.LT.JMX)AMP=A(I-1,J+1)
          IF(I.GT.0.AND.J.GT.1)A0M=A(I,J-1)
          IF(I.GT.0.AND.J.GT.0)A00=A(I,J)
          IF(I.GT.0.AND.J.LT.JMX)A0P=A(I,J+1)
          IF(I.LT.IMX.AND.J.GT.1)APM=A(I+1,J-1)
          IF(I.LT.IMX.AND.J.GT.0)AP0=A(I+1,J)
          IF(I.LT.IMX.AND.J.LT.JMX)APP=A(I+1,J+1)
          IF ((A0M.NE.ANINE).AND.   &
              (((AMM.NE.ANINE)).OR.   &
                ((APM.NE.ANINE)))) THEN
            J=J-1
            IJD=3
          ELSE IF ((AM0.NE.ANINE).AND.   &
              (((AMM.NE.ANINE)).OR.   &
                ((AMP.NE.ANINE)))) THEN
            I=I-1
            IJD=4
          ELSE IF ((A0P.NE.ANINE).AND.   &
              (((AMP.NE.ANINE)).OR.   &
                ((APP.NE.ANINE)))) THEN
            J=J+1
            IJD=1
          END IF
!
        END IF
        IBNB=I
        JBNB=J
        IF (NB.GT.1) THEN
          IF (IBNB.NE.IB(NB-1).AND.JBNB.NE.JB(NB-1)) NB=NB+1
        ELSE
          NB=NB+1
        END IF
        IB(NB)=I
        JB(NB)=J
        IF (IB(NB).EQ.IB(1).AND.JB(NB).EQ.JB(1)) IFLG=1
        GO TO 700
 799  CONTINUE
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'NDRY')THEN
        WRITE(ICOUT,9051)NB
 9051   FORMAT('FROM END OF BNDRY: NB = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NB.GT.0)THEN
          DO 9055 II=1,NB
            WRITE(ICOUT,9059)II,IB(II),JB(II)
 9059       FORMAT('II,IB(II),JB(II) = ',3I6)
            CALL DPWRST('XXX','BUG ')
 9055     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE BNDRY
      SUBROUTINE BNFAC(W,NROWW,NROW,NBANDL,NBANDU,IFLAG)
!***BEGIN PROLOGUE  BNFAC
!***REFER TO  BINT4,BINTK
!
!  BNFAC is the BANFAC routine from
!        * A Practical Guide to Splines *  by C. de Boor
!
!  Returns in  W  the lu-factorization (without pivoting) of the banded
!  matrix  A  of order  NROW  with  (NBANDL + 1 + NBANDU) bands or diag-
!  onals in the work array  W .
!
! *****  I N P U T  ******
!  W.....Work array of size  (NROWW,NROW)  containing the interesting
!        part of a banded matrix  A , with the diagonals or bands of  A
!        stored in the rows of  W , while columns of  A  correspond to
!        columns of  W . This is the storage mode used in  LINPACK  and
!        results in efficient innermost loops.
!           Explicitly,  A  has  NBANDL  bands below the diagonal
!                            +     1     (main) diagonal
!                            +   NBANDU  bands above the diagonal
!        and thus, with    MIDDLE = NBANDU + 1,
!          A(I+J,J)  is in  W(I+MIDDLE,J)  for I=-NBANDU,...,NBANDL
!                                              J=1,...,NROW .
!        For example, the interesting entries of A (1,2)-banded matrix
!        of order  9  would appear in the first  1+1+2 = 4  rows of  W
!        as follows.
!                          13 24 35 46 57 68 79
!                       12 23 34 45 56 67 78 89
!                    11 22 33 44 55 66 77 88 99
!                    21 32 43 54 65 76 87 98
!
!        All other entries of  W  not identified in this way with an en-
!        try of  A  are never referenced .
!  NROWW.....Row dimension of the work array  W .
!        must be  .GE.  NBANDL + 1 + NBANDU  .
!  NBANDL.....Number of bands of  A  below the main diagonal
!  NBANDU.....Number of bands of  A  above the main diagonal .
!
! *****  O U T P U T  ******
!  IFLAG.....Integer indicating success( = 1) or failure ( = 2) .
!     If  IFLAG = 1, then
!  W.....contains the LU-factorization of  A  into a unit lower triangu-
!        lar matrix  L  and an upper triangular matrix  U (both banded)
!        and stored in customary fashion over the corresponding entries
!        of  A . This makes it possible to solve any particular linear
!        system  A*X = B  for  X  by A
!              CALL BNSLV ( W, NROWW, NROW, NBANDL, NBANDU, B )
!        with the solution X  contained in  B  on return .
!     If  IFLAG = 2, then
!        one of  NROW-1, NBANDL,NBANDU failed to be nonnegative, or else
!        one of the potential pivots was found to be zero indicating
!        that  A  does not have an LU-factorization. This implies that
!        A  is singular in case it is totally positive .
!
! *****  M E T H O D  ******
!     Gauss elimination  W I T H O U T  pivoting is used. The routine is
!  intended for use with matrices  A  which do not require row inter-
!  changes during factorization, especially for the  T O T A L L Y
!  P O S I T I V E  matrices which occur in spline calculations.
!     The routine should not be used for an arbitrary banded matrix.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  BNFAC
!
      INTEGER IFLAG, NBANDL, NBANDU, NROW, NROWW, I, IPK, J, JMAX, K,   &
       KMAX, MIDDLE, MIDMK, NROWM1
      REAL W(NROWW,NROW), FACTOR, PIVOT
!
!***FIRST EXECUTABLE STATEMENT  BNFAC
      IFLAG = 1
      MIDDLE = NBANDU + 1
!                         W(MIDDLE,.) CONTAINS THE MAIN DIAGONAL OF  A .
      NROWM1 = NROW - 1
!CCCC IF (NROWM1) 120, 110, 10
      IF (NROWM1.LT.0) THEN
         GO TO 120
      ELSEIF (NROWM1.EQ.0) THEN
         GO TO 110
      ELSEIF (NROWM1.GT.0) THEN
         GO TO 10
      ENDIF
   10 IF (NBANDL.GT.0) GO TO 30
!                A IS UPPER TRIANGULAR. CHECK THAT DIAGONAL IS NONZERO .
      DO 20 I=1,NROWM1
        IF (W(MIDDLE,I).EQ.0.0E0) GO TO 120
   20 CONTINUE
      GO TO 110
   30 IF (NBANDU.GT.0) GO TO 60
!              A IS LOWER TRIANGULAR. CHECK THAT DIAGONAL IS NONZERO AND
!                 DIVIDE EACH COLUMN BY ITS DIAGONAL .
      DO 50 I=1,NROWM1
        PIVOT = W(MIDDLE,I)
        IF (PIVOT.EQ.0.0E0) GO TO 120
        JMAX = MIN0(NBANDL,NROW-I)
        DO 40 J=1,JMAX
          W(MIDDLE+J,I) = W(MIDDLE+J,I)/PIVOT
   40   CONTINUE
   50 CONTINUE
      RETURN
!
!        A  IS NOT JUST A TRIANGULAR MATRIX. CONSTRUCT LU FACTORIZATION
   60 DO 100 I=1,NROWM1
!                                  W(MIDDLE,I)  IS PIVOT FOR I-TH STEP .
        PIVOT = W(MIDDLE,I)
        IF (PIVOT.EQ.0.0E0) GO TO 120
!                 JMAX  IS THE NUMBER OF (NONZERO) ENTRIES IN COLUMN  I
!                     BELOW THE DIAGONAL .
        JMAX = MIN0(NBANDL,NROW-I)
!              DIVIDE EACH ENTRY IN COLUMN  I  BELOW DIAGONAL BY PIVOT .
        DO 70 J=1,JMAX
          W(MIDDLE+J,I) = W(MIDDLE+J,I)/PIVOT
   70   CONTINUE
!                 KMAX  IS THE NUMBER OF (NONZERO) ENTRIES IN ROW  I  TO
!                     THE RIGHT OF THE DIAGONAL .
        KMAX = MIN0(NBANDU,NROW-I)
!                  SUBTRACT  A(I,I+K)*(I-TH COLUMN) FROM (I+K)-TH COLUMN
!                  (BELOW ROW  I ) .
        DO 90 K=1,KMAX
          IPK = I + K
          MIDMK = MIDDLE - K
          FACTOR = W(MIDMK,IPK)
          DO 80 J=1,JMAX
            W(MIDMK+J,IPK) = W(MIDMK+J,IPK) - W(MIDDLE+J,I)*FACTOR
   80     CONTINUE
   90   CONTINUE
  100 CONTINUE
!                                       CHECK THE LAST DIAGONAL ENTRY .
  110 IF (W(MIDDLE,NROW).NE.0.0E0) RETURN
  120 IFLAG = 2
      RETURN
      END SUBROUTINE BNFAC
      SUBROUTINE BNOCDF(DX,DALPHA,DBETA,DCDF)
!
!     PURPOSE   --COMPUTE THE BETA-NORMAL CDF FUNCTION
!                 THIS CDF FUNCTION IS DEFINED AS:
!                    F(X;A,B) = (1/BETA(A,B)*INTERGRAL[0 TO G(X)]
!                               [W**(A-1)*(1-W)**(B-1)dw
!                               A, B > 0
!                 WITH G(X) DENOTING A FUNCTION.  IN THIS CASE,
!                 WE TAKE G(X) TO BE THE NORMAL CDF FUNCTION.
!                 THAT IS, THIS IS ESSENTIALLY A BETA CDF, BUT
!                 WITH THE UPPER LIMIT OF INTEGRATION REPLACED WITH
!                 THE NORMAL CDF VALUE OF X.
!     REFERENCE --"HANDBOOK OF BETA DISTRIBUTION AND ITS APPLICATIONS",
!                 EDITED BY ARJUN GUPTA AND SARALEES NADARAJAH,
!                 MARCEL DEKKER INC., 2004, PP. 146-152.
!               --"BETA-NORMAL DISTRIBUTION AND ITS APPLICATIONS",
!                 EUGENE, LEE, AND FAMOYE.  COMMUNICATIONS IN
!                 STATISTICS-THEORY AND METHODS, 2002, 31, PP. 497-512.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DNOCDF
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DX
      DOUBLE PRECISION DBETAI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR--FOR BNOCDF, THE ALPHA SHAPE PARAMETER IS ',   &
             'NON-POSITIVE.')
  102 FORMAT('***** ERROR--FOR BNOCDF, THE BETA SHAPE PARAMETER IS ',   &
             'NON-POSITIVE.')
  103 FORMAT('***** THE VALUE IS ',G15.7)
!
      CALL NODCDF(DX,DNOCDF)
      DCDF=DBETAI(DNOCDF,DALPHA,DBETA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BNOCDF
      SUBROUTINE BNOFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              BETA-NORMAL MAXIMUM LIKELIHOOD EQUATIONS
!              TO ESTIMATE THE ALPHA AND BETA SHAPE PARAMETERS
!              AND THE LOCATION/SCALE PARAMETERS.  THE MAXIMUM
!              LIKELIHOOD EQUATIONS ARE:
!
!                 N*PSI(ALPHA+BETA) - N*PSI(ALPHA) +
!                 SUM[i=1 to N][LOG(NORCDF((X(i)-MU)/SIGMA))] = 0
!
!                 N*PSI(ALPHA+BETA) - N*PSI(BETA) +
!                 SUM[i=1 to N][LOG(1-NORCDF((X(i)-MU)/SIGMA))] = 0
!
!                 SUM[i=1 to n][{
!                 (1-ALPHA)*NORPDF((X(i)-MU)/SIGMA)/
!                 NORCDF((X(i)-MU)/SIGMA) +
!                 (BETA-1)*NORPDF((X(i)-MU)/SIGMA)/
!                 (1 - NORCDF((X(i)-MU)/SIGMA)) +
!                 (X(i)-MU)/SIGMA**2)} = 0
!
!                 SUM[i=1 to n][{
!                 (1-ALPHA)*NORPDF((X(i)-MU)/SIGMA)*(X(i)-MU)/SIGMA)/
!                 NORCDF((X(i)-MU)/SIGMA) +
!                 (BETA-1)*NORPDF((X(i)-MU)/SIGMA)*(X(i)-MU)/SIGMA)/
!                 (1 - NORCDF((X(i)-MU)/SIGMA)) +
!                 (X(i)-MU)**2/SIGMA**3)} - (N/SIGMA)= 0
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--BETA NORMAL MAXIMUM LIKELIHOOD Y
!     REFERENCE--EUGENE, LEE, AND FAMOYE (2002), "BETA-NORMAL
!                DISTRIBUTION AND ITS APPLICATIONS", COMMUNICATIONS
!                IN STATISTICS--THEORY AND METHODS, 31(4),
!                PP. 497-512.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/6
!     ORIGINAL VERSION--JUNE      2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DX
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!CCCC DOUBLE PRECISION DTERM5
!CCCC DOUBLE PRECISION DTERM6
!CCCC DOUBLE PRECISION DTERM7
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DEPS
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=4
      IFLAG=0
!
      DA=X(1)
      DB=X(2)
      DMU=X(3)
      DSIGMA=X(4)
!
      DN=DBLE(NOBS)
      DTERM1=DN*DPSI(DA+DB)
      DTERM2=DN*DPSI(DA)
      DTERM3=DN*DPSI(DB)
      DEPS=1.0D-20
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,NOBS
        DX=DBLE(XDATA(I))
        DZ=(DX - DMU)/DSIGMA
        CALL NODCDF(DZ,DTERM4)
        IF(DTERM4.LE.0.0D0)DTERM4=DEPS
        DSUM1=DSUM1 + DLOG(DTERM4)
        CALL NODCDF(DZ,DTERM4)
        DTERM4=1.0D0 - DTERM4
        IF(DTERM4.LE.0.0D0)DTERM4=DEPS
        DSUM2=DSUM2 + DLOG(DTERM4)
  100 CONTINUE
!
      FVEC(1)=DTERM1 - DTERM2 + DSUM1
      FVEC(2)=DTERM1 - DTERM3 + DSUM2
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DZ=(DX - DMU)/DSIGMA
        CALL NODPDF(DZ,DTERM1)
        CALL NODCDF(DZ,DTERM2)
        DTERM3=(1.0D0 - DA)*DTERM1
        IF(DTERM2.NE.0.0D0)THEN
          DSUM1=DSUM1 + DTERM3/DTERM2
        ELSE
          DSUM1=DSUM1 + DTERM3/DEPS
        ENDIF
        DTERM3=(DB - 1.0D0)*DTERM1
        DTERM4=1.0D0 - DTERM2
        IF(DTERM4.NE.0.0D0)THEN
          DSUM2=DSUM2 + DTERM3/DTERM4
        ELSE
          DSUM2=DSUM2 + DTERM3/DEPS
        ENDIF
        DSUM3=DSUM3 + DZ/DSIGMA
  200 CONTINUE
      FVEC(3)=DSUM1 + DSUM2 + DSUM3
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DO 300 I=1,NOBS
        DX=DBLE(XDATA(I))
        DZ=(DX - DMU)/DSIGMA
        CALL NODPDF(DZ,DTERM1)
        CALL NODCDF(DZ,DTERM2)
        DTERM3=(1.0D0 - DA)*DTERM1
        IF(DTERM2.NE.0.0D0)THEN
          DSUM1=DSUM1 + (DTERM3/DTERM2)*DZ
        ELSE
          DSUM1=DSUM1 + (DTERM3/DEPS)*DZ
        ENDIF
        DTERM3=(DB - 1.0D0)*DTERM1
        DTERM4=1.0D0 - DTERM2
        IF(DTERM4.NE.0.0D0)THEN
          DSUM2=DSUM2 + (DTERM3/DTERM4)*DZ
        ELSE
          DSUM2=DSUM2 + (DTERM3/DEPS)*DZ
        ENDIF
        DSUM3=DSUM3 + (DX-DMU)**2/(DSIGMA**3)
  300 CONTINUE
      FVEC(4)=DSUM1 + DSUM2 + DSUM3 - DN/DSIGMA
!
      RETURN
      END SUBROUTINE BNOFUN 
      DOUBLE PRECISION FUNCTION BNOFU2(DX)
!
!     PURPOSE--BNOPPF CALLS DFZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  BNOFU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - BNOCDF(X,ALPHA,BETA)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE BNOFU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BNOCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --"HANDBOOK OF BETA DISTRIBUTION AND ITS APPLICATIONS",
!                 EDITED BY ARJUN GUPTA AND SARALEES NADARAJAH,
!                 MARCEL DEKKER INC., 2004, PP. 146-152.
!               --"BETA-NORMAL DISTRIBUTION AND ITS APPLICATIONS",
!                 EUGENE, LEE, AND FAMOYE.  COMMUNICATIONS IN
!                 STATISTICS-THEORY AND METHODS, 2002, 31, PP. 497-512.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      COMMON/BNOCOM/DP,DALPHA,DBETA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL BNOCDF(DX,DALPHA,DBETA,DCDF)
      BNOFU2=DP - DCDF
!
      RETURN
      END FUNCTION BNOFU2
      SUBROUTINE BNOML1(Y,N,MAXNXT,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        AMUSV,SIGMSV,ALPHSV,BETASV,   &
                        AMUML,SIGMML,ALPHML,BETAML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE BETA NORMAL DISTRIBUTION.
!     NOTE--THE MAXIMUM LIKELIHOOD ESTIMATES ARE THE SOLUTION
!           TO THE FOLLOWING SYSTEM OF EQUATIONS:
!
!                 N*PSI(ALPHA+BETA) - N*PSI(ALPHA) +
!                 SUM[i=1 to N][LOG(NORCDF((X(i)-MU)/SIGMA))] = 0
!
!                 N*PSI(ALPHA+BETA) - N*PSI(BETA) +
!                 SUM[i=1 to N][LOG(1-NORCDF((X(i)-MU)/SIGMA))] = 0
!
!                 SUM[i=1 to n][{
!                 (1-ALPHA)*NORPDF((X(i)-MU)/SIGMA)/
!                 NORCDF((X(i)-MU)/SIGMA) +
!                 (BETA-1)*NORPDF((X(i)-MU)/SIGMA)/
!                 (1 - NORCDF((X(i)-MU)/SIGMA)) +
!                 (X(i)-MU)/SIGMA**2)} = 0
!
!                 SUM[i=1 to n][{
!                 (1-ALPHA)*NORPDF((X(i)-MU)/SIGMA)*(X(i)-MU)/SIGMA)/
!                 NORCDF((X(i)-MU)/SIGMA) +
!                 (BETA-1)*NORPDF((X(i)-MU)/SIGMA)*(X(i)-MU)/SIGMA)/
!                 (1 - NORCDF((X(i)-MU)/SIGMA)) +
!                 (X(i)-MU)**2/SIGMA**3)} - (N/SIGMA)= 0
!
!           NOTE THAT EUGENE AND HIS CO-AUTHORS SUGGEST TWO
!           DIFFERENT STARTING VALUES DEPENDING ON WHETHER
!           THE DISTRIBUTION IS UNIMODAL OR BIMODAL.  THIS CAN
!           BE DETERMINED BY EVALUATING THE LIKELIHOOD EQUATION
!           AT THESE TWO POINTS.
!     REFERENCE--EUGENE, LEE, AND FAMOYE (2002), "BETA-NORMAL
!                DISTRIBUTION AND ITS APPLICATIONS", COMMUNICATIONS
!                IN STATISTICS--THEORY AND METHODS, 31(4),
!                PP. 497-512.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLAD)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(4)
      DOUBLE PRECISION FVEC(4)
!CCCC DOUBLE PRECISION DAE
!CCCC DOUBLE PRECISION DRE
!CCCC DOUBLE PRECISION DXSTRT
!CCCC DOUBLE PRECISION DXLOW
!CCCC DOUBLE PRECISION DXUP
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION DTERM3
!CCCC DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DLIKE1
      DOUBLE PRECISION DLIKE2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
      EXTERNAL BNOFUN
!
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BNOM'
      ISUBN2='L1  '
!
      IERROR='NO'
      IWRITE='OFF'
!
      AMUML=CPUMIN
      SIGMML=CPUMIN
      ALPHML=CPUMIN
      BETAML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'OML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF BNOML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)AMUSV,SIGMSV,ALPHSV,BETASV
   54   FORMAT('AMUSV,SIGMSV,ALPHSV,BETASV =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ***************************************
!               **  STEP 2--                         **
!               **  CARRY OUT CALCULATIONS           **
!               **  FOR BETA-NORMAL MLE ESTIMATE     **
!               ***************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'OML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='BETA-NORMAL'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CALL SORT(Y,N,Y)
!
!     DETERMINE WHETHER TO USE STARTING VALUES FOR
!     UNIMODAl OR BI-MODAL CASE BY EVALUATING LIKELIHOOD
!     FUNCTION.
!
!     UNIMODAL STARTING VALUE: (1,1,MU,SIGMA)
!
      DN=DBLE(N)
      DA=1.0D0
      DB=1.0D0
      DMU=DBLE(XMEAN)
      DSIGMA=DBLE(XSD)
      DTERM1=DN*DLNGAM(DA+DB) - DN*DLNGAM(DA) - DN*DLNGAM(DB) -   &
             (DN/2.0D0)*DLOG(2.0*DPI) - DN*DLOG(DSIGMA)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DEPS=1.0D-20
      DO 1010 I=1,N
        DX=DBLE(Y(I))
        DZ=(DX - DMU)/DSIGMA
        CALL NODCDF(DX,DTERM2)
        IF(DTERM2.LE.0.0D0)DTERM2=DEPS
        DSUM1=DSUM1 + (DA-1.0D0)*DLOG(DTERM2)
        CALL NODCDF(DX,DTERM2)
        DTERM2=1.0D0 - DTERM2
        IF(DTERM2.LE.0.0D0)DTERM2=DEPS
        DSUM2=DSUM2 + (DB-1.0D0)*DLOG(DTERM2)
        DSUM3=DSUM3 + (DX-DMU)**2/(2.0D0*DSIGMA)
 1010 CONTINUE
       DLIKE1=DTERM1 + (DSUM1 + DSUM2 - DSUM3)
!
!     BI-MODAL STARTING VALUE: (0.1,0.1,MU,SIGMA)
!
      DA=0.1D0
      DB=0.1D0
      DTERM1=DN*DLNGAM(DA+DB) - DN*DLNGAM(DA) - DN*DLNGAM(DB) -   &
             (DN/2.0D0)*DLOG(2.0*DPI) - DN*DLOG(DSIGMA)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DEPS=1.0D-20
      DO 1020 I=1,N
        DX=DBLE(Y(I))
        DZ=(DX - DMU)/DSIGMA
        CALL NODCDF(DX,DTERM2)
        IF(DTERM2.LE.0.0D0)DTERM2=DEPS
        DSUM1=DSUM1 + (DA-1.0D0)*DLOG(DTERM2)
        CALL NODCDF(DX,DTERM2)
        DTERM2=1.0D0 - DTERM2
        IF(DTERM2.LE.0.0D0)DTERM2=DEPS
        DSUM2=DSUM2 + (DB-1.0D0)*DLOG(DTERM2)
        DSUM3=DSUM3 + (DX-DMU)**2/(2.0D0*DSIGMA)
 1020 CONTINUE
       DLIKE2=DTERM1 + (DSUM1 + DSUM2 - DSUM3)
!
      IF(DLIKE1.GE.DLIKE2)THEN
        XPAR(1)=2.0D0
        XPAR(2)=2.0D0
      ELSE
        XPAR(1)=0.1D0
        XPAR(2)=0.1D0
      ENDIF
      XPAR(3)=DMU
      XPAR(4)=DSIGMA
!
      IF(ALPHSV.GT.0.0)XPAR(1)=DBLE(ALPHSV)
      IF(BETASV.GT.0.0)XPAR(2)=DBLE(BETASV)
      IF(AMUSV.GT.CPUMIN)XPAR(3)=DBLE(AMUSV)
      IF(SIGMSV.GT.0.0)XPAR(4)=DBLE(SIGMSV)
!
      IOPT=2
      TOL=1.0D-6
      NVAR=4
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(BNOFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      ALPHML=REAL(XPAR(1))
      BETAML=REAL(XPAR(2))
      AMUML=REAL(XPAR(3))
      SIGMML=REAL(XPAR(4))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'OML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF BNOML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)AMUML,SIGMML,ALPHML,BETAML
 9019   FORMAT('AMUML,SIGMML,ALPHML,BETAML =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9021)IERROR
 9021   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE BNOML1
      SUBROUTINE BNOPDF(DX,DALPHA,DBETA,DPDF)
!
!     PURPOSE   --COMPUTE THE BETA-NORMAL PDF FUNCTION
!                 THIS PDF FUNCTION IS DEFINED AS:
!                    f(X;A,B) = (1/BETA(A,B)*NORCDF(X)**(A-1)*
!                               (1-NORCDF(X))**(B-1)*NORPDF(X)
!                               A, B > 0
!                 WITH A, B, AND BETA DENOTING THE SHAPE PARAMETERS
!                 ALPHA AND BETA AND THE BETA FUNCTION, RESPECTIVELY.
!     REFERENCE --"HANDBOOK OF BETA DISTRIBUTION AND ITS APPLICATIONS",
!                 EDITED BY ARJUN GUPTA AND SARALEES NADARAJAH,
!                 MARCEL DEKKER INC., 2004, PP. 146-152.
!               --"BETA-NORMAL DISTRIBUTION AND ITS APPLICATIONS",
!                 EUGENE, LEE, AND FAMOYE.  COMMUNICATIONS IN
!                 STATISTICS-THEORY AND METHODS, 2002, 31, PP. 497-512.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DNOCDF
      DOUBLE PRECISION DNOCD2
      DOUBLE PRECISION DNOPDF
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DLBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DEPS
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS/0.1D-12/
!
!-----START POINT-----------------------------------------------------
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
  101 FORMAT('***** ERROR--FOR BNOPDF, THE ALPHA SHAPE PARAMETER IS ',   &
             'NON-POSITIVE.')
  102 FORMAT('***** ERROR--FOR BNOPDF, THE BETA SHAPE PARAMETER IS ',   &
             'NON-POSITIVE.')
  103 FORMAT('***** THE VALUE IS ',G15.7)
!
      CALL NODPDF(DX,DNOPDF)
      CALL NODCDF(DX,DNOCDF)
      CALL NODCDF(-DX,DNOCD2)
!
!  NOTE: PDF EFFECTIVELY ZERO IMPLIES BNOPDF ALSO EFFECTIVELY ZERO.
!        ALSO NEED TO CHECK FOR CDF = 0 OR 1 (CDF=1 PRESENTS THE
!        MORE SERIOUS PROBLEM IN PRACTICE SINCE NODCDF SINCE THE
!        ROUNDING TO 1 OCCURS AT A MUCH SMALLER ABSOLUTE VALUE THAN
!        DOES ROUNDING TO 0).  SOLUTION IS TO COMPUTE THE LOG OF A
!        VERY SMALL VALUE (SET BY DPES) FOR THAT TERM.
!
      IF(DNOPDF.LE.0.0D0)THEN
        DPDF=0.0D0
      ELSEIF(DNOCDF.LE.0.0D0)THEN
        DTERM1=DLBETA(DALPHA,DBETA)
        DTERM2=(DALPHA-1.0D0)*DLOG(DEPS)
        DTERM3=0.0D0
        DPDF=DTERM2 + DTERM3 + DLOG(DNOPDF) - DTERM1
        IF(DPDF.LE.-500.0D0)THEN
          DPDF=0.0D0
        ELSE
          DPDF=DEXP(DPDF)
        ENDIF
      ELSEIF(DNOCDF.GE.1.0D0)THEN
        DTERM1=DLBETA(DALPHA,DBETA)
        DTERM2=(DALPHA-1.0D0)*DLOG(DNOCDF)
        DTERM3=(DBETA-1.0D0)*DLOG(DNOCD2)
        DPDF=DTERM2 + DTERM3 + DLOG(DNOPDF) - DTERM1
        IF(DPDF.LE.-500.0D0)THEN
          DPDF=0.0D0
        ELSE
          DPDF=DEXP(DPDF)
        ENDIF
      ELSE
        DTERM1=DLBETA(DALPHA,DBETA)
        DTERM2=(DALPHA-1.0D0)*DLOG(DNOCDF)
        DTERM3=(DBETA-1.0D0)*DLOG(DNOCD2)
        DPDF=DTERM2 + DTERM3 + DLOG(DNOPDF) - DTERM1
        IF(DPDF.LE.-500.0D0)THEN
          DPDF=0.0D0
        ELSE
          DPDF=DEXP(DPDF)
        ENDIF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BNOPDF
      SUBROUTINE BNOPPF(DP,DALPHA,DBETA,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BETA-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR REAL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE FIRST SHAPE PARAMETER
!                     --DBETA  = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE DPPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --"HANDBOOK OF BETA DISTRIBUTION AND ITS APPLICATIONS",
!                 EDITED BY ARJUN GUPTA AND SARALEES NADARAJAH,
!                 MARCEL DEKKER INC., 2004, PP. 146-152.
!               --"BETA-NORMAL DISTRIBUTION AND ITS APPLICATIONS",
!                 EUGENE, LEE, AND FAMOYE.  COMMUNICATIONS IN
!                 STATISTICS-THEORY AND METHODS, 2002, 31, PP. 497-512.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPPF
!
      DOUBLE PRECISION BNOFU2
      EXTERNAL BNOFU2
!
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DALPH2
      DOUBLE PRECISION DBETA2
      COMMON/BNOCOM/DP2,DALPH2,DBETA2
!
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XLOW2
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(DBETA.LE.0.0D0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DBETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, ALPHA, TO THE')
  102 FORMAT('      BNOPPF ROUTINE IS NON-POSITIVE.')
  103 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER, BETA, TO THE')
  104 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.7,' ******')
!
      IF(DP.LE.0.0D0.OR.DP.GE.1.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE BNOPPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)DP
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH (-5,5) AND
!          INCREMENT UNITL A BRACKETING INTERVAL IS FOUND.
!
      MAXIT=1000
      XLOW2=-5.0D0
      XUP2=5.0D0
  200 CONTINUE
        CALL BNOCDF(XLOW2,DALPHA,DBETA,PTEMPL)
        CALL BNOCDF(XUP2,DALPHA,DBETA,PTEMPU)
        IF(PTEMPL.LT.DP .AND. PTEMPU.GT.DP)THEN
          XUP=XUP2
          XLOW=XLOW2
          GO TO 300
        ELSEIF(PTEMPL.LT.DP .AND. PTEMPU.LT.DP)THEN
          MAXIT=MAXIT+1
          XUP2=2.0D0*XUP2
          IF(MAXIT.LE.MAXIT)GO TO 200
        ELSEIF(PTEMPL.GT.DP .AND. PTEMPU.GT.DP)THEN
          MAXIT=MAXIT+1
          XLOW2=2.0D0*XLOW2
          IF(MAXIT.LE.MAXIT)GO TO 200
        ENDIF
!
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR FROM BNOPPF--UNABLE TO FIND A ',   &
               'BRACKETING INTERVAL')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!
  300 CONTINUE
      AE=1.0D-8
      RE=1.0D-8
      DP2=DP
      DALPH2=DALPHA
      DBETA2=DBETA
      CALL DFZERO(BNOFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      DPPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,121)
!C111   FORMAT('***** WARNING FROM BNOPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM BNOPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM BNOPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BNOPPF
      SUBROUTINE BNORAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BETA-NORMAL DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL X AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!                    f(X;A,B) = (1/BETA(A,B)*NORCDF(X)**(A-1)*
!                               (1-NORCDF(X))**(B-1)*NORPDF(X)
!                               A, B > 0
!                 WITH A, B, AND BETA DENOTING THE SHAPE PARAMETERS
!                 ALPHA AND BETA AND THE BETA FUNCTION, RESPECTIVELY.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE FIRST SHAPE PARAMETER FOR THE
!                                BETA-NORMAL DISTRIBUTION
!                     --BETA   = THE SECOND SHAPE PARAMETER FOR THE
!                                BETA-NORMAL DISTRIBUTION
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE BETA-NORMAL
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, NBOPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --"HANDBOOK OF BETA DISTRIBUTION AND ITS APPLICATIONS",
!                 EDITED BY ARJUN GUPTA AND SARALEES NADARAJAH,
!                 MARCEL DEKKER INC., 2004, PP. 146-152.
!               --"BETA-NORMAL DISTRIBUTION AND ITS APPLICATIONS",
!                 EUGENE, LEE, AND FAMOYE.  COMMUNICATIONS IN
!                 STATISTICS-THEORY AND METHODS, 2002, 31, PP. 497-512.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
    5 FORMAT('***** ERROR--FOR THE BETA-NORMAL DISTRIBUTION, ',   &
             'THE REQUESTED')
    6 FORMAT('      NUMBER OF RANDOM NUMBERS WAS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,17)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
    7 FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (ALPHA)',   &
             ' FOR BETA-NORMAL')
   17 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,18)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)BETA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: VALUE OF SECOND SHAPE PARAMETER (BETA)',   &
             ' FOR BETA-NORMAL')
   18 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!     COMPUTE THE BETA-NORMAL RANDOM NUMBERS USING THE
!     PERCENT POINT TRANSFORMATION OF UNIFORM RANDOM NUMBERS.
!
      CALL UNIRAN(N,ISEED,X)
      NTEMP=1
      DO 100 I=1,N
        ATEMP=X(I)
        CALL BNOPPF(DBLE(ATEMP),DBLE(ALPHA),DBLE(BETA),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BNORAN
      SUBROUTINE BNSLV(W,NROWW,NROW,NBANDL,NBANDU,B)
!***BEGIN PROLOGUE  BNSLV
!***REFER TO  BINT4,BINTK
!
!  BNSLV is the BANSLV routine from
!        * A Practical Guide to Splines *  by C. de Boor
!
!  Companion routine to  BNFAC . It returns the solution  X  of the
!  linear system  A*X = B  in place of  B , given the LU-factorization
!  for  A  in the work array  W from BNFAC.
!
! *****  I N P U T  ******
!  W, NROWW,NROW,NBANDL,NBANDU.....describe the LU-factorization of a
!        banded matrix  A  of order  NROW  as constructed in  BNFAC .
!        For details, see  BNFAC .
!  B.....Right side of the system to be solved .
!
! *****  O U T P U T  ******
!  B.....Contains the solution  X , of order  NROW .
!
! *****  M E T H O D  ******
!     (With  A = L*U, as stored in  W,) the unit lower triangular system
!  L(U*X) = B  is solved for  Y = U*X, and  Y  stored in  B . Then the
!  upper triangular system  U*X = Y  is solved for  X  . The calcul-
!  ations are so arranged that the innermost loops stay within columns.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  BNSLV
!
      INTEGER NBANDL, NBANDU, NROW, NROWW, I, J, JMAX, MIDDLE, NROWM1
      REAL W(NROWW,NROW), B(NROW)
!***FIRST EXECUTABLE STATEMENT  BNSLV
      MIDDLE = NBANDU + 1
      IF (NROW.EQ.1) GO TO 80
      NROWM1 = NROW - 1
      IF (NBANDL.EQ.0) GO TO 30
!                                 FORWARD PASS
!            FOR I=1,2,...,NROW-1, SUBTRACT  RIGHT SIDE(I)*(I-TH COLUMN
!            OF  L )  FROM RIGHT SIDE  (BELOW I-TH ROW) .
      DO 20 I=1,NROWM1
        JMAX = MIN0(NBANDL,NROW-I)
        DO 10 J=1,JMAX
          B(I+J) = B(I+J) - B(I)*W(MIDDLE+J,I)
   10   CONTINUE
   20 CONTINUE
!                                 BACKWARD PASS
!            FOR I=NROW,NROW-1,...,1, DIVIDE RIGHT SIDE(I) BY I-TH DIAG-
!            ONAL ENTRY OF  U, THEN SUBTRACT  RIGHT SIDE(I)*(I-TH COLUMN
!            OF  U)  FROM RIGHT SIDE  (ABOVE I-TH ROW).
   30 IF (NBANDU.GT.0) GO TO 50
!                                A  IS LOWER TRIANGULAR .
      DO 40 I=1,NROW
        B(I) = B(I)/W(1,I)
   40 CONTINUE
      RETURN
   50 I = NROW
   60 B(I) = B(I)/W(MIDDLE,I)
      JMAX = MIN0(NBANDU,I-1)
      DO 70 J=1,JMAX
        B(I-J) = B(I-J) - B(I)*W(MIDDLE-J,I)
   70 CONTINUE
      I = I - 1
      IF (I.GT.1) GO TO 60
   80 B(1) = B(1)/W(MIDDLE,1)
      RETURN
      END SUBROUTINE BNSLV
      SUBROUTINE BOOTSS(Y1,Y2,N1,IWRITE,   &
                        Y3,N3,   &
                        TEMPY1,TEMPY2,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CONSTRUCT A BOOTSTRAP SAMPLE
!              OF THE DATA IN Y1(.) BASED ON THE INDICES IN Y2(.).
!
!     INPUT  ARGUMENTS--Y1     = ORIGINAL SAMPLE
!                     --Y2     = BOOTSTRAP INDEX
!     OUTPUT ARGUMENTS--Y3     = BOOTSTRAP SAMPLE
!
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y3(.)
!           BEING IDENTICAL TO EITHER OF THE INPUT VECTORS Y1(.) OR Y2(.)
!      NOTE--IF AN ELEMENT OF THE INPUT INDEX (Y2) IS SMALLER THAN 1
!            OR LARGER THAN N1, THEN THIS WILL BE INTERPRETED AS
!            A NON-OPERATION--THIS WILL ALLOW ONE TO FORM JACKNIFE
!            SAMPLES BY SIMPLY SETTING SOME INDEX ELEMENT TO, SAY, 0.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY  1987.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --JUNE      2019. PASS SCRATCH ARRAYS FROM CALLING
!                                       ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION TEMPY1(*)
      DIMENSION TEMPY2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='BOOT'
      ISUBN2='SS  '
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'OTSS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF BOOTSS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IWRITE,N1
   52   FORMAT('IBUGA3,ISUBRO,IWRITE,N1 = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *************************************
!               **  CONSTRUCT A  BOOTSTRAP SAMPLE  **
!               *************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
 1151   FORMAT('***** ERROR IN BOOTSTRAP SAMPLE (BOOTSS)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1153)
 1153   FORMAT('      VARIABLE IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1157)N1
 1157   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DO 1200 I=1,N1
        TEMPY1(I)=Y1(I)
        TEMPY2(I)=Y2(I)
 1200 CONTINUE
!
      J=0
      DO 1300 I=1,N1
        INDEX=INT(TEMPY2(I)+0.1)
        IF(INDEX.LT.1.OR.INDEX.GT.N1)GO TO 1300
        J=J+1
        Y3(J)=TEMPY1(INDEX)
 1300 CONTINUE
      N3=J
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'OTSS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF BOOTSS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N3
 9013   FORMAT('IERROR,N3 = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        IF(N1.GE.1)THEN
          DO 9021 I=1,N1
            WRITE(ICOUT,9022)I,Y1(I),Y2(I)
 9022       FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
        ENDIF
        IF(N3.GT.0)THEN
          DO 9031 I=1,N3
            WRITE(ICOUT,9032)I,Y3(I)
 9032       FORMAT('I,Y3(I) = ',I8,E13.5)
            CALL DPWRST('XXX','BUG ')
 9031     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE BOOTSS
      SUBROUTINE BPADJU(IND1,IND2,L,NRANK,NCIRQ,KOUNT,   &
                        ALPHA,ANGLE,K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
!CCCC RENAME TO HAVE 6-CHARACTER NAME
!CCCC SUBROUTINE BP_ADJUST(IND1,IND2,L,NRANK,NCIRQ,KOUNT,
!CCCC+           ALPHA,ANGLE,K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
!
!  Updates NCIRQ and NRANK, detects the special k-dividers and stores
!  their angles and the constant terms of their equations.
!
      INTEGER NCIRQ(N),NRANK(N),IND1(M),IND2(M)
      INTEGER KAND1(MAXNUM),KAND2(MAXNUM)
      INTEGER KOUNT,K,L,N,IV,IV1,IV2,D1,D2
      double precision X(N),Y(N),ANGLE(M),D(M)
      double precision ALPHA(MAXNUM),DUM,PI,PI2
      PI=DACOS(DBLE(-1.0))
      PI2=PI/2.0
      D1=IND1(L)
      IV1=NRANK(D1)
      D2=IND2(L)
      IV2=NRANK(D2)
      IV=NCIRQ(IV1)
      NCIRQ(IV1)=NCIRQ(IV2)
      NCIRQ(IV2)=IV
      IV=IV1
      NRANK(D1)=IV2
      NRANK(D2)=IV
       IF (((IV1.EQ.K).AND.(IV2.EQ.(K+1)))   &
            .OR.((IV2.EQ.K).AND.(IV1.EQ.(K+1)))   &
            .OR.((IV1.EQ.(N-K)).AND.(IV2.EQ.(N-K+1)))   &
            .OR.((IV2.EQ.(N-K)).AND.(IV1.EQ.(N-K+1)))) THEN
          IF (ANGLE(L).LT.PI2) THEN
             DUM=ANGLE(L)+PI2
            ELSE
             DUM=ANGLE(L)-PI2
            ENDIF
            IF (((IV1.EQ.K).AND.(IV2.EQ.(K+1)))   &
               .OR.((IV2.EQ.K).AND.(IV1.EQ.(K+1)))) THEN
             IF (DUM.LE.PI2) THEN
              ALPHA(KOUNT)=ANGLE(L)+PI
               ELSE
              ALPHA(KOUNT)=ANGLE(L)
               ENDIF
            ENDIF
          IF (((IV1.EQ.(N-K)).AND.(IV2.EQ.(N-K+1)))   &
              .OR.((IV2.EQ.(N-K)).AND.(IV1.EQ.(N-K+1)))) THEN
             IF (DUM.LE.PI2) THEN
              ALPHA(KOUNT)=ANGLE(L)
               ELSE
              ALPHA(KOUNT)=ANGLE(L)+PI
               ENDIF
            ENDIF
          KAND1(KOUNT)=IND1(L)
          KAND2(KOUNT)=IND2(L)
          D(KOUNT)=DSIN(ALPHA(KOUNT))*X(IND1(L))   &
                      -DCOS(ALPHA(KOUNT))*Y(IND1(L))
            KOUNT=KOUNT+1
         ENDIF
      RETURN
      END SUBROUTINE BPADJU
      SUBROUTINE BPDEPT(U,V,N,X,Y,BETA,F,DPF,JLV,JRV,HDEP)
!CCCC RENAME TO 6-CHARACTER NAME
!CCCC SUBROUTINE BP_DEPTH(U,V,N,X,Y,BETA,F,DPF,JLV,JRV,HDEP)
!
!  Computes the halfspace depth of a point. This subroutine was described
!  in: Rousseeuw, P.J. and Ruts, I. (1996). Algorithm AS 307: Bivariate
!  location depth. Applied Statistics (JRSS-C) 45, 516-526.
!
      double precision U,V,BETA(N),X(N),Y(N),DPF(N)
      double precision P,P2,EPSI,D,XU,YU,ANG,ALPHK,BETAK
      INTEGER F(N),GI,HDEP
      integer JLV(N),JRV(N)
      NUMH=0
      HDEP=0
      IF (N.LT.1) RETURN
      P=DACOS(DBLE(-1.0))
      P2=P*2.0
      EPSI=0.000001
      NZ=0
!
!  Construct the array BETA.
!
                                                                                                                                  
      DO 10 I=1,N
          D=DSQRT((X(I)-U)*(X(I)-U)+(Y(I)-V)*(Y(I)-V))
          IF (D.LE.EPSI) THEN
              NZ=NZ+1
          ELSE
              XU=(X(I)-U)/D
              YU=(Y(I)-V)/D
              IF (DABS(XU).GT.DABS(YU)) THEN
                  IF (X(I).GE.U) THEN
                      BETA(I-NZ)=DASIN(YU)
                      IF(BETA(I-NZ).LT.0.0) THEN
                          BETA(I-NZ)=P2+BETA(I-NZ)
                      ENDIF
                  ELSE
                      BETA(I-NZ)=P-DASIN(YU)
                  ENDIF
              ELSE
                  IF (Y(I).GE.V) THEN
                      BETA(I-NZ)=DACOS(XU)
                  ELSE
                      BETA(I-NZ)=P2-DACOS(XU)
                  ENDIF
              ENDIF
              IF (BETA(I-NZ).GE.(P2-EPSI)) BETA(I-NZ)=0.0
          ENDIF
  10  CONTINUE
      NN=N-NZ
      IF (NN.LE.1) GO TO  60
!
!  Sort the array BETA.
!
      DO 15 I=1,NN
      DPF(I)=DBLE(F(I))
15    CONTINUE
      CALL BPSORT(BETA,F,F,DPF,NN,JLV,JRV)
!
!  Check whether Z=(U,V) lies outside the data cloud.
!
      ANG=BETA(1)-BETA(NN)+P2
      DO 20 I=2,NN
          ANG=DMAX1(ANG,(BETA(I)-BETA(I-1)))
  20  CONTINUE
      IF (ANG.GT.(P+EPSI)) GO TO  60
!
!  Make smallest BETA equal to zero,
!  and compute NU = number of BETA < PI.
!
      ANG=BETA(1)
      NU=0
      DO 30 I=1,NN
          BETA(I)=BETA(I)-ANG
          IF (BETA(I).LT.(P-EPSI)) NU=NU+1
  30  CONTINUE
      IF (NU.GE.NN) GO TO  60
!
!  Mergesort the BETA with their antipodal angles,
!  and at the same time update I, F(I), and NBAD.
!
      JA=1
      JB=1
      ALPHK=BETA(1)
      BETAK=BETA(NU+1)-P
      NN2=NN*2
      NBAD=0
      I=NU
      NF=NN
      DO 40 J=1,NN2
          IF ((ALPHK+EPSI).LT.BETAK) THEN
              NF=NF+1
              IF (JA.LT.NN) THEN
                  JA=JA+1
                  ALPHK=BETA(JA)
              ELSE
                  ALPHK=P2+1.0
              ENDIF
          ELSE
              I=I+1
              IF (I.EQ.(NN+1)) THEN
                  I=1
                  NF=NF-NN
              ENDIF
              F(I)=NF
              NBAD=NBAD+NBPK((NF-I),2)
              IF (JB.LT.NN) THEN
                  JB=JB+1
                  IF ((JB+NU).LE.NN) THEN
                      BETAK=BETA(JB+NU)-P
                  ELSE
                      BETAK=BETA(JB+NU-NN)+P
                  ENDIF
              ELSE
                  BETAK=P2+1.0
              ENDIF
          ENDIF
  40  CONTINUE
!
!  Computation of NUMH for halfspace depth.
!
      GI=0
      JA=1
      ANG=BETA(1)
      NUMH=MIN0(F(1),(NN-F(1)))
      DO 50 I=2,NN
          IF(BETA(I).LE.(ANG+EPSI)) THEN
              JA=JA+1
          ELSE
              GI=GI+JA
              JA=1
              ANG=BETA(I)
          ENDIF
          KI=F(I)-GI
          NUMH=MIN0(NUMH,MIN0(KI,(NN-KI)))
   50 CONTINUE
!
!  Adjust for the number NZ of data points equal to Z=(U,V).
!
   60 NUMH=NUMH+NZ
      HDEP=NUMH
      RETURN
      END SUBROUTINE BPDEPT
      SUBROUTINE BPISOD(N,M,X,Y,MAXN,MAXM,MAXNUM,NRANK,D,F,BETA,   &
        KAND1,KAND2,ALPHA,IND1,IND2,NCIRQ,MCIRQ,ANGLE,KORNR,L,   &
        JRV,JLV,DPF,NUM,K,EMPTY)
!CCCC RENAME TO 6-CHARACTER NAME
!CCCC SUBROUTINE BP_ISODEPTH(N,M,X,Y,MAXN,MAXM,MAXNUM,NRANK,D,F,BETA,
!CCCC+  KAND1,KAND2,ALPHA,IND1,IND2,NCIRQ,MCIRQ,ANGLE,KORNR,L,
!CCCC+  JRV,JLV,DPF,NUM,K,EMPTY)
!
!     Computes the depth contour of depth k. This subroutine was described
!     in: Ruts, I. and Rousseeuw, P.J. (1996). Computing depth contours of
!     bivariate point clouds. CSDA 23, 153-168.
!
      INTEGER NCIRQ(N),MCIRQ(N),NRANK(N),F(N)
      integer JLV(M),JRV(M)
      INTEGER IND1(M),IND2(M)
      INTEGER KAND1(MAXNUM),KAND2(MAXNUM),KORNR(MAXNUM,4)
      INTEGER KON,KONTROL,NDATA,NDK,HALT,halt2,jj,JFULL,EMPTY
      INTEGER IV,IW1,IW2,NEXT,JFLAG,KOUNT,NUM,tel
      INTEGER HDEP1,HDEP2,HDEP3,HDEP4,HDEP5,I,J,K,L,M,N
      double precision X(N),Y(N),BETA(N)
      double precision ANGLE(M),D(M),ALPHA(MAXNUM),DPF(N)
      double precision PI,PI2,EPS
      double precision XCORD,YCORD,ANG1,xcord1,ycord1,m1,m2
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
      IF(ISUBG4.EQ.'ON')THEN
        WRITE(ICOUT,11)MAXN,MAXM
   11   FORMAT('MAXN,MAXM = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      PI=DACOS(DBLE(-1.0))
      PI2=PI/2.0
      EPS=0.0000001
      empty=0
      YCORD1=0.0D0
      XCORD1=0.0D0
      J=0
!
!   (Re)initialize NCIRQ and NRANK.
!
      DO 45 I=1,N
       NCIRQ(I)=MCIRQ(I)
45    CONTINUE
      DO 50 I=1,N
       IV=NCIRQ(I)
       NRANK(IV)=I
 50   CONTINUE
!
!  Let the line rotate from zero to ANGLE(1).
!
      KOUNT=1
      HALT=0
      if (angle(1).gt.pi2) then
         l=1
       CALL BPADJU(IND1,IND2,L,NRANK,NCIRQ,KOUNT,ALPHA,ANGLE,   &
                              K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
         halt=1
      endif
      L=2
 60   KONTROL=0
      IF ((PI.LE.(ANGLE(L)+PI2)).AND.((ANGLE(L)-PI2).LT.ANGLE(1))) THEN
       CALL BPADJU(IND1,IND2,L,NRANK,NCIRQ,KOUNT,ALPHA,ANGLE,   &
                              K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
       KONTROL=1
      ENDIF
      L=L+1
      IF (KONTROL.EQ.1) HALT=1
      IF ((L.EQ.M+1).AND.(KONTROL.EQ.1)) THEN
       JFLAG=1
       GO TO  79
      ENDIF
      IF (((HALT.EQ.1).AND.(KONTROL.EQ.0)).OR.(L.EQ.M+1)) THEN
       GO TO  70
      ELSE
       GO TO  60
      ENDIF
 70   if (l.gt.1) then
         JFLAG=L-1
      else
         jflag=m
      endif
      J=0
!
!  In case the first switch didn't occur between zero and ANGLE(1),
!  look for it between the following angles.
!
      IF ((L.EQ.M+1).AND.(KONTROL.EQ.0)) THEN
       HALT=0
         halt2=0
 73      J=J+1
         if (j.eq.m+1) j=1
       L=J+1
         if (l.eq.m+1) l=1
 75      KONTROL=0
       IF ((ANGLE(L)+PI2).LT.PI) THEN
          ANG1=ANGLE(L)+PI2
         ELSE
          ANG1=ANGLE(L)-PI2
         ENDIF
         if (j.eq.m) then
            jj=1
            if (halt2.eq.0) angle(1)=angle(1)+pi
         else
            jj=j+1
         endif
       IF ((ANGLE(J).LE.ANG1).AND.(ANG1.LT.ANGLE(jj))) THEN
            if (angle(1).gt.pi) angle(1)=angle(1)-pi
          CALL BPADJU(IND1,IND2,L,NRANK,NCIRQ,KOUNT,ALPHA,ANGLE,   &
                             K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
          KONTROL=1
         ENDIF
         if (angle(1).gt.pi) angle(1)=angle(1)-pi
       IF (L.NE.M) THEN
          L=L+1
         ELSE
          L=1
         ENDIF
       IF (KONTROL.EQ.1) HALT=1
       IF ((HALT.EQ.1).AND.(KONTROL.EQ.0)) THEN
            if (halt2.eq.1) go to 101
            if (l.gt.1) then
               jflag=l-1
            else
               jflag=m
            endif
          GO TO  79
         ELSE
            IF (L.EQ.jj) THEN
               if (jj.eq.1) halt2=1
               GO TO  73
            ELSE
             GO TO  75
            ENDIF
         ENDIF
      ENDIF
!
!  The first switch has occurred. Now start looking for the next ones,
!  between the following angles.
!
79    DO 80 I=J+1,M-1
       L=JFLAG
 90      KONTROL=0
       IF ((ANGLE(L)+PI2).LT.PI) THEN
          ANG1=ANGLE(L)+PI2
         ELSE
          ANG1=ANGLE(L)-PI2
         ENDIF
       IF ((ANGLE(I).LE.ANG1).AND.(ANG1.LT.ANGLE(I+1))) THEN
          CALL BPADJU(IND1,IND2,L,NRANK,NCIRQ,KOUNT,ALPHA,   &
                        ANGLE,K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
          KONTROL=1
         ENDIF
       IF (KONTROL.EQ.0) THEN
          JFLAG=L
         ELSE
          IF (L.NE.M) THEN
             L=L+1
            ELSE
             L=1
            ENDIF
          GO TO  90
         ENDIF
 80   CONTINUE
      L=JFLAG
!
!  Finally, look for necessary switches between the last angle and zero.
!
100   KONTROL=0
      IF ((ANGLE(L)+PI2).LT.PI) THEN
       ANG1=ANGLE(L)+PI2
      ELSE
       ANG1=ANGLE(L)-PI2
      ENDIF
      IF ((ANGLE(M).LE.ANG1).AND.(ANG1.LT.PI)) THEN
       CALL BPADJU(IND1,IND2,L,NRANK,NCIRQ,KOUNT,ALPHA,   &
                     ANGLE,K,N,M,MAXNUM,KAND1,KAND2,D,X,Y)
       KONTROL=1
      ENDIF
      IF (KONTROL.EQ.1) THEN
         IF (L.NE.M) THEN
           L=L+1
         ELSE
           L=1
         ENDIF
         GO TO  100
      ENDIF
101      NUM=KOUNT-1
!
!  Sort the NUM special k-dividers.
!  Permute KAND1, KAND2 and D in the same way.
!
      CALL BPSORT(ALPHA,KAND1,KAND2,D,NUM,JLV,JRV)
      IW1=1
      IW2=2
      JFULL=0
      NDK=0
      tel=0
                                                                                                                                  
120   NDATA=0
!
!  Compute the intersection point.
!
      IF (DABS(-DSIN(ALPHA(IW2))*DCOS(ALPHA(IW1))   &
               +DSIN(ALPHA(IW1))*DCOS(ALPHA(IW2))).LT.EPS) THEN
       IW2=IW2+1
       IF (IW2.EQ.NUM+1) IW2=1
       GO TO  120
      ENDIF
      XCORD=(DCOS(ALPHA(IW2))*D(IW1)-DCOS(ALPHA(IW1))*D(IW2))   &
       /(-DSIN(ALPHA(IW2))*DCOS(ALPHA(IW1))   &
                         +DSIN(ALPHA(IW1))*DCOS(ALPHA(IW2)))
      YCORD=(-DSIN(ALPHA(IW2))*D(IW1)+DSIN(ALPHA(IW1))*D(IW2))   &
       /(-DSIN(ALPHA(IW1))*DCOS(ALPHA(IW2))   &
                         +DSIN(ALPHA(IW2))*DCOS(ALPHA(IW1)))
!
!  Test whether the intersection point is a data point.
!  If so, adjust IW1 and IW2.
!
      IF ((KAND1(IW1).EQ.KAND1(IW2)).OR.(KAND1(IW1).EQ.KAND2(IW2)))   &
           NDATA=KAND1(IW1)
      IF ((KAND2(IW1).EQ.KAND1(IW2)).OR.(KAND2(IW1).EQ.KAND2(IW2)))   &
           NDATA=KAND2(IW1)
      IF (NDATA.NE.0) THEN
         iv=0
 125     NEXT=IW2+1
         iv=iv+1
         IF (NEXT.EQ.(NUM+1)) NEXT=1
         if (next.ne.iw1) then
            IF ((NDATA.EQ.KAND1(NEXT)).OR.(NDATA.EQ.KAND2(NEXT))) THEN
               IW2=IW2+1
               IF (IW2.EQ.(NUM+1)) IW2=1
               GO TO  125
            ENDIF
         endif
         if (iv.eq.(num-1)) then
            num=1
            KORNR(1,1)=KAND1(IW1)
            KORNR(1,2)=KAND2(IW1)
            KORNR(1,3)=KAND1(IW2)
            KORNR(1,4)=KAND2(IW2)
            return
         endif
      ENDIF
      IF (IW2.EQ.NUM) THEN
         KON=1
      ELSE
         KON=IW2+1
      ENDIF
      if (kon.eq.iw1) kon=kon+1
      if (kon.eq.num+1) kon=1
!
!  Test whether the intersection point lies to the left of the special
!  k-divider which corresponds to ALPHA(KON). If so, compute its depth.
!
      IF ((DSIN(ALPHA(KON))*XCORD-DCOS(ALPHA(KON))*YCORD   &
           -D(KON)).le.eps) THEN
                                                                                                                                  
         CALL BPDEPT(XCORD,YCORD,N,X,Y,BETA,F,DPF,JLV,JRV,HDEP1)
                                                                                                                                  
         IF (HDEP1.EQ.K) NDK=1
         IF (HDEP1.NE.K) THEN
         CALL BPDEPT(XCORD-EPS*10,YCORD-EPS*10,N,X,Y,BETA,F,DPF,   &
                 JLV,JRV,HDEP2)
         CALL BPDEPT(XCORD+EPS*10,YCORD+EPS*10,N,X,Y,BETA,F,DPF,   &
              JLV,JRV,HDEP3)
         CALL BPDEPT(XCORD-EPS*10,YCORD+EPS*10,N,X,Y,BETA,F,DPF,   &
              JLV,JRV,HDEP4)
         CALL BPDEPT(XCORD+EPS*10,YCORD-EPS*10,N,X,Y,BETA,F,DPF,   &
              JLV,JRV,HDEP5)
         IF ((NDK.EQ.0).AND.   &
              ((HDEP1.ge.K).OR.(HDEP2.ge.K).OR.(HDEP3.ge.K)   &
              .OR.(HDEP4.ge.K).OR.(HDEP5.ge.K))) THEN
            NDK=1
         ENDIF
         IF ((HDEP1.LT.K).AND.(HDEP2.LT.K)   &
              .AND.(HDEP3.LT.K).AND.(HDEP4.LT.K)   &
              .AND.(HDEP5.LT.K).AND.(NDK.EQ.1)) THEN
!
!  The intersection point is not the correct one,
!  try the next special k-divider.
!
            IW2=IW2+1
            IF (IW2.EQ.(NUM+1)) IW2=1
            GO TO  120
         ENDIF
      ENDIF
!
!  Store IW1 and IW2 in KORNR. If KORNR has already been filled, check whether
!  we have encountered this intersection point before.
!
      IF ((IW2.GT.IW1).AND.(JFULL.EQ.0)) THEN
         DO 130 I=IW1,IW2-1
            KORNR(I,1)=KAND1(IW1)
            KORNR(I,2)=KAND2(IW1)
            KORNR(I,3)=KAND1(IW2)
            KORNR(I,4)=KAND2(IW2)
 130     CONTINUE
      ELSE
         IF (IW2.GT.IW1) THEN
            DO 140 I=IW1,IW2-1
               IF ((KORNR(I,1).EQ.KAND1(IW1)).AND.   &
                    (KORNR(I,2).EQ.KAND2(IW1)).AND.   &
                    (KORNR(I,3).EQ.KAND1(IW2)).AND.   &
                    (KORNR(I,4).EQ.KAND2(IW2)))   &
                    THEN
              GO TO  170
               ELSE
                  tel=tel+1
                  if (tel.gt.num*num) then
                     ndk=1
                     go to 170
                  endif
                  m1=(y(kornr(i,2))-y(kornr(i,1)))/   &
                       (x(kornr(i,2))-x(kornr(i,1)))
                  m2=(y(kornr(i,4))-y(kornr(i,3)))/   &
                       (x(kornr(i,4))-x(kornr(i,3)))
                  if (m1.ne.m2) then
                     xcord1=(m1*x(kornr(i,1))-y(kornr(i,1))-   &
                          m2*x(kornr(i,3))-y(kornr(i,3)))/(m1-m2)
                     ycord1=(m2*(m1*x(kornr(i,1))-y(kornr(i,1)))-   &
                          m1*(m2*x(kornr(i,3))-y(kornr(i,3))))/(m1-m2)
                  endif
                  if ((dabs(xcord1-xcord).le.eps).and.   &
                       (dabs(ycord1-ycord).le.eps)) then
                     go to 170
                  endif
                                                                                                                                  
              KORNR(I,1)=KAND1(IW1)
              KORNR(I,2)=KAND2(IW1)
              KORNR(I,3)=KAND1(IW2)
              KORNR(I,4)=KAND2(IW2)
               ENDIF
 140        CONTINUE
         ELSE
            JFULL=1
            DO 150 I=IW1,NUM
               KORNR(I,1)=KAND1(IW1)
               KORNR(I,2)=KAND2(IW1)
               KORNR(I,3)=KAND1(IW2)
               KORNR(I,4)=KAND2(IW2)
 150        CONTINUE
            DO 160 I=1,IW2-1
               IF ((KORNR(I,1).EQ.KAND1(IW1)).AND.   &
                    (KORNR(I,2).EQ.KAND2(IW1)).AND.   &
                    (KORNR(I,3).EQ.KAND1(IW2)).AND.   &
                    (KORNR(I,4).EQ.KAND2(IW2)))   &
                    THEN
              GO TO  170
               ELSE
                  tel=tel+1
                  if (tel.gt.num*num) then
                     ndk=1
                     go to 170
                  endif
                  m1=(y(kornr(i,2))-y(kornr(i,1)))/   &
                       (x(kornr(i,2))-x(kornr(i,1)))
                  m2=(y(kornr(i,4))-y(kornr(i,3)))/   &
                       (x(kornr(i,4))-x(kornr(i,3)))
                  if (m1.ne.m2) then
                     xcord1=(m1*x(kornr(i,1))-y(kornr(i,1))-   &
                          m2*x(kornr(i,3))-y(kornr(i,3)))/(m1-m2)
                     ycord1=(m2*(m1*x(kornr(i,1))-y(kornr(i,1)))-   &
                          m1*(m2*x(kornr(i,3))-y(kornr(i,3))))/(m1-m2)
                  endif
                  if ((dabs(xcord1-xcord).le.eps).and.   &
                       (dabs(ycord1-ycord).le.eps)) then
                     go to 170
                  endif
                                                                                                                                  
              KORNR(I,1)=KAND1(IW1)
              KORNR(I,2)=KAND2(IW1)
              KORNR(I,3)=KAND1(IW2)
              KORNR(I,4)=KAND2(IW2)
               ENDIF
 160        CONTINUE
         ENDIF
      ENDIF
      ELSE
!
!  The intersection point is not the correct one,
!  try the next special k-divider.
!
       IW2=IW2+1
       IF (IW2.EQ.(NUM+1)) IW2=1
       GO TO  120
      ENDIF
!
!  Look for the next vertex of the convex figure.
!
      IW1=IW2
      IW2=IW2+1
      IF (IW2.EQ.(NUM+1)) IW2=1
      GO TO  120
170   if (ndk.eq.0) empty=1
      RETURN
      END SUBROUTINE BPISOD
      subroutine bprdra(a,ntot,seed,n)
!CCCC RENAME TO 6-CHARACTER NAME
!CCCC subroutine bp_rdraw(a,ntot,seed,n)
!
!     Draws n elements out of a dataset of size ntot, such that
!     the selected case numbers are uniformly distributed from 1 to ntot.
!
      integer a(n)
      integer seed,nrand
        real xjunk(1)
        double precision urand
      jndex=0
      do 20 m=1,n
!CCCC     call bp_uniran(1,seed,urand)
          call uniran(1,seed,xjunk)
          urand=dble(xjunk(1))
        nrand=int(urand*(ntot-jndex))+1
        jndex=jndex+1
        if(jndex.eq.1) then
          a(jndex)=nrand
        else
          a(jndex)=nrand+jndex-1
          do 5 i=1,jndex-1
            if(a(i).gt.nrand+i-1) then
              do 6 j=jndex,i+1,-1
                a(j)=a(j-1)
 6              continue
              a(i)=nrand+i-1
              go to 20
            endif
 5          continue
        endif
 20     continue
      return
      end
      DOUBLE PRECISION FUNCTION bpser(a,b,x,eps)
!-----------------------------------------------------------------------
!     POWER SERIES EXPANSION FOR EVALUATING IX(A,B) WHEN B .LE. 1
!     OR B*X .LE. 0.7.  EPS IS THE TOLERANCE USED.
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,eps,x
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION a0,apb,b0,c,n,sum,t,tol,u,w,z
      INTEGER i,m
!     ..
!     .. External Functions ..
      DOUBLE PRECISION algdiv,betaln,gam1,gamln1
      EXTERNAL algdiv,betaln,gam1,gamln1
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dble,dlog,dmax1,dmin1,exp
!     ..
!     .. Executable Statements ..
!
      bpser = 0.0D0
      IF (x.EQ.0.0D0) RETURN
!-----------------------------------------------------------------------
!            COMPUTE THE FACTOR X**A/(A*BETA(A,B))
!-----------------------------------------------------------------------
      a0 = dmin1(a,b)
      IF (a0.LT.1.0D0) GO TO 10
      z = a*dlog(x) - betaln(a,b)
      bpser = exp(z)/a
      GO TO 100
                                                                                                                                  
   10 b0 = dmax1(a,b)
      IF (b0.GE.8.0D0) GO TO 90
      IF (b0.GT.1.0D0) GO TO 40
!
!            PROCEDURE FOR A0 .LT. 1 AND B0 .LE. 1
!
      bpser = x**a
      IF (bpser.EQ.0.0D0) RETURN
!
      apb = a + b
      IF (apb.GT.1.0D0) GO TO 20
      z = 1.0D0 + gam1(apb)
      GO TO 30
                                                                                                                                  
   20 u = dble(a) + dble(b) - 1.D0
      z = (1.0D0+gam1(u))/apb
!
   30 c = (1.0D0+gam1(a))* (1.0D0+gam1(b))/z
      bpser = bpser*c* (b/apb)
      GO TO 100
!
!         PROCEDURE FOR A0 .LT. 1 AND 1 .LT. B0 .LT. 8
!
   40 u = gamln1(a0)
      m = int(b0 - 1.0D0)
      IF (m.LT.1) GO TO 60
      c = 1.0D0
      DO 50 i = 1,m
          b0 = b0 - 1.0D0
          c = c* (b0/ (a0+b0))
   50 CONTINUE
      u = dlog(c) + u
!
   60 z = a*dlog(x) - u
      b0 = b0 - 1.0D0
      apb = a0 + b0
      IF (apb.GT.1.0D0) GO TO 70
      t = 1.0D0 + gam1(apb)
      GO TO 80
                                                                                                                                  
   70 u = dble(a0) + dble(b0) - 1.D0
      t = (1.0D0+gam1(u))/apb
   80 bpser = exp(z)* (a0/a)* (1.0D0+gam1(b0))/t
      GO TO 100
!
!            PROCEDURE FOR A0 .LT. 1 AND B0 .GE. 8
!
   90 u = gamln1(a0) + algdiv(a0,b0)
      z = a*dlog(x) - u
      bpser = (a0/a)*exp(z)
  100 IF (bpser.EQ.0.0D0 .OR. a.LE.0.1D0*eps) RETURN
!-----------------------------------------------------------------------
!                     COMPUTE THE SERIES
!-----------------------------------------------------------------------
      sum = 0.0D0
      n = 0.0D0
      c = 1.0D0
      tol = eps/a
  110 n = n + 1.0D0
      c = c* (0.5D0+ (0.5D0-b/n))*x
      w = c/ (a+n)
      sum = sum + w
      IF (abs(w).GT.tol) GO TO 110
      bpser = bpser* (1.0D0+a*sum)
      RETURN
                                                                                                                                  
      END FUNCTION bpser
      SUBROUTINE BPSORT(B,I1,I2,R,N,JLV,JRV)
!CCCC RENAME TO USE 6 CHARACTER NAME
!CCCC SUBROUTINE BP_SORT(B,I1,I2,R,N,JLV,JRV)
!
!  Sorts a double precision  array B of length N and permutes two
!  integer arrays I1 and I2 and one double precision array R in the
!  same way.
!
      INTEGER N,I1(*),I2(*),H1,H2
      double precision B(*),XX,AMM
      double precision R(*),H3
      integer JLV(*),JRV(*)
      JSS=1
      JLV(1)=1
      JRV(1)=N
 10   JNDL=JLV(JSS)
      JR=JRV(JSS)
      JSS=JSS-1
 20   JNC=JNDL
      J=JR
      JTWE=(JNDL+JR)/2
      XX=B(JTWE)
 30   IF (B(JNC).GE.XX) GO TO  40
      JNC=JNC+1
      GO TO  30
 40   IF (XX.GE.B(J)) GO TO  50
      J=J-1
      GO TO  40
 50   IF (JNC.GT.J) GO TO  60
      AMM=B(JNC)
      H1=I1(JNC)
      H2=I2(JNC)
      H3=R(JNC)
      B(JNC)=B(J)
      I1(JNC)=I1(J)
      I2(JNC)=I2(J)
      R(JNC)=R(J)
      B(J)=AMM
      I1(J)=H1
      I2(J)=H2
      R(J)=H3
      JNC=JNC+1
      J=J-1
 60   IF (JNC.LE.J) GO TO  30
      IF ((J-JNDL).LT.(JR-JNC)) GO TO  80
      IF (JNDL.GE.J) GO TO  70
      JSS=JSS+1
      JLV(JSS)=JNDL
      JRV(JSS)=J
 70   JNDL=JNC
      GO TO  100
 80   IF (JNC.GE.JR) GO TO  90
      JSS=JSS+1
      JLV(JSS)=JNC
      JRV(JSS)=JR
 90   JR=J
100   IF (JNDL.LT.JR) GO TO  20
      IF (JSS.NE.0) GO TO  10
      RETURN
      END SUBROUTINE BPSORT
      SUBROUTINE BRACDF(X,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BRADFORD
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = BETA.
!              THE BRADFORD DISTRIBUTION USED
!              HEREIN IS DEFINED FOR 0 < x < 1.
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = [BETA / LOG(1+BETA)]*(1/(1+BETA*X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.
!                     --BETA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                BETA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE CDF FOR THE BRADFORD
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--BETA SHOULD BE POSITIVE.
!                 --X SHOULD BE POSITIVE AND LESS THAN 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND. ED., 1994, PAGE 347.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DB
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0.OR.X.GE.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT ',   &
      'TO BRACDF IS OUTSIDE THE (0,1) INTERVAL')
      IF(BETA.LE.-1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO BRACDF IS LESS THAN OR EQUAL TO -1')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DB=DBLE(BETA)
      IF(DB.LE.0.0D0)THEN
        DCDF=DLOG(1.0D0+DB*DX)/DLOG(1.0D0+DB)
        CDF=SNGL(DCDF)
      ELSE
        DTERM1=DLOG(DLOG(1.0D0+DB*DX))-DLOG(DLOG(1.0D0+DB))
        IF(DTERM1.GE.-65.0D0)THEN
          DCDF=DEXP(DTERM1)
          CDF=SNGL(DCDF)
        ELSE
          CDF=0.0
        ENDIF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BRACDF
      SUBROUTINE BRAPDF(X,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BRADFORD
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = BETA.
!              THE BRADFORD DISTRIBUTION USED
!              HEREIN IS DEFINED FOR 0 < x < 1.
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = [BETA / LOG(1+BETA)]*(1/(1+BETA*X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE GREATER THAN
!                                OR EQUAL TO 1.
!                     --BETA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                BETA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BRADFORD
!             DISTRIBUTION WITH TAIL LENGTH PARAMETER VALUE = BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--BETA SHOULD BE POSITIVE.
!                 --X SHOULD BE POSITIVE AND LESS THAN 1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND. ED., 1994, PAGE 347.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DB
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0.OR.X.GE.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST  INPUT ARGUMENT ',   &
      'TO BRAPDF IS OUTSIDE THE (0,1) INTERVAL')
      IF(BETA.LE.-1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO BRAPDF IS LESS THAN OR EQUAL TO -1')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DB=DBLE(BETA)
      IF(DB.LE.0.0D0)THEN
        DPDF=DB/(DLOG(1.0D0+DB)*(1.0D0+DB*DX))
        PDF=SNGL(DPDF)
      ELSE
        DTERM1=DLOG(DB)-DLOG(DLOG(1.0D0+DB))-DLOG(1.0D0+DB*DX)
        IF(DTERM1.GE.-65.0D0)THEN
          DPDF=DEXP(DTERM1)
          PDF=SNGL(DPDF)
        ELSE
          PDF=0.0
        ENDIF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BRAPDF
      SUBROUTINE BRAPPF(P,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BRADFORD
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = BETA.
!              THE BRADFORD DISTRIBUTION USED
!              HEREIN IS DEFINED FOR 0 < x < 1.
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = [BETA / LOG(1+BETA)]*(1/(1+BETA*X))
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --BETA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                BETA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE BRADFORD DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--BETA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND. ED., 1994, PAGE 347.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--96.2
!     ORIGINAL VERSION--FEBRUARY  1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DB
      DOUBLE PRECISION DPPF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'BRAPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
      IF(BETA.LE.-1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO BRAPPF IS LESS THAN OR EQUAL TO -1')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DP=DBLE(P)
      DB=DBLE(BETA)
      DPPF=(DEXP(DLOG(1.0D0+DB)*DP)-1.0D0)/DB
      PPF=SNGL(DPPF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BRAPPF
      SUBROUTINE BRARAN(N,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BRADFORD DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = BETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --BETA  = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!                                BETA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BRADFORD DISTRIBUTION
!             WITH SHAPE PARAMETER VALUE = BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --BETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'BRARAN SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT TO THE ',   &
      'BRARAN SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N BRADFORD DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL BRAPPF(X(I),BETA,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BRARAN
      SUBROUTINE bratio(a,b,x,y,w,w1,ierr)
!-----------------------------------------------------------------------
!
!            EVALUATION OF THE INCOMPLETE BETA FUNCTION IX(A,B)
!
!                     --------------------
!
!     IT IS ASSUMED THAT A AND B ARE NONNEGATIVE, AND THAT X .LE. 1
!     AND Y = 1 - X.  BRATIO ASSIGNS W AND W1 THE VALUES
!
!                      W  = IX(A,B)
!                      W1 = 1 - IX(A,B)
!
!     IERR IS A VARIABLE THAT REPORTS THE STATUS OF THE RESULTS.
!     IF NO INPUT ERRORS ARE DETECTED THEN IERR IS SET TO 0 AND
!     W AND W1 ARE COMPUTED. OTHERWISE, IF AN ERROR IS DETECTED,
!     THEN W AND W1 ARE ASSIGNED THE VALUE 0 AND IERR IS SET TO
!     ONE OF THE FOLLOWING VALUES ...
!
!        IERR = 1  IF A OR B IS NEGATIVE
!        IERR = 2  IF A = B = 0
!        IERR = 3  IF X .LT. 0 OR X .GT. 1
!        IERR = 4  IF Y .LT. 0 OR Y .GT. 1
!        IERR = 5  IF X + Y .NE. 1
!        IERR = 6  IF X = A = 0
!        IERR = 7  IF Y = B = 0
!
!--------------------
!     WRITTEN BY ALFRED H. MORRIS, JR.
!        NAVAL SURFACE WARFARE CENTER
!        DAHLGREN, VIRGINIA
!     REVISED ... NOV 1991
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,w,w1,x,y
      INTEGER ierr
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION a0,b0,eps,lambda,t,x0,y0,z
      INTEGER ierr1,ind,n
!     ..
!     .. External Functions ..
      DOUBLE PRECISION apser,basym,bfrac,bpser,bup,fpser,spmpar
      EXTERNAL apser,basym,bfrac,bpser,bup,fpser,spmpar
!     ..
!     .. External Subroutines ..
      EXTERNAL bgrat
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dmax1,dmin1
!     ..
!     .. Executable Statements ..
!-----------------------------------------------------------------------
!
!     ****** EPS IS A MACHINE DEPENDENT CONSTANT. EPS IS THE SMALLEST
!            FLOATING POINT NUMBER FOR WHICH 1.0 + EPS .GT. 1.0
!
      eps = spmpar(1)
!
!-----------------------------------------------------------------------
      w = 0.0D0
      w1 = 0.0D0
      IF (a.LT.0.0D0 .OR. b.LT.0.0D0) GO TO 270
      IF (a.EQ.0.0D0 .AND. b.EQ.0.0D0) GO TO 280
      IF (x.LT.0.0D0 .OR. x.GT.1.0D0) GO TO 290
      IF (y.LT.0.0D0 .OR. y.GT.1.0D0) GO TO 300
      z = ((x+y)-0.5D0) - 0.5D0
      IF (abs(z).GT.3.0D0*eps) GO TO 310
!
      ierr = 0
      IF (x.EQ.0.0D0) GO TO 210
      IF (y.EQ.0.0D0) GO TO 230
      IF (a.EQ.0.0D0) GO TO 240
      IF (b.EQ.0.0D0) GO TO 220
!
      eps = dmax1(eps,1.D-15)
      IF (dmax1(a,b).LT.1.D-3*eps) GO TO 260
!
      ind = 0
      a0 = a
      b0 = b
      x0 = x
      y0 = y
      IF (dmin1(a0,b0).GT.1.0D0) GO TO 40
!
!             PROCEDURE FOR A0 .LE. 1 OR B0 .LE. 1
!
      IF (x.LE.0.5D0) GO TO 10
      ind = 1
      a0 = b
      b0 = a
      x0 = y
      y0 = x
!
   10 IF (b0.LT.dmin1(eps,eps*a0)) GO TO 90
      IF (a0.LT.dmin1(eps,eps*b0) .AND. b0*x0.LE.1.0D0) GO TO 100
      IF (dmax1(a0,b0).GT.1.0D0) GO TO 20
      IF (a0.GE.dmin1(0.2D0,b0)) GO TO 110
      IF (x0**a0.LE.0.9D0) GO TO 110
      IF (x0.GE.0.3D0) GO TO 120
      n = 20
      GO TO 140
!
   20 IF (b0.LE.1.0D0) GO TO 110
      IF (x0.GE.0.3D0) GO TO 120
      IF (x0.GE.0.1D0) GO TO 30
      IF ((x0*b0)**a0.LE.0.7D0) GO TO 110
   30 IF (b0.GT.15.0D0) GO TO 150
      n = 20
      GO TO 140
!
!             PROCEDURE FOR A0 .GT. 1 AND B0 .GT. 1
!
   40 IF (a.GT.b) GO TO 50
      lambda = a - (a+b)*x
      GO TO 60
                                                                                                                                  
   50 lambda = (a+b)*y - b
   60 IF (lambda.GE.0.0D0) GO TO 70
      ind = 1
      a0 = b
      b0 = a
      x0 = y
      y0 = x
      lambda = abs(lambda)
!
   70 IF (b0.LT.40.0D0 .AND. b0*x0.LE.0.7D0) GO TO 110
      IF (b0.LT.40.0D0) GO TO 160
      IF (a0.GT.b0) GO TO 80
      IF (a0.LE.100.0D0) GO TO 130
      IF (lambda.GT.0.03D0*a0) GO TO 130
      GO TO 200
                                                                                                                                  
   80 IF (b0.LE.100.0D0) GO TO 130
      IF (lambda.GT.0.03D0*b0) GO TO 130
      GO TO 200
!
!            EVALUATION OF THE APPROPRIATE ALGORITHM
!
   90 w = fpser(a0,b0,x0,eps)
      w1 = 0.5D0 + (0.5D0-w)
      GO TO 250
!
  100 w1 = apser(a0,b0,x0,eps)
      w = 0.5D0 + (0.5D0-w1)
      GO TO 250
!
  110 w = bpser(a0,b0,x0,eps)
      w1 = 0.5D0 + (0.5D0-w)
      GO TO 250
!
  120 w1 = bpser(b0,a0,y0,eps)
      w = 0.5D0 + (0.5D0-w1)
      GO TO 250
!
  130 w = bfrac(a0,b0,x0,y0,lambda,15.0D0*eps)
      w1 = 0.5D0 + (0.5D0-w)
      GO TO 250
!
  140 w1 = bup(b0,a0,y0,x0,n,eps)
      b0 = b0 + n
  150 CALL bgrat(b0,a0,y0,x0,w1,15.0D0*eps,ierr1)
      w = 0.5D0 + (0.5D0-w1)
      GO TO 250
!
  160 n = int(b0)
      b0 = b0 - real(n)
      IF (b0.NE.0.0D0) GO TO 170
      n = n - 1
      b0 = 1.0D0
  170 w = bup(b0,a0,y0,x0,n,eps)
      IF (x0.GT.0.7D0) GO TO 180
      w = w + bpser(a0,b0,x0,eps)
      w1 = 0.5D0 + (0.5D0-w)
      GO TO 250
!
  180 IF (a0.GT.15.0D0) GO TO 190
      n = 20
      w = w + bup(a0,b0,x0,y0,n,eps)
      a0 = a0 + n
  190 CALL bgrat(a0,b0,x0,y0,w,15.0D0*eps,ierr1)
      w1 = 0.5D0 + (0.5D0-w)
      GO TO 250
!
  200 w = basym(a0,b0,lambda,100.0D0*eps)
      w1 = 0.5D0 + (0.5D0-w)
      GO TO 250
!
!               TERMINATION OF THE PROCEDURE
!
  210 IF (a.EQ.0.0D0) GO TO 320
  220 w = 0.0D0
      w1 = 1.0D0
      RETURN
!
  230 IF (b.EQ.0.0D0) GO TO 330
  240 w = 1.0D0
      w1 = 0.0D0
      RETURN
!
  250 IF (ind.EQ.0) RETURN
      t = w
      w = w1
      w1 = t
      RETURN
!
!           PROCEDURE FOR A AND B .LT. 1.E-3*EPS
!
  260 w = b/ (a+b)
      w1 = a/ (a+b)
      RETURN
!
!                       ERROR RETURN
!
  270 ierr = 1
      RETURN
                                                                                                                                  
  280 ierr = 2
      RETURN
                                                                                                                                  
  290 ierr = 3
      RETURN
                                                                                                                                  
  300 ierr = 4
      RETURN
                                                                                                                                  
  310 ierr = 5
      RETURN
                                                                                                                                  
  320 ierr = 6
      RETURN
                                                                                                                                  
  330 ierr = 7
      RETURN
                                                                                                                                  
      END SUBROUTINE bratio
      DOUBLE PRECISION FUNCTION brcmp1(mu,a,b,x,y)
!-----------------------------------------------------------------------
!          EVALUATION OF  EXP(MU) * (X**A*Y**B/BETA(A,B))
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,x,y
      INTEGER mu
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION a0,apb,b0,c,const,e,h,lambda,lnx,lny,t,u,v,x0,y0,   &
                       z
      INTEGER i,n
!     ..
!     .. External Functions ..
      DOUBLE PRECISION algdiv,alnrel,bcorr,betaln,esum,gam1,gamln1,rlog1
      EXTERNAL algdiv,alnrel,bcorr,betaln,esum,gam1,gamln1,rlog1
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dble,dlog,dmax1,dmin1,exp,sqrt
!     ..
!     .. Data statements ..
!-----------------
!     CONST = 1/SQRT(2*PI)
!-----------------
      DATA const/.398942280401433D0/
!     ..
!     .. Executable Statements ..
!
      a0 = dmin1(a,b)
      IF (a0.GE.8.0D0) GO TO 130
!
      IF (x.GT.0.375D0) GO TO 10
      lnx = dlog(x)
      lny = alnrel(-x)
      GO TO 30
                                                                                                                                  
   10 IF (y.GT.0.375D0) GO TO 20
      lnx = alnrel(-y)
      lny = dlog(y)
      GO TO 30
                                                                                                                                  
   20 lnx = dlog(x)
      lny = dlog(y)
!
   30 z = a*lnx + b*lny
      IF (a0.LT.1.0D0) GO TO 40
      z = z - betaln(a,b)
      brcmp1 = esum(mu,z)
      RETURN
!-----------------------------------------------------------------------
!              PROCEDURE FOR A .LT. 1 OR B .LT. 1
!-----------------------------------------------------------------------
   40 b0 = dmax1(a,b)
      IF (b0.GE.8.0D0) GO TO 120
      IF (b0.GT.1.0D0) GO TO 70
!
!                   ALGORITHM FOR B0 .LE. 1
!
      brcmp1 = esum(mu,z)
      IF (brcmp1.EQ.0.0D0) RETURN
!
      apb = a + b
      IF (apb.GT.1.0D0) GO TO 50
      z = 1.0D0 + gam1(apb)
      GO TO 60
                                                                                                                                  
   50 u = dble(a) + dble(b) - 1.D0
      z = (1.0D0+gam1(u))/apb
!
   60 c = (1.0D0+gam1(a))* (1.0D0+gam1(b))/z
      brcmp1 = brcmp1* (a0*c)/ (1.0D0+a0/b0)
      RETURN
!
!                ALGORITHM FOR 1 .LT. B0 .LT. 8
!
   70 u = gamln1(a0)
      n = int(b0 - 1.0D0)
      IF (n.LT.1) GO TO 90
      c = 1.0D0
      DO 80 i = 1,n
          b0 = b0 - 1.0D0
          c = c* (b0/ (a0+b0))
   80 CONTINUE
      u = dlog(c) + u
!
   90 z = z - u
      b0 = b0 - 1.0D0
      apb = a0 + b0
      IF (apb.GT.1.0D0) GO TO 100
      t = 1.0D0 + gam1(apb)
      GO TO 110
                                                                                                                                  
  100 u = dble(a0) + dble(b0) - 1.D0
      t = (1.0D0+gam1(u))/apb
  110 brcmp1 = a0*esum(mu,z)* (1.0D0+gam1(b0))/t
      RETURN
!
!                   ALGORITHM FOR B0 .GE. 8
!
  120 u = gamln1(a0) + algdiv(a0,b0)
      brcmp1 = a0*esum(mu,z-u)
      RETURN
!-----------------------------------------------------------------------
!              PROCEDURE FOR A .GE. 8 AND B .GE. 8
!-----------------------------------------------------------------------
  130 IF (a.GT.b) GO TO 140
      h = a/b
      x0 = h/ (1.0D0+h)
      y0 = 1.0D0/ (1.0D0+h)
      lambda = a - (a+b)*x
      GO TO 150
                                                                                                                                  
  140 h = b/a
      x0 = 1.0D0/ (1.0D0+h)
      y0 = h/ (1.0D0+h)
      lambda = (a+b)*y - b
!
  150 e = -lambda/a
      IF (abs(e).GT.0.6D0) GO TO 160
      u = rlog1(e)
      GO TO 170
                                                                                                                                  
  160 u = e - dlog(x/x0)
!
  170 e = lambda/b
      IF (abs(e).GT.0.6D0) GO TO 180
      v = rlog1(e)
      GO TO 190
                                                                                                                                  
  180 v = e - dlog(y/y0)
!
  190 z = esum(mu,- (a*u+b*v))
      brcmp1 = const*sqrt(b*x0)*z*exp(-bcorr(a,b))
      RETURN
                                                                                                                                  
      END FUNCTION brcmp1
      DOUBLE PRECISION FUNCTION brcomp(a,b,x,y)
!-----------------------------------------------------------------------
!               EVALUATION OF X**A*Y**B/BETA(A,B)
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,x,y
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION a0,apb,b0,c,const,e,h,lambda,lnx,lny,t,u,v,x0,y0,   &
                       z
      INTEGER i,n
!     ..
!     .. External Functions ..
      DOUBLE PRECISION algdiv,alnrel,bcorr,betaln,gam1,gamln1,rlog1
      EXTERNAL algdiv,alnrel,bcorr,betaln,gam1,gamln1,rlog1
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,dble,dlog,dmax1,dmin1,exp,sqrt
!     ..
!     .. Data statements ..
!-----------------
!     CONST = 1/SQRT(2*PI)
!-----------------
      DATA const/.398942280401433D0/
!     ..
!     .. Executable Statements ..
!
      brcomp = 0.0D0
      IF (x.EQ.0.0D0 .OR. y.EQ.0.0D0) RETURN
      a0 = dmin1(a,b)
      IF (a0.GE.8.0D0) GO TO 130
!
      IF (x.GT.0.375D0) GO TO 10
      lnx = dlog(x)
      lny = alnrel(-x)
      GO TO 30
                                                                                                                                  
   10 IF (y.GT.0.375D0) GO TO 20
      lnx = alnrel(-y)
      lny = dlog(y)
      GO TO 30
                                                                                                                                  
   20 lnx = dlog(x)
      lny = dlog(y)
!
   30 z = a*lnx + b*lny
      IF (a0.LT.1.0D0) GO TO 40
      z = z - betaln(a,b)
      brcomp = exp(z)
      RETURN
!-----------------------------------------------------------------------
!              PROCEDURE FOR A .LT. 1 OR B .LT. 1
!-----------------------------------------------------------------------
   40 b0 = dmax1(a,b)
      IF (b0.GE.8.0D0) GO TO 120
      IF (b0.GT.1.0D0) GO TO 70
!
!                   ALGORITHM FOR B0 .LE. 1
!
      brcomp = exp(z)
      IF (brcomp.EQ.0.0D0) RETURN
!
      apb = a + b
      IF (apb.GT.1.0D0) GO TO 50
      z = 1.0D0 + gam1(apb)
      GO TO 60
                                                                                                                                  
   50 u = dble(a) + dble(b) - 1.D0
      z = (1.0D0+gam1(u))/apb
!
   60 c = (1.0D0+gam1(a))* (1.0D0+gam1(b))/z
      brcomp = brcomp* (a0*c)/ (1.0D0+a0/b0)
      RETURN
!
!                ALGORITHM FOR 1 .LT. B0 .LT. 8
!
   70 u = gamln1(a0)
      n = int(b0 - 1.0D0)
      IF (n.LT.1) GO TO 90
      c = 1.0D0
      DO 80 i = 1,n
          b0 = b0 - 1.0D0
          c = c* (b0/ (a0+b0))
   80 CONTINUE
      u = dlog(c) + u
!
   90 z = z - u
      b0 = b0 - 1.0D0
      apb = a0 + b0
      IF (apb.GT.1.0D0) GO TO 100
      t = 1.0D0 + gam1(apb)
      GO TO 110
                                                                                                                                  
  100 u = dble(a0) + dble(b0) - 1.D0
      t = (1.0D0+gam1(u))/apb
  110 brcomp = a0*exp(z)* (1.0D0+gam1(b0))/t
      RETURN
!
!                   ALGORITHM FOR B0 .GE. 8
!
  120 u = gamln1(a0) + algdiv(a0,b0)
      brcomp = a0*exp(z-u)
      RETURN
!-----------------------------------------------------------------------
!              PROCEDURE FOR A .GE. 8 AND B .GE. 8
!-----------------------------------------------------------------------
  130 IF (a.GT.b) GO TO 140
      h = a/b
      x0 = h/ (1.0D0+h)
      y0 = 1.0D0/ (1.0D0+h)
      lambda = a - (a+b)*x
      GO TO 150
                                                                                                                                  
  140 h = b/a
      x0 = 1.0D0/ (1.0D0+h)
      y0 = h/ (1.0D0+h)
      lambda = (a+b)*y - b
!
  150 e = -lambda/a
      IF (abs(e).GT.0.6D0) GO TO 160
      u = rlog1(e)
      GO TO 170
                                                                                                                                  
  160 u = e - dlog(x/x0)
!
  170 e = lambda/b
      IF (abs(e).GT.0.6D0) GO TO 180
      v = rlog1(e)
      GO TO 190
                                                                                                                                  
  180 v = e - dlog(y/y0)
!
  190 z = exp(- (a*u+b*v))
      brcomp = const*sqrt(b*x0)*z*exp(-bcorr(a,b))
      RETURN
                                                                                                                                  
      END FUNCTION brcomp
      SUBROUTINE BSINIT(NDIM, W, LENRUL, G)
!
!     For initializing basic rule weights and symmetric sum parameters.
!
      INTEGER NDIM, LENRUL, RULPTS(6), I, J, NUMNUL, SDIM
      PARAMETER ( NUMNUL = 4, SDIM = 12 )
      DOUBLE PRECISION W(LENRUL,4), G(NDIM,LENRUL)
      DOUBLE PRECISION LAM1, LAM2, LAM3, LAMP, RULCON
!
!     The following code determines rule parameters and weights for a
!      degree 7 rule (W(1,1),...,W(5,1)), two degree 5 comparison rules
!      (W(1,2),...,W(5,2) and W(1,3),...,W(5,3)) and a degree 3
!      comparison rule (W(1,4),...W(5,4)).
!
!       If NDIM = 1, then LENRUL = 5 and total points = 9.
!       If NDIM < SDIM, then LENRUL = 6 and
!                      total points = 1+2*NDIM*(NDIM+2)+2**NDIM.
!       If NDIM > = SDIM, then LENRUL = 6 and
!                      total points = 1+2*NDIM*(1+2*NDIM).
!
      DO 100 I = 1,LENRUL
         DO 200 J = 1,NDIM
            G(J,I) = 0
  200    CONTINUE
         DO 300 J = 1,NUMNUL
            W(I,J) = 0
  300    CONTINUE
  100 CONTINUE
      RULPTS(5) = 2*NDIM*(NDIM-1)
      RULPTS(4) = 2*NDIM
      RULPTS(3) = 2*NDIM
      RULPTS(2) = 2*NDIM
      RULPTS(1) = 1
      LAMP = 0.85
      LAM3 = 0.4707
      LAM2 = 4/(15 - 5/LAM3)
      W(5,1) = ( 3 - 5*LAM3 )/( 180*(LAM2-LAM3)*LAM2**2 )
      IF ( NDIM .LT. SDIM ) THEN
         LAM1 = 8*LAM3*(31*LAM3-15)/( (3*LAM3-1)*(5*LAM3-3)*35 )
         W(LENRUL,1) = 1/(3*LAM3)**3/2**NDIM
      ELSE
         LAM1 = ( LAM3*(15 - 21*LAM2) + 35*(NDIM-1)*(LAM2-LAM3)/9 )   &
             /  ( LAM3*(21 - 35*LAM2) + 35*(NDIM-1)*(LAM2/LAM3-1)/9 )
         W(6,1) = 1/(4*(3*LAM3)**3)
      ENDIF
      W(3,1) = ( 15 - 21*(LAM3+LAM1) + 35*LAM3*LAM1 )   &
           /( 210*LAM2*(LAM2-LAM3)*(LAM2-LAM1) ) - 2*(NDIM-1)*W(5,1)
      W(2,1) = ( 15 - 21*(LAM3+LAM2) + 35*LAM3*LAM2 )   &
           /( 210*LAM1*(LAM1-LAM3)*(LAM1-LAM2) )
      IF ( NDIM .LT. SDIM ) THEN
         RULPTS(LENRUL) = 2**NDIM
         LAM3 = SQRT(LAM3)
         DO 400 I = 1,NDIM
            G(I,LENRUL) = LAM3
  400    CONTINUE
      ELSE
         W(6,1) = 1/(4*(3*LAM3)**3)
         RULPTS(6) = 2*NDIM*(NDIM-1)
         LAM3 = SQRT(LAM3)
         DO 500 I = 1,2
            G(I,6) = LAM3
  500    CONTINUE
      ENDIF
      IF ( NDIM .GT. 1 ) THEN
         W(5,2) = 1/(6*LAM2)**2
         W(5,3) = 1/(6*LAM2)**2
      ENDIF
      W(3,2) = ( 3 - 5*LAM1 )/( 30*LAM2*(LAM2-LAM1) )   &
           - 2*(NDIM-1)*W(5,2)
      W(2,2) = ( 3 - 5*LAM2 )/( 30*LAM1*(LAM1-LAM2) )
      W(4,3) = ( 3 - 5*LAM2 )/( 30*LAMP*(LAMP-LAM2) )
      W(3,3) = ( 3 - 5*LAMP )/( 30*LAM2*(LAM2-LAMP) )   &
           - 2*(NDIM-1)*W(5,3)
      W(2,4) = 1/(6*LAM1)
      LAMP = SQRT(LAMP)
      LAM2 = SQRT(LAM2)
      LAM1 = SQRT(LAM1)
      G(1,2) = LAM1
      G(1,3) = LAM2
      G(1,4) = LAMP
      IF ( NDIM .GT. 1 ) THEN
         G(1,5) = LAM2
         G(2,5) = LAM2
      ENDIF
      DO 600 J = 1, NUMNUL
         W(1,J) = 1
         DO 700 I = 2,LENRUL
            W(1,J) = W(1,J) - RULPTS(I)*W(I,J)
  700    CONTINUE
  600 CONTINUE
      RULCON = 2
      CALL RULNRM( LENRUL, NUMNUL, RULPTS, W, RULCON )
!
      RETURN
      END SUBROUTINE BSINIT
      SUBROUTINE BSPVN(T,JHIGH,K,INDEX,X,ILEFT,VNIKX,WORK,IWORK)
!***BEGIN PROLOGUE  BSPVN
!***DATE WRITTEN   800901   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  E3,K6
!***KEYWORDS  B-SPLINE,DATA FITTING,INTERPOLATION,SPLINE
!***AUTHOR  AMOS, D. E., (SNLA)
!***PURPOSE  Calculates the value of all (possibly) nonzero basis
!            functions at X.
!***DESCRIPTION
!
!     Written by Carl de Boor and modified by D. E. Amos
!
!     Reference
!         SIAM J. Numerical Analysis, 14, No. 3, June, 1977, pp.441-472.
!
!     Abstract
!         BSPVN is the BSPLVN routine of the reference.
!
!         BSPVN calculates the value of all (possibly) nonzero basis
!         functions at X of order MAX(JHIGH,(J+1)*(INDEX-1)), where
!         T(K) .LE. X .LE. T(N+1) and J=IWORK is set inside the routine
!         on the first call when INDEX=1.  ILEFT is such that T(ILEFT)
!         .LE. X .LT. T(ILEFT+1).  A call to INTRV(T,N+1,X,ILO,ILEFT,
!         MFLAG) produces the proper ILEFT.  BSPVN calculates using the
!         basic algorithm needed in BSPVD.  If only basis functions are
!         desired, setting JHIGH=K and INDEX=1 can be faster than
!         calling BSPVD, but extra coding is required for derivatives
!         (INDEX=2) and BSPVD is set up for this purpose.
!
!         Left limiting values are set up as described in BSPVD.
!
!     Description of Arguments
!         Input
!          T       - knot vector of length N+K, where
!                    N = number of B-spline basis functions
!                    N = sum of knot multiplicities-K
!          JHIGH   - order of B-spline, 1 .LE. JHIGH .LE. K
!          K       - highest possible order
!          INDEX   - INDEX = 1 gives basis functions of order JHIGH
!                          = 2 denotes previous entry with WORK, IWORK
!                              values saved for subsequent calls to
!                              BSPVN.
!          X       - argument of basis functions,
!                    T(K) .LE. X .LE. T(N+1)
!          ILEFT   - largest integer such that
!                    T(ILEFT) .LE. X .LT. T(ILEFT+1)
!
!         Output
!          VNIKX   - vector of length K for spline values.
!          WORK    - a work vector of length 2*K
!          IWORK   - a work parameter.  Both WORK and IWORK contain
!                    information necessary to continue for INDEX = 2.
!                    When INDEX = 1 exclusively, these are scratch
!                    variables and can be used for other purposes.
!
!     Error Conditions
!         Improper input is a fatal error.
!***REFERENCES  C. DE BOOR, *PACKAGE FOR CALCULATING WITH B-SPLINES*,
!                 SIAM JOURNAL ON NUMERICAL ANALYSIS, VOLUME 14, NO. 3,
!                 JUNE 1977, PP. 441-472.
!***ROUTINES CALLED  XERROR
!***END PROLOGUE  BSPVN
!
!
      INTEGER ILEFT, IMJP1, INDEX, IPJ, IWORK, JHIGH, JP1, JP1ML, K, L
      REAL T, VM, VMPREV, VNIKX, WORK, X
!     DIMENSION T(ILEFT+JHIGH)
      DIMENSION T(*), VNIKX(K), WORK(*)
!     CONTENT OF J, DELTAM, DELTAP IS EXPECTED UNCHANGED BETWEEN CALLS.
!     WORK(I) = DELTAP(I), WORK(K+I) = DELTAM(I), I = 1,K
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  BSPVN
      IF(K.LT.1) GO TO 90
      IF(JHIGH.GT.K .OR. JHIGH.LT.1) GO TO 100
      IF(INDEX.LT.1 .OR. INDEX.GT.2) GO TO 105
      IF(X.LT.T(ILEFT) .OR. X.GT.T(ILEFT+1)) GO TO 110
      GO TO (10, 20), INDEX
   10 IWORK = 1
      VNIKX(1) = 1.0E0
      IF (IWORK.GE.JHIGH) GO TO 40
!
   20 IPJ = ILEFT + IWORK
      WORK(IWORK) = T(IPJ) - X
      IMJP1 = ILEFT - IWORK + 1
      WORK(K+IWORK) = X - T(IMJP1)
      VMPREV = 0.0E0
      JP1 = IWORK + 1
      DO 30 L=1,IWORK
        JP1ML = JP1 - L
        VM = VNIKX(L)/(WORK(L)+WORK(K+JP1ML))
        VNIKX(L) = VM*WORK(L) + VMPREV
        VMPREV = VM*WORK(K+JP1ML)
   30 CONTINUE
      VNIKX(JP1) = VMPREV
      IWORK = JP1
      IF (IWORK.LT.JHIGH) GO TO 20
!
   40 RETURN
!
!
   90 CONTINUE
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,91)
      CALL DPWRST('XXX','BUG ')
   91 FORMAT('***** FROM BSPVN,  K DOES NOT SATISFY K.GE.1 *****')
      RETURN
  100 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,102)
      CALL DPWRST('XXX','BUG ')
  101 FORMAT('***** FROM BSPVN,  JHIGH DOES NOT SATISFY ')
  102 FORMAT('      1.LE.JHIGH.LE.K                     ******')
      RETURN
  105 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,106)
      CALL DPWRST('XXX','BUG ')
  106 FORMAT('***** FROM BSPVN, INDEX IS NOT 1 OR 2 *****')
      RETURN
  110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
      CALL DPWRST('XXX','BUG ')
  111 FORMAT('***** FROM BSPVN,  X DOES NOT SATISFY ')
  112 FORMAT('      T(ILEFT).LE.X.LE.T(ILEFT+1)     *****')
      RETURN
      END SUBROUTINE BSPVN
      SUBROUTINE BTACDF(X,LAMBDA,K,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE BOREL-TANNER DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS LAMBDA AND K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              POSITIVE INTEGER X >= K.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,K) = K*EXP(-LAMBDA*X)*(LAMBDA*X)**(X-K)/
!                              (X*(X-K)!),   X >= K, 0 < LAMBDA < 1.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY DIRECT
!              SUMMATION OF THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --K      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE BOREL-TANNER DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < LAMBDA < 1,  AND K SHOULD BE  A POSITIVE
!                   INTEGER
!     OTHER DATAPAC   SUBROUTINES NEEDED--LNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-396.
!               --LUC DEVROYE, "THE BRANCHING PROCESS METHOD IN
!                 LAGRANGE RANDOM VARIATE GENERATION",
!                 FROM DEVROYES'S WEB SITE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL K
      REAL LAMBDA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DK
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLNGAM
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      IK=INT(K+0.5)
      INTX=INT(X+0.5)
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BTACDF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(IK.LT.1)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BTACDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IK
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(INTX.LT.IK)THEN
        WRITE(ICOUT,5)IK
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BTACDF ',   &
               'IS LESS THAN THE THIRD ARGUMENT (= ',I8,').')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DLAMB=DBLE(LAMBDA)
      DK=DBLE(IK)
      DCDF=0.0D0
!
      DO 100 I=INTX,IK,-1
        DX=DBLE(I)
        DTERM1=DLOG(DK) + (-DLAMB*DX) + (DX-DK)*DLOG(DLAMB*DX)
        DTERM2=DLOG(DX) + DLNGAM(DX-DK+1.0D0)
        DPDF=DEXP(DTERM1 - DTERM2)
        DCDF=DCDF + DPDF
  100 CONTINUE
!
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BTACDF
      SUBROUTINE BTAPDF(X,LAMBDA,K,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE BOREL-TANNER DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS LAMBDA AND K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              POSITIVE INTEGER X >= K.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,K) = K*EXP(-LAMBDA*X)*(LAMBDA*X)**(X-K)/
!                              (X*(X-K)!),   X >= K, 0 < LAMBDA < 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --K      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF
!             FOR THE BOREL-TANNER DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < LAMBDA < 1,  AND K SHOULD BE  A POSITIVE
!                   INTEGER
!     OTHER DATAPAC   SUBROUTINES NEEDED--LNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-396.
!               --LUC DEVROYE, "THE BRANCHING PROCESS METHOD IN
!                 LAGRANGE RANDOM VARIATE GENERATION",
!                 FROM DEVROYES'S WEB SITE.
!               --HAIGHT AND BREUER (1960), "THE BOREL-TANNER
!                 DISTRIBUTION", BIOMETRIKA, 47, PP. 143-150.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL K
      REAL LAMBDA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DK
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLNGAM
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IK=INT(K+0.5)
      INTX=INT(X+0.5)
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO BTAPDF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(IK.LT.1)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO BTAPDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IK
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(INTX.LT.IK)THEN
        WRITE(ICOUT,5)IK
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO BTAPDF ',   &
               'IS LESS THAN THE THIRD ARGUMENT (= ',I8,').')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DX=DBLE(INTX)
      DLAMB=DBLE(LAMBDA)
      DK=DBLE(IK)
!
      DTERM1=DLOG(DK) + (-DLAMB*DX) + (DX-DK)*DLOG(DLAMB*DX)
      DTERM2=DLOG(DX) + DLNGAM(DX-DK+1.0D0)
      DPDF=DEXP(DTERM1 - DTERM2)
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BTAPDF
      SUBROUTINE BTAPPF(P,LAMBDA,K,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE BOREL-TANNER DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETERS LAMBDA AND K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              POSITIVE INTEGER X >= K.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,K) = K*EXP(-LAMBDA*X)*(LAMBDA*X)**(X-K)/
!                              (X*(X-K)!),   X >= K, 0 < LAMBDA < 1.
!              THIS DISTRIBUTION IS DEFINED FOR 0 <= P <= 1.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                0 <= P < 1.
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --K      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION VALUE PPF
!             FOR THE BOREL-TANNER DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P < 1
!                 --0 < LAMBDA < 1, K A POSITIVE INTEGER
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-396.
!               --LUC DEVROYE, "THE BRANCHING PROCESS METHOD IN
!                 LAGRANGE RANDOM VARIATE GENERATION",
!                 FROM DEVROYES'S WEB SITE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL K
      REAL LAMBDA
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DEPS
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DK
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLNGAM
!
      INCLUDE 'DPCOMC.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
      PPF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
      ENDIF
!
      IF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
!
      IK=INT(K+0.5)
      IF(IK.LT.1)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IK
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
!
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
      ' BTAPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1] INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      ' BTAPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   12 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      ' BTAPPF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(P.LE.0.0)THEN
        PPF=REAL(IK)
        GO TO 9999
      ENDIF
!
      DLAMB=DBLE(LAMBDA)
      DK=DBLE(IK)
      DP=DBLE(P)
      DEPS=1.0D-7
!
!     COMPUTE PDF FOR X = IK
!
      DX=DK
      DCDF=DEXP(-DLAMB*DX - DLNGAM(1.0D0))
!
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=REAL(IK)
        GO TO 9999
      ENDIF
      I=IK
!
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9999
        ENDIF
        DX=DBLE(I)
        DTERM1=DLOG(DK) + (-DLAMB*DX) + (DX-DK)*DLOG(DLAMB*DX)
        DTERM2=DLOG(DX) + DLNGAM(DX-DK+1.0D0)
        DPDF=DEXP(DTERM1 - DTERM2)
        DCDF=DCDF + DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9999
        ENDIF
      GO TO 100
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BTAPPF
      SUBROUTINE BTARAN(N,LAMBDA,K,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BOREL-TANNER DISTRIBUTION
!              WITH SHAPE PARAMETERS LAMBDA AND K.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              POSITIVE INTEGER X >= K.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,K) = K*EXP(-LAMBDA*X)*(LAMBDA*X)**(X-K)/
!                              (X*(X-K)!),   X >= K, 0 < LAMBDA < 1.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --K      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BOREL-TANNER DISTRIBUTION
!             WITH SHAPE PARAMETERS LAMBDA AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < LAMBDA < 1, K A POSITIVE INTEGER
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-396.
!               --LUC DEVROYE, "THE BRANCHING PROCESS METHOD IN
!                 LAGRANGE RANDOM VARIATE GENERATION",
!                 FROM DEVROYES'S WEB SITE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL LAMBDA
      REAL K
      DIMENSION X(*)
!
!CCCC DIMENSION U(2)
!
!CCCC DOUBLE PRECISION PI
!CCCC DOUBLE PRECISION C
!CCCC DOUBLE PRECISION V
!CCCC DOUBLE PRECISION Y
!CCCC DOUBLE PRECISION DK
!CCCC DOUBLE PRECISION DLAMB
!CCCC DOUBLE PRECISION U1
!CCCC DOUBLE PRECISION W
!CCCC DOUBLE PRECISION WT
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!CCCC DATA PI / 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
!
      IK=INT(K+0.5)
      IF(IK.LT.1)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IK
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'BOREL-TANNER RANDOM NUMBERS IS NON-POSITIVE')
   11 FORMAT('***** ERROR--THE LAMBDA PARAMETER FOR THE ',   &
      'BOREL-TANNER RANDOM NUMBERS IS OUTSIDE THE (0,1) INTERVAL')
   12 FORMAT('***** ERROR--THE K PARAMETER FOR THE ',   &
      'BOREL-TANNER RANDOM NUMBERS IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N BOREL-TANNER DISTRIBUTION RANDOM NUMBERS
!     USING THE ALGORITHM GIVEN IN THE DEVROYE PAPER.
!
!     I DON'T THINK I HAVE THIS QUITE RIGHT, SO JUST USE
!     INVERSE PPF METHOD FOR NOW.
!
!CCCC NTEMP=2
!CCCC C=1.0D0/DSQRT(2.0D0*PI)
!CCCC DK=DBLE(IK)
!CCCC DLAMB=DBLE(LAMBDA)
!
!CCCC DO100I=1,N
!
!110    CONTINUE
!CCCC   CALL UNIRAN(NTEMP,ISEED,U)
!CCCC   U1=DBLE(U(1))
!
!CCCC   V=(1.0D0 + 4.0D0*C*DSQRT(DK))*U1
!
!CCCC   IF(V.LE.1.0D0)THEN
!CCCC     X(I)=REAL(IK)
!CCCC     GO TO 100
!CCCC   ELSEIF(V.GT.1.0D0 .AND. V.LE.1.0D0+2.0D0*C*DSQRT(DK))THEN
!CCCC     Y=DK + 1.0D0 + (V - 1.0D0)**2/(4.0D0*C*C)
!CCCC     T=C/DSQRT(Y-1.0D0-DK)
!CCCC   ELSE
!CCCC     Y=DK + 1.0D0 + (2.0D0*DK*C/(1.0D0+4.0D0*C*DSQRT(DK)-V))**2
!CCCC     T=DK*C/(Y-1.0D0-DK)**1.5
!CCCC   ENDIF
!
!CCCC   W=DBLE(U(2))
!CCCC   WT=W*T
!CCCC   CALL BTACDF(REAL(Y),LAMBDA,K,CDF)
!CCCC   CALL BTAPDF(REAL(Y),LAMBDA,K,PDF)
!CCCC   CALL BTAPDF(REAL(Y),LAMBDA,K,PPF)
!CCCC   IF(WT.LT.DBLE(PPF))THEN
!CCCC     IY=INT(Y+0.5)
!CCCC     X(I)=REAL(IY)
!CCCC     GO TO 100
!CCCC   ELSE
!CCCC     GO TO 110
!CCCC   ENDIF
!
! 100 CONTINUE
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        XTEMP=X(I)
        CALL BTAPPF(XTEMP,LAMBDA,K,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE BTARAN
      SUBROUTINE BTPCF(X,N,FCN,LDF,NF,T,K,BCOEF,WORK)
!***BEGIN PROLOGUE  BTPCF
!***REFER TO  B2INK,B3INK
!***ROUTINES CALLED  BINTK,BNSLV
!***END PROLOGUE  BTPCF
!
!  -----------------------------------------------------------------
!  BTPCF COMPUTES B-SPLINE INTERPOLATION COEFFICIENTS FOR NF SETS
!  OF DATA STORED IN THE COLUMNS OF THE ARRAY FCN. THE B-SPLINE
!  COEFFICIENTS ARE STORED IN THE ROWS OF BCOEF HOWEVER.
!  EACH INTERPOLATION IS BASED ON THE N ABCISSA STORED IN THE
!  ARRAY X, AND THE N+K KNOTS STORED IN THE ARRAY T. THE ORDER
!  OF EACH INTERPOLATION IS K. THE WORK ARRAY MUST BE OF LENGTH
!  AT LEAST 2*K*(N+1).
!  -----------------------------------------------------------------
!
!  ------------
!  DECLARATIONS
!  ------------
!
!  PARAMETERS
!
      INTEGER   &
              N, LDF, K
      REAL   &
           X(N), FCN(LDF,NF), T(*), BCOEF(NF,N), WORK(*)
!
!  LOCAL VARIABLES
!
      INTEGER   &
              I, J, K1, K2, IQ, IW
!
!  ---------------------------------------------
!  CHECK FOR NULL INPUT AND PARTITION WORK ARRAY
!  ---------------------------------------------
!
!***FIRST EXECUTABLE STATEMENT
      IF (NF .LE. 0)  GO TO 500
      K1 = K - 1
      K2 = K1 + K
      IQ = 1 + N
      IW = IQ + K2*N+1
!
!  -----------------------------
!  COMPUTE B-SPLINE COEFFICIENTS
!  -----------------------------
!
!
!   FIRST DATA SET
!
      CALL BINTK(X,FCN,T,N,K,WORK,WORK(IQ),WORK(IW))
      DO 20 I=1,N
         BCOEF(1,I) = WORK(I)
   20 CONTINUE
!
!  ALL REMAINING DATA SETS BY BACK-SUBSTITUTION
!
      IF (NF .EQ. 1)  GO TO 500
      DO 100 J=2,NF
         DO 50 I=1,N
            WORK(I) = FCN(I,J)
   50    CONTINUE
         CALL BNSLV(WORK(IQ),K2,N,K1,K1,WORK)
         DO 60 I=1,N
            BCOEF(J,I) = WORK(I)
   60    CONTINUE
  100 CONTINUE
!
!  ----
!  EXIT
!  ----
!
  500 CONTINUE
      RETURN
      END SUBROUTINE BTPCF
      SUBROUTINE BU2CDF(DX,DR,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 2 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R) = 1/[(1+EXP(-X))**R]    -INF <  X <  INF; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 2 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU2CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 2  CDF                    **
!               **************************************************
!
      DTERM1=1.0D0 + DEXP(-DX)
      DTERM2=DTERM1**DR
      DCDF=1.0D0/DTERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU2CDF
      SUBROUTINE BU2PDF(DX,DR,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 2 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R) = R*(1 + EXP(-X))**(-1-R)/EXP(X)
!                       -INF <  X <  INF; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY DENSITY
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 2 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU2PDF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE II PDF                    **
!               **************************************************
!
      DTERM1=DLOG(DR) + (-1.0D0 - DR)*DLOG(1.0D0 + DEXP(-DX))
      DTERM2=DX
      DPDF=DEXP(DTERM1 - DTERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU2PDF
      SUBROUTINE BU2PPF(DP,DR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 2 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R) = -LOG((1/P)**(1/R) - 1)   0 < P < 1; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 2 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU2PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU2PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 2 PPF                     **
!               **************************************************
!
      DTERM1=(1.0D0/DP)**(1.0D0/DR)
      DPPF=-DLOG(DTERM1 - 1.0D0)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU2PPF
      SUBROUTINE BU2RAN(N,R,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYPE 2 DISTRIBUTION WITH
!              SHAPE PARAMETER R.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER R.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYPE 2 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BU2PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYPE 2 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE R SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL BU2PPF(DBLE(X(I)),DBLE(R),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU2RAN
      SUBROUTINE BU3CDF(DX,DR,DK,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 3 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R,K) = (1+X**(-K))**(-R)    0 <  X <  INF; R, K > 0
!
!              WITH SHAPE PARAMETERS R AND K.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 3 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU3CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU3CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 3 CDF                     **
!               **************************************************
!
      IF(DX.LE.0.0D0)THEN
        DCDF=0.0D0
      ELSE
        DTERM1=1.0D0 + DX**(-DK)
        DCDF=DTERM1**(-DR)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU3CDF
      SUBROUTINE BU3PDF(DX,DR,DK,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 3 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R,K) = R*K*X**(R*K-1)/(1+X**K)**(R+1)
!              X >  0; R, K > 0
!
!              WITH SHAPE PARAMETERS R AND K.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 3 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DX.LE.0.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU3PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU3PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU3PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 3 PDF                     **
!               **************************************************
!
      DTERM1=DLOG(DR) + DLOG(DK) + (DR*DK - 1.0D0)*DLOG(DX)
      DTERM2=(DR+1.0D0)*DLOG(1.0D0 + DX**DK)
      DPDF=DEXP(DTERM1 - DTERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU3PDF
      SUBROUTINE BU3PPF(DP,DR,DK,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 3 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R,K) = (P**(-1/R) - 1)**(-1/K)  0 < P < 1; R, K > 0
!
!              WITH SHAPE PARAMETERS R AND K.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 3 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DK
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU3PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU3PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU3PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 12 PPF                    **
!               **************************************************
!
      IF(DP.LE.0.0D0)THEN
        DPPF=0.0D0
      ELSE
        DPPF=(DP**(-1.0D0/DR) - 1.0D0)**(-1.0D0/DK)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU3PPF
      SUBROUTINE BU3RAN(N,R,AK,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYPE 3 DISTRIBUTION WITH
!              SHAPE PARAMETERS R AND K.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER R.
!                     --AK     = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER K.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYPE 3 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BU3PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYPE 3 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE R SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ELSEIF(AK.LE.0.0)THEN
        WRITE(ICOUT,211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,213)AK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  211   FORMAT('***** ERROR--THE K SHAPE PARAMETER IS NON-POSITIVE.')
  213   FORMAT('      THE VALUE OF K IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL BU3PPF(DBLE(X(I)),DBLE(R),DBLE(AK),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU3RAN
      SUBROUTINE BU4CDF(DX,DR,DC,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 4 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R,C) = [1 + (C-X)/X)**(1/C)]**(-R)
!                         0 <  X <  C; C, R > 0
!
!              WITH SHAPE PARAMETERS R AND C.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DC     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 4 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND C.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DC
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DX.GE.DC)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU4CDF IS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,108)
  108   FORMAT('      GREATER THAN OR EQUAL TO THE THIRD INPUT ',   &
               'ARGUMENT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)DX
  141   FORMAT('      THE VALUE OF THE FIRST ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)DC
  143   FORMAT('      THE VALUE OF THE THIRD ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU4CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DC.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU4CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DC
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 4 CDF                     **
!               **************************************************
!
      IF(DX.LE.0.0D0)THEN
        DCDF=0.0D0
      ELSE
        DCDF=(1.0D0 + ((DC-DX)/DX)**(1.0D0/DC))**(-DR)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU4CDF
      SUBROUTINE BU4PPF(DP,DR,DC,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 4 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R,C) = C/[1 + (P**(-1/R) - 1)**C]
!                         0 <= P < 1; R, C > 0
!
!              WITH SHAPE PARAMETERS R AND C.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DC     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 4 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DC
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU4PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU4PPF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DC.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU4PPF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DC
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 4 PPF                     **
!               **************************************************
!
      IF(DP.LE.0.0D0)THEN
        DPPF=0.0D0
      ELSE
        DPPF=DC/(1.0D0 + (DP**(-1.0D0/DR) - 1.0D0)**DC)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU4PPF
