      SUBROUTINE BU7CDF(DX,DR,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 7 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R) = 2**(-R)*(1+TANH(X))**R
!              -INF <  X <  INF; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 7 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--TANH.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU7CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 7  CDF                    **
!               **************************************************
!
      IF(DX.GT.80.0D0)THEN
        DTERM1=1.0D0
      ELSEIF(DX.LT.-80.0D0)THEN
        DTERM1=-1.0D0
      ELSE
        DTERM1=(DEXP(DX)-DEXP(-DX))/(DEXP(DX)+DEXP(-DX))
      ENDIF
      DTERM2=(1.0D0 + DTERM1)**DR
      DCDF=(2.0D0**(-DR))*DTERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU7CDF
      SUBROUTINE BU7PDF(DX,DR,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 7 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R) = R*SECH(x)**2*(1+TANH(X))**(R-1)/(2**R)
!              -INF <  X <  INF; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 7 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--TANH, SECH.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU7PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 7  PDF                    **
!               **************************************************
!
      DTERM1=2.0D0/(DEXP(DX)+DEXP(-DX))
      DTERM2=(DEXP(DX)-DEXP(-DX))/(DEXP(DX)+DEXP(-DX))
      DTERM3=DLOG(DR) + 2.0D0*DLOG(DTERM1) +   &
             (DR-1.0D0)*DLOG(1.0D0 + DTERM2)
      DTERM4=DR*DLOG(2.0D0)
      DPDF=DEXP(DTERM3 - DTERM4)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU7PDF
      SUBROUTINE BU7PPF(DP,DR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 7 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R) = ARCTANH((2**R*P)**(1/R) - 1)
!                       0 < P < 1; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 7 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU7PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU7PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 7 PPF                     **
!               **************************************************
!
      DTERM1=((2.0D0**DR)*DP)**(1.0D0/DR) - 1.0D0
      IF(DTERM1.GE.1.0D0 .OR. DTERM1.LE.-1.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR IN BU7PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,126)
  126   FORMAT('      ATTEMPT TO TAKE ARCTANH OF A NUMBER ',   &
               '>= 1 OR <= -1')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)
  127   FORMAT('      THIS CAN HAPPEN IF BOTH ARGUMENTS ARE ',   &
               'SUFFICIENT SMALL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,128)DP
  128   FORMAT('      THE VALUE OF THE FIRST ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,129)DR
  129   FORMAT('      THE VALUE OF THE SECOND ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ELSE
        DTERM2=(1.0D0 + DTERM1)/(1.0D0 - DTERM1)
        DPPF=0.5D0*DLOG(DTERM2)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU7PPF
      SUBROUTINE BU8CDF(DX,DR,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 8 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R) = ((2/PI)*ARCTAN(EXP(X)))**R
!              -INF <  X <  INF; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 8 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, ARCTAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU8CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 8  CDF                    **
!               **************************************************
!
      DTERM1=DEXP(DX)
      DTERM2=DATAN(DTERM1)
      DCDF=((2.0D0/DPI)*DTERM2)**DR
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU8CDF
      SUBROUTINE BU8PDF(DX,DR,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 8 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R) = R*EXP(X)*(2/PI)**R*ARCTAN(EXP(X))**(R-1)/
!                       (1 + EXP(2*X))
!              -INF <  X <  INF; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 8 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ARCTAN, EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU8PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 8  PDF                    **
!               **************************************************
!
      DTERM1=DATAN(DEXP(DX))
      DTERM2=DLOG(DR) + DX + DR*DLOG(2.0D0/DPI) +   &
             (DR-1.0D0)*DLOG(DTERM1)
      DTERM3=DLOG(1.0D0 + DEXP(2.0D0*DX))
      DPDF=DEXP(DTERM2 - DTERM3)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU8PDF
      SUBROUTINE BU8PPF(DP,DR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 8 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R) = LOG(TAN(PI*P**(1/R)/2))
!                       0 < P < 1; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 8 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU8PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU8PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 8 PPF                     **
!               **************************************************
!
      DTERM1=DPI*(DP**(1.0D0/DR))
      DTERM2=DTAN(DTERM1/2.0D0)
      DPPF=DLOG(DTERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU8PPF
      SUBROUTINE BU8RAN(N,R,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYYPE 8 DISTRIBUTION WITH
!              SHAPE PARAMETER R.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER R.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYYPE 8 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BU8PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYYPE 8 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE R SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL BU8PPF(DBLE(X(I)),DBLE(R),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU8RAN
      SUBROUTINE BU9CDF(DX,DR,DK,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 9 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R,K) = 1 - 2/{2 + K*((1+EXP(X))**R - 1)}
!                         -INF <  X <  INF; R, K > 0
!
!              WITH SHAPE PARAMETERS R AND K.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 9 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU9CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU9CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 9 CDF                     **
!               **************************************************
!
      DTERM1=(1.0D0 + DEXP(DX))**DR
      DTERM2=2.0D0 + DK*(DTERM1 - 1.0D0)
      DCDF=1.0D0 - 2.0D0/DTERM2
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU9CDF
      SUBROUTINE BU9PDF(DX,DR,DK,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 9 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R,K) = 2*EXP(X)*(1+EXP(X))**(R-1)*K*R/
!                         (2+(-1+(1+EXP(X))**R)K)**2
!                         -INF <  X <  INF; R, K > 0
!
!              WITH SHAPE PARAMETERS R AND K.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 9 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU9PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU9PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 9 PDF                     **
!               **************************************************
!
      DTERM1=DLOG(2.0D0) + DLOG(DK) + DLOG(DR) + DX
      DTERM2=(DR-1.0D0)*DLOG(1.0D0 + DEXP(DX))
      DTERM3=(1.0D0 + DEXP(DX))**DR
      DTERM4=2.0D0 + DK*(-1.0D0 + DTERM3)
      DTERM5=2.0D0*DLOG(DTERM4)
      DPDF=DEXP(DTERM1 + DTERM2 - DTERM5)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU9PDF
      SUBROUTINE BU9PPF(DP,DR,DK,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 9 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R,K) = LOG{[1 + (1/K)*(2/(1-P) - 2)]**(1/R) - 1}
!                         0 < P < 1; R, K > 0
!
!              WITH SHAPE PARAMETERS R AND K.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 9 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO BU9PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO BU9PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO BU9PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 9 PPF                     **
!               **************************************************
!
      DTERM1=1.0D0 + (1.0D0/DK)*(2.0D0/(1.0D0-DP) - 2.0D0)
      DTERM2=DTERM1**(1.0D0/DR)
      DPPF=DLOG(DTERM2 - 1.0D0)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU9PPF
      SUBROUTINE BU9RAN(N,R,AK,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYPE 9 DISTRIBUTION WITH
!              SHAPE PARAMETERS R AND K.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER R.
!                     --AK     = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER K.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYPE 9 DISTRIBUTION
!             WITH SHAPE PARAMETERS R AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, BU9PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYPE 9 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE R SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ELSEIF(AK.LE.0.0)THEN
        WRITE(ICOUT,211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,213)AK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  211   FORMAT('***** ERROR--THE K SHAPE PARAMETER IS NON-POSITIVE.')
  213   FORMAT('      THE VALUE OF K IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL BU9PPF(DBLE(X(I)),DBLE(R),DBLE(AK),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE BU9RAN
      SUBROUTINE B10CDF(DX,DR,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 10 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R) = (1 - EXP(-X**2))**R   X >  0; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 10 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!                 (NOTE: THERE IS A TYPO IN THE DEVROYE CDF EQUATION,
!                 CORRECT FORM TAKEN FROM JOHNSON AND KOTZ).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B10CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 10 CDF                    **
!               **************************************************
!
      DCDF=(1.0D0 - DEXP(-DX**2))**DR
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B10CDF
      SUBROUTINE B10FUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              BURR TYPE 10 MAXIMUM LIKELIHOOD EQUATIONS.
!
!              (N/R) + SUM[i=1 to N][LN(1 - EXP(-(S*X(i))**2) = 0
!
!              (2*N/S) - 2*S*SUM[i=1 to n][X(i)**2] +
!              2*S*(R-1)*SUM[i=1 tp n][X(i)^2*EXP(-(S*X(i))**2)/
!              1 - EXP(-(S*X(i))**2))] = 0
!
!              WITH R AND S DENOTING THE SHAPE PARAMETER R AND
!              SCALE PARAMETER S RESPECTIVELY.
!
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--BURR TYPE 10 MAXIMUM LIKELIHOOD Y
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!                 (NOTE: THERE IS A TYPO IN THE DEVROYE CDF EQUATION,
!                 CORRECT FORM TAKEN FROM JOHNSON AND KOTZ).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DX3
      DOUBLE PRECISION DR
      DOUBLE PRECISION DS
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DN=DBLE(NOBS)
      DR=X(1)
      DS=X(2)
      DTERM1=DN/DR
      DTERM2=2.0D0*DN/DS
      DTERM3=2.0D0*DS
      DTERM4=2.0D0*DS*(DR-1.0D0)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DX2=DX**2
        DX3=DEXP(-(DS*DX)**2)
        DSUM1=DSUM1 + DLOG(1.0D0 - DX3)
        DSUM2=DSUM2 + DX2
        DSUM3=DSUM3 + DX2*DX3/(1.0D0 - DX3)
  200 CONTINUE
!
      FVEC(1)=DTERM1 + DSUM1
      FVEC(2)=DTERM2 - DTERM3*DSUM2 + DTERM4*DSUM3
!
      RETURN
      END SUBROUTINE B10FUN 
      SUBROUTINE B10LI1(Y,N,ICASPL,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LOG-LIKELIHOOD FUNCTION FOR
!              THE BURR TYPE 10 DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KUNDU AND RAQAB, "GENERALIZED RAYLEIGH DISTRIBUTION:
!                METHODS OF ESTIMATION", COMPUTATIONAL STATISTICS
!                AND DATA ANALYSIS, 49, PP. 187-200.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/4
!     ORIGINAL VERSION--APRIL     2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DR
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='B10L'
      ISUBN2='I1  '
!
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'0LI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF B10LI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE,SHAPE
   55   FORMAT('N,ALOC,SCALE,SHAPE = ',I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'0LI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'3B10')ALOC=0.0
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     N*LOG(2) + N*LOG(R) - 2*N*LOG(S) + SUM[i=1 to N][LOG(X(i) - L)] +
!     (R-1)*SUM[i=1 to N][1 - EXP(-((X(i)-L)/S)**2)] -
!     SUM[i=1 to N][((X(i)-L)/S)**2]
!
!     WITH R, L, AND S DENOTING THE SHAPE, LOCATION, AND SCALE
!     PARAMETERS, RESPECTIVELY.
!
      DN=DBLE(N)
      DS=DBLE(1.0/SCALE)
      DU=DBLE(ALOC)
      DR=DBLE(SHAPE)
!
      DTERM1=DN*DLOG(2.0D0) + DN*DLOG(DR) + 2.0D0*DN*DLOG(DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DX=DX-DU
        IF(DX.GT.0.0D0)THEN
          DSUM1=DSUM1 + DLOG(DX)
        ENDIF
        DSUM2=DSUM2 + DX**2
        DTERM2=1.0D0 - DEXP(-(DS*DX)**2)
        IF(DTERM2.GE.0.0D0)THEN
          DSUM3=DSUM3 + DLOG(DTERM2)
        ENDIF
 1000 CONTINUE
!
      DLIK=DTERM1 + DSUM1 - DS**2*DSUM2 + (DR-1.0D0)*DSUM3
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'3B10')DNP=3.0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'0LI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF B10LI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DSUM3,DTERM1,DTERM2
 9013   FORMAT('DSUM1,DSUM2,DSUM3,DTERM1,DTERM2 = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE B10LI1
      SUBROUTINE B10ML1(Y,N,MAXNXT,   &
                        TEMP1,TEMP2,DISPAR,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        SCALSV,SHAPSV,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER BURR TYPE 10 DISTRIBUTION FOR THE RAW
!              DATA CASE (I.E., NO CENSORING AND NO GROUPING).  THIS
!              ROUTINE RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE
!              INTERVALS WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMB10 WILL GENERATE THE OUTPUT
!              FOR THE BURR TYPE 10 MLE COMMAND).
!
!     REFERENCES--RAQAB AND KUNDU (2006).  "BURR TYPE X DISTRIBUTIIONS:
!                 REVISITED", JOURNAL OF PROBABILITY AND STATISTICAL
!                 SCIENCE, VOL. 4, NO. 2, PP. 179-193.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMB10)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION DISPAR(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
      DIMENSION DISPA2(1)
      INTEGER IPPCAP(2)
!
      EXTERNAL B10FUN
!
      DOUBLE PRECISION DXOUT
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='B10M'
      ISUBN2='L1  '
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'0ML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF B10ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)SHAPSV,SCALSV
   53   FORMAT('SHAPSV,SCALSV = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'0ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  CARRY OUT CALCULATIONS                         **
!               **  FOR BURR TYPE 10 MLE ESTIMATE                  **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'0ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='BURR TYPE 10'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      SHAPML=CPUMIN
      SCALML=CPUMIN
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(SHAPSV.GT.0.0 .AND. SCALSV.GT.0.0)THEN
        XPAR(1)=DBLE(SHAPSV)
        XPAR(2)=DBLE(1.0/SCALSV)
      ELSE
!
!       IF NO STARTING VALUES SPECIFIED, COMPUTE STARTING
!       VALUES BASED ON PPCC METHOD.
!
        CALL UNIMED(N,TEMP1)
        CALL SORT(Y,N,Y)
        ICASP2='BU10'
        ICASPL='PPCC'
        IPPCAP(1)=100
        IPPCAP(2)=1
!
!       OBTAIN LOWER/UPPER LIMITS FOR SHAPE PARAMETER
!
        CALL EXTPA2(ICASP2,IDIST,A,B,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ISUBRO,IBUGA3,IERROR)
!
!       CREATE ARRAY FOR THE CANDIDATE VALUES OF SHAPE PARAMETER
!
        NUMSHA=1
        CALL DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    XMIN,XMAX,A,B,   &
                    DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                    ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                    IBUGA3,ISUBRO,IERROR)
!
        CORRMX=-1.0
        IWRITE='OFF'
        DO 1010 IDIS=1,NUMDIS
          SHAPE=DISPAR(IDIS)
          DO 1020 I=1,N
            CALL B10PPF(DBLE(TEMP1(I)),DBLE(SHAPE),DXOUT)
            TEMP2(I)=REAL(DXOUT)
 1020     CONTINUE
          CALL CORR(Y,TEMP2,N,IWRITE,CC,IBUGA3,IERROR)
          IF(CC.GT.CORRMX)THEN
            SHAPE1=SHAPE
            CALL LINFI2(Y,TEMP2,N,PPA0,PPA1,ISUBRO,IBUGA3,IERROR)
            CORRMX=CC
          ENDIF
 1010   CONTINUE
        XPAR(1)=DBLE(SHAPE1)
        XPAR(2)=DBLE(1.0/PPA1)
      ENDIF
!
      IOPT=2
      TOL=1.0D-8
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(B10FUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      SHAPML=REAL(XPAR(1))
      SCALML=1.0/REAL(XPAR(2))
      IF(SHAPML.LE.0.0)IERROR='YES'
      IF(SCALML.LE.0.0)IERROR='YES'
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'0ML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF B10ML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)XPAR(1),XPAR(2),SHAPML,SCALML
 9017   FORMAT('XPAR(1),XPAR(2),SHAPML,SCALML =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE B10ML1
      SUBROUTINE B10PDF(DX,DR,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 10 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R) = 2*R*X*(1 - EXP(-X**2)**(R-1)/EXP(X^2)
!                       X >  0; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY DENSITY
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 10 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!                 (NOTE: THERE IS A TYPO IN THE DEVROYE CDF EQUATION,
!                 CORRECT FORM TAKEN FROM JOHNSON AND KOTZ).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DX.LE.0.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO B10PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B10PDF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 10 PDF                    **
!               **************************************************
!
      DTERM1=(DR-1.0D0)*DLOG(1.0D0 - DEXP(-DX**2))
      DTERM2=DLOG(2.0D0) + DLOG(DR) + DLOG(DX)
      DTERM3=DX**2
      DPDF=DEXP(DTERM1 + DTERM2 - DTERM3)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B10PDF
      SUBROUTINE B10PPF(DP,DR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 10 DISTRIBUTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;R) = SQRT(-LOG(1 - P**(1/R)))    0 < P < 1; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 10 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO B10PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B10PPF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 10 PPF                    **
!               **************************************************
!
      DPPF=DSQRT(-DLOG(1.D0 - DP**(1.0D0/DR)))
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B10PPF
      SUBROUTINE B10RAN(N,R,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYPE 10 DISTRIBUTION WITH
!              SHAPE PARAMETER R.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER R.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYPE 10 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, B10PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYPE 10 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE R SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL B10PPF(DBLE(X(I)),DBLE(R),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B10RAN
      SUBROUTINE B11CDF(DX,DR,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 11 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R) = [X - (1/(2*PI))*SIN(2*PI*X)]**R
!              0 <  X <  1; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 11 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B11CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 11  CDF                   **
!               **************************************************
!
      IF(DX.LE.0.0D0)THEN
        DCDF=0.0D0
      ELSEIF(DX.GE.1.0D0)THEN
        DCDF=1.0D0
      ELSE
        DTERM1=SIN(2.0D0*DPI*DX)/(2.0D0*DPI)
        DTERM2=DX - DTERM1
        DCDF=DTERM2**DR
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B11CDF
      SUBROUTINE B11PDF(DX,DR,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 11 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;R) = R*{1 - COS(2*PI*DX)*
!                       (X - SIN(2*PI*X)/(2*PI)}**(R-1)
!              0 <  X <  1; R > 0
!
!              WITH SHAPE PARAMETER R.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 11 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SIN, COS.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPI
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DX.LE.0.0D0 .OR. DX.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO B11PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B11PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DR
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 11  PDF                   **
!               **************************************************
!
      DTERM1=1.0D0 - DCOS(2.0D0*DPI*DX)
      DTERM2=DX - DSIN(2.0D0*DPI*DX)/(2.0D0*DPI)
      DPDF=DR*DTERM1*(DTERM2**(DR-1.0D0))
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B11PDF
      SUBROUTINE B11PPF(DP,DR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 11 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;R) = [X - (1/(2*PI))*SIN(2*PI*X)]**R
!              0 <  X <  1; R > 0
!
!              WITH SHAPE PARAMETER R.
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DR     = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 11 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DR
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION XL
      DOUBLE PRECISION XR
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION FCS
      DOUBLE PRECISION P1
      DOUBLE PRECISION EPS
      DOUBLE PRECISION SIG
      DOUBLE PRECISION ZERO
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0D-10/
      DATA SIG /1.0D-9/
      DATA ZERO /0.D0/
      DATA MAXIT /500/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
!
      IF(DP.LT.0.0D0 .OR. DP.GT.1.0D0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE FIRST ARGUMENT TO B11PPF IS ',   &
               'OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DR.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B11PPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DR
   47   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DP.LE.0.0D0)THEN
        DPPF=0.0D0
        GO TO 9000
      ELSEIF(DP.GE.1.0D0)THEN
        DPPF=1.0D0
        GO TO 9000
      ENDIF
!
      IERR=0
      IC = 0
      XL = 0.0D0
      XR = 1.0D0
      FXL = -DP
      FXR = 1.0D0 - DP
!
      IF(FXL*FXR .GT. ZERO)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!  BISECTION METHOD
!
  105 CONTINUE
      DX = (XL+XR)*0.5D0
      CALL B11CDF(DX,DR,DCDF)
      P1=DCDF
      DPPF=DX
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = DX
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = DX
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9000
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
  130 FORMAT('***** ERROR--B11PPF ROUTINE DID NOT CONVERGE.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B11PPF
      SUBROUTINE B11RAN(N,R,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYPE 11 DISTRIBUTION WITH
!              SHAPE PARAMETER R.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --R      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER R.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYPE 11 DISTRIBUTION
!             WITH SHAPE PARAMETER R.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, B11PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYPE 11 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(R.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)R
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE R SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N BURR TYPE 11 DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL B11PPF(DBLE(X(I)),DBLE(R),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B11RAN
      SUBROUTINE B12CDF(DX,DC,DK,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BURR TYPE 12 DISTRIBTION.
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS:
!
!              F(X;C,K) = 1 - (1+X**C)**(-K)   X >= 0
!
!              WITH SHAPE PARAMETERS C AND K.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DC     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE BURR TYPE 12 DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
!
      IF(DC.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B12CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DC
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO B12CDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 12 CDF                    **
!               **************************************************
!
      IF(DX.LE.0.0D0)THEN
        DCDF=0.0D0
      ELSE
        DTERM1=1.0D0 + DX**DC
        DCDF=1.0D0 - DTERM1**(-DK)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B12CDF
      SUBROUTINE B12PDF(DX,DC,DK,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BURR TYPE 12 DISTRIBTION.
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;C,K) = C*K*X**(C-1)*(1 + X**C)**(-K-1)
!                         X > 0; C, K >0
!
!              WITH SHAPE PARAMETERS C AND K.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DC     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE BURR TYPE 12 DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPDF=0.0D0
!
      IF(DX.LE.0.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO B12PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DC.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B12PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DC
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO B12PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR TYPE 12 PDF                    **
!               **************************************************
!
      DTERM1=DLOG(DC) + DLOG(DK) + (DC-1.0D0)*DLOG(DX)
      DTERM2=(-DK-1.0D0)*DLOG(1.0D0 + DX**DC)
      DPDF=DEXP(DTERM1+DTERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B12PDF
      SUBROUTINE B12PPF(DP,DC,DK,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BURR TYPE 12 DISTRIBTION.
!              THE PERCENT POINT FUNCTION IS:
!
!              G(P;C,K) = [(1-P)**(-1/K)-1]**(1/C)  0 <= P < 1; C, K > 0
!
!              WITH SHAPE PARAMETERS C AND K.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DC     = THE FIRST SHAPE PARAMETER
!                     --DK     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BURR TYPE 12 DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
!
      IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,105)
  105   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO B12PPF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DC.LE.0.0D0)THEN
        WRITE(ICOUT,115)
  115   FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO B12PPF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DC
  147   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DK.LE.0.0D0)THEN
        WRITE(ICOUT,125)
  125   FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO B12PPF ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)DK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2B-                                    **
!               **  COMPUTE BURR 12 PPF                         **
!               **************************************************
!
      IF(DP.LE.0.0D0)THEN
        DPPF=0.0D0
      ELSE
        DPPF=((1.0D0 - DP)**(-1.0D0/DK) - 1.0D0)**(1.0D0/DC)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B12PPF
      SUBROUTINE B12RAN(N,C,AK,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BURR TYPE 12 DISTRIBUTION WITH
!              SHAPE PARAMETERS C AND K.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --C      = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER C.
!                     --AK     = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER K.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BURR TYPE 12 DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, B12PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHMOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007.10
!     ORIGINAL VERSION--OCTOBER   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'BURR TYPE 12 RANDOM NUMBERS IS NON-POSITIVE')
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  201   FORMAT('***** ERROR--THE C SHAPE PARAMETER IS NON-POSITIVE.')
  203   FORMAT('      THE VALUE OF R IS ',G15.7)
      ELSEIF(AK.LE.0.0)THEN
        WRITE(ICOUT,211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,213)AK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
  211   FORMAT('***** ERROR--THE K SHAPE PARAMETER IS NON-POSITIVE.')
  213   FORMAT('      THE VALUE OF K IS ',G15.7)
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N SLOPE DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 300 I=1,N
        CALL B12PPF(DBLE(X(I)),DBLE(C),DBLE(AK),DTEMP)
        X(I)=DBLE(DTEMP)
  300 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE B12RAN
      DOUBLE PRECISION FUNCTION bup(a,b,x,y,n,eps)
!-----------------------------------------------------------------------
!     EVALUATION OF IX(A,B) - IX(A+N,B) WHERE N IS A POSITIVE INTEGER.
!     EPS IS THE TOLERANCE USED.
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a,b,eps,x,y
      INTEGER n
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION ap1,apb,d,l,r,t,w
      INTEGER i,k,kp1,mu,nm1
!     ..
!     .. External Functions ..
      DOUBLE PRECISION brcmp1,exparg
      EXTERNAL brcmp1,exparg
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC abs,exp
!     ..
!     .. Executable Statements ..
!
!          OBTAIN THE SCALING FACTOR EXP(-MU) AND
!             EXP(MU)*(X**A*Y**B/BETA(A,B))/A
!
      apb = a + b
      ap1 = a + 1.0D0
      mu = 0
      d = 1.0D0
      IF (n.EQ.1 .OR. a.LT.1.0D0) GO TO 10
      IF (apb.LT.1.1D0*ap1) GO TO 10
      mu = int(abs(exparg(1)))
      k = int(exparg(0))
      IF (k.LT.mu) mu = k
      t = mu
      d = exp(-t)
!
   10 bup = brcmp1(mu,a,b,x,y)/a
      IF (n.EQ.1 .OR. bup.EQ.0.0D0) RETURN
      nm1 = n - 1
      w = d
!
!          LET K BE THE INDEX OF THE MAXIMUM TERM
!
      k = 0
      IF (b.LE.1.0D0) GO TO 50
      IF (y.GT.1.D-4) GO TO 20
      k = nm1
      GO TO 30
                                                                                                                                  
   20 r = (b-1.0D0)*x/y - a
      IF (r.LT.1.0D0) GO TO 50
      k = nm1
      t = nm1
      IF (r.LT.t) k = int(r)
!
!          ADD THE INCREASING TERMS OF THE SERIES
!
   30 DO 40 i = 1,k
          l = i - 1
          d = ((apb+l)/ (ap1+l))*x*d
          w = w + d
   40 CONTINUE
      IF (k.EQ.nm1) GO TO 70
!
!          ADD THE REMAINING TERMS OF THE SERIES
!
   50 kp1 = k + 1
      DO 60 i = kp1,nm1
          l = i - 1
          d = ((apb+l)/ (ap1+l))*x*d
          w = w + d
          IF (d.LE.eps*w) GO TO 70
   60 CONTINUE
!
!               TERMINATE THE PROCEDURE
!
   70 bup = bup*w
      RETURN
                                                                                                                                  
      END FUNCTION bup
      FUNCTION BVALU(T,A,N,K,IDERIV,X,INBV,WORK)
!***BEGIN PROLOGUE  BVALU
!***DATE WRITTEN   800901   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  E3,K6
!***KEYWORDS  B-SPLINE,DATA FITTING,INTERPOLATION,SPLINE
!***AUTHOR  AMOS, D. E., (SNLA)
!***PURPOSE  Evaluates the B-representation of a B-spline at X for the
!            function value or any of its derivatives.
!***DESCRIPTION
!
!     Written by Carl de Boor and modified by D. E. Amos
!
!     Reference
!         SIAM J. Numerical Analysis, 14, No. 3, June, 1977, pp.441-472.
!
!     Abstract
!         BVALU is the BVALUE function of the reference.
!
!         BVALU evaluates the B-representation (T,A,N,K) of a B-spline
!         at X for the function value on IDERIV = 0 or any of its
!         derivatives on IDERIV = 1,2,...,K-1.  Right limiting values
!         (right derivatives) are returned except at the right end
!         point X=T(N+1) where left limiting values are computed.  The
!         spline is defined on T(K) .LE. X .LE. T(N+1).  BVALU returns
!         a fatal error message when X is outside of this interval.
!
!         To compute left derivatives or left limiting values at a
!         knot T(I), replace N by I-1 and set X=T(I), I=K+1,N+1.
!
!         BVALU calls INTRV
!
!     Description of Arguments
!         Input
!          T       - knot vector of length N+K
!          A       - B-spline coefficient vector of length N
!          N       - number of B-spline coefficients
!                    N = sum of knot multiplicities-K
!          K       - order of the B-spline, K .GE. 1
!          IDERIV  - order of the derivative, 0 .LE. IDERIV .LE. K-1
!                    IDERIV=0 returns the B-spline value
!          X       - argument, T(K) .LE. X .LE. T(N+1)
!          INBV    - an initialization parameter which must be set
!                    to 1 the first time BVALU is called.
!
!         Output
!          INBV    - INBV contains information for efficient process-
!                    ing after the initial call and INBV must not
!                    be changed by the user.  Distinct splines require
!                    distinct INBV parameters.
!          WORK    - work vector of length 3*K.
!          BVALU   - value of the IDERIV-th derivative at X
!
!     Error Conditions
!         An improper input is a fatal error
!***REFERENCES  C. DE BOOR, *PACKAGE FOR CALCULATING WITH B-SPLINES*,
!                 SIAM JOURNAL ON NUMERICAL ANALYSIS, VOLUME 14, NO. 3,
!                 JUNE 1977, PP. 441-472.
!***ROUTINES CALLED  INTRV,XERROR
!***END PROLOGUE  BVALU
!
!
      INTEGER I,IDERIV,IDERP1,IHI,IHMKMJ,ILO,IMK,IMKPJ, INBV, IPJ,   &
       IP1, IP1MJ, J, JJ, J1, J2, K, KMIDER, KMJ, KM1, KPK, MFLAG, N
      REAL A, FKMJ, T, WORK, X
!     DIMENSION T(N+K), WORK(3*K)
      DIMENSION T(*), A(N), WORK(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  BVALU
      BVALU = 0.0E0
      IF(K.LT.1) GO TO 102
      IF(N.LT.K) GO TO 101
      IF(IDERIV.LT.0 .OR. IDERIV.GE.K) GO TO 110
      KMIDER = K - IDERIV
!
! *** FIND *I* IN (K,N) SUCH THAT T(I) .LE. X .LT. T(I+1)
!     (OR, .LE. T(I+1) IF T(I) .LT. T(I+1) = T(N+1)).
      KM1 = K - 1
      CALL INTRV(T, N+1, X, INBV, I, MFLAG)
      IF (X.LT.T(K)) GO TO 120
      IF (MFLAG.EQ.0) GO TO 20
      IF (X.GT.T(I)) GO TO 130
   10 IF (I.EQ.K) GO TO 140
      I = I - 1
      IF (X.EQ.T(I)) GO TO 10
!
! *** DIFFERENCE THE COEFFICIENTS *IDERIV* TIMES
!     WORK(I) = AJ(I), WORK(K+I) = DP(I), WORK(K+K+I) = DM(I), I=1.K
!
   20 IMK = I - K
      DO 30 J=1,K
        IMKPJ = IMK + J
        WORK(J) = A(IMKPJ)
   30 CONTINUE
      IF (IDERIV.EQ.0) GO TO 60
      DO 50 J=1,IDERIV
        KMJ = K - J
        FKMJ = FLOAT(KMJ)
        DO 40 JJ=1,KMJ
          IHI = I + JJ
          IHMKMJ = IHI - KMJ
          WORK(JJ) = (WORK(JJ+1)-WORK(JJ))/(T(IHI)-T(IHMKMJ))*FKMJ
   40   CONTINUE
   50 CONTINUE
!
! *** COMPUTE VALUE AT *X* IN (T(I),(T(I+1)) OF IDERIV-TH DERIVATIVE,
!     GIVEN ITS RELEVANT B-SPLINE COEFF. IN AJ(1),...,AJ(K-IDERIV).
   60 IF (IDERIV.EQ.KM1) GO TO 100
      IP1 = I + 1
      KPK = K + K
      J1 = K + 1
      J2 = KPK + 1
      DO 70 J=1,KMIDER
        IPJ = I + J
        WORK(J1) = T(IPJ) - X
        IP1MJ = IP1 - J
        WORK(J2) = X - T(IP1MJ)
        J1 = J1 + 1
        J2 = J2 + 1
   70 CONTINUE
      IDERP1 = IDERIV + 1
      DO 90 J=IDERP1,KM1
        KMJ = K - J
        ILO = KMJ
        DO 80 JJ=1,KMJ
          WORK(JJ) = (WORK(JJ+1)*WORK(KPK+ILO)+WORK(JJ)   &
                    *WORK(K+JJ))/(WORK(KPK+ILO)+WORK(K+JJ))
          ILO = ILO - 1
   80   CONTINUE
   90 CONTINUE
  100 BVALU = WORK(1)
      RETURN
!
!
  101 CONTINUE
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,901)
      CALL DPWRST('XXX','BUG ')
  901 FORMAT('*****FROM BVALU, N DOES NOT SATISFY N.GE.K *****')
      RETURN
  102 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,902)
      CALL DPWRST('XXX','BUG ')
  902 FORMAT('*****FROM BVALU, K DOES NOT SATISFY K.GE.1 *****')
      RETURN
  110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,903)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,904)
      CALL DPWRST('XXX','BUG ')
  903 FORMAT('*****FROM BVALU, IDERIV DOES NOT SATISFY')
  904 FORMAT('     0.LE.IDERIV.LT.K                    *****')
      RETURN
  120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,921)
      CALL DPWRST('XXX','BUG ')
  921 FORMAT('*****FROM BVALU, X IS N0T GREATER THAN OR EQUAL TO T(K)')
      RETURN
  130 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,931)
      CALL DPWRST('XXX','BUG ')
  931 FORMAT('*****FROM BVALU, X IS NOT LESS THAN OR EQUAL TO T(N+1)')
      RETURN
  140 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,941)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,942)
      CALL DPWRST('XXX','BUG ')
  941 FORMAT('*****FROM BVALU, A LEFT LIMITING VALUE CANN0T BE')
  942 FORMAT('     OBTAINED AT T(K)                            *****')
      RETURN
      END FUNCTION BVALU
      SUBROUTINE BVNCDF(X1,X2,CORR,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BIVARIATE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEANS = 0 AND STANDARD DEVIATIONS = 1
!              AND WITH A CORRELATION OF CORR.
!              F(X) = (1/SQRT(2*PI))*EXP(-X*X/2).
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VALUE AT WHICH
!                                THE FIRST CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --X1     = THE SINGLE PRECISION VALUE AT WHICH
!                                THE SECOND CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --CORR   = THE CORRELATION BETWEEN THE 2
!                                DISTRIBUTIONS
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF, THA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"A REMARK ON ALGORITHM AS76: AN INTEGRAL USEFUL IN
!                 CALCULATING NONCENTRAL T AND BIVARIATE NORMAL
!                 PROBABILITIES", BOYS, APPLIED STATISTICS,
!               --"TABLES FOR COMPUTING BIVARIATE NORMAL PROBABILITIES"
!                 ANNALS OF MATHEMATICAL STATISTICS, OWEN, 1956 (1075-
!                 1090).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--94.10
!     ORIGINAL VERSION--OCTOBER   1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ONE/1.0/
      DATA EPS/0.0000001/
!
!-----START POINT-----------------------------------------------------
!
      ACORR=ABS(CORR)
      IF(ACORR.GT.1.0)THEN
        WRITE(ICOUT,10)
 10     FORMAT('***** ERROR--THIRD TERM TO BVNCDF IS OUTSIDE THE ',   &
         'INTERVAL (-1,1).  *****')
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
!
!  CORRELATION OF 1 IS A SPECIAL CASE
!
      IF(ACORR.EQ.1.0)THEN
        TERM1=MIN(X1,X2)
        CALL NORCDF(TERM1,CDF)
        GO TO 9999
      ENDIF
!
      XH=X1
      XK=X2
      IF(ABS(XH).LE.EPS .AND. ABS(XK).LE.EPS)THEN
        XH=EPS
        XK=-EPS
      ENDIF
      CALL NORCDF(XH,TERM1)
      CALL NORCDF(XK,TERM2)
      TERM3=1.0
      IF(XH*XK.GT.0.0 .OR. (XH*XK.EQ.0.0.AND.XH+XK.GE.0.0))TERM3=0.0
      A1=(XK-CORR*XH)/SQRT(1.0-CORR*CORR)
      A2=XH
      IF(A1.EQ.0.0.AND.A2.EQ.0.0)A1=0.000001
      TERM4=THA(XH,ONE,A1,A2)
      A1=(XH-CORR*XK)/SQRT(1.0-CORR*CORR)
      A2=XK
      IF(A1.EQ.0.0.AND.A2.EQ.0.0)A1=0.000001
      TERM5=THA(XK,ONE,A1,A2)
      CDF=0.5*(TERM1+TERM2-TERM3)-TERM4-TERM5
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BVNCDF
      SUBROUTINE BVNPDF(X1,X2,CORR,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE BIVARIATE NORMAL (GAUSSIAN)
!              DISTRIBUTION WITH MEANS = 0 AND STANDARD DEVIATIONS = 1
!              AND WITH A CORRELATION OF CORR.  USE THE FOLLOWING
!              FORMULA FROM ABRAMOWITZ AND STEGUM
!              F(X) = (1-P**2)**(-1/2)*NORPDF(X1)
!                     *NORPDF((X2-P*X1)/(SQRT(1-P**2)))
!              WHERE NORPDF IS THE UNIVARIATE NORMAL PDF FUNCTION.
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VALUE AT WHICH
!                                THE FIRST PROBABILTY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --X1     = THE SINGLE PRECISION VALUE AT WHICH
!                                THE SECOND PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --CORR   = THE CORRELATION BETWEEN THE 2
!                                DISTRIBUTIONS
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"AMS 55", ABRAMOWITZ AND STEGUM.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95.9
!     ORIGINAL VERSION--SEPTEMBER 1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ACORR=ABS(CORR)
      IF(ACORR.GT.1.0)THEN
        WRITE(ICOUT,10)
 10     FORMAT('***** ERROR--THIRD TERM TO BVNPDF IS OUTSIDE THE ',   &
         'INTERVAL (-1,1).  *****')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
!
!  CORRELATION OF 1 IS A SPECIAL CASE (UNDEFINED SINCE GET DIVISION
!  BY ZERO IN THE FORMULA).
!
      IF(ACORR.EQ.1.0)THEN
        PDF=0.0
        GO TO 9999
      ENDIF
!
      TERM1=(1.0-ACORR*ACORR)
      TERM2=1.0/SQRT(TERM1)
      CALL NORPDF(X1,TERM3)
      ARG1=(X2-CORR*X1)/SQRT(1.0-CORR*CORR)
      CALL NORPDF(ARG1,TERM4)
!
      PDF=TERM2*TERM3*TERM4
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BVNPDF
      SUBROUTINE BWECDF(X,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,CDF,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE BI-WEIBULL DISTRIBUTION AS
!              AS DEFINED IN THE THIRD EDITION OF "STATISTICAL
!              DISTRIBUTIONS", THIRD EDITION, EVANS, HASTINGS, AND
!              PEACOCK.  THIS DISTRIBUTION IS RELATED TO, BUT SOMEWHAT
!              DIFFERENT THAN, A STRAIGHT MIXTURE OF TWO WEIBULL
!              DISTRIBUTIONS.  THE CDF IS DEFINED AS:
!              F(X,S1,G1,L2,S2,G2) =
!               1 - EXP[-(X/S1)**G1]                  0 < X < L2
!               1 - EXP[-{(X/S1)**G1 +
!                   [(X-L2)/S2]**G2}]                 X > L2
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ASCAL1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --ALOC2  = LOCATION PARAMETER (SECOND PART)
!                     --ASCAL2 = SCALE PARAMETER (SECOND PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE WEIBULL DISTRIBUTION
!             WITH 5 SHAPE PARAMETERS
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,ASCAL1,ASCAL2,ALOC2 SHOULD BE
!                   POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION,
!                 2000, PP. 200-202.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2002.5
!     ORIGINAL VERSION--MAY       2002.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DS1
      DOUBLE PRECISION DG1
      DOUBLE PRECISION DL2
      DOUBLE PRECISION DS2
      DOUBLE PRECISION DG2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DCDF=0.0D0
      CDF=0.0
      IF(ASCAL1.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR BWECDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA1.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR ',   &
              'BWECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ASCAL2.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR ',   &
               'BWECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA2.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR ',   &
               'BWECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALOC2.LE.0.0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE LOCATION(2) PARAMETER FOR ',   &
               'BWECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALOC2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      IF(X.LE.0.0)GO TO 9999
!
      DX=DBLE(X)
      DG1=DBLE(GAMMA1)
      DS1=DBLE(ASCAL1)
      DG2=DBLE(GAMMA2)
      DS2=DBLE(ASCAL2)
      DL2=DBLE(ALOC2)
!
      IF(DX.LE.DL2)THEN
         DCDF=DEXP(-(DX/DS1)**DG1)
      ELSE
         DTERM1=(DX/DS1)**DG1
         DTERM2=((DX-DL2)/DS2)**DG2
         DCDF=DEXP(-(DTERM1 + DTERM2))
      ENDIF
      DCDF=1.0D0 - DCDF
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BWECDF
      SUBROUTINE BWEHAZ(X,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,HAZ,DHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE BI-WEIBULL DISTRIBUTION AS
!              AS DEFINED IN THE THIRD EDITION OF "STATISTICAL
!              DISTRIBUTIONS", THIRD EDITION, EVANS, HASTINGS, AND
!              PEACOCK.  THIS DISTRIBUTION IS RELATED TO, BUT SOMEWHAT
!              DIFFERENT THAN, A STRAIGHT MIXTURE OF TWO WEIBULL
!              DISTRIBUTIONS.  THE HAZARD FUNCTION IS DEFINED AS:
!              h(X,S1,G1,L2,S2,G2) =
!               (1/S1)*G1*(X/S1)**(G1-1)          0 < X < L2
!               (1/S1)*G1*(X/S1)**(G1-1) +
!               (G2/S2)*((X-L2)/S2)**(G2-1)       X >= L2
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ASCAL1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --ALOC2  = LOCATION PARAMETER (SECOND PART)
!                     --ASCAL2 = SCALE PARAMETER (SECOND PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE HAZ FOR THE WEIBULL DISTRIBUTION
!             WITH 5 SHAPE PARAMETERS
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA1,GAMMA2,ASCAL1,ASCAL2,ALOC2 SHOULD BE
!                   POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION,
!                 2000, PP. 200-202.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2002.5
!     ORIGINAL VERSION--MAY       2002.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DS1
      DOUBLE PRECISION DG1
      DOUBLE PRECISION DL2
      DOUBLE PRECISION DS2
      DOUBLE PRECISION DG2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      DHAZ=0.0D0
      IF(ASCAL1.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR ',   &
               'BWEHAZ IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA1.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR ',   &
               'BWEHAZ IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ASCAL2.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR ',   &
               'BWEHAZ IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA2.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR ',   &
               'BWEHAZ IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALOC2.LE.0.0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE LOCATION(2) PARAMETER FOR ',   &
               'BWEHAZ IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALOC2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      IF(X.LE.0.0)GO TO 9999
!
      DX=DBLE(X)
      DG1=DBLE(GAMMA1)
      DS1=DBLE(ASCAL1)
      DG2=DBLE(GAMMA2)
      DS2=DBLE(ASCAL2)
      DL2=DBLE(ALOC2)
!
      IF(DX.LE.DL2)THEN
         DHAZ=(DG1/DS1)*(DX/DS1)**(DG1-1.0D0)
      ELSE
         DTERM1=(DG1/DS1)*(DX/DS1)**(DG1-1.0D0)
         DTERM2=(DG2/DS2)*((DX-DL2)/DS2)**(DG2-1.0D0)
         DHAZ=DTERM1 + DTERM2
      ENDIF
      HAZ=REAL(DHAZ)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BWEHAZ
      SUBROUTINE BWEPPF(P,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,PPF,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE BI-WEIBULL DISTRIBUTION AS
!              AS DEFINED IN THE THIRD EDITION OF "STATISTICAL
!              DISTRIBUTIONS", THIRD EDITION, EVANS, HASTINGS, AND
!              PEACOCK.  THIS DISTRIBUTION IS RELATED TO, BUT SOMEWHAT
!              DIFFERENT THAN, A STRAIGHT MIXTURE OF TWO WEIBULL
!              DISTRIBUTIONS.  THE CDF IS DEFINED AS:
!              F(X,S1,G1,L2,S2,G2) =
!               1 - EXP[-(X/S1)**G1]                  0 < X < L2
!               1 - EXP[-{(X/S1)**G1 +
!                   [(X-L2)/S2]**G2}]                 X > L2
!              THE PERCENT POINT FUNCTION IS CALCULATED ANALYTICALLY
!              FOR CASE WHEN X < L2.  IT IS CALCULATED NUMERICALLY
!              FOR X > L2.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT FUNCTION
!                                FUNCTION IS TO BE EVALUATED.
!                                P SHOULD BE IN THE INTERVAL [0,1).
!                     --ASCAL1 = SCALE PARAMETER (FIRST PART)
!                     --GAMMA1 = SHAPE PARAMETER (FIRST PART)
!                     --ALOC2  = LOCATION PARAMETER (SECOND PART)
!                     --ASCAL2 = SCALE PARAMETER (SECOND PART)
!                     --GAMMA2 = SHAPE PARAMETER (SECOND PART)
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE BI-WEIBULL DISTRIBUTION
!             WITH 5 SHAPE PARAMETERS
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0<= P < 1
!                 --GAMMA1,GAMMA2,ASCAL1,ASCAL2,ALOC2 SHOULD BE
!                   POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION,
!                 2000, PP. 200-202.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2002.5
!     ORIGINAL VERSION--MAY       2002.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DS1
      DOUBLE PRECISION DG1
      DOUBLE PRECISION DL2
      DOUBLE PRECISION DS2
      DOUBLE PRECISION DG2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DCDFL
      DOUBLE PRECISION DCDFR
      DOUBLE PRECISION DXINC
      DOUBLE PRECISION DXL
      DOUBLE PRECISION DXR
      DOUBLE PRECISION DFXL
      DOUBLE PRECISION DFXR
      DOUBLE PRECISION DP1
      DOUBLE PRECISION DFCS
      DOUBLE PRECISION DXRML
      DOUBLE PRECISION DSIG
      DOUBLE PRECISION DEPS
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DEPS /0.0000001/
      DATA DSIG /1.0D-7/
      DATA MAXIT /2000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      DPPF=0.0D0
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE INPUT ARGUMENT FOR BWEPPF ',   &
               'BWEPPF IS OUTSIDE THE INTERVAL [0,1).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ASCAL1.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR ',   &
               'BWEPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA1.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR ',   &
               'BWEPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ASCAL2.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR ',   &
               'BWEPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA2.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR ',   &
               'BWEPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALOC2.LE.0.0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE LOCATION(2) PARAMETER FOR ',   &
               'BWEPPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALOC2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      IF(P.EQ.0.0)GO TO 9999
!
      DP=DBLE(P)
      DG1=DBLE(GAMMA1)
      DS1=DBLE(ASCAL1)
      DG2=DBLE(GAMMA2)
      DS2=DBLE(ASCAL2)
      DL2=DBLE(ALOC2)
!
!  CHECK IF P <= BWECDF(LOC2)
!
      CALL BWECDF(ALOC2,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,CDF,DCDF)
      IF(DP.LE.DCDF)THEN
        DPPF=(DLOG(1.0D0/(1.0D0-DP)))**(1.0D0/DG1)
        DPPF=DS1*DPPF
        PPF=REAL(DPPF)
        GO TO 9999
      ENDIF
!
!  CASE WHERE PPF CALCULATED NUMERICALLY
!
!
!  FIND BRACKETING INTERVAL.
!
      DXL=DL2
      DXINC=DS2
      IF(DXINC.LT.1.0D0)DXINC=1.0D0
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      DXR=DXL+DXINC
      IF(DXL.LE.DL2)DXL=DL2
      IF(DXR.LE.DL2)DXR=DXL+DXINC
      XL=REAL(DXL)
      XR=REAL(DXR)
      CALL BWECDF(XL,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,CDFL,DCDFL)
      CALL BWECDF(XR,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,CDFR,DCDFR)
      IF(DCDFL.LT.DP .AND. DCDFR.LT.DP)THEN
        DXL=DXR
      ELSEIF(DCDFL.GT.DP .AND. DCDFR.GT.DP)THEN
        DXL=DXL-DXINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** FATAL ERROR--BWEPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      DFXL = -DP
      DFXR = 1.0D0 - DP
  105 CONTINUE
      DX = (DXL+DXR)*0.5D0
      X=REAL(DX)
      CALL BWECDF(X,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,CDF,DCDF)
      DP1=DCDF
      DPPF=DX
      PPF=REAL(DPPF)
      DFCS = DP1 - DP
      IF(DFCS*DFXL.GT.0.0D0)GO TO 110
      DXR = DX
      DFXR = DFCS
      GO TO 115
  110 CONTINUE
      DXL = DX
      DFXL = DFCS
  115 CONTINUE
      DXRML = DXR - DXL
      IF(DXRML.LE.DSIG .AND. DABS(DFCS).LE.DEPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--BWEPPF ROUTINE DID NOT CONVERGE.')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BWEPPF
      SUBROUTINE BWERAN(N,ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE BIWEIBULL DISTRIBUTION
!              WITH 5 SHAPE PARAMETERS.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ASCAL1 = THE SINGLE PRECISION VALUE OF THE
!                                SCALE (1) PARAMETER.
!                     --GAMMA1 = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE (1) PARAMETER.
!                     --ALOC2  = THE SINGLE PRECISION VALUE OF THE
!                                LOCATION (2) PARAMETER.
!                     --ASCAL2 = THE SINGLE PRECISION VALUE OF THE
!                                SCALE (2) PARAMETER.
!                     --GAMMA2 = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE (2) PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE BIWEIBULL DISTRIBUTION
!             WITH 5 SHAPE PARAMETERS.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --5 SHAPE PARAMETERS SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2002.5
!     ORIGINAL VERSION--MAY       2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DOUBLE PRECISION DTEMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ASCAL1.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SCALE(1) PARAMETER FOR ',   &
               'THE BWERAN SUBROUTINE IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL1
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA1.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE GAMMA(1) SHAPE PARAMETER FOR ',   &
               'BWERAN IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA1
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ASCAL2.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE SCALE(2) PARAMETER FOR ',   &
               'BWERAN IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ASCAL2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA2.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE GAMMA(2) SHAPE PARAMETER FOR ',   &
               'BWERAN IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALOC2.LE.0.0)THEN
        WRITE(ICOUT,45)
   45   FORMAT('***** ERROR--THE LOCATION(2) PARAMETER FOR ',   &
               'BWERAN IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALOC2
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N BIWEIBULL DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL BWEPPF(X(I),ASCAL1,GAMMA1,ALOC2,ASCAL2,GAMMA2,   &
                    XTEMP,DTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE BWERAN
      DOUBLE PRECISION FUNCTION BVN ( LOWER, UPPER, INFIN, CORREL )
!
!     A function for computing bivariate normal probabilities.
!
!  Parameters
!
!     LOWER  REAL, array of lower integration limits.
!     UPPER  REAL, array of upper integration limits.
!     INFIN  INTEGER, array of integration limits flags:
!            if INFIN(I) = 0, Ith limits are (-infinity, UPPER(I)];
!            if INFIN(I) = 1, Ith limits are [LOWER(I), infinity);
!            if INFIN(I) = 2, Ith limits are [LOWER(I), UPPER(I)].
!     CORREL REAL, correlation coefficient.
!
      DOUBLE PRECISION LOWER(*), UPPER(*), CORREL, BVNU
      INTEGER INFIN(*)
!
      BVN = 0.0D0
!
      IF ( INFIN(1) .EQ. 2  .AND. INFIN(2) .EQ. 2 ) THEN
         BVN =  BVNU ( LOWER(1), LOWER(2), CORREL )   &
              - BVNU ( UPPER(1), LOWER(2), CORREL )   &
              - BVNU ( LOWER(1), UPPER(2), CORREL )   &
              + BVNU ( UPPER(1), UPPER(2), CORREL )
      ELSE IF ( INFIN(1) .EQ. 2  .AND. INFIN(2) .EQ. 1 ) THEN
         BVN =  BVNU ( LOWER(1), LOWER(2), CORREL )   &
              - BVNU ( UPPER(1), LOWER(2), CORREL )
      ELSE IF ( INFIN(1) .EQ. 1  .AND. INFIN(2) .EQ. 2 ) THEN
         BVN =  BVNU ( LOWER(1), LOWER(2), CORREL )   &
              - BVNU ( LOWER(1), UPPER(2), CORREL )
      ELSE IF ( INFIN(1) .EQ. 2  .AND. INFIN(2) .EQ. 0 ) THEN
         BVN =  BVNU ( -UPPER(1), -UPPER(2), CORREL )   &
              - BVNU ( -LOWER(1), -UPPER(2), CORREL )
      ELSE IF ( INFIN(1) .EQ. 0  .AND. INFIN(2) .EQ. 2 ) THEN
         BVN =  BVNU ( -UPPER(1), -UPPER(2), CORREL )   &
              - BVNU ( -UPPER(1), -LOWER(2), CORREL )
      ELSE IF ( INFIN(1) .EQ. 1  .AND. INFIN(2) .EQ. 0 ) THEN
         BVN =  BVNU ( LOWER(1), -UPPER(2), -CORREL )
      ELSE IF ( INFIN(1) .EQ. 0  .AND. INFIN(2) .EQ. 1 ) THEN
         BVN =  BVNU ( -UPPER(1), LOWER(2), -CORREL )
      ELSE IF ( INFIN(1) .EQ. 1  .AND. INFIN(2) .EQ. 1 ) THEN
         BVN =  BVNU ( LOWER(1), LOWER(2), CORREL )
      ELSE IF ( INFIN(1) .EQ. 0  .AND. INFIN(2) .EQ. 0 ) THEN
         BVN =  BVNU ( -UPPER(1), -UPPER(2), CORREL )
      END IF
!
      RETURN
      END FUNCTION BVN 
      DOUBLE PRECISION FUNCTION BVNU( SH, SK, R )
!
!     A function for computing bivariate normal probabilities.
!
!       Yihong Ge
!       Department of Computer Science and Electrical Engineering
!       Washington State University
!       Pullman, WA 99164-2752
!       Email : yge@eecs.wsu.edu
!     and
!       Alan Genz
!       Department of Mathematics
!       Washington State University
!       Pullman, WA 99164-3113
!       Email : alangenz@wsu.edu
!
! BVN - calculate the probability that X is larger than SH and Y is
!       larger than SK.
!
! Parameters
!
!   SH  REAL, integration limit
!   SK  REAL, integration limit
!   R   REAL, correlation coefficient
!   LG  INTEGER, number of Gauss Rule Points and Weights
!
      DOUBLE PRECISION BVN, SH, SK, R, ZERO, TWOPI
      INTEGER I, LG, NG
      PARAMETER ( ZERO = 0.0D0, TWOPI = 6.283185307179586D0 )
      DOUBLE PRECISION X(10,3), W(10,3), AS, A, B, C, D, RS, XS
      DOUBLE PRECISION PHI, SN, ASR, H, K, BS, HS, HK
!     Gauss Legendre Points and Weights, N =  6
      DATA ( W(I,1), X(I,1), I = 1,3) /   &
        0.1713244923791705D+00,-0.9324695142031522D+00,   &
        0.3607615730481384D+00,-0.6612093864662647D+00,   &
        0.4679139345726904D+00,-0.2386191860831970D+00/
!     Gauss Legendre Points and Weights, N = 12
      DATA ( W(I,2), X(I,2), I = 1,6) /   &
        0.4717533638651177D-01,-0.9815606342467191D+00,   &
        0.1069393259953183D+00,-0.9041172563704750D+00,   &
        0.1600783285433464D+00,-0.7699026741943050D+00,   &
        0.2031674267230659D+00,-0.5873179542866171D+00,   &
        0.2334925365383547D+00,-0.3678314989981802D+00,   &
        0.2491470458134029D+00,-0.1252334085114692D+00/
!     Gauss Legendre Points and Weights, N = 20
      DATA ( W(I,3), X(I,3), I = 1,10) /   &
        0.1761400713915212D-01,-0.9931285991850949D+00,   &
        0.4060142980038694D-01,-0.9639719272779138D+00,   &
        0.6267204833410906D-01,-0.9122344282513259D+00,   &
        0.8327674157670475D-01,-0.8391169718222188D+00,   &
        0.1019301198172404D+00,-0.7463319064601508D+00,   &
        0.1181945319615184D+00,-0.6360536807265150D+00,   &
        0.1316886384491766D+00,-0.5108670019508271D+00,   &
        0.1420961093183821D+00,-0.3737060887154196D+00,   &
        0.1491729864726037D+00,-0.2277858511416451D+00,   &
        0.1527533871307259D+00,-0.7652652113349733D-01/
      SAVE X, W
      IF ( ABS(R) .LT. 0.3 ) THEN
         NG = 1
         LG = 3
      ELSE IF ( ABS(R) .LT. 0.75 ) THEN
         NG = 2
         LG = 6
      ELSE
         NG = 3
         LG = 10
      ENDIF
      H = SH
      K = SK
      HK = H*K
      BVN = 0.0D0
      IF ( ABS(R) .LT. 0.925D0 ) THEN
         HS = ( H*H + K*K )/2.0D0
         ASR = ASIN(R)
         DO 10  I = 1, LG
            SN = SIN(ASR*( X(I,NG)+1.0D0 )/2.0D0)
            BVN = BVN + W(I,NG)*EXP( ( SN*HK - HS )/(1.0D0 - SN*SN))
            SN = SIN(ASR*(-X(I,NG)+1.0D0 )/2.0D0)
            BVN = BVN + W(I,NG)*EXP( ( SN*HK - HS )/(1.0D0 - SN*SN))
 10      CONTINUE
         BVN = BVN*ASR/(2.0D0*TWOPI) + PHI(-H)*PHI(-K)
      ELSE
         IF ( R .LT. 0.0D0 ) THEN
            K = -K
            HK = -HK
         ENDIF
         IF ( ABS(R) .LT. 1.0D0 ) THEN
            AS = ( 1.0D0 - R )*( 1.0D0 + R )
            A = SQRT(AS)
            BS = ( H - K )**2
            C = ( 4.0D0 - HK )/8.0D0
            D = ( 12.0D0 - HK )/16.0D0
            BVN = A*EXP( -(BS/AS + HK)/2.0D0 )   &
                   *( 1.0D0 - C*(BS - AS)*(1.0D0 - D*BS/5)/3.0D0   &
                   + C*D*AS*AS/5.0D0 )
            IF ( HK .GT. -160.0D0 ) THEN
               B = SQRT(BS)
               BVN = BVN - EXP(-HK/2.0D0)*SQRT(TWOPI)*PHI(-B/A)*B   &
                     *( 1.0D0 - C*BS*( 1.0D0 - D*BS/5.0D0 )/3.0D0 )
            ENDIF
            A = A/2.0D0
            DO 20 I = 1, LG
               XS = ( A*(X(I,NG)+1) )**2
               RS = SQRT( 1.0D0 - XS )
               BVN = BVN + A*W(I,NG)*   &
                    ( EXP( -BS/(2.0D0*XS) - HK/(1.0D0+RS) )/RS   &
                    - EXP( -(BS/XS+HK)/2.0D0 )*   &
                    ( 1.0D0 + C*XS*( 1.0D0 + D*XS ) ) )
               XS = AS*(-X(I,NG)+1.0D0)**2/4.0D0
               RS = SQRT( 1.0D0 - XS )
               BVN = BVN + A*W(I,NG)*EXP( -(BS/XS + HK)/2.0D0 )   &
                     *( EXP( -HK*(1.0D0-RS)/(2.0D0*(1.0D0+RS)))/RS   &
                     - ( 1.0D0 + C*XS*( 1.0D0 + D*XS ) ) )
 20         CONTINUE
            BVN = -BVN/TWOPI
         ENDIF
         IF (R .GT. 0.0D0) BVN =  BVN + PHI( -MAX( H, K ) )
         IF (R .LT. 0.0D0) BVN = -BVN + MAX( ZERO, PHI(-H) - PHI(-K))
      ENDIF
      BVNU = BVN
!
      RETURN
      END FUNCTION BVNU
